private struct NJInvestmentSymbolConvention {
    let instrumentID: String
    let name: String
    let webull: [String]
    let yahoo: [String]
    let stooq: [String]
    let ibkr: [String]

    func contains(_ symbol: String) -> Bool {
        let key = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        return ([instrumentID] + webull + yahoo + stooq + ibkr)
            .map { $0.uppercased() }
            .contains(key)
    }
}

