private func NJInvestmentSymbolConventionRow(for symbol: String) -> NJInvestmentSymbolConvention? {
    NJInvestmentSymbolConventionTable.first { $0.contains(symbol) }
}

private extension Array {
    func chunked(into size: Int) -> [[Element]] {
        guard size > 0 else { return [self] }
        return stride(from: 0, to: count, by: size).map {
            Array(self[$0..<Swift.min($0 + size, count)])
        }
    }
}

private extension Double {
    func isWithinInvestmentBand(low: Double?, high: Double?) -> Bool {
        if let low, low > 0, self < low * 0.5 {
            return false
        }
        if let high, high > 0, self > high * 1.5 {
            return false
        }
        return true
    }
}

private extension CharacterSet {
    static let webullOpenAPISignatureAllowed = CharacterSet.alphanumerics
        .union(CharacterSet(charactersIn: "-_.~"))
}

struct NJInvestmentWatchResearchWindow: View {
    @Environment(\.dismiss) private var dismiss
    let payload: String?
    @State private var selectedTab: NJInvestmentWatchPopupTab = .chart
    @State private var selectedInterval: NJInvestmentChartInterval = .daily
    @State private var chartPoints: [NJInvestmentChartPoint] = []
    @State private var chartStatus = "Loading chart..."

    var body: some View {
        NavigationStack {
            if let row = decodedRow {
                NJInvestmentModuleView(detachedWatchRow: row)
                    .navigationTitle("IRC - \(row.symbol)")
                    .navigationBarTitleDisplayMode(.inline)
                    .toolbar {
                        ToolbarItem(placement: .cancellationAction) {
                            Button("Close Window") { dismiss() }
                        }
                    }
            } else {
                ContentUnavailableView("Watch item not available", systemImage: "exclamationmark.triangle")
            }
        }
        .frame(minWidth: 860, idealWidth: 1180, maxWidth: .infinity, minHeight: 640, idealHeight: 860, maxHeight: .infinity)
    }

    private var decodedRow: NJInvestmentWatchRow? {
        guard let payload,
              let data = Data(base64Encoded: payload) else { return nil }
        return try? JSONDecoder().decode(NJInvestmentWatchRow.self, from: data)
    }

    private func header(_ row: NJInvestmentWatchRow) -> some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 4) {
                    Text("\(row.symbol) - \(row.name)")
                        .font(.title2.weight(.bold))
                    Text("Result date: \(row.resultDate)")
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(.secondary)
                }
                Spacer()
                Text(row.percentChange)
                    .font(.caption.weight(.bold))
                    .foregroundStyle(row.percentChange.trimmingCharacters(in: .whitespaces).hasPrefix("-") ? Color.red : Color.green)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 5)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 8))
            }

            LazyVGrid(columns: [GridItem(.adaptive(minimum: 140), spacing: 8)], spacing: 8) {
                watchMetric("Initial", row.initialPrice)
                watchMetric("Current", row.todayPrice)
                watchMetric("52W High", row.week52High)
                watchMetric("52W Low", row.week52Low)
                watchMetric("T+1", row.tPlusOne)
                watchMetric("T+2", row.tPlusTwo)
                watchMetric("T+3", row.tPlusThree)
            }
        }
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func watchMetric(_ title: String, _ value: String) -> some View {
        VStack(alignment: .leading, spacing: 3) {
            Text(title)
                .font(.caption2.weight(.semibold))
                .foregroundStyle(.secondary)
            Text(value)
                .font(.caption.weight(.bold))
                .lineLimit(2)
                .minimumScaleFactor(0.8)
        }
        .frame(maxWidth: .infinity, minHeight: 48, alignment: .topLeading)
        .padding(10)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private var tabPicker: some View {
        Picker("Research tab", selection: $selectedTab) {
            ForEach(NJInvestmentWatchPopupTab.allCases) { tab in
                Text(tab.rawValue).tag(tab)
            }
        }
        .pickerStyle(.segmented)
    }

    @ViewBuilder
    private func tabContent(_ row: NJInvestmentWatchRow) -> some View {
        switch selectedTab {
        case .chart:
            chartPanel(row)
        case .company:
            markdownPanel(title: "Company", markdown: synopsisMarkdown(for: row))
        case .result:
            markdownPanel(title: "Result", markdown: latestResultMarkdown(for: row))
        case .dividend:
            markdownPanel(title: "Dividend", markdown: "Dividend schedule and yield data are shown in the in-app Instrument Research Console.")
        case .news:
            markdownPanel(title: "News", markdown: "Open this watch item from the Investment tab to refresh and read live related news.")
        case .analysis:
            markdownPanel(title: "Analysis", markdown: analysisMarkdown(for: row))
        case .risk:
            markdownPanel(title: "Risk", markdown: riskMarkdown(for: row))
        case .notes:
            markdownPanel(title: "Notes", markdown: "Open this watch item from the Investment tab to see journal blocks tagged to \(row.symbol).")
        }
    }

    private func chartPanel(_ row: NJInvestmentWatchRow) -> some View {
        return VStack(alignment: .leading, spacing: 10) {
            HStack {
                Label("Stock Chart", systemImage: "chart.line.uptrend.xyaxis")
                    .font(.headline.weight(.semibold))
                Spacer()
                Picker("Interval", selection: $selectedInterval) {
                    ForEach(NJInvestmentChartInterval.allCases) { interval in
                        Text(interval.shortTitle).tag(interval)
                    }
                }
                .pickerStyle(.segmented)
                .frame(width: 240)
            }

            if chartPoints.isEmpty {
                Text(chartStatus)
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                    .frame(maxWidth: .infinity, minHeight: 220)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 8))
            } else {
                let domain = smartChartYDomain(for: chartPoints)
                if selectedInterval.isIntraday {
                    Chart(Array(chartPoints.enumerated()), id: \.element.id) { index, point in
                        LineMark(
                            x: .value("Bar", index),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(Color.accentColor)

                        AreaMark(
                            x: .value("Bar", index),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(
                            LinearGradient(
                                colors: [Color.accentColor.opacity(0.22), Color.accentColor.opacity(0.02)],
                                startPoint: .top,
                                endPoint: .bottom
                            )
                        )
                    }
                    .chartXAxis {
                        AxisMarks(values: .automatic(desiredCount: 5)) { value in
                            AxisGridLine()
                            AxisTick()
                            AxisValueLabel {
                                if let index = value.as(Int.self),
                                   chartPoints.indices.contains(index) {
                                    Text(intradayAxisLabel(for: chartPoints[index].date))
                                }
                            }
                        }
                    }
                    .chartYAxis { AxisMarks(position: .trailing) }
                    .chartYScale(domain: domain)
                    .frame(minHeight: 360, idealHeight: 460, maxHeight: .infinity)
                    .padding(10)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 8))
                } else {
                    Chart(chartPoints) { point in
                        LineMark(
                            x: .value("Date", point.date),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(Color.accentColor)

                        AreaMark(
                            x: .value("Date", point.date),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(
                            LinearGradient(
                                colors: [Color.accentColor.opacity(0.22), Color.accentColor.opacity(0.02)],
                                startPoint: .top,
                                endPoint: .bottom
                            )
                        )
                    }
                    .chartXAxis { AxisMarks(values: .automatic(desiredCount: 5)) }
                    .chartYAxis { AxisMarks(position: .trailing) }
                    .chartYScale(domain: domain)
                    .frame(minHeight: 360, idealHeight: 460, maxHeight: .infinity)
                    .padding(10)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 8))
                }
            }
        }
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func intradayAxisLabel(for date: Date) -> String {
        watchXAxisLabel(for: date, interval: .hourly)
    }

    private func watchXAxisLabel(for date: Date, interval: NJInvestmentChartInterval) -> String {
        let formatter = DateFormatter()
        switch interval {
        case .daily:
            formatter.dateFormat = "M/d"
        case .hourly:
            formatter.dateFormat = "M/d HH"
        case .fifteenMinutes, .fiveMinutes:
            formatter.dateFormat = "M/d HH:mm"
        }
        return formatter.string(from: date)
    }

    private func markdownPanel(title: String, markdown: String) -> some View {
        VStack(alignment: .leading, spacing: 10) {
            Label(title, systemImage: "doc.text")
                .font(.headline.weight(.semibold))
            Text((try? AttributedString(markdown: markdown)) ?? AttributedString(markdown))
                .font(.subheadline)
                .fixedSize(horizontal: false, vertical: true)
        }
        .frame(maxWidth: .infinity, alignment: .topLeading)
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func synopsisMarkdown(for row: NJInvestmentWatchRow) -> String {
        """
        **Symbol:** \(row.symbol)

        **Role:** \(row.usCloseReference)

        **Dashboard use:** This watch item is opened from a trade-thesis watchlist. Read the chart and T+1/T+2/T+3 behavior as evidence for the trade thesis, not as a standalone buy/sell recommendation.
        """
    }

    private func latestResultMarkdown(for row: NJInvestmentWatchRow) -> String {
        """
        **Result date:** \(row.resultDate)

        **Result / reference:** \(row.usCloseReference)

        **Reaction path:** T+1 \(row.tPlusOne), T+2 \(row.tPlusTwo), T+3 \(row.tPlusThree).
        """
    }

    private func analysisMarkdown(for row: NJInvestmentWatchRow) -> String {
        """
        **Analysis note**

        For the US Q1 trade, the important signal is whether strong news gets sold. A pop that fades by T+1/T+2 supports the QQQ exhaustion thesis; a clean hold through T+3 weakens it.
        """
    }

    private func riskMarkdown(for row: NJInvestmentWatchRow) -> String {
        """
        **Risk**

        Do not treat one ticker as the trade. The thesis needs index confirmation from QQQ/SMH and cross-market confirmation from Japan/HK/China. If good-news gaps hold and breadth improves, the short thesis is not confirmed.
        """
    }

    private func refreshChart(for row: NJInvestmentWatchRow) async {
        guard let sourceSymbol = yahooSymbol(for: row.symbol) else {
            await MainActor.run {
                chartPoints = []
                chartStatus = "No chart source mapped for \(row.symbol)."
            }
            return
        }

        await MainActor.run {
            chartStatus = "Loading \(selectedInterval.rawValue.lowercased()) chart..."
        }

        let range = selectedInterval.isIntraday ? "5d" : "1y"
        let interval: String = {
            switch selectedInterval {
            case .daily: return "1d"
            case .hourly: return "1h"
            case .fifteenMinutes: return "15m"
            case .fiveMinutes: return "5m"
            }
        }()
        let points = await fetchYahooChartPoints(sourceSymbol: sourceSymbol, range: range, interval: interval)
        await MainActor.run {
            chartPoints = points
            chartStatus = points.isEmpty ? "No chart data returned for \(sourceSymbol)." : "Loaded \(points.count) points"
        }
    }

    private func yahooSymbol(for symbol: String) -> String? {
        let trimmed = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        switch trimmed {
        case "USD/JPY": return "JPY=X"
        case "USD/CNH": return "CNH=X"
        case "SU FP": return "SU.PA"
        case "ENR GR": return "ENR.DE"
        default: break
        }
        if trimmed.hasSuffix(" HK") {
            return "\(trimmed.replacingOccurrences(of: " HK", with: "")).HK"
        }
        if trimmed.hasSuffix(" JP") {
            return "\(trimmed.replacingOccurrences(of: " JP", with: "")).T"
        }
        if trimmed.hasSuffix(" CN") {
            let code = trimmed.replacingOccurrences(of: " CN", with: "")
            return "\(code).\(code.hasPrefix("6") ? "SS" : "SZ")"
        }
        if trimmed.range(of: #"^[A-Z.]{1,8}$"#, options: .regularExpression) != nil {
            return trimmed
        }
        return nil
    }

    private func fetchYahooChartPoints(sourceSymbol: String, range: String, interval: String) async -> [NJInvestmentChartPoint] {
        let encoded = sourceSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? sourceSymbol
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=\(range)&interval=\(interval)&includePrePost=true") else {
            return []
        }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            guard let object = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = object["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let timestamps = result["timestamp"] as? [TimeInterval],
                  let indicators = result["indicators"] as? [String: Any],
                  let quoteRows = indicators["quote"] as? [[String: Any]],
                  let quote = quoteRows.first,
                  let closes = quote["close"] as? [Any] else {
                return []
            }

            var points: [NJInvestmentChartPoint] = []
            for (index, timestamp) in timestamps.enumerated() where index < closes.count {
                guard let close = doubleValue(closes[index]) else { continue }
                let previous = points.last?.value ?? close
                let change = previous == 0 ? "live" : String(format: "%+.2f%%", (close / previous - 1) * 100)
                points.append(
                    NJInvestmentChartPoint(
                        id: "\(sourceSymbol)-\(interval)-\(Int(timestamp))",
                        date: Date(timeIntervalSince1970: timestamp),
                        value: close,
                        change: change,
                        isDown: close < previous
                    )
                )
            }
            return points
        } catch {
            return []
        }
    }

    private func doubleValue(_ value: Any?) -> Double? {
        if let value = value as? Double { return value }
        if let value = value as? Int { return Double(value) }
        if let value = value as? String { return Double(value) }
        return nil
    }

    private func smartChartYDomain(for points: [NJInvestmentChartPoint]) -> ClosedRange<Double> {
        let values = points.map(\.value)
        guard let minValue = values.min(), let maxValue = values.max() else { return 0...1 }
        let range = maxValue - minValue
        if range == 0 {
            let padding = max(abs(maxValue), 1) * 0.01
            return (minValue - padding)...(maxValue + padding)
        }
        let padding = max(range * 0.12, max(abs(maxValue), abs(minValue), 1) * 0.002)
        return (minValue - padding)...(maxValue + padding)
    }
}

enum NJInvestmentMarket: String, CaseIterable, Identifiable {
    case all = "All"
    case us = "US"
    case hk = "HK"
    case china = "China"
    case chinaHK = "HK / China"
    case japan = "Japan"
    case europe = "Europe"
    case crypto = "Commodity / Crypto"

    static var allCases: [NJInvestmentMarket] {
        [.all, .us, .hk, .china, .chinaHK, .japan, .europe, .crypto]
    }

    var id: String { rawValue }

    var symbolName: String {
        switch self {
        case .all: return "globe"
        case .us: return "building.columns"
        case .hk: return "arrow.left.arrow.right.circle"
        case .china: return "chart.bar.xaxis"
        case .chinaHK: return "dollarsign.arrow.circlepath"
        case .japan: return "yensign.circle"
        case .europe: return "eurosign.circle"
        case .crypto: return "bitcoinsign.circle"
        }
    }

    func matches(region: String) -> Bool {
        let value = region.lowercased()
        switch self {
        case .all:
            return true
        case .us:
            return value.contains("us") || value.contains("united states")
        case .hk:
            return value.contains("hk") || value.contains("hong kong")
        case .china:
            return value.contains("china") || value.contains("shanghai") || value.contains("shenzhen")
        case .chinaHK:
            return value.contains("china") || value.contains("hk") || value.contains("hong kong")
        case .japan:
            return value.contains("japan")
        case .europe:
            return value.contains("europe") || value.contains("euro") || value.contains("ecb") || value.contains("germany") || value.contains("france") || value.contains("uk") || value.contains("united kingdom")
        case .crypto:
            return value.contains("crypto") || value.contains("bitcoin") || value.contains("btc") || value.contains("commodity") || value.contains("oil") || value.contains("gold") || value.contains("silver")
        }
    }
}

