private struct NJInvestmentThesisBudgetRow: Identifiable {
    let id: String
    let thesis: String
    let plannedHKD: Double
    let deployedHKD: Double
    let marketValueHKD: Double?
    let unrealizedPLHKD: Double?
    let note: String

    var remainingHKD: Double {
        plannedHKD - deployedHKD
    }

    var deployedPercent: Double {
        guard plannedHKD > 0 else { return 0 }
        return deployedHKD / plannedHKD * 100
    }
}

private struct NJInvestmentChildTradeBudgetRow: Identifiable {
    let id: String
    let thesis: String
    let tradeName: String
    let plannedHKD: Double
    let deployedHKD: Double
    let marketValueHKD: Double?
    let unrealizedPLHKD: Double?
    let lifecycle: NJInvestmentTradeLifecycle
    let goal: String

    var remainingHKD: Double {
        plannedHKD - deployedHKD
    }

    var deployedPercent: Double {
        guard plannedHKD > 0 else { return 0 }
        return deployedHKD / plannedHKD * 100
    }
}

private enum NJInvestmentCalendarMode: String, CaseIterable, Identifiable {
    case week = "Week"
