private enum NJInvestmentChartInterval: String, CaseIterable, Identifiable {
    case daily = "Daily"
    case hourly = "Hourly"
    case fifteenMinutes = "15 Min"
    case fiveMinutes = "5 Min"

    var id: String { rawValue }

    var shortTitle: String {
        switch self {
        case .daily: return "1D"
        case .hourly: return "1H"
        case .fifteenMinutes: return "15M"
        case .fiveMinutes: return "5M"
        }
    }

    var isIntraday: Bool {
        switch self {
        case .hourly, .fifteenMinutes, .fiveMinutes:
            return true
        case .daily:
            return false
        }
    }
}

