private struct NJInvestmentAnalysisInboxItem: Identifiable, Hashable {
    let id: String
    let tradeThesis: String
    let cadence: String
    let severity: String
    let category: String
    let verdict: String
    let notify: Bool
    let headline: String
    let whatHappened: String
    let tradeRead: String
    let nextWatch: String
    let asOf: Date
    let source: String
    let symbols: [String]
    let cloudKitNewsID: String
    let articlePath: String

    var titleLine: String {
        let cleanedHeadline = cleanInvestmentAnalysisInboxHeadline(headline)
        if !cleanedHeadline.isEmpty {
            return cleanedHeadline
        }
        let cleanedWhatHappened = cleanInvestmentAnalysisInboxHeadline(whatHappened)
        if !cleanedWhatHappened.isEmpty {
            return cleanedWhatHappened
        }
        return "\(tradeThesis) - \(cadence)"
    }

    var isCritical: Bool {
        let h = headline.lowercased()
        let w = whatHappened.lowercased()
        let n = nextWatch.lowercased()
        let combined = "\(h) \(w) \(n)"
        let escalationTerms = [
            "war", "invasion", "missile", "drone attack", "airstrike", "terror attack",
            "ceasefire collapse", "ceasefire collapsed", "blockade", "strait",
            "red sea", "taiwan", "nato", "mobilization", "martial law", "sanction",
            "project freedom",
            "default", "missed payment", "bank run", "deposit freeze", "debt restructuring",
            "failed auction", "weak auction", "auction tail", "tails", "emergency treasury",
            "currency slump", "currency slumped", "currency plunge", "devaluation",
            "capital controls", "fx intervention", "circuit breaker", "trading halt",
            "bank failure", "sovereign downgrade", "emergency rate hike", "bond rout"
        ]
        let geopoliticalActors = [
            "trump", "white house", "iran", "israel", "russia", "ukraine", "china",
            "taiwan", "nato", "gulf", "hormuz", "opec"
        ]
        let geopoliticalActions = [
            "deal", "peace", "ceasefire", "negotiate", "negotiation", "talks",
            "sanction", "nuclear", "attack", "strike", "retaliation", "blockade", "closed", "over"
        ]
        let promoTerms = [
            "press release", "collaborat", "partnership", "partner", "expands ai",
            "ai capabilities", "ai-powered features", "conference", "media alert",
            "price target", "raised to", "upgraded", "downgraded", "earnings",
            "revenue", "eps", "guidance", "shares", "stock", "rebound", "selloff",
            "slump", "beat", "miss", "analyst", "barrons", "market talk",
            "launches", "introducing", "platform", "software"
        ]
        let hasEmergencyTerm = escalationTerms.contains { investmentAnalysisInboxContainsRiskTerm($0, in: combined) }
        let hasGeopoliticalActor = geopoliticalActors.contains { investmentAnalysisInboxContainsRiskTerm($0, in: combined) }
        let hasGeopoliticalAction = geopoliticalActions.contains { combined.contains($0) }
        let looksPromotional = promoTerms.contains { combined.contains($0) }
        if hasEmergencyTerm || (hasGeopoliticalActor && hasGeopoliticalAction) { return true }
        if looksPromotional { return false }
        return false
    }

    var isSuppressedNewsNoise: Bool {
        if isCritical { return false }
        let combined = "\(headline) \(whatHappened) \(tradeRead) \(nextWatch) \(category) \(source)".lowercased()
        let noiseTerms = [
            "press release", "price target", "maintained at", "initiated at", "raised to",
            "upgraded", "downgraded", "outperform", "underperform", "market perform",
            "earnings", "revenue", "eps", "guidance", "shares", "stock rebounds",
            "stock market today", "market recap", "closing bell", "market talk",
            "barrons.com", "dow's", "s&p 500", "nasdaq", "share gains", "share losses",
            "launches", "introducing", "partnership", "collaborat"
        ]
        return noiseTerms.contains { combined.contains($0) }
    }

    var displaySeverity: String {
        let raw = severity.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !raw.isEmpty else { return "" }
        if raw.lowercased() == "ignore" { return "" }
        if isCritical { return raw }
        let lower = raw.lowercased()
        if lower.contains("critical") || lower.contains("breaking") || lower.contains("urgent") {
            return symbols.isEmpty ? "Digest" : "Important"
        }
        return raw
    }

    var displayCategory: String {
        let raw = category.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !raw.isEmpty else { return "" }
        if !isCritical, raw.lowercased().contains("macro breaking") {
            return symbols.isEmpty ? "Global News Digest" : "Symbol News"
        }
        return raw
    }

    var displayNotify: Bool {
        notify && isCritical
    }
}

private func cleanInvestmentAnalysisInboxHeadline(_ title: String) -> String {
    title
        .replacingOccurrences(of: #"\{A:[^}]+\}"#, with: "", options: .regularExpression)
        .replacingOccurrences(of: #"(?i)^press release:\s*"#, with: "", options: .regularExpression)
        .replacingOccurrences(of: #">\w+$"#, with: "", options: .regularExpression)
        .trimmingCharacters(in: .whitespacesAndNewlines)
}

private func investmentAnalysisInboxContainsRiskTerm(_ term: String, in text: String) -> Bool {
    let escaped = NSRegularExpression.escapedPattern(for: term)
    let pattern = #"(?<![A-Za-z0-9])"# + escaped + #"(?![A-Za-z0-9])"#
    return text.range(of: pattern, options: [.regularExpression, .caseInsensitive]) != nil
}

