private struct NJInvestmentWatchRow: Identifiable, Codable {
    let id: String
    let symbol: String
    let name: String
    let monitorDate: String
    let resultDate: String
    let usCloseReference: String
    let tPlusOne: String
    let tPlusTwo: String
    let tPlusThree: String
    let initialPrice: String
    let week52High: String
    let week52Low: String
    let todayPrice: String
    let vwap: String
    let percentChange: String

    init(
        id: String,
        symbol: String,
        name: String,
        monitorDate: String,
        resultDate: String = "TBD",
        usCloseReference: String = "-",
        tPlusOne: String = "Pending",
        tPlusTwo: String = "Pending",
        tPlusThree: String = "Pending",
        initialPrice: String,
        week52High: String,
        week52Low: String,
        todayPrice: String,
        vwap: String = "Pending",
        percentChange: String
    ) {
        self.id = id
        self.symbol = symbol
        self.name = name
        self.monitorDate = monitorDate
        self.resultDate = resultDate
        self.usCloseReference = usCloseReference
        self.tPlusOne = tPlusOne
        self.tPlusTwo = tPlusTwo
        self.tPlusThree = tPlusThree
        self.initialPrice = initialPrice
        self.week52High = week52High
        self.week52Low = week52Low
        self.todayPrice = todayPrice
        self.vwap = vwap
        self.percentChange = percentChange
    }

    var percentFrom52WeekHigh: String {
        percentDistance(from: week52High)
    }

    var percentFrom52WeekLow: String {
        percentDistance(from: week52Low)
    }

    var percentFromInitialPrice: String {
        percentDistance(from: initialPrice)
    }

    private func percentDistance(from anchor: String) -> String {
        guard let price = Self.numericValue(from: todayPrice),
              let anchorValue = Self.numericValue(from: anchor),
              anchorValue != 0 else { return "n/a" }
        let pct = (price / anchorValue - 1) * 100
        return String(format: "%+.1f%%", pct)
    }

    private static func numericValue(from text: String) -> Double? {
        let cleaned = text
            .replacingOccurrences(of: ",", with: "")
            .replacingOccurrences(of: "$", with: "")
            .replacingOccurrences(of: "HK$", with: "")
            .replacingOccurrences(of: "CNY", with: "")
            .replacingOccurrences(of: "EUR", with: "")
            .replacingOccurrences(of: "JPY", with: "")
        let pattern = #"[-+]?\d*\.?\d+"#
        guard let range = cleaned.range(of: pattern, options: .regularExpression) else { return nil }
        return Double(cleaned[range])
    }
}

