private struct NJInvestmentLiveQuote: Identifiable, Hashable {
    let id: String
    let sourceSymbol: String
    let dateKey: String
    let timeText: String
    let close: Double
    let previousClose: Double?
    let source: String
    let fiftyTwoWeekHigh: Double?
    let fiftyTwoWeekLow: Double?
    let open: Double?
    let dayHigh: Double?
    let dayLow: Double?
    let volume: Double?

    init(
        id: String,
        sourceSymbol: String,
        dateKey: String,
        timeText: String,
        close: Double,
        previousClose: Double?,
        source: String,
        fiftyTwoWeekHigh: Double? = nil,
        fiftyTwoWeekLow: Double? = nil,
        open: Double? = nil,
        dayHigh: Double? = nil,
        dayLow: Double? = nil,
        volume: Double? = nil
    ) {
        self.id = id
        self.sourceSymbol = sourceSymbol
        self.dateKey = dateKey
        self.timeText = timeText
        self.close = close
        self.previousClose = previousClose
        self.source = source
        self.fiftyTwoWeekHigh = fiftyTwoWeekHigh
        self.fiftyTwoWeekLow = fiftyTwoWeekLow
        self.open = open
        self.dayHigh = dayHigh
        self.dayLow = dayLow
        self.volume = volume
    }

    var valueText: String {
        if close >= 1000 {
            return String(format: "%.0f", close)
        }
        if close >= 100 {
            return String(format: "%.2f", close)
        }
        return String(format: "%.3f", close)
    }

    var changeText: String {
        guard let previousClose, previousClose != 0 else { return "live" }
        let pct = (close / previousClose - 1) * 100
        return String(format: "%+.2f%%", pct)
    }

    var isDown: Bool {
        guard let previousClose else { return false }
        return close < previousClose
    }

    var isWebullSource: Bool {
        source.localizedCaseInsensitiveContains("webull")
    }
}

