private struct NJInvestmentPositionSummary: Identifiable {
    let id: String
    let tradeThesis: String
    let symbol: String
    let institutions: [String]
    let currency: String
    let netQuantity: Double
    let averageCost: Double
    let grossCost: Double
    let realizedPL: Double
    let currentPrice: Double?
    let lots: [NJInvestmentOpenLot]

    var marketValue: Double? {
        currentPrice.map { netQuantity * $0 }
    }

    var unrealizedPL: Double? {
        marketValue.map { $0 - grossCost }
    }

    var unrealizedPct: Double? {
        guard grossCost != 0, let unrealizedPL else { return nil }
        return unrealizedPL / grossCost * 100
    }
}

