            uiView.load(URLRequest(url: url))
        }
    }
}

private final class NJObservationRSSParser: NSObject, XMLParserDelegate {
    private var items: [NJObservationNewsItem] = []
    private var currentElement = ""
    private var insideItem = false
    private var title = ""
    private var link = ""
    private var pubDate = ""

    static func parse(data: Data) -> [NJObservationNewsItem] {
        let delegate = NJObservationRSSParser()
        let parser = XMLParser(data: data)
        parser.delegate = delegate
        parser.parse()
        return delegate.items
    }

    func parser(_ parser: XMLParser, didStartElement elementName: String, namespaceURI: String?, qualifiedName qName: String?, attributes attributeDict: [String: String] = [:]) {
        currentElement = elementName
        if elementName == "item" {
            insideItem = true
            title = ""
            link = ""
            pubDate = ""
        }
    }

    func parser(_ parser: XMLParser, foundCharacters string: String) {
        guard insideItem else { return }
        switch currentElement {
        case "title": title += string
        case "link": link += string
        case "pubDate": pubDate += string
        default: break
        }
    }

    func parser(_ parser: XMLParser, didEndElement elementName: String, namespaceURI: String?, qualifiedName qName: String?) {
        guard elementName == "item" else { return }
        let cleanedTitle = decodeRSSString(title.trimmingCharacters(in: .whitespacesAndNewlines))
        let parts = cleanedTitle.components(separatedBy: " - ")
        let source = parts.count > 1 ? parts.last ?? "" : ""
        let displayTitle = parts.count > 1 ? parts.dropLast().joined(separator: " - ") : cleanedTitle
        let url = URL(string: link.trimmingCharacters(in: .whitespacesAndNewlines))
        let publishedAt = parsedDate(pubDate)
        items.append(
            NJObservationNewsItem(
                id: "\(displayTitle)-\(pubDate)",
                title: displayTitle,
                source: source,
                dateText: shortDateText(pubDate, parsedDate: publishedAt),
                publishedAt: publishedAt,
                url: url
            )
        )
        insideItem = false
        currentElement = ""
    }

    private func decodeRSSString(_ value: String) -> String {
        value
            .replacingOccurrences(of: "&amp;", with: "&")
            .replacingOccurrences(of: "&quot;", with: "\"")
            .replacingOccurrences(of: "&#39;", with: "'")
            .replacingOccurrences(of: "&apos;", with: "'")
            .replacingOccurrences(of: "&lt;", with: "<")
            .replacingOccurrences(of: "&gt;", with: ">")
    }

    private func parsedDate(_ value: String) -> Date? {
        let input = DateFormatter()
        input.locale = Locale(identifier: "en_US_POSIX")
        input.dateFormat = "E, d MMM yyyy HH:mm:ss zzz"
        return input.date(from: value.trimmingCharacters(in: .whitespacesAndNewlines))
    }

    private func shortDateText(_ value: String, parsedDate: Date?) -> String {
        guard let date = parsedDate else {
            return value
        }
        let output = DateFormatter()
        output.dateFormat = "MMM d HH:mm"
        return output.string(from: date)
    }
}

private func observationNewsSort(_ lhs: NJObservationNewsItem, _ rhs: NJObservationNewsItem) -> Bool {
    switch (lhs.publishedAt, rhs.publishedAt) {
    case let (l?, r?): return l > r
    case (_?, nil): return true
    case (nil, _?): return false
    case (nil, nil): return lhs.title < rhs.title
    }
}

private extension NJObservationNewsItem {
    var isFreshObservationNews: Bool {
        guard let publishedAt else { return false }
        return publishedAt >= Date().addingTimeInterval(-36 * 60 * 60)
    }
}

private extension String {
    var normalizedObservationNewsKey: String {
        lowercased()
            .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }
}

@MainActor
private final class NJObservationLiveLoader: ObservableObject {
    static let shared = NJObservationLiveLoader()

    @Published var evidenceByObservationID: [String: [NJObservationEvidencePoint]] = [:]
    @Published var newsByObservationID: [String: [NJObservationNewsItem]] = [:]
    @Published var loadingObservationIDs: Set<String> = []

    func refresh(_ observation: NJTradingJournalObservation) {
        guard !loadingObservationIDs.contains(observation.id) else { return }
        loadingObservationIDs.insert(observation.id)
        NJInvestmentDebugLog("OBSERVATION_LIVE_START id=\(observation.id)")

        Task { [weak self] in
            let evidence = await Self.fetchEvidence(for: observation)
            guard let self else { return }
            evidenceByObservationID[observation.id] = evidence
            NJInvestmentDebugLog("OBSERVATION_EVIDENCE_DONE id=\(observation.id) evidence=\(evidence.count)")

            let news = await Self.fetchNews(for: observation)
            newsByObservationID[observation.id] = news
            loadingObservationIDs.remove(observation.id)
            NJInvestmentDebugLog("OBSERVATION_LIVE_DONE id=\(observation.id) evidence=\(evidence.count) news=\(news.count)")
        }
    }

    private static func newsQueries(for observation: NJTradingJournalObservation) -> [String] {
        switch observation.id {
        case "amd-nvidia-grind":
            return ["AMD Nvidia AI stocks market breadth", "Mag 7 AI stocks VIX"]
        case "post-nvidia-lower-highs":
            return ["Nvidia earnings reaction AI stocks failed breakout", "Nasdaq AI stocks lower highs"]
        case "june-monetary-regime":
            return ["Federal Reserve BOJ JGB USD JPY yields", "US yields yen liquidity regime"]
        case "xi-trump-save-trade":
            return ["Trump Xi trade talks tariffs China stocks", "China Hong Kong stocks trade deal"]
        case "iran-us-no-clean-deal":
            return ["Iran US Israel war negotiations Hormuz oil stocks", "Ukraine Russia grain exports fertilizer oil war markets"]
        default:
            return []
        }
    }

    private static func evidenceTargets(for observation: NJTradingJournalObservation) -> [NJObservationEvidenceTarget] {
        switch observation.id {
        case "amd-nvidia-grind":
            return [
                NJObservationEvidenceTarget(id: "qqq", label: "Nasdaq proxy holding", yahooSymbol: "qqq.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "smh", label: "Semis holding", yahooSymbol: "smh.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "nvda", label: "Nvidia leadership", yahooSymbol: "nvda.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "vxx", label: "Volatility contained", yahooSymbol: "vxx.us", holdingWhenUp: false)
            ]
        case "post-nvidia-lower-highs":
            return [
                NJObservationEvidenceTarget(id: "nvda", label: "Nvidia pressure", yahooSymbol: "nvda.us", holdingWhenUp: false),
                NJObservationEvidenceTarget(id: "smh", label: "Semi ETF pressure", yahooSymbol: "smh.us", holdingWhenUp: false),
                NJObservationEvidenceTarget(id: "qqq", label: "Nasdaq fatigue", yahooSymbol: "qqq.us", holdingWhenUp: false)
            ]
        case "june-monetary-regime":
            return [
                NJObservationEvidenceTarget(id: "usdjpy", label: "USD/JPY pressure", yahooSymbol: "usdjpy", holdingWhenUp: false),
                NJObservationEvidenceTarget(id: "tlt", label: "Long bond bid", yahooSymbol: "tlt.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "vxx", label: "Volatility check", yahooSymbol: "vxx.us", holdingWhenUp: false)
            ]
        case "xi-trump-save-trade":
            return [
                NJObservationEvidenceTarget(id: "hsi", label: "Hong Kong beta", yahooSymbol: "^hsi", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "baba", label: "China ADR beta", yahooSymbol: "baba.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "fxi", label: "China ETF beta", yahooSymbol: "fxi.us", holdingWhenUp: true)
            ]
        case "iran-us-no-clean-deal":
            return [
                NJObservationEvidenceTarget(id: "oil", label: "Oil risk premium", yahooSymbol: "cl.f", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "wheat", label: "Wheat pressure", yahooSymbol: "weat.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "fertilizer", label: "Fertilizer beta", yahooSymbol: "mos.us", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "gold", label: "Gold safety bid", yahooSymbol: "xauusd", holdingWhenUp: true),
                NJObservationEvidenceTarget(id: "vxx", label: "Volatility risk", yahooSymbol: "vxx.us", holdingWhenUp: true)
            ]
        default:
            return []
        }
    }

    private static func fetchEvidence(for observation: NJTradingJournalObservation) async -> [NJObservationEvidencePoint] {
        await withTaskGroup(of: NJObservationEvidencePoint?.self) { group in
            for target in evidenceTargets(for: observation) {
                group.addTask {
                    await fetchEvidencePoint(target)
                }
            }
            var rows: [NJObservationEvidencePoint] = []
            for await row in group {
                if let row { rows.append(row) }
            }
            return rows.sorted { $0.id < $1.id }
        }
    }

    private static func fetchEvidencePoint(_ target: NJObservationEvidenceTarget) async -> NJObservationEvidencePoint? {
        var components = URLComponents(string: "https://stooq.com/q/l/")!
        components.queryItems = [
            URLQueryItem(name: "s", value: target.yahooSymbol),
            URLQueryItem(name: "f", value: "sd2t2ohlcvp"),
            URLQueryItem(name: "h", value: ""),
            URLQueryItem(name: "e", value: "csv")
        ]
        guard let url = components.url else { return nil }

        do {
            let request = URLRequest(url: url, timeoutInterval: 8)
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let text = String(data: data, encoding: .utf8) else { return nil }
            let rows = text.split(whereSeparator: \.isNewline).map(String.init)
            guard rows.count > 1 else { return nil }
            let values = parseCSVRow(rows[1])
            guard values.count >= 7,
                  values[1] != "N/D",
                  let open = Double(values[3]),
                  let price = Double(values[6]) else { return nil }
            let previous = values.count > 8 ? Double(values[8]) : nil
            let base = previous ?? open
            let pct = base == 0 ? 0 : (price / base - 1) * 100
            let isHolding = target.holdingWhenUp ? pct >= -0.35 : pct <= 0.35
            return NJObservationEvidencePoint(
                id: target.id,
                label: target.label,
                symbol: values[0],
                priceText: formatPrice(price),
                changeText: String(format: "%+.2f%%", pct),
                isHolding: isHolding,
                dateText: "\(values[1]) \(values.count > 2 ? values[2] : "")".trimmingCharacters(in: .whitespaces)
            )
        } catch {
            NJInvestmentDebugLog("OBSERVATION_EVIDENCE_ERR id=\(target.id) err=\(error.localizedDescription)")
            return nil
        }
    }

    private static func fetchNews(for observation: NJTradingJournalObservation) async -> [NJObservationNewsItem] {
        var seen = Set<String>()
        var rows: [NJObservationNewsItem] = []
        for query in newsQueries(for: observation) {
            let items = await fetchGoogleNewsRSS(query: query)
            for item in items where item.isFreshObservationNews && seen.insert(item.title.normalizedObservationNewsKey).inserted {
                rows.append(item)
                if rows.count >= 6 {
                    return rows.sorted(by: observationNewsSort)
                }
            }
        }
        return rows.sorted(by: observationNewsSort)
    }

    private static func fetchGoogleNewsRSS(query: String) async -> [NJObservationNewsItem] {
        var components = URLComponents(string: "https://news.google.com/rss/search")
        components?.queryItems = [
            URLQueryItem(name: "q", value: "\(query) when:1d"),
            URLQueryItem(name: "hl", value: "en-US"),
            URLQueryItem(name: "gl", value: "US"),
            URLQueryItem(name: "ceid", value: "US:en")
        ]
        guard let url = components?.url else { return [] }

        do {
            let request = URLRequest(url: url, timeoutInterval: 8)
            let (data, _) = try await URLSession.shared.data(for: request)
            return NJObservationRSSParser.parse(data: data)
        } catch {
            NJInvestmentDebugLog("OBSERVATION_NEWS_ERR query=\(query) err=\(error.localizedDescription)")
            return []
        }
    }

    private static func parseCSVRow(_ row: String) -> [String] {
        row.split(separator: ",", omittingEmptySubsequences: false)
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
    }

    private static func formatPrice(_ value: Double) -> String {
        if value >= 1000 { return String(format: "%.0f", value) }
        if value >= 100 { return String(format: "%.2f", value) }
        return String(format: "%.3f", value)
    }
}

