private struct NJInvestmentReferenceBlock: Identifiable, Hashable {
    let id: String
    let noteID: String
    let noteDomain: String
    let tags: [String]
    let body: String
    let updatedAtMs: Int64

    var isAllocation: Bool {
        tags.contains { $0.caseInsensitiveCompare("FNallocation") == .orderedSame || $0.caseInsensitiveCompare("#FNallocation") == .orderedSame }
    }

    var isStrategy: Bool {
        tags.contains {
            $0.caseInsensitiveCompare("FNstrategy") == .orderedSame
            || $0.caseInsensitiveCompare("#FNstrategy") == .orderedSame
            || $0.caseInsensitiveCompare("FNstrat") == .orderedSame
            || $0.caseInsensitiveCompare("#FNstrat") == .orderedSame
        }
    }
}

