    @State private var savedStatus: String?
    @State private var selectedDate: Date = Date()
    @State private var draftKind: String = "Thought"
    @State private var draftAuthor: String = "Me"
    @State private var draftAttr: NSAttributedString = NSAttributedString(string: "")
    @State private var draftSelection: NSRange = NSRange(location: 0, length: 0)
    @State private var draftEditorHeight: CGFloat = 80
    @State private var draftProtonHandle = NJProtonEditorHandle()
    @State private var draftEditorResetID = UUID()
    @State private var pickedPhotoItem: PhotosPickerItem?
    @State private var editorNoteID: NJNoteID?
    @State private var editorReloadID = UUID()
    @State private var referenceBlocks: [NJInvestmentReferenceBlock] = []
    @State private var referenceEditorNoteID: NJNoteID?

    private var selectedDayTitle: String {
        let formatter = DateFormatter()
        formatter.dateFormat = "EEE, MMM d, yyyy"
        return formatter.string(from: selectedDate)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            weekCalendar
            tradeJournalControls
            legacyJournalRecoveryPanel
            tradeJournalNoteEditor
        }
        .onAppear {
            reloadPersistentReferenceBlocks()
            ensureTradeJournalNote()
            logJournalState(source: "trade_journal_on_appear")
        }
        .onChange(of: selectedDate) { _, _ in
            ensureTradeJournalNote()
        }
        .onChange(of: encodedBlocksByDate) { _, _ in
            logJournalState(source: "trade_journal_storage_changed")
        }
        .sheet(item: $referenceEditorNoteID, onDismiss: {
            reloadPersistentReferenceBlocks()
        }) { noteID in
            NavigationStack {
                NJNoteEditorContainerView(noteID: noteID)
                    .environmentObject(store)
                    .navigationTitle("Reference Block")
                    .navigationBarTitleDisplayMode(.inline)
                    .toolbar {
                        ToolbarItem(placement: .cancellationAction) {
                            Button("Close") { referenceEditorNoteID = nil }
                        }
                    }
            }
        }
    }

