    private func referenceGroup(title: String, tag: String, rows: [NJInvestmentReferenceBlock], emptyText: String) -> some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(spacing: 8) {
                Text(title)
                    .font(.subheadline.weight(.bold))
                Text(tag)
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
                    .padding(.horizontal, 7)
                    .padding(.vertical, 3)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 6))
            }

            if rows.isEmpty {
                Text(emptyText)
                    .font(.caption)
                    .foregroundStyle(.secondary)
            } else {
                ForEach(rows.prefix(4)) { row in
                    persistentReferenceRow(row)
                }
            }
        }
    }

    private func persistentReferenceRow(_ row: NJInvestmentReferenceBlock) -> some View {
        VStack(alignment: .leading, spacing: 7) {
            HStack(alignment: .firstTextBaseline) {
                Text(row.noteDomain.isEmpty ? "Reference block" : row.noteDomain)
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
                Spacer()
                if !row.noteID.isEmpty {
                    Button {
                        referenceEditorNoteID = NJNoteID(row.noteID)
                    } label: {
                        Label("Open", systemImage: "arrow.up.forward.square")
                    }
                    .font(.caption.weight(.semibold))
                    .buttonStyle(.bordered)
                    .controlSize(.small)
                }
            }

            Text(row.body.isEmpty ? "(No text preview)" : row.body)
                .font(.subheadline)
                .lineLimit(8)
                .fixedSize(horizontal: false, vertical: true)

            Text(row.tags.filter { !$0.isEmpty }.prefix(4).joined(separator: "  "))
                .font(.caption2.weight(.semibold))
                .foregroundStyle(.secondary)
        }
        .padding(10)
        .frame(maxWidth: .infinity, alignment: .topLeading)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func reloadPersistentReferenceBlocks() {
        let rows = (try? store.notes.exportTaggedBlockRows(tagFilter: "#FNallocation #FNstrategy #FNstrat", limit: 12)) ?? []
        referenceBlocks = rows.filter { row in
            Self.hasPersistentReferenceTag(row.blockTags)
        }.map { row in
            let body = NJBlockExporter.plainTextFromPayloadJSON(row.payloadJSON)
            var tags = row.blockTags
            if Self.hasAllocationTag(tags),
               !tags.contains(where: { Self.normalizedReferenceTag($0) == "fnallocation" }) {
                tags.append("FNallocation")
            }
            if Self.hasStrategyTag(tags),
               !tags.contains(where: { Self.normalizedReferenceTag($0) == "fnstrat" }) {
                tags.append("FNstrat")
            }
            return NJInvestmentReferenceBlock(
                id: row.blockID,
                noteID: row.noteID,
                noteDomain: row.noteDomain,
                tags: tags,
                body: body,
                updatedAtMs: row.tsMs
            )
        }
        NJInvestmentDebugLog("TRADE_JOURNAL_REFERENCES_RELOAD count=\(referenceBlocks.count) ids=\(referenceBlocks.map(\.id).prefix(6).joined(separator: ","))")
    }

    private static func normalizedReferenceTag(_ tag: String) -> String {
        tag.trimmingCharacters(in: .whitespacesAndNewlines)
            .trimmingCharacters(in: CharacterSet(charactersIn: "#"))
            .lowercased()
    }

    private static func hasAllocationTag(_ tags: [String]) -> Bool {
        tags.contains { normalizedReferenceTag($0) == "fnallocation" }
    }

    private static func hasStrategyTag(_ tags: [String]) -> Bool {
        tags.contains {
            let tag = normalizedReferenceTag($0)
            return tag == "fnstrategy" || tag == "fnstrat"
        }
    }

    private static func hasPersistentReferenceTag(_ tags: [String]) -> Bool {
        hasAllocationTag(tags) || hasStrategyTag(tags)
    }

