    private func ensureTradeJournalNote() {
        guard let notebookID = store.selectedNotebookID,
              let tabDomain = store.currentTabDomain else {
            editorNoteID = nil
            return
        }

        let title = "Trade Journal \(dateKey(selectedDate))"
        if let existing = existingTradeJournalNote(title: title, notebookID: notebookID, currentTabDomain: tabDomain) {
            editorNoteID = existing.id
            cleanupStalePersistentReferenceAttachments(noteID: existing.id.raw)
            attachPersistentReferenceBlocksIntoNote(existing.id.raw)
            NJInvestmentDebugLog("TRADE_JOURNAL_NOTE_OPEN title=\(title) note=\(existing.id.raw) tab=\(existing.tabDomain) blocks=\(liveBlockCount(noteID: existing.id.raw))")
            return
        }

        let note = store.notes.createNote(notebook: notebookID, tabDomain: tabDomain, title: title)
        editorNoteID = note.id
        cleanupStalePersistentReferenceAttachments(noteID: note.id.raw)
        attachPersistentReferenceBlocksIntoNote(note.id.raw)
        store.sync.schedulePush(debounceMs: 0)
    }

    private func cleanupStalePersistentReferenceAttachments(noteID: String) {
        let now = DBNoteRepository.nowMs()
        let staleInstanceIDs: [String] = store.notes.db.withDB { dbp in
            var stmt: OpaquePointer?
            let sql = """
            SELECT nb.instance_id
            FROM nj_note_block nb
            JOIN nj_block b ON b.block_id = nb.block_id
            WHERE nb.note_id = ?
              AND nb.deleted = 0
              AND b.deleted = 0
              AND nb.order_key < 0
              AND NOT EXISTS (
                  SELECT 1
                  FROM nj_block_tag t
                  WHERE t.block_id = b.block_id
                    AND lower(trim(t.tag, '#')) IN ('fnallocation', 'fnstrategy', 'fnstrat')
              );
            """
            guard sqlite3_prepare_v2(dbp, sql, -1, &stmt, nil) == SQLITE_OK else { return [] }
            defer { sqlite3_finalize(stmt) }
            noteID.withCString { sqlite3_bind_text(stmt, 1, $0, -1, nil) }

            var ids: [String] = []
            while sqlite3_step(stmt) == SQLITE_ROW {
                if let raw = sqlite3_column_text(stmt, 0) {
                    ids.append(String(cString: raw))
                }
            }
            return ids
        }

        guard !staleInstanceIDs.isEmpty else { return }

        store.notes.db.withDB { dbp in
            var stmt: OpaquePointer?
            let sql = "UPDATE nj_note_block SET deleted = 1, updated_at_ms = ? WHERE instance_id = ?;"
            guard sqlite3_prepare_v2(dbp, sql, -1, &stmt, nil) == SQLITE_OK else { return }
            defer { sqlite3_finalize(stmt) }

            for instanceID in staleInstanceIDs {
                sqlite3_reset(stmt)
                sqlite3_clear_bindings(stmt)
                sqlite3_bind_int64(stmt, 1, now)
                instanceID.withCString { sqlite3_bind_text(stmt, 2, $0, -1, nil) }
                _ = sqlite3_step(stmt)
            }
        }

        for instanceID in staleInstanceIDs {
            store.notes.enqueueDirty(entity: "note_block", entityID: instanceID, op: "upsert", updatedAtMs: now)
        }
        store.sync.schedulePush(debounceMs: 0)
        NJInvestmentDebugLog("TRADE_JOURNAL_REFERENCES_CLEANUP note=\(noteID) stale_instances=\(staleInstanceIDs.joined(separator: ","))")
    }

    private func attachPersistentReferenceBlocksIntoNote(_ noteID: String) {
        if referenceBlocks.isEmpty {
            reloadPersistentReferenceBlocks()
        }

        let refs = referenceBlocks
            .filter { $0.isAllocation || $0.isStrategy }
            .sorted { lhs, rhs in
                if lhs.isAllocation != rhs.isAllocation { return lhs.isAllocation }
                return lhs.updatedAtMs > rhs.updatedAtMs
            }

        guard !refs.isEmpty else { return }

        var orderKey = -2000.0
        var attachedIDs: [String] = []
        for ref in refs.prefix(4) {
            let instanceID = store.notes.attachExistingBlockToNote(
                noteID: noteID,
                blockID: ref.id,
                orderKey: orderKey
            )
            if !instanceID.isEmpty {
                attachedIDs.append(ref.id)
            }
            orderKey += 100.0
        }

        if !attachedIDs.isEmpty {
            store.sync.schedulePush(debounceMs: 0)
            NJInvestmentDebugLog("TRADE_JOURNAL_REFERENCES_ATTACHED note=\(noteID) blocks=\(attachedIDs.joined(separator: ","))")
        }
    }

    private func addTradeJournalBlock() {
        guard let noteID = editorNoteID?.raw else {
            savedStatus = "Open a Trade Journal day first."
            return
        }

        let payloadJSON = NJQuickNotePayload.makePayloadJSON(from: "")
        guard let blockID = store.notes.createQuickNoteBlock(
            payloadJSON: payloadJSON,
            createdAtMs: DBNoteRepository.nowMs(),
            tags: ["investment", "trade-journal"]
        ) else {
            savedStatus = "Could not create a new Trade Journal block."
            NJInvestmentDebugLog("TRADE_JOURNAL_ADD_BLOCK_FAILED note=\(noteID)")
            return
        }

        let orderKey = max(1000.0, store.notes.nextAppendOrderKey(noteID: noteID))
        let instanceID = store.notes.attachExistingBlockToNote(
            noteID: noteID,
            blockID: blockID,
            orderKey: orderKey
        )
        guard !instanceID.isEmpty else {
            savedStatus = "Created a block, but could not attach it to this note."
            NJInvestmentDebugLog("TRADE_JOURNAL_ADD_BLOCK_ATTACH_FAILED note=\(noteID) block=\(blockID)")
            return
        }

        editorReloadID = UUID()
        store.sync.schedulePush(debounceMs: 0)
        savedStatus = "Added a new Trade Journal block."
        NJInvestmentDebugLog("TRADE_JOURNAL_ADD_BLOCK note=\(noteID) block=\(blockID) instance=\(instanceID) order=\(orderKey)")
    }

    private func restoreLegacyBlocksIntoCurrentNote() {
        let key = dateKey(selectedDate)
        let legacyBlocks = journalBlocks
        guard !legacyBlocks.isEmpty else {
            savedStatus = "No old Trade Journal blocks found for \(key)."
            return
        }

        guard !legacyJournalBlocksRestored(for: selectedDate) else {
            savedStatus = "Already restored into Trade Journal \(key)."
            return
        }

        guard let notebookID = store.selectedNotebookID,
              let tabDomain = store.currentTabDomain else {
            savedStatus = "Select a notebook and tab before restoring old Trade Journal blocks."
            return
        }

        let title = "Trade Journal \(key)"
        let note = existingTradeJournalNote(title: title, notebookID: notebookID, currentTabDomain: tabDomain)
            ?? store.notes.createNote(notebook: notebookID, tabDomain: tabDomain, title: title)

        var restoredCount = 0
        for block in legacyBlocks.sorted(by: { $0.createdAt < $1.createdAt }) {
            let body = """
            [\(block.author) / \(block.kind)]
            \(block.text)
            """
            let payloadJSON = NJQuickNotePayload.makePayloadJSON(from: body)
            guard let blockID = store.notes.createQuickNoteBlock(
                payloadJSON: payloadJSON,
                createdAtMs: Int64(block.createdAt * 1000),
                tags: ["investment", "trade-journal", "legacy-trade-journal"]
            ) else {
                NJInvestmentDebugLog("TRADE_JOURNAL_LEGACY_RESTORE_BLOCK_FAILED date=\(key) kind=\(block.kind) author=\(block.author) chars=\(block.text.count)")
                continue
            }

            let orderKey = store.notes.nextAppendOrderKey(noteID: note.id.raw)
            _ = store.notes.attachExistingBlockToNote(noteID: note.id.raw, blockID: blockID, orderKey: orderKey)
            restoredCount += 1
        }

        guard restoredCount > 0 else {
            savedStatus = "I found old blocks, but could not restore them into the note."
            NJInvestmentDebugLog("TRADE_JOURNAL_LEGACY_RESTORE_NONE date=\(key) blocks=\(legacyBlocks.count)")
            return
        }

        UserDefaults.standard.set(true, forKey: legacyJournalRestoreKey(for: selectedDate))
        editorNoteID = note.id
        store.sync.schedulePush(debounceMs: 0)
        savedStatus = "Restored \(restoredCount) old blocks into \(title)."
        NJInvestmentDebugLog("TRADE_JOURNAL_LEGACY_RESTORED date=\(key) restored=\(restoredCount) blocks=\(legacyBlocks.count) note=\(note.id.raw)")
    }

    private func existingTradeJournalNote(title: String, notebookID: String, currentTabDomain: String) -> NJNote? {
        let matches = tradeJournalNoteCandidates(title: title)
        let summary = matches.map { note in
            "\(note.id.raw)@\(note.tabDomain):nb=\(note.notebook == notebookID ? 1 : 0):cur=\(note.tabDomain == currentTabDomain ? 1 : 0):blocks=\(liveBlockCount(noteID: note.id.raw))"
        }.joined(separator: ",")
        NJInvestmentDebugLog("TRADE_JOURNAL_CANDIDATES title=\(title) current_notebook=\(notebookID) current_tab=\(currentTabDomain) count=\(matches.count) [\(summary)]")
        return matches.sorted { lhs, rhs in
            let lhsBlocks = liveBlockCount(noteID: lhs.id.raw)
            let rhsBlocks = liveBlockCount(noteID: rhs.id.raw)
            if lhsBlocks != rhsBlocks { return lhsBlocks > rhsBlocks }
            let lhsIsCurrentNotebook = lhs.notebook == notebookID
            let rhsIsCurrentNotebook = rhs.notebook == notebookID
            if lhsIsCurrentNotebook != rhsIsCurrentNotebook { return lhsIsCurrentNotebook }
            let lhsIsCurrent = lhs.tabDomain == currentTabDomain
            let rhsIsCurrent = rhs.tabDomain == currentTabDomain
            if lhsIsCurrent != rhsIsCurrent { return lhsIsCurrent }
            return lhs.updatedAtMs > rhs.updatedAtMs
        }.first
    }

    private func tradeJournalNoteCandidates(title: String) -> [NJNote] {
        store.notes.db.withDB { dbp in
            var stmt: OpaquePointer?
            let sql = """
            SELECT note_id, created_at_ms, updated_at_ms, notebook, tab_domain, title, note_type, dominance_mode, is_checklist, card_id, card_category, card_area, card_context, card_status, card_priority, pinned, favorited, deleted
            FROM nj_note
            WHERE deleted = 0 AND title = ?;
            """
            guard sqlite3_prepare_v2(dbp, sql, -1, &stmt, nil) == SQLITE_OK else { return [] }
            defer { sqlite3_finalize(stmt) }
            title.withCString { sqlite3_bind_text(stmt, 1, $0, -1, nil) }

            var notes: [NJNote] = []
            while sqlite3_step(stmt) == SQLITE_ROW {
                let noteID = String(cString: sqlite3_column_text(stmt, 0))
                notes.append(NJNote(
                    id: NJNoteID(noteID),
                    createdAtMs: sqlite3_column_int64(stmt, 1),
                    updatedAtMs: sqlite3_column_int64(stmt, 2),
                    notebook: String(cString: sqlite3_column_text(stmt, 3)),
                    tabDomain: String(cString: sqlite3_column_text(stmt, 4)),
                    title: String(cString: sqlite3_column_text(stmt, 5)),
                    rtfData: Data(),
                    deleted: sqlite3_column_int64(stmt, 17),
                    pinned: sqlite3_column_int64(stmt, 15),
                    favorited: sqlite3_column_int64(stmt, 16),
                    noteTypeRaw: String(cString: sqlite3_column_text(stmt, 6)),
                    dominanceModeRaw: String(cString: sqlite3_column_text(stmt, 7)),
                    isChecklist: sqlite3_column_int64(stmt, 8),
                    cardID: String(cString: sqlite3_column_text(stmt, 9)),
                    cardCategory: String(cString: sqlite3_column_text(stmt, 10)),
                    cardArea: String(cString: sqlite3_column_text(stmt, 11)),
                    cardContext: String(cString: sqlite3_column_text(stmt, 12)),
                    cardStatus: String(cString: sqlite3_column_text(stmt, 13)),
                    cardPriority: String(cString: sqlite3_column_text(stmt, 14))
                ))
            }
            return notes
        }
    }

    private func hasTradeJournalNoteBlocks(for date: Date) -> Bool {
        let title = "Trade Journal \(dateKey(date))"
        return tradeJournalNoteCandidates(title: title).contains { liveBlockCount(noteID: $0.id.raw) > 0 }
    }

    private func liveBlockCount(noteID: String) -> Int {
        store.notes.db.withDB { dbp in
            var stmt: OpaquePointer?
            let sql = """
            SELECT COUNT(*)
            FROM nj_note_block nb
            JOIN nj_block b ON b.block_id = nb.block_id
            WHERE nb.note_id = ? AND nb.deleted = 0 AND b.deleted = 0;
            """
            guard sqlite3_prepare_v2(dbp, sql, -1, &stmt, nil) == SQLITE_OK else { return 0 }
            defer { sqlite3_finalize(stmt) }
            return noteID.withCString { cString in
                sqlite3_bind_text(stmt, 1, cString, -1, nil)
                guard sqlite3_step(stmt) == SQLITE_ROW else { return 0 }
                return Int(sqlite3_column_int(stmt, 0))
            }
        }
    }

