    private func seedTodayIfNeeded() {
        guard journalBlocks.isEmpty else { return }
        var blocks = journalBlocks
        blocks.append(NJInvestmentJournalBlock(kind: "Thought", author: "Me", text: """
        Bigger picture feel:

        Prediction alignment:
        - Now to AMD:
        - Before Nvidia:
        - After Nvidia into June:

        Trade focus:
        - Japan Short:
        - SaaS Overshoot:
        - China / Xi-Trump optionality:

        Risk I am rationalizing today:
        """))
        setJournalBlocks(blocks)
    }

    private func addDraftBlock() {
        draftProtonHandle.snapshot(markUserEdit: true)
        let trimmed = draftText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        var blocks = journalBlocks
        blocks.insert(NJInvestmentJournalBlock(kind: draftKind, author: draftAuthor, text: trimmed), at: 0)
        setJournalBlocks(blocks)
        resetDraftEditor()
    }

    private func saveTodayAsJournalNote() {
        guard let notebookID = store.selectedNotebookID,
              let tabDomain = store.currentTabDomain else {
            savedStatus = "Select a notebook and tab before saving this Trade Journal note."
            return
        }

        draftProtonHandle.snapshot(markUserEdit: true)
        let trimmedDraft = draftText.trimmingCharacters(in: .whitespacesAndNewlines)
        let blockText = journalBlocks.map { block in
            "[\(block.author) / \(block.kind)] \(block.text)"
        }.joined(separator: "\n\n")
        let draftBlockText = trimmedDraft.isEmpty ? "" : "[\(draftAuthor) / \(draftKind)] \(trimmedDraft)"
        let finalBlockText = [blockText, draftBlockText]
            .filter { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty }
            .joined(separator: "\n\n")
        guard !finalBlockText.isEmpty else {
            savedStatus = "Nothing to save yet."
            return
        }

        let key = dateKey(selectedDate)
        let title = "Trade Journal \(key)"
        let note = store.notes.listNotes(tabDomainKey: tabDomain).first {
            $0.deleted == 0 && $0.notebook == notebookID && $0.title == title
        } ?? store.notes.createNote(notebook: notebookID, tabDomain: tabDomain, title: title)

        let timestampFormatter = DateFormatter()
        timestampFormatter.dateFormat = "HH:mm"
        let timestamp = timestampFormatter.string(from: Date())
        let body = """
        \(selectedDayTitle) \(timestamp)

        \(finalBlockText)
        """
        let payloadJSON = NJQuickNotePayload.makePayloadJSON(from: body)
        guard let blockID = store.notes.createQuickNoteBlock(
            payloadJSON: payloadJSON,
            createdAtMs: DBNoteRepository.nowMs(),
            tags: ["investment", "trade-journal"]
        ) else {
            savedStatus = "Unable to save this Trade Journal note."
            return
        }

        let orderKey = store.notes.nextAppendOrderKey(noteID: note.id.raw)
        _ = store.notes.attachExistingBlockToNote(noteID: note.id.raw, blockID: blockID, orderKey: orderKey)
        store.sync.schedulePush(debounceMs: 0)
        savedStatus = "Saved to \(title)."
    }

    private var draftText: String {
        draftAttr.string
    }

    private func resetDraftEditor() {
        draftAttr = NSAttributedString(string: "")
        draftSelection = NSRange(location: 0, length: 0)
        draftEditorHeight = 80
        draftProtonHandle = NJProtonEditorHandle()
        draftEditorResetID = UUID()
    }

    private func dateKey(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.string(from: date)
    }

    private func legacyJournalRestoreKey(for date: Date) -> String {
        "nj_investment_trade_journal_legacy_restored_\(dateKey(date))"
    }

    private func legacyJournalBlocksRestored(for date: Date) -> Bool {
        UserDefaults.standard.bool(forKey: legacyJournalRestoreKey(for: date))
    }

    private var journalBlocksByDate: [String: [NJInvestmentJournalBlock]] {
        decodeJournalBlocks(source: "trade_journal_decode")
    }

    private var journalBlocks: [NJInvestmentJournalBlock] {
        journalBlocksByDate[dateKey(selectedDate)] ?? []
    }

    private var weekDates: [Date] {
        guard let start = Calendar.current.dateInterval(of: .weekOfYear, for: selectedDate)?.start else {
            return [selectedDate]
        }
        return (0..<7).compactMap { Calendar.current.date(byAdding: .day, value: $0, to: start) }
    }

    private func weekdaySymbol(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "E"
        return formatter.string(from: date).uppercased()
    }

    private func dayNumber(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "d"
        return formatter.string(from: date)
    }

    private func setJournalBlocks(_ blocks: [NJInvestmentJournalBlock]) {
        var allBlocks = journalBlocksByDate
        allBlocks[dateKey(selectedDate)] = blocks
        if let data = try? JSONEncoder().encode(allBlocks),
           let json = String(data: data, encoding: .utf8) {
            encodedBlocksByDate = json
            NJInvestmentDebugLog("TRADE_JOURNAL_WRITE date=\(dateKey(selectedDate)) day_blocks=\(blocks.count) total_days=\(allBlocks.count) bytes=\(json.utf8.count)")
        } else {
            NJInvestmentDebugLog("TRADE_JOURNAL_WRITE_FAILED date=\(dateKey(selectedDate)) day_blocks=\(blocks.count)")
        }
    }

    private func blockTimestamp(_ timestamp: TimeInterval) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm"
        return formatter.string(from: Date(timeIntervalSince1970: timestamp))
    }

    private func investmentTimestamp(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm"
        return formatter.string(from: date)
    }

    private func decodeJournalBlocks(source: String) -> [String: [NJInvestmentJournalBlock]] {
        let data = Data(encodedBlocksByDate.utf8)
        guard !encodedBlocksByDate.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            NJInvestmentDebugLog("TRADE_JOURNAL_JSON_EMPTY source=\(source)")
            return [:]
        }
        do {
            return try JSONDecoder().decode([String: [NJInvestmentJournalBlock]].self, from: data)
        } catch {
            NJInvestmentDebugLog("TRADE_JOURNAL_JSON_DECODE_ERR source=\(source) bytes=\(data.count) prefix=\(String(encodedBlocksByDate.prefix(160))) err=\(error)")
            return [:]
        }
    }

    private func logJournalState(source: String) {
        let decoded = decodeJournalBlocks(source: source)
        let totalBlocks = decoded.values.reduce(0) { $0 + $1.count }
        let key = dateKey(selectedDate)
        NJInvestmentDebugLog("TRADE_JOURNAL_STATE source=\(source) selected_date=\(key) json_bytes=\(encodedBlocksByDate.utf8.count) days=\(decoded.count) total_blocks=\(totalBlocks) selected_blocks=\(decoded[key]?.count ?? 0) draft_chars=\(draftText.count)")
    }
}

private struct NJInvestmentObservationContent: View {
    @Environment(\.horizontalSizeClass) private var horizontalSizeClass
    @AppStorage("nj_investment_trading_journal_blocks_v1") private var encodedBlocksByDate: String = "{}"
    @State private var copiedObservationID: String?
    @State private var selectedObservation: NJTradingJournalObservation?
    @State private var selectedNewsItem: NJObservationNewsItem?
    @State private var evidenceByObservationID: [String: [NJObservationEvidencePoint]] = [:]
    @State private var newsByObservationID: [String: [NJObservationNewsItem]] = [:]
    @State private var loadingObservationIDs: Set<String> = []
    @State private var expandedSummaryIDs: Set<String> = []
    @ObservedObject private var liveLoader = NJObservationLiveLoader.shared

    init() {
        NJInvestmentDebugLog("OBSERVATION_CONTENT_INIT")
    }

    private var isCompactLayout: Bool {
        horizontalSizeClass == .compact
    }

    var body: some View {
        let _ = NJInvestmentDebugLog("OBSERVATION_BODY_BEGIN compact=\(isCompactLayout ? 1 : 0) appstorage_bytes=\(encodedBlocksByDate.utf8.count)")
        let cards = observations
        let _ = NJInvestmentDebugLog("OBSERVATION_BODY_CARDS_READY compact=\(isCompactLayout ? 1 : 0) cards=\(cards.count)")
        VStack(alignment: .leading, spacing: 14) {
            let _ = NJInvestmentDebugLog("OBSERVATION_BODY_VSTACK_ENTER compact=\(isCompactLayout ? 1 : 0)")
            VStack(alignment: .leading, spacing: 4) {
                Label("Observation", systemImage: "scope")
                    .font(.title2.weight(.bold))
            }
            .padding(14)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color(UIColor.systemBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))

            if isCompactLayout {
                let _ = NJInvestmentDebugLog("OBSERVATION_BODY_RENDER_LIST compact=1 cards=\(cards.count)")
                VStack(alignment: .leading, spacing: 10) {
                    ForEach(cards) { observation in
                        observationSummaryCard(observation)
                    }
                }
            } else {
                let _ = NJInvestmentDebugLog("OBSERVATION_BODY_RENDER_GRID compact=0 cards=\(cards.count)")
                LazyVGrid(columns: [GridItem(.adaptive(minimum: 300), spacing: 12)], spacing: 12) {
                    ForEach(cards) { observation in
                        observationSummaryCard(observation)
                    }
                }
            }
        }
        .onAppear {
            logObservationState(source: "observation_on_appear")
        }
        .onChange(of: encodedBlocksByDate) { _, _ in
            logObservationState(source: "observation_storage_changed")
        }
        .sheet(item: $selectedObservation) { observation in
            NavigationStack {
                ScrollView {
                    fullObservationCard(observation)
                        .padding(16)
                }
                .background(Color(UIColor.systemGroupedBackground))
                .navigationTitle("Observation")
                .navigationBarTitleDisplayMode(.inline)
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) {
                        Button("Done") {
                            selectedObservation = nil
                        }
                    }
                }
                .sheet(item: $selectedNewsItem) { item in
                    NJObservationNewsArticleSheet(item: item)
                }
            }
            .presentationDetents([.large])
        }
    }

