    private func observationDailyNewsRead(observation: NJTradingJournalObservation, rows: [NJObservationNewsItem]) -> NJObservationNewsRead {
        let titles = rows.map(\.title)
        let joined = titles.joined(separator: " ").lowercased()
        let newest = rows.first?.dateText ?? "today"
        let sourceCount = rows.count

        func has(_ words: [String]) -> Bool {
            words.contains { joined.contains($0) }
        }

        switch observation.id {
        case "amd-nvidia-grind":
            if has(["selloff", "slides", "slumps", "pressure", "demand fear", "off target", "nosedives"]) {
                return NJObservationNewsRead(title: "Codex read: AI tape is not clean holding today.", bullets: [
                    "\(sourceCount) fresh item(s), newest \(newest). Headlines point to AI/semis being questioned rather than effortlessly rewarded.",
                    "Observation read: sideways grind can still hold, but this weakens the quality of the hold; watch QQQ/SMH/NVDA close, not just intraday bounces."
                ])
            }
            if has(["rally", "surge", "record", "all-time high", "broadens", "gain"]) {
                return NJObservationNewsRead(title: "Codex read: AI leadership is still being rewarded today.", bullets: [
                    "\(sourceCount) fresh item(s), newest \(newest). Headlines lean toward chip/AI strength rather than exhaustion.",
                    "Observation read: this supports the grind into AMD/Nvidia unless breadth narrows badly into the close."
                ])
            }
        case "post-nvidia-lower-highs":
            return NJObservationNewsRead(title: "Codex read: use today's headlines only as a pre-test.", bullets: [
                "\(sourceCount) fresh item(s), newest \(newest). The post-Nvidia thesis is not active until Nvidia reaction exists.",
                has(["fade", "failed", "selloff", "lower"]) ? "Early read: failed good news would support the lower-highs setup." : "Early read: no clear lower-high/lower-low confirmation from headlines alone."
            ])
        case "june-monetary-regime":
            return NJObservationNewsRead(title: "Codex read: monetary stress is the thing to isolate today.", bullets: [
                "\(sourceCount) fresh item(s), newest \(newest). Check whether BOJ/JGB/USDJPY/yield headlines are moving together.",
                has(["boj", "jgb", "yen", "usdjpy", "yield", "hawkish", "intervention"]) ? "Observation read: the news is relevant to the June regime-test window." : "Observation read: no decisive regime-stress headline in the fresh set."
            ])
        case "xi-trump-save-trade":
            return NJObservationNewsRead(title: "Codex read: policy optionality, not a chase signal.", bullets: [
                "\(sourceCount) fresh item(s), newest \(newest). Fresh China/HK/trade headlines matter only if they appear alongside market stress or policy relief.",
                has(["talk", "tariff", "trade", "deal", "xi", "trump"]) ? "Observation read: optionality is alive, but wait for risk-off incentive or China beta confirmation." : "Observation read: today's headlines do not yet activate the trade-relief setup."
            ])
        case "iran-us-no-clean-deal":
            return NJObservationNewsRead(title: "Codex read: separate rhetoric from market stress.", bullets: [
                "\(sourceCount) fresh item(s), newest \(newest). The key is whether oil/gold/wheat/fertilizer/VIX react like a real commodity shock.",
                has(["strike", "bomb", "attack", "oil spike", "vix", "gold", "grain", "wheat", "fertilizer", "black sea"]) ? "Observation read: escalation language needs immediate oil/grain/fertilizer and credit confirmation." : "Observation read: fresh news still looks like negotiation/rhetoric unless commodity or market stress confirms it."
            ])
        default:
            break
        }

        return NJObservationNewsRead(title: "Codex read: fresh headlines found, no decisive change.", bullets: [
            "\(sourceCount) fresh item(s), newest \(newest).",
            "Observation read: keep the card status unchanged until price evidence confirms or refutes the headlines."
        ])
    }

    private func realEvidenceSection(for observation: NJTradingJournalObservation) -> some View {
        let rows = liveLoader.evidenceByObservationID[observation.id] ?? []
        return VStack(alignment: .leading, spacing: 8) {
            Label("Real Data", systemImage: "chart.xyaxis.line")
                .font(.headline.weight(.semibold))

            if rows.isEmpty {
                Text(liveLoader.loadingObservationIDs.contains(observation.id) ? "Loading live evidence..." : "No live evidence returned yet.")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                    .fixedSize(horizontal: false, vertical: true)
            } else {
                ForEach(rows) { row in
                    HStack(alignment: .firstTextBaseline, spacing: 8) {
                        Image(systemName: row.isHolding ? "checkmark.circle.fill" : "exclamationmark.circle.fill")
                            .foregroundStyle(row.isHolding ? .green : .orange)
                        VStack(alignment: .leading, spacing: 3) {
                            HStack(alignment: .firstTextBaseline) {
                                Text(row.label)
                                    .font(.subheadline.weight(.semibold))
                                Spacer()
                                Text(row.changeText)
                                    .font(.caption.weight(.bold))
                                    .foregroundStyle(row.isHolding ? .green : .orange)
                            }
                            Text("\(row.symbol) \(row.priceText) - \(row.dateText)")
                                .font(.caption)
                                .foregroundStyle(.secondary)
                                .lineLimit(1)
                        }
                    }
                }
            }
        }
        .padding(12)
        .frame(maxWidth: .infinity, alignment: .topLeading)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

