    @MainActor
    private func setObservationLoading(_ id: String, isLoading: Bool) {
        if isLoading {
            loadingObservationIDs.insert(id)
        } else {
            loadingObservationIDs.remove(id)
        }
    }

    private func refreshObservationEvidenceAndNews(_ observation: NJTradingJournalObservation) async {
        if loadingObservationIDs.contains(observation.id) { return }
        await setObservationLoading(observation.id, isLoading: true)
        async let evidence = fetchObservationEvidence(for: observation)
        async let news = fetchObservationNews(for: observation)
        let result = await (evidence, news)
        await MainActor.run {
            evidenceByObservationID[observation.id] = result.0
            newsByObservationID[observation.id] = result.1
            loadingObservationIDs.remove(observation.id)
            NJInvestmentDebugLog("OBSERVATION_LIVE_DONE id=\(observation.id) evidence=\(result.0.count) news=\(result.1.count)")
        }
    }

    private func fetchObservationEvidence(for observation: NJTradingJournalObservation) async -> [NJObservationEvidencePoint] {
        await withTaskGroup(of: NJObservationEvidencePoint?.self) { group in
            for target in observationEvidenceTargets(for: observation) {
                group.addTask {
                    await fetchObservationEvidencePoint(target)
                }
            }
            var rows: [NJObservationEvidencePoint] = []
            for await row in group {
                if let row { rows.append(row) }
            }
            return rows.sorted { $0.id < $1.id }
        }
    }

    private func fetchObservationEvidencePoint(_ target: NJObservationEvidenceTarget) async -> NJObservationEvidencePoint? {
        if target.yahooSymbol.hasPrefix("yahoo:") {
            return await fetchObservationYahooEvidencePoint(target, yahooSymbol: String(target.yahooSymbol.dropFirst("yahoo:".count)))
        }

        var components = URLComponents(string: "https://stooq.com/q/l/")!
        components.queryItems = [
            URLQueryItem(name: "s", value: target.yahooSymbol),
            URLQueryItem(name: "f", value: "sd2t2ohlcvp"),
            URLQueryItem(name: "h", value: ""),
            URLQueryItem(name: "e", value: "csv")
        ]
        guard let url = components.url else { return nil }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            guard let text = String(data: data, encoding: .utf8) else { return nil }
            let rows = text.split(whereSeparator: \.isNewline).map(String.init)
            guard rows.count > 1 else { return nil }
            let values = parseObservationCSVRow(rows[1])
            guard values.count >= 7,
                  values[1] != "N/D",
                  let open = Double(values[3]),
                  let price = Double(values[6]) else { return nil }
            let previous = values.count > 8 ? Double(values[8]) : nil
            let base = previous ?? open
            let pct = base == 0 ? 0 : (price / base - 1) * 100
            let isHolding = target.holdingWhenUp ? pct >= -0.35 : pct <= 0.35
            return NJObservationEvidencePoint(
                id: target.id,
                label: target.label,
                symbol: values[0],
                priceText: formattedObservationPrice(price),
                changeText: String(format: "%+.2f%%", pct),
                isHolding: isHolding,
                dateText: "\(values[1]) \(values.count > 2 ? values[2] : "")".trimmingCharacters(in: .whitespaces)
            )
        } catch {
            NJInvestmentDebugLog("OBSERVATION_EVIDENCE_ERR id=\(target.id) err=\(error.localizedDescription)")
            return nil
        }
    }

    private func fetchObservationYahooEvidencePoint(_ target: NJObservationEvidenceTarget, yahooSymbol: String) async -> NJObservationEvidencePoint? {
        let encoded = yahooSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? yahooSymbol
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=5d&interval=1d") else { return nil }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = root["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let meta = result["meta"] as? [String: Any],
                  let price = doubleValue(meta["regularMarketPrice"]) else { return nil }
            let previous = doubleValue(meta["chartPreviousClose"]) ?? doubleValue(meta["previousClose"])
            let pct = previous.flatMap { $0 == 0 ? nil : (price / $0 - 1) * 100 } ?? 0
            let isHolding = target.holdingWhenUp ? pct >= -0.35 : pct <= 0.35
            let marketTime = (meta["regularMarketTime"] as? TimeInterval).map { Date(timeIntervalSince1970: $0) } ?? Date()
            return NJObservationEvidencePoint(
                id: target.id,
                label: target.label,
                symbol: yahooSymbol,
                priceText: formattedObservationPrice(price),
                changeText: String(format: "%+.2f%%", pct),
                isHolding: isHolding,
                dateText: observationDateText(marketTime)
            )
        } catch {
            NJInvestmentDebugLog("OBSERVATION_EVIDENCE_ERR id=\(target.id) err=\(error.localizedDescription)")
            return nil
        }
    }

    private func fetchObservationNews(for observation: NJTradingJournalObservation) async -> [NJObservationNewsItem] {
        var seen = Set<String>()
        var rows: [NJObservationNewsItem] = []
        for query in observationNewsQueries(for: observation) {
            let items = await fetchGoogleNewsRSS(query: query)
            for item in items where item.isFreshObservationNews && seen.insert(item.title.normalizedObservationNewsKey).inserted {
                rows.append(item)
                if rows.count >= 6 {
                    return rows.sorted(by: observationNewsSort)
                }
            }
        }
        return rows.sorted(by: observationNewsSort)
    }

    private func fetchGoogleNewsRSS(query: String) async -> [NJObservationNewsItem] {
        var components = URLComponents(string: "https://news.google.com/rss/search")
        components?.queryItems = [
            URLQueryItem(name: "q", value: "\(query) when:1d"),
            URLQueryItem(name: "hl", value: "en-US"),
            URLQueryItem(name: "gl", value: "US"),
            URLQueryItem(name: "ceid", value: "US:en")
        ]
        guard let url = components?.url else { return [] }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            return NJObservationRSSParser.parse(data: data)
        } catch {
            NJInvestmentDebugLog("OBSERVATION_NEWS_ERR query=\(query) err=\(error.localizedDescription)")
            return []
        }
    }

    private func formattedObservationPrice(_ value: Double) -> String {
        if value >= 1000 { return String(format: "%.0f", value) }
        if value >= 100 { return String(format: "%.2f", value) }
        return String(format: "%.3f", value)
    }

    private func doubleValue(_ value: Any?) -> Double? {
        if let value = value as? Double { return value }
        if let value = value as? Int { return Double(value) }
        if let value = value as? NSNumber { return value.doubleValue }
        if let value = value as? String { return Double(value) }
        return nil
    }

    private func observationDateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "MMM d HH:mm"
        return formatter.string(from: date)
    }

    private func parseObservationCSVRow(_ row: String) -> [String] {
        row.split(separator: ",", omittingEmptySubsequences: false)
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
    }

    private func trackerColumn(title: String, value: String) -> some View {
        VStack(alignment: .leading, spacing: 4) {
            Text(title)
                .font(.caption.weight(.bold))
                .foregroundStyle(.secondary)
            Text(value)
                .font(.caption)
                .fixedSize(horizontal: false, vertical: true)
        }
        .frame(maxWidth: .infinity, alignment: .topLeading)
    }

    private func appendObservationToTradeJournal(_ observation: NJTradingJournalObservation) {
        let entry = NJInvestmentJournalBlock(kind: "Observation", author: "Me", text: """
        Observation check - \(observation.title)
        Status: \(observation.status)
        \(observation.copyText)
        Daily read:
        """)
        let key = dateKey(Date())
        var allBlocks = journalBlocksByDate
        var blocks = allBlocks[key] ?? []
        blocks.insert(entry, at: 0)
        allBlocks[key] = blocks
        if let data = try? JSONEncoder().encode(allBlocks),
           let json = String(data: data, encoding: .utf8) {
            encodedBlocksByDate = json
            NJInvestmentDebugLog("OBSERVATION_APPEND id=\(observation.id) date=\(key) day_blocks=\(blocks.count) total_days=\(allBlocks.count) bytes=\(json.utf8.count)")
        } else {
            NJInvestmentDebugLog("OBSERVATION_APPEND_ENCODE_FAILED id=\(observation.id) date=\(key) day_blocks=\(blocks.count)")
        }
        UIPasteboard.general.string = entry.text
        copiedObservationID = observation.id
    }

    private var journalBlocksByDate: [String: [NJInvestmentJournalBlock]] {
        decodeJournalBlocks(source: "observation_decode")
    }

    private func dateKey(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = .current
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.string(from: date)
    }

    private func decodeJournalBlocks(source: String) -> [String: [NJInvestmentJournalBlock]] {
        let data = Data(encodedBlocksByDate.utf8)
        guard !encodedBlocksByDate.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            NJInvestmentDebugLog("OBSERVATION_JSON_EMPTY source=\(source)")
            return [:]
        }
        do {
            return try JSONDecoder().decode([String: [NJInvestmentJournalBlock]].self, from: data)
        } catch {
            NJInvestmentDebugLog("OBSERVATION_JSON_DECODE_ERR source=\(source) bytes=\(data.count) prefix=\(String(encodedBlocksByDate.prefix(160))) err=\(error)")
            return [:]
        }
    }

    private func logObservationState(source: String) {
        let decoded = decodeJournalBlocks(source: source)
        let totalBlocks = decoded.values.reduce(0) { $0 + $1.count }
        NJInvestmentDebugLog("OBSERVATION_STATE source=\(source) cards=\(observations.count) json_bytes=\(encodedBlocksByDate.utf8.count) journal_days=\(decoded.count) journal_blocks=\(totalBlocks)")
    }

