    private static let watchChartDefaultsKey = "nj_investment_watch_chart_defaults_v1"

    init() {
        self.detachedWatchRow = nil
    }

    fileprivate init(detachedWatchRow: NJInvestmentWatchRow) {
        self.detachedWatchRow = detachedWatchRow
        _selectedWatchRow = State(initialValue: detachedWatchRow)
        _selectedWatchPopupTab = State(initialValue: .chart)
    }

    private func applyPersistedWatchChartDefaults() {
        guard let data = UserDefaults.standard.data(forKey: Self.watchChartDefaultsKey),
              let payload = try? JSONDecoder().decode(NJInvestmentWatchChartDefaults.self, from: data) else { return }
        if let interval = NJInvestmentChartInterval(rawValue: payload.interval) {
            selectedWatchChartInterval = interval
        }
        if let range = NJInvestmentChartRange(rawValue: payload.range) {
            selectedWatchChartRange = range
        }
        if let provider = NJInvestmentMarketDataProvider(rawValue: payload.provider) {
            selectedWatchDataProvider = provider
        }
        watchShowCandles = payload.showCandles
        watchShowMA9 = payload.showMA9
        watchShowMA20 = payload.showMA20
        watchShowMA50 = payload.showMA50
        watchShowMA200 = payload.showMA200
        watchShowVWMA9 = payload.showVWMA9
        watchShowVWMA20 = payload.showVWMA20
        watchShowVWMA50 = payload.showVWMA50
        watchShowVWMA200 = payload.showVWMA200
        watchShowVolume = payload.showVolume
        watchShowVolumeSupportResistance = payload.showVolumeSupportResistance
        watchShowRSI = payload.showRSI
        watchShowMACD = payload.showMACD
        watchFibTraceEnabled = payload.fibTraceEnabled
    }

    private func persistWatchChartDefaults() {
        let payload = NJInvestmentWatchChartDefaults(
            interval: selectedWatchChartInterval.rawValue,
            range: selectedWatchChartRange.rawValue,
            provider: selectedWatchDataProvider.rawValue,
            showCandles: watchShowCandles,
            showMA9: watchShowMA9,
            showMA20: watchShowMA20,
            showMA50: watchShowMA50,
            showMA200: watchShowMA200,
            showVWMA9: watchShowVWMA9,
            showVWMA20: watchShowVWMA20,
            showVWMA50: watchShowVWMA50,
            showVWMA200: watchShowVWMA200,
            showVolume: watchShowVolume,
            showVolumeSupportResistance: watchShowVolumeSupportResistance,
            showRSI: watchShowRSI,
            showMACD: watchShowMACD,
            fibTraceEnabled: watchFibTraceEnabled
        )
        guard let data = try? JSONEncoder().encode(payload) else { return }
        UserDefaults.standard.set(data, forKey: Self.watchChartDefaultsKey)
    }

    private func applyInvestmentShortcutMarket() {
        let market = normalizedMacroDataMarket(store.selectedInvestmentMarket)
        if selectedMarket != market {
            selectedMarket = market
            selectedSnapshotLineID = defaultSnapshotLineID(for: market)
        }
        if (store.selectedInvestmentSection == .macroLine || store.selectedInvestmentSection == .heatlist),
           selectedHeatMarket != market {
            selectedHeatMarket = market
        }
    }

    private var macroDataMarkets: [NJInvestmentMarket] {
        [.all, .us, .hk, .china, .japan, .europe, .crypto]
    }

    private func normalizedMacroDataMarket(_ market: NJInvestmentMarket) -> NJInvestmentMarket {
        switch market {
        case .chinaHK:
            return .china
        default:
            return market
        }
    }

    private var persistedWatchChartInterval: Binding<NJInvestmentChartInterval> {
        Binding(
            get: { selectedWatchChartInterval },
            set: { newValue in
                selectedWatchChartInterval = newValue
                persistWatchChartDefaults()
            }
        )
    }

    private func persistedBoolBinding(_ binding: Binding<Bool>) -> Binding<Bool> {
        Binding(
            get: { binding.wrappedValue },
            set: { newValue in
                binding.wrappedValue = newValue
                persistWatchChartDefaults()
            }
        )
    }

    private let calendar: Calendar = {
        var cal = Calendar(identifier: .gregorian)
        cal.firstWeekday = 1
        return cal
    }()

