    @ViewBuilder
    var body: some View {
        if let detachedWatchRow {
            detachedWatchResearchBody(detachedWatchRow)
        } else {
            mainInvestmentBody
        }
    }

    private var mainInvestmentBody: some View {
        let _ = NJInvestmentDebugLog("MODULE_BODY compact=\(isCompactLayout ? 1 : 0) section=\(store.selectedInvestmentSection.rawValue) trade=\(store.selectedInvestmentTradeTab.rawValue) local_ready=\(store.localDataReady ? 1 : 0)")
        return ScrollView {
            VStack(alignment: .leading, spacing: 14) {
                if isCompactLayout {
                    compactInvestmentNavigation
                }

                selectedWorkspace
            }
            .padding(isCompactLayout ? 10 : 18)
        }
        .background(Color(UIColor.systemGroupedBackground))
        .navigationTitle("Investment")
        .navigationBarTitleDisplayMode(.inline)
        .toolbar {
            ToolbarItem(placement: .primaryAction) {
                Button {
                    openWindow(id: "investment-module")
                } label: {
                    Label("Detach Investment", systemImage: "rectangle.on.rectangle")
                }
                .help("Open Investment in a separate window")
            }
        }
        .onAppear {
            NJInvestmentDebugLog("MODULE_ON_APPEAR_BEGIN section=\(store.selectedInvestmentSection.rawValue) compact=\(isCompactLayout ? 1 : 0)")
            applyInvestmentShortcutMarket()
            applyPersistedWatchChartDefaults()
            hydrateCachedInvestmentData()
            loadSyncedWatchTrendLines()
            migrateLocalWatchTrendLinesIfNeeded()
            seedInvestmentSymbolRegistryIfNeeded()
            loadInvestmentSymbolConventionRegistry()
            logInvestmentState(source: "module_on_appear_before_reload")
            NJInvestmentDebugLog("MODULE_ON_APPEAR_RELOAD_BEGIN")
            reloadEvents()
            NJInvestmentDebugLog("MODULE_ON_APPEAR_RELOAD_DONE")
            logInvestmentState(source: "module_on_appear_after_reload")
            NJInvestmentDebugLog("MODULE_ON_APPEAR_LIVE_REFRESH_BEGIN")
            refreshLiveInvestmentDataIfVisible(reason: "open")
            NJInvestmentDebugLog("MODULE_ON_APPEAR_LIVE_REFRESH_RETURN")
        }
        .onChange(of: focusedMonth) { _, _ in
            reloadEvents()
            logInvestmentState(source: "focused_month_changed")
        }
        .onChange(of: calendarMode) { _, _ in
            reloadEvents()
            logInvestmentState(source: "calendar_mode_changed")
        }
        .onChange(of: selectedMarket) { _, _ in
            reloadEvents()
            logInvestmentState(source: "market_changed")
            refreshLiveInvestmentDataIfVisible(reason: "market")
        }
        .onChange(of: selectedSnapshotLineID) { _, _ in
            snapshotChartZoomScale = 1
            snapshotChartBaseZoomScale = 1
            refreshLiveInvestmentDataIfVisible(reason: "line")
            refreshHourlyChartIfNeeded(reason: "line")
        }
        .onChange(of: selectedSnapshotChartInterval) { _, _ in
            selectedSnapshotChartInterval = normalizedSnapshotChartInterval(selectedSnapshotChartInterval, for: selectedSnapshotChartRange)
            snapshotChartZoomScale = 1
            snapshotChartBaseZoomScale = 1
            refreshHourlyChartIfNeeded(reason: "interval")
        }
        .onChange(of: selectedSnapshotChartRange) { _, _ in
            selectedSnapshotChartInterval = normalizedSnapshotChartInterval(selectedSnapshotChartInterval, for: selectedSnapshotChartRange)
            snapshotChartZoomScale = 1
            snapshotChartBaseZoomScale = 1
            refreshHourlyChartIfNeeded(reason: "range")
        }
        .onChange(of: store.investmentRefreshNonce) { _, _ in
            applyInvestmentShortcutMarket()
            loadSyncedWatchTrendLines()
            refreshLiveInvestmentDataIfVisible(reason: "tab")
        }
        .onChange(of: store.selectedInvestmentSection) { _, _ in
            logInvestmentState(source: "section_changed_before_refresh")
            hydrateCachedInvestmentData()
            refreshLiveInvestmentDataIfVisible(reason: "section")
        }
        .onChange(of: store.selectedInvestmentTradeTab) { _, _ in
            logInvestmentState(source: "trade_changed_before_refresh")
            hydrateCachedInvestmentData()
            refreshLiveInvestmentDataIfVisible(reason: "trade")
        }
        .onChange(of: store.selectedInvestmentLedgerTab) { _, _ in
            logInvestmentState(source: "ledger_tab_changed_before_refresh")
            refreshLiveInvestmentDataIfVisible(reason: "ledger")
        }
        .onChange(of: scenePhase) { _, phase in
            if phase == .active {
                logInvestmentState(source: "scene_active")
                refreshLiveInvestmentDataIfVisible(reason: "active")
            }
        }
        .onReceive(liveRefreshTimer) { _ in
            refreshLiveInvestmentDataIfVisible(reason: "timer")
        }
        .onReceive(NotificationCenter.default.publisher(for: .njPullCompleted)) { _ in
            reloadEvents()
            logInvestmentState(source: "ck_pull_completed")
        }
        .sheet(item: $selectedEvent) { event in
            NavigationStack {
                ScrollView {
                    eventResearchPanel(event, showsCloseButton: false)
                        .padding(16)
                }
                .background(Color(UIColor.systemGroupedBackground))
                .navigationTitle("Event Research")
                .navigationBarTitleDisplayMode(.inline)
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) {
                        Button("Done") {
                            selectedEvent = nil
                        }
                    }
                }
            }
        }
        .sheet(item: $selectedUSQ1NewsItem) { item in
            NJObservationNewsArticleSheet(item: item)
        }
        .sheet(item: $selectedIndustryNewsItem) { item in
            NJObservationNewsArticleSheet(item: item)
        }
        .sheet(item: $selectedWatchNewsItem) { item in
            NJObservationNewsArticleSheet(item: item)
        }
        .sheet(item: $selectedWatchAnalysisReport) { report in
            NJInvestmentAnalysisReportSheet(report: report)
        }
        .sheet(item: $selectedAnalysisInboxItem) { item in
            analysisInboxSheet(item)
        }
        .sheet(item: $selectedSystemLiquidityInfoItem) { item in
            systemLiquidityInfoSheet(item)
        }
        .sheet(isPresented: $showInvestmentQuickJump) {
            investmentQuickJumpSheet
        }
        .overlay {
            GeometryReader { proxy in
                if UIDevice.current.userInterfaceIdiom == .phone,
                   let row = selectedWatchRow {
                    floatingWatchResearchPopup(row, containerSize: proxy.size)
                }
            }
        }
        .sheet(item: $selectedJapanBlueChipResult) { row in
            NavigationStack {
                ScrollView {
                    japanBlueChipResultPanel(row)
                        .padding(16)
                }
                .background(Color(UIColor.systemGroupedBackground))
                .navigationTitle(row.symbol)
                .navigationBarTitleDisplayMode(.inline)
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) {
                        Button("Done") {
                            selectedJapanBlueChipResult = nil
                        }
                    }
                }
            }
        }
    }

    private func detachedWatchResearchBody(_ row: NJInvestmentWatchRow) -> some View {
        ScrollView {
            watchResearchPanel(row)
                .padding(16)
                .frame(maxWidth: .infinity, alignment: .topLeading)
        }
        .background(Color(UIColor.systemGroupedBackground))
        .onAppear {
            applyPersistedWatchChartDefaults()
            hydrateCachedInvestmentData()
            loadSyncedWatchTrendLines()
            migrateLocalWatchTrendLinesIfNeeded()
            refreshLiveInvestmentDataIfVisible(reason: "detached_irc_open")
        }
        .task(id: "detached-quote-\(row.symbol)") {
            await refreshDetachedWatchQuote(for: row)
        }
        .sheet(item: $selectedWatchNewsItem) { item in
            NJObservationNewsArticleSheet(item: item)
        }
        .sheet(item: $selectedWatchAnalysisReport) { report in
            NJInvestmentAnalysisReportSheet(report: report)
        }
        .sheet(item: $selectedAnalysisInboxItem) { item in
            analysisInboxSheet(item)
        }
    }

    private var isCompactLayout: Bool {
        horizontalSizeClass == .compact
    }

    private var selectedWorkspace: AnyView {
        switch store.selectedInvestmentSection {
        case .macro:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE macro compact=\(isCompactLayout ? 1 : 0)")
            if isCompactLayout {
                return AnyView(compactMacroWorkspace)
            } else {
                return AnyView(macroWorkspace)
            }
        case .macroLine:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE macroLine")
            return AnyView(macroLineWorkspace)
        case .liquidity:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE liquidity")
            return AnyView(systemLiquidityWorkspace)
        case .observations:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE observations")
            return AnyView(observationWorkspace)
        case .heatlist:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE heatlist market=\(selectedHeatMarket.rawValue)")
            return AnyView(macroLineWorkspace)
        case .industryAnalysis:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE industryAnalysis theme=\(selectedIndustryThemeID)")
            return AnyView(industryAnalysisWorkspace)
        case .watchlist:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE watchlist")
            return AnyView(investmentWatchlistWorkspace)
        case .tradeJournal:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE tradeJournal")
            return AnyView(tradingJournalWorkspace)
        case .trades:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE trades trade=\(store.selectedInvestmentTradeTab.rawValue)")
            return AnyView(tradeWorkspace)
        case .analysisInbox:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE analysisInbox")
            return AnyView(analysisInboxWorkspace)
        case .ledger:
            NJInvestmentDebugLog("MODULE_SWITCH_CASE ledger tab=\(store.selectedInvestmentLedgerTab.rawValue)")
            return AnyView(investmentLedgerWorkspace)
        }
    }

    private var compactInvestmentNavigation: some View {
        VStack(alignment: .leading, spacing: 10) {
            HStack(spacing: 10) {
                Label("Investment", systemImage: "chart.line.uptrend.xyaxis")
                    .font(.headline.weight(.bold))
                Spacer()
                Menu {
                    ForEach(NJInvestmentSection.navigationCases) { section in
                        Button {
                            store.selectedInvestmentSection = section
                            store.investmentRefreshNonce += 1
                            NJInvestmentDebugLog("COMPACT_MENU_SECTION_TAP section=\(section.rawValue) nonce=\(store.investmentRefreshNonce)")
                        } label: {
                            Label(section.rawValue, systemImage: section.symbolName)
                        }
                    }
                } label: {
                    Label(store.selectedInvestmentSection.rawValue, systemImage: store.selectedInvestmentSection.symbolName)
                        .font(.subheadline.weight(.semibold))
                }
            }

            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 8) {
                    ForEach(NJInvestmentSection.navigationCases) { section in
                        Button {
                            store.selectedInvestmentSection = section
                            store.investmentRefreshNonce += 1
                            NJInvestmentDebugLog("COMPACT_BUTTON_SECTION_TAP section=\(section.rawValue) nonce=\(store.investmentRefreshNonce)")
                        } label: {
                            Label(section.rawValue, systemImage: section.symbolName)
                                .font(.caption.weight(.semibold))
                                .padding(.horizontal, 10)
                                .padding(.vertical, 7)
                                .background(store.selectedInvestmentSection == section ? Color.accentColor.opacity(0.18) : Color(UIColor.secondarySystemGroupedBackground))
                                .clipShape(RoundedRectangle(cornerRadius: 8))
                        }
                        .buttonStyle(.plain)
                    }
                }
            }

            if store.selectedInvestmentSection == .trades {
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(spacing: 8) {
                        ForEach(NJInvestmentTradeTab.allCases) { tab in
                            Button {
                                store.selectedInvestmentTradeTab = tab
                                store.investmentRefreshNonce += 1
                                NJInvestmentDebugLog("COMPACT_TRADE_TAP trade=\(tab.rawValue) nonce=\(store.investmentRefreshNonce)")
                            } label: {
                                Label(tab.rawValue, systemImage: tab.symbolName)
                                    .font(.caption.weight(.semibold))
                                    .padding(.horizontal, 10)
                                    .padding(.vertical, 7)
                                    .background(store.selectedInvestmentTradeTab == tab ? Color.accentColor.opacity(0.18) : Color(UIColor.secondarySystemGroupedBackground))
                                    .clipShape(RoundedRectangle(cornerRadius: 8))
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
            }

            if store.selectedInvestmentSection == .ledger {
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack(spacing: 8) {
                        ForEach(NJInvestmentLedgerTab.allCases) { tab in
                            Button {
                                store.selectedInvestmentLedgerTab = tab
                                store.investmentRefreshNonce += 1
                                NJInvestmentDebugLog("COMPACT_LEDGER_TAP tab=\(tab.rawValue) nonce=\(store.investmentRefreshNonce)")
                            } label: {
                                Label(tab.rawValue, systemImage: tab.symbolName)
                                    .font(.caption.weight(.semibold))
                                    .padding(.horizontal, 10)
                                    .padding(.vertical, 7)
                                    .background(store.selectedInvestmentLedgerTab == tab ? Color.accentColor.opacity(0.18) : Color(UIColor.secondarySystemGroupedBackground))
                                    .clipShape(RoundedRectangle(cornerRadius: 8))
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
            }

            HStack {
                Spacer()
                Button {
                    showInvestmentQuickJump = true
                } label: {
                    Image(systemName: "square.grid.2x2.fill")
                        .font(.headline.weight(.semibold))
                        .foregroundStyle(.white)
                        .frame(width: 42, height: 42)
                        .background(Color.accentColor)
                        .clipShape(Circle())
                }
                .buttonStyle(.plain)
                .accessibilityLabel("Quick Jump")
            }
        }
        .padding(12)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private var investmentQuickJumpSheet: some View {
        NavigationStack {
            ScrollView {
                VStack(alignment: .leading, spacing: 16) {
                    VStack(alignment: .leading, spacing: 5) {
                        Text("Quick Jump")
                            .font(.largeTitle.weight(.bold))
                        Text("Jump straight to the workspace you need.")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                    }

                    quickJumpGroup("Daily Work", icon: "bolt.fill") {
                        quickJumpButton(title: "Observation", subtitle: "Daily culling, holding evidence, related news", icon: "scope") {
                            openInvestmentSection(.observations)
                        }
                        quickJumpButton(title: "Trade Journal", subtitle: "Today journal and persistent finance reference blocks", icon: "book.closed") {
                            openInvestmentSection(.tradeJournal)
                        }
                        quickJumpButton(title: "Watchlist", subtitle: "Tracked symbols and IRC entry points", icon: "bell.badge") {
                            openInvestmentSection(.watchlist)
                        }
                        quickJumpButton(title: "News Inbox", subtitle: "Research reports, saved news, and critical alerts", icon: "tray.full") {
                            openInvestmentSection(.analysisInbox)
                        }
                    }

                    quickJumpGroup("Market Map", icon: "globe") {
                        quickJumpButton(title: "Macro Calendar", subtitle: "Events across US, HK, China, Japan, Europe, commodities", icon: "globe.americas") {
                            openInvestmentSection(.macro)
                        }
                        quickJumpButton(title: "Macro Data", subtitle: "Live macro snapshots, scorecards, and heatlist", icon: "list.bullet.rectangle") {
                            openInvestmentSection(.macroLine)
                        }
                        quickJumpButton(title: "Liquidity", subtitle: "World liquidity, credit, funding, and auction stress", icon: "drop.circle") {
                            openInvestmentSection(.liquidity)
                        }
                        quickJumpButton(title: "Industry Analysis", subtitle: "Sector / industry news and structure", icon: "building.2.crop.circle") {
                            openInvestmentSection(.industryAnalysis)
                        }
                    }

                    quickJumpGroup("Trade Thesis", icon: "chart.xyaxis.line") {
                        ForEach(NJInvestmentTradeTab.allCases) { tab in
                            quickJumpButton(title: tab.rawValue, subtitle: "Open thesis workspace", icon: tab.symbolName) {
                                openInvestmentTrade(tab)
                            }
                        }
                    }

                    quickJumpGroup("Portfolio / Ledger", icon: "chart.pie") {
                        ForEach(NJInvestmentLedgerTab.allCases) { tab in
                            quickJumpButton(title: tab.rawValue, subtitle: ledgerQuickJumpSubtitle(tab), icon: tab.symbolName) {
                                openInvestmentLedger(tab)
                            }
                        }
                    }
                }
                .padding(18)
            }
            .background(Color(UIColor.systemGroupedBackground))
            .navigationTitle("Investment Menu")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Done") {
                        showInvestmentQuickJump = false
                    }
                }
            }
        }
        .presentationDetents([.large])
    }

    private func quickJumpGroup<Content: View>(_ title: String, icon: String, @ViewBuilder content: () -> Content) -> some View {
        VStack(alignment: .leading, spacing: 10) {
            Label(title, systemImage: icon)
                .font(.headline.weight(.bold))
            VStack(spacing: 8) {
                content()
            }
        }
        .padding(12)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func quickJumpButton(title: String, subtitle: String, icon: String, action: @escaping () -> Void) -> some View {
        Button {
            action()
        } label: {
            HStack(spacing: 12) {
                Image(systemName: icon)
                    .font(.title3.weight(.semibold))
                    .frame(width: 32, height: 32)
                    .foregroundStyle(Color.accentColor)
                VStack(alignment: .leading, spacing: 3) {
                    Text(title)
                        .font(.subheadline.weight(.bold))
                        .foregroundStyle(Color.primary)
                    Text(subtitle)
                        .font(.caption)
                        .foregroundStyle(.secondary)
                        .lineLimit(2)
                }
                Spacer()
                Image(systemName: "chevron.right")
                    .font(.caption.weight(.bold))
                    .foregroundStyle(.tertiary)
            }
            .padding(10)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color(UIColor.secondarySystemGroupedBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
    }

    private func openInvestmentSection(_ section: NJInvestmentSection) {
        store.selectedInvestmentSection = section
        store.investmentRefreshNonce += 1
        showInvestmentQuickJump = false
        NJInvestmentDebugLog("QUICK_JUMP_SECTION section=\(section.rawValue) nonce=\(store.investmentRefreshNonce)")
    }

    private func openInvestmentTrade(_ tab: NJInvestmentTradeTab) {
        store.selectedInvestmentSection = .trades
        store.selectedInvestmentTradeTab = tab
        store.investmentRefreshNonce += 1
        showInvestmentQuickJump = false
        NJInvestmentDebugLog("QUICK_JUMP_TRADE trade=\(tab.rawValue) nonce=\(store.investmentRefreshNonce)")
    }

    private func openInvestmentLedger(_ tab: NJInvestmentLedgerTab) {
        store.selectedInvestmentSection = .ledger
        store.selectedInvestmentLedgerTab = tab
        store.investmentRefreshNonce += 1
        showInvestmentQuickJump = false
        NJInvestmentDebugLog("QUICK_JUMP_LEDGER tab=\(tab.rawValue) nonce=\(store.investmentRefreshNonce)")
    }

    private func ledgerQuickJumpSubtitle(_ tab: NJInvestmentLedgerTab) -> String {
        switch tab {
        case .ledger:
            return "Execution rows and broker references"
        case .portfolio:
            return "Open positions and mark-to-market"
        case .liquidity:
            return "Cash, dry powder, risk concentration, opportunity book"
        }
    }

