    private var systemLiquidityWorkspace: some View {
        VStack(alignment: .leading, spacing: 14) {
            VStack(alignment: .leading, spacing: 10) {
                HStack(alignment: .top, spacing: 12) {
                    VStack(alignment: .leading, spacing: 4) {
                        Text("Liquidity")
                            .font(.title2.weight(.bold))
                        Text("World liquidity, funding pressure, credit tightness, duration stress, and auction demand.")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                    }
                    Spacer()
                    VStack(alignment: .trailing, spacing: 8) {
                        Text(systemLiquidityStatus)
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(.secondary)
                            .multilineTextAlignment(.trailing)
                        Button {
                            refreshSystemLiquidityDashboardIfVisible(reason: "manual")
                        } label: {
                            Label("Refresh", systemImage: "arrow.clockwise")
                        }
                        .buttonStyle(.borderedProminent)
                        .controlSize(.small)
                    }
                }

                if let refreshedAt = systemLiquidityLastRefreshAt {
                    Text("Last daily read: \(systemLiquidityRefreshDateText(refreshedAt))")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }
            .padding(14)
            .background(Color(UIColor.systemBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))

            ForEach(systemLiquiditySections) { section in
                VStack(alignment: .leading, spacing: 10) {
