    private var systemLiquiditySections: [NJSystemLiquiditySectionDefinition] {
        [
            NJSystemLiquiditySectionDefinition(
                id: "central-bank-stretch",
                title: "Central Bank Stretch",
                subtitle: "Simple read on how much central-bank cushion remains and whether Japan is becoming a rates-pressure problem.",
                kpis: [
                    NJSystemLiquidityKPIDefinition(
                        id: "fed-balance-sheet",
                        title: "Fed Balance Sheet",
                        whatIsIt: "Total assets held by the Federal Reserve, mainly Treasuries and mortgage-backed securities.",
                        calculation: "Reported on the Fed H.4.1 statement. We track the latest level from the FRED WALCL series and display it in trillions of dollars.",
                        howToRead: "A shrinking balance sheet means QT is still draining support. A stable or expanding balance sheet means the Fed is adding or preserving system support.",
                        sourceHint: "FRED WALCL"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "rrp",
                        title: "RRP Cushion",
                        whatIsIt: "Cash parked overnight at the Fed through the reverse repo facility by money funds and other eligible counterparties.",
                        calculation: "Latest daily total from the ON RRP series. We display it in billions of dollars.",
                        howToRead: "High RRP means the system still has spare idle cash. A deeply drained RRP means one of the easiest liquidity cushions is already gone.",
                        sourceHint: "FRED RRPONTSYD"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "jgb10y-stretch",
                        title: "10Y JGB",
                        whatIsIt: "Japan's 10-year government bond yield, which acts as the daily pressure gauge on BOJ control of the rates regime.",
                        calculation: "We use the latest live or snapshot JGB 10Y yield available in the Investment module.",
                        howToRead: "A rising JGB yield means BOJ pressure is building. That matters because it can spill into yen carry, global rates, and cross-market duration stress.",
                        sourceHint: "Investment live/snapshot feed"
                    )
                ]
            ),
            NJSystemLiquiditySectionDefinition(
                id: "funding-stress",
                title: "Funding Stress",
                subtitle: "Can money still move smoothly through the short-term system, or are funding markets starting to strain?",
                kpis: [
                    NJSystemLiquidityKPIDefinition(
                        id: "sofr",
                        title: "SOFR",
                        whatIsIt: "The Secured Overnight Financing Rate, the core overnight secured funding rate in the US.",
                        calculation: "Latest daily SOFR print from FRED.",
                        howToRead: "Stable SOFR means funding is orderly. Sudden jumps or instability mean the plumbing is getting tighter.",
                        sourceHint: "FRED SOFR"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "effr-sofr",
                        title: "EFFR vs SOFR",
                        whatIsIt: "The gap between Effective Fed Funds and SOFR, showing whether unsecured and secured money-market funding are diverging.",
                        calculation: "Latest EFFR minus latest SOFR, displayed in basis points.",
                        howToRead: "A small spread is normal. A widening or strange spread means something in funding plumbing deserves attention.",
                        sourceHint: "FRED EFFR and SOFR"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "cp-spread",
                        title: "Commercial Paper Spread",
                        whatIsIt: "Extra short-term funding cost paid by nonfinancial corporate borrowers over a 3-month Treasury bill benchmark.",
                        calculation: "3-month nonfinancial commercial paper minus 3-month Treasury bill, displayed in basis points.",
                        howToRead: "A wider spread means short-term corporate funding is becoming less easy and less trusted.",
                        sourceHint: "FRED DCPN3M and DTB3"
                    )
                ]
            ),
            NJSystemLiquiditySectionDefinition(
                id: "credit-stress",
                title: "Credit Stress",
                subtitle: "This is the black-swan layer: whether risky credit, quality credit, and the banking core are all starting to demand more compensation.",
                kpis: [
                    NJSystemLiquidityKPIDefinition(
                        id: "hy-oas",
                        title: "HY OAS",
                        whatIsIt: "High-yield option-adjusted spread: the extra yield junk bonds pay over Treasuries after adjusting for embedded options.",
                        calculation: "Latest ICE BofA high-yield OAS from FRED, displayed in basis points.",
                        howToRead: "When HY OAS widens, the market is demanding more compensation to hold risky credit. Fast widening is a serious warning.",
                        sourceHint: "FRED BAMLH0A0HYM2"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "ig-oas",
                        title: "IG OAS",
                        whatIsIt: "Investment-grade option-adjusted spread: the extra yield paid by stronger corporate borrowers over Treasuries.",
                        calculation: "Latest ICE BofA US Corporate OAS from FRED, displayed in basis points.",
                        howToRead: "If IG spreads widen too, stress is moving beyond junk and into better-quality corporate borrowing.",
                        sourceHint: "FRED BAMLC0A0CM"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "bank-spread",
                        title: "Bank Spread",
                        whatIsIt: "A read on how much extra compensation the market demands to lend to banks or insure bank balance-sheet risk.",
                        calculation: "This still needs a reliable public daily source. For now it stays a research KPI rather than a fully automated feed.",
                        howToRead: "If bank spreads widen, trust in the financial core is weakening. That matters more than equity headlines.",
                        sourceHint: "Research / public spread proxy"
                    )
                ]
            ),
            NJSystemLiquiditySectionDefinition(
                id: "duration-pressure",
                title: "Duration Pressure",
                subtitle: "Long-end yields tell us whether capital is getting more expensive and whether Japan is adding extra strain to the global rates regime.",
                kpis: [
                    NJSystemLiquidityKPIDefinition(
                        id: "us10y",
                        title: "US 10Y",
                        whatIsIt: "The 10-year US Treasury yield, the market's main long-duration discount rate.",
                        calculation: "Latest live or snapshot US 10Y yield in the module.",
                        howToRead: "A rising US 10Y tightens financial conditions and hurts long-duration equity valuation.",
                        sourceHint: "Investment live/snapshot feed"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "jgb10y",
                        title: "JGB 10Y",
                        whatIsIt: "The 10-year Japanese government bond yield, a key signal for BOJ pressure and global carry stress.",
                        calculation: "Latest live or snapshot JGB 10Y yield in the module.",
                        howToRead: "When JGB yields rise, BOJ pressure rises too, which can destabilize yen carry and global duration.",
                        sourceHint: "Investment live/snapshot feed"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "us-jp-gap",
                        title: "US-JP 10Y Gap",
                        whatIsIt: "The spread between the US 10Y and the Japan 10Y yield.",
                        calculation: "US 10Y minus JGB 10Y, displayed in basis points.",
                        howToRead: "A very wide gap keeps carry incentives alive. A narrowing gap driven by rising JGB yields can signal Japan becoming the pressure point.",
                        sourceHint: "Derived from live/snapshot yields"
                    )
                ]
            ),
            NJSystemLiquiditySectionDefinition(
                id: "auction-demand",
                title: "Auction Demand",
                subtitle: "How easily the market is absorbing government debt supply. Weak auctions can tighten conditions even without a policy move.",
                kpis: [
                    NJSystemLiquidityKPIDefinition(
                        id: "bid-to-cover",
                        title: "Bid-to-Cover",
                        whatIsIt: "Total bids received divided by the amount of debt sold at auction.",
                        calculation: "Total bids / amount offered.",
                        howToRead: "Higher is stronger. Repeated weak bid-to-cover means buyers are becoming less eager to absorb supply.",
                        sourceHint: "Treasury auction result"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "auction-tail",
                        title: "Auction Tail",
                        whatIsIt: "How much higher the final auction yield is than the pre-auction when-issued market yield.",
                        calculation: "Stop-out yield minus when-issued yield, displayed in basis points.",
                        howToRead: "A positive tail means the market needed a higher yield to clear the debt. The fatter the tail, the weaker the demand.",
                        sourceHint: "Treasury auction result"
                    ),
                    NJSystemLiquidityKPIDefinition(
                        id: "indirect-share",
                        title: "Indirect Share",
                        whatIsIt: "The share of the auction taken by indirect bidders, usually foreign and institutional end-demand.",
                        calculation: "Indirect allotment divided by total auction size.",
                        howToRead: "A healthy indirect share means real sponsorship is showing up. Weak indirect demand can mean dealers are being left with more supply.",
                        sourceHint: "Treasury auction result"
                    )
                ]
            )
        ]
    }

    private func systemLiquidityKPIRow(_ kpi: NJSystemLiquidityKPIDefinition) -> some View {
        let snapshot = systemLiquiditySnapshot(for: kpi.id)
        return VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .top, spacing: 8) {
                VStack(alignment: .leading, spacing: 3) {
                    HStack(spacing: 6) {
                        Text(kpi.title)
                            .font(.subheadline.weight(.bold))
                        Button {
                            selectedSystemLiquidityInfoItem = kpi
                        } label: {
                            Image(systemName: "info.circle.fill")
                                .font(.caption)
                                .foregroundStyle(Color.accentColor)
                        }
                        .buttonStyle(.plain)
                    }
                    Text(snapshot.source)
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(.secondary)
                }
                Spacer()
                Text(snapshot.tone.rawValue)
                    .font(.caption2.weight(.bold))
                    .foregroundStyle(snapshot.tone.color)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 4)
                    .background(snapshot.tone.color.opacity(0.12))
                    .clipShape(RoundedRectangle(cornerRadius: 7))
            }

            HStack(alignment: .lastTextBaseline, spacing: 8) {
                Text(snapshot.valueText)
                    .font(.title3.weight(.bold))
