    private func systemLiquiditySnapshot(for id: String) -> NJSystemLiquiditySnapshot {
        systemLiquiditySnapshots[id] ?? NJSystemLiquiditySnapshot(
            valueText: "Pending",
            detailText: "Daily read has not been loaded yet.",
            tone: .research,
            source: "Daily dashboard",
            updatedAt: nil
        )
    }

    private func systemLiquidityHistory(for id: String, daysBack: Int = 370) -> [NJSystemLiquidityHistoryPoint] {
        let now = Date()
        let start = calendar.date(byAdding: .day, value: -daysBack, to: now) ?? now
        let rows = store.notes
            .listFinanceMacroEvents(startKey: dateKey(start), endKey: dateKey(now))
            .filter { $0.category == "cache_system_liquidity" && $0.deleted == 0 }

        var newestByDay: [String: (updatedAtMs: Int64, point: NJSystemLiquidityHistoryPoint)] = [:]
        for row in rows {
            guard let payload = decodeCachePayload(NJSystemLiquiditySnapshotCachePayload.self, from: row.notes),
                  payload.id == id,
                  let numericValue = payload.numericValue else { continue }
            let pointDate = Date(timeIntervalSince1970: TimeInterval(payload.updatedAtMs) / 1000.0)
            let point = NJSystemLiquidityHistoryPoint(
                id: "\(payload.id).\(row.dateKey)",
                date: pointDate,
                value: numericValue
            )
            if let existing = newestByDay[row.dateKey], existing.updatedAtMs >= row.updatedAtMs { continue }
            newestByDay[row.dateKey] = (row.updatedAtMs, point)
        }

        return newestByDay.values
            .map(\.point)
            .sorted { $0.date < $1.date }
    }

    private func systemLiquidityRefreshDateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.calendar = calendar
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "yyyy-MM-dd HH:mm"
        return formatter.string(from: date)
    }

    private func systemLiquidityTimeText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.calendar = calendar
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "MMM d"
        return formatter.string(from: date)
    }

    private struct NJFredObservation {
        let date: Date
        let value: Double
    }

    private func refreshSystemLiquidityDashboardIfVisible(reason: String) {
        guard scenePhase == .active || reason == "manual" || reason == "open" else { return }
        guard store.selectedInvestmentSection == .liquidity else { return }
        guard !isSystemLiquidityRefreshing else { return }
        if reason != "manual" && reason != "open" && reason != "active" && reason != "section" && reason != "market",
           let last = systemLiquidityLastRefreshAt,
           calendar.isDate(last, inSameDayAs: Date()),
           !systemLiquiditySnapshots.isEmpty {
            systemLiquidityStatus = "Daily read is current"
            return
        }

        isSystemLiquidityRefreshing = true
        systemLiquidityStatus = reason == "manual" ? "Refreshing liquidity dashboard" : "Loading daily liquidity read"

        Task {
            async let fedSeries = fetchFredRecentSeries(seriesID: "WALCL", limit: 6)
            async let rrpSeries = fetchFredRecentSeries(seriesID: "RRPONTSYD", limit: 6)
            async let sofrSeries = fetchFredRecentSeries(seriesID: "SOFR", limit: 6)
            async let effrSeries = fetchFredRecentSeries(seriesID: "EFFR", limit: 6)
            async let cpSeries = fetchFredRecentSeries(seriesID: "DCPN3M", limit: 6)
            async let billSeries = fetchFredRecentSeries(seriesID: "DTB3", limit: 6)
            async let hySeries = fetchFredRecentSeries(seriesID: "BAMLH0A0HYM2", limit: 6)
            async let igSeries = fetchFredRecentSeries(seriesID: "BAMLC0A0CM", limit: 6)

            let fed = await fedSeries
            let rrp = await rrpSeries
            let sofr = await sofrSeries
            let effr = await effrSeries
            let cp = await cpSeries
            let bill = await billSeries
            let hy = await hySeries
            let ig = await igSeries

            let us10y = await MainActor.run { currentSystemLiquidityYield(lineID: "us10y", market: .us) }
            let jgb10y = await MainActor.run { currentSystemLiquidityYield(lineID: "jgb", market: .japan) }

            let snapshots = buildSystemLiquiditySnapshots(
                fed: fed,
                rrp: rrp,
                sofr: sofr,
                effr: effr,
                cp: cp,
                bill: bill,
                hy: hy,
                ig: ig,
                us10y: us10y,
                jgb10y: jgb10y
            )

            await MainActor.run {
                systemLiquiditySnapshots = snapshots
                systemLiquidityLastRefreshAt = Date()
                persistCachedSystemLiquiditySnapshots(snapshots)
                let loaded = snapshots.values.filter { $0.tone != .research || $0.valueText != "Research" }.count
                systemLiquidityStatus = loaded > 0
                    ? "Daily read updated \(loaded)/15"
                    : "Daily read unavailable"
                isSystemLiquidityRefreshing = false
            }
        }
    }

    private func portfolioLiquidityHoldingsURL() -> URL {
        URL(fileURLWithPath: "/Users/mac/Developer/Notion Journal/Notion Journal/Docs/Investment_Liquidity_Holdings.json")
    }

    private func refreshPortfolioLiquidityIfVisible(reason: String) {
        guard scenePhase == .active || reason == "manual" || reason == "open" else { return }
        guard store.selectedInvestmentSection == .ledger,
              store.selectedInvestmentLedgerTab == .liquidity else { return }

        let url = portfolioLiquidityHoldingsURL()
        guard let data = try? Data(contentsOf: url) else {
            portfolioLiquidityHoldingsOverride = []
            portfolioLiquidityLastRefreshAt = Date()
            portfolioLiquidityStatus = "Using bundled balances"
            return
        }

        let decoder = JSONDecoder()
        if let payload = try? decoder.decode(NJInvestmentLiquidHoldingFilePayload.self, from: data) {
            portfolioLiquidityHoldingsOverride = payload.holdings
            portfolioLiquidityLastRefreshAt = Date()
            portfolioLiquidityStatus = payload.holdings.isEmpty
                ? "Using bundled balances"
                : "Loaded file balances \(payload.holdings.count)"
            return
        }
        if let holdings = try? decoder.decode([NJInvestmentLiquidHolding].self, from: data) {
            portfolioLiquidityHoldingsOverride = holdings
            portfolioLiquidityLastRefreshAt = Date()
            portfolioLiquidityStatus = holdings.isEmpty
                ? "Using bundled balances"
                : "Loaded file balances \(holdings.count)"
            return
        }

        portfolioLiquidityHoldingsOverride = []
        portfolioLiquidityLastRefreshAt = Date()
        portfolioLiquidityStatus = "Holdings file invalid"
    }

    private func currentSystemLiquidityYield(lineID: String, market: NJInvestmentMarket) -> NJFredObservation? {
        if let quote = liveQuotes[lineID] {
            return NJFredObservation(
                date: parseDateKey(quote.dateKey) ?? Date(),
                value: liveDisplayValue(quote.close, lineID: lineID)
            )
        }
        guard let metric = snapshotMetrics(for: market).first(where: { $0.id == lineID }),
              let value = chartNumericValue(from: metric.value) else { return nil }
        return NJFredObservation(date: Date(), value: value)
    }

    private func fetchFredRecentSeries(seriesID: String, limit: Int) async -> [NJFredObservation] {
        guard let url = URL(string: "https://fred.stlouisfed.org/graph/fredgraph.csv?id=\(seriesID)") else { return [] }
        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            return parseFredSeries(data: data, limit: limit)
        } catch {
            return []
        }
    }

    private func parseFredSeries(data: Data, limit: Int) -> [NJFredObservation] {
        guard let text = String(data: data, encoding: .utf8) else { return [] }
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "yyyy-MM-dd"

        let rows = text
            .split(whereSeparator: \.isNewline)
            .dropFirst()
            .compactMap { line -> NJFredObservation? in
                let parts = line.split(separator: ",", omittingEmptySubsequences: false)
                guard parts.count >= 2 else { return nil }
                let dateString = String(parts[0])
                let valueString = String(parts[1]).trimmingCharacters(in: .whitespacesAndNewlines)
                guard valueString != "." && !valueString.isEmpty,
                      let date = formatter.date(from: dateString),
                      let value = Double(valueString) else { return nil }
                return NJFredObservation(date: date, value: value)
            }
        return Array(rows.suffix(limit))
    }

    private func buildSystemLiquiditySnapshots(
        fed: [NJFredObservation],
        rrp: [NJFredObservation],
        sofr: [NJFredObservation],
        effr: [NJFredObservation],
        cp: [NJFredObservation],
        bill: [NJFredObservation],
        hy: [NJFredObservation],
        ig: [NJFredObservation],
        us10y: NJFredObservation?,
        jgb10y: NJFredObservation?
    ) -> [String: NJSystemLiquiditySnapshot] {
        var snapshots: [String: NJSystemLiquiditySnapshot] = [:]

        if let latest = fed.last {
            let prior = fed.dropLast().last
            let trillions = latest.value / 1_000_000
            let deltaPct = prior.map { (($0.value == 0) ? 0 : ((latest.value / $0.value) - 1) * 100) } ?? 0
            let tone: NJSystemLiquidityTone = deltaPct < -0.6 ? .stress : (deltaPct < -0.15 ? .watch : .calm)
            snapshots["fed-balance-sheet"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "$%.2fT", trillions),
                detailText: "Week-on-week \(signedPercent(deltaPct)). Shrinking balance sheet means QT is still draining support.",
                tone: tone,
                source: "FRED WALCL",
                updatedAt: latest.date,
                numericValue: trillions
            )
        }

        if let latest = rrp.last {
            let billions = latest.value
            let tone: NJSystemLiquidityTone = billions < 100 ? .stress : (billions < 300 ? .watch : .calm)
            let cushionText: String
            switch tone {
            case .stress: cushionText = "RRP cushion is thin; spare cash is mostly already drained."
            case .watch: cushionText = "RRP cushion is fading; less idle cash is left to absorb stress."
            case .calm: cushionText = "RRP still shows a usable spare-cash cushion."
            case .research: cushionText = "Daily cushion read."
            }
            snapshots["rrp"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "$%.0fB", billions),
                detailText: cushionText,
                tone: tone,
                source: "FRED RRPONTSYD",
                updatedAt: latest.date,
                numericValue: billions
            )
        }

        if let latest = jgb10y {
            let tone: NJSystemLiquidityTone = latest.value >= 1.60 ? .stress : (latest.value >= 1.20 ? .watch : .calm)
            snapshots["jgb10y-stretch"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.2f%%", latest.value),
                detailText: "Japan 10Y pressure gauge. Rising JGB yields mean BOJ control is getting tested.",
                tone: tone,
                source: "Investment rates feed",
                updatedAt: latest.date,
                numericValue: latest.value
            )
        }

        if let latest = sofr.last {
            let tone: NJSystemLiquidityTone = latest.value >= 5.50 ? .watch : .calm
            snapshots["sofr"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.2f%%", latest.value),
                detailText: "Core secured overnight funding rate. Sudden jumps mean money-market plumbing is tightening.",
                tone: tone,
                source: "FRED SOFR",
                updatedAt: latest.date,
                numericValue: latest.value
            )
        }

        if let latestSOFR = sofr.last, let latestEFFR = effr.last {
            let spreadBps = (latestEFFR.value - latestSOFR.value) * 100
            let absSpread = abs(spreadBps)
            let tone: NJSystemLiquidityTone = absSpread >= 8 ? .stress : (absSpread >= 4 ? .watch : .calm)
            snapshots["effr-sofr"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%+.1f bps", spreadBps),
                detailText: String(format: "EFFR %.2f%% vs SOFR %.2f%%. Large divergence means money-market plumbing deserves attention.", latestEFFR.value, latestSOFR.value),
                tone: tone,
                source: "FRED EFFR / SOFR",
                updatedAt: max(latestSOFR.date, latestEFFR.date),
                numericValue: spreadBps
            )
        }

        if let latestCP = cp.last, let latestBill = bill.last {
            let spreadBps = (latestCP.value - latestBill.value) * 100
            let tone: NJSystemLiquidityTone = spreadBps >= 50 ? .stress : (spreadBps >= 20 ? .watch : .calm)
            snapshots["cp-spread"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%+.0f bps", spreadBps),
                detailText: String(format: "3M CP %.2f%% minus 3M bill %.2f%%. Wider spread means short-term corporate funding is less easy.", latestCP.value, latestBill.value),
                tone: tone,
                source: "FRED DCPN3M / DTB3",
                updatedAt: max(latestCP.date, latestBill.date),
                numericValue: spreadBps
            )
        }

        if let latest = hy.last {
            let bps = latest.value * 100
            let tone: NJSystemLiquidityTone = bps >= 450 ? .stress : (bps >= 350 ? .watch : .calm)
            snapshots["hy-oas"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.0f bps", bps),
                detailText: "High-yield spread over Treasuries. Fast widening is a serious warning that risky credit is repricing.",
                tone: tone,
                source: "FRED BAMLH0A0HYM2",
                updatedAt: latest.date,
                numericValue: bps
            )
        }

        if let latest = ig.last {
            let bps = latest.value * 100
            let tone: NJSystemLiquidityTone = bps >= 150 ? .stress : (bps >= 100 ? .watch : .calm)
            snapshots["ig-oas"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.0f bps", bps),
                detailText: "Investment-grade spread over Treasuries. If this widens too, stress is broadening beyond junk.",
                tone: tone,
                source: "FRED BAMLC0A0CM",
                updatedAt: latest.date,
                numericValue: bps
            )
        }

        snapshots["bank-spread"] = NJSystemLiquiditySnapshot(
            valueText: "Research",
            detailText: "Still needs a clean public daily bank-credit proxy. Keep this on the build list rather than pretending with a bad feed.",
            tone: .research,
            source: "Research feed",
            updatedAt: nil
        )

        if let latest = us10y {
            let tone: NJSystemLiquidityTone = latest.value >= 4.75 ? .stress : (latest.value >= 4.40 ? .watch : .calm)
            snapshots["us10y"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.2f%%", latest.value),
                detailText: "Main long-duration discount rate. Higher US 10Y means tighter financial conditions.",
                tone: tone,
                source: "Investment rates feed",
                updatedAt: latest.date,
                numericValue: latest.value
            )
        }

        if let latest = jgb10y {
            let tone: NJSystemLiquidityTone = latest.value >= 1.60 ? .stress : (latest.value >= 1.20 ? .watch : .calm)
            snapshots["jgb10y"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.2f%%", latest.value),
                detailText: "Japan duration pressure. Rising JGB yields add stress to BOJ control and global carry.",
                tone: tone,
                source: "Investment rates feed",
                updatedAt: latest.date,
                numericValue: latest.value
            )
        }

        if let us10y, let jgb10y {
            let gapBps = (us10y.value - jgb10y.value) * 100
            let tone: NJSystemLiquidityTone = gapBps <= 250 ? .stress : (gapBps <= 320 ? .watch : .calm)
            snapshots["us-jp-gap"] = NJSystemLiquiditySnapshot(
                valueText: String(format: "%.0f bps", gapBps),
                detailText: "US 10Y minus JGB 10Y. A narrowing gap driven by Japan can signal BOJ / carry stress.",
                tone: tone,
                source: "Derived from rates feed",
                updatedAt: max(us10y.date, jgb10y.date),
                numericValue: gapBps
            )
        }

        snapshots["bid-to-cover"] = NJSystemLiquiditySnapshot(
            valueText: "Await",
            detailText: "Use latest 10Y or 30Y Treasury auction bid-to-cover. Higher is stronger demand; repeated weakness matters.",
            tone: .research,
            source: "Treasury auction result",
            updatedAt: nil
        )
        snapshots["auction-tail"] = NJSystemLiquiditySnapshot(
            valueText: "Await",
            detailText: "Use stop-out minus when-issued yield. Positive tail means the market needed a higher yield to absorb supply.",
            tone: .research,
            source: "Treasury auction result",
            updatedAt: nil
        )
        snapshots["indirect-share"] = NJSystemLiquiditySnapshot(
            valueText: "Await",
            detailText: "Use indirect allotment share at the latest Treasury auction. Healthy indirect demand means real sponsorship is showing up.",
            tone: .research,
            source: "Treasury auction result",
            updatedAt: nil
        )

        return snapshots
    }

    private func signedPercent(_ value: Double) -> String {
        String(format: "%+.2f%%", value)
    }

