    private func investmentWatchlistDataRow(_ item: NJInvestmentAlertWatchItem) -> some View {
        let quote = liveQuotes[item.symbol]
        let activeAlert = item.rules.first { rule in
            quote.map { $0.close <= rule.level } ?? false
        }
        let values = [
            item.displaySymbol,
            item.name,
            quote.map { watchlistPriceText($0.close) } ?? watchlistPriceText(item.referencePrice),
            watchlistOptionalPriceText(quote?.open),
            watchlistOptionalPriceText(quote?.dayHigh),
            watchlistOptionalPriceText(quote?.dayLow),
            watchlistOptionalPriceText(quote?.fiftyTwoWeekHigh),
            watchlistOptionalPriceText(quote?.fiftyTwoWeekLow),
            watchlistVolumeText(quote?.volume),
            item.support,
            item.resistance,
            item.target,
            activeAlert.map { "\($0.severity) <= \(watchlistPriceText($0.level))" } ?? nextWatchlistAlertText(item, quote: quote),
            item.route
        ]
        return Button {
            openWatchResearchPopup(for: watchRow(for: item, quote: quote))
        } label: {
            investmentWatchlistTableRow(
                values,
                widths: watchlistTableWidths,
                isAlert: activeAlert != nil
            )
        }
        .buttonStyle(.plain)
        .accessibilityLabel("\(item.displaySymbol) watchlist row")
    }

    private func watchRow(for item: NJInvestmentAlertWatchItem, quote: NJInvestmentLiveQuote?) -> NJInvestmentWatchRow {
        NJInvestmentWatchRow(
            id: "alert-watch-\(item.id)",
            symbol: item.displaySymbol,
            name: item.name,
            monitorDate: "Watchlist",
            resultDate: item.decisionQuestion,
            usCloseReference: item.unit,
            tPlusOne: "Support \(item.support)",
            tPlusTwo: "Resistance \(item.resistance)",
            tPlusThree: "Target \(item.target)",
            initialPrice: watchlistPriceText(item.referencePrice),
            week52High: watchlistOptionalPriceText(quote?.fiftyTwoWeekHigh),
            week52Low: watchlistOptionalPriceText(quote?.fiftyTwoWeekLow),
            todayPrice: quote.map { watchlistPriceText($0.close) } ?? watchlistPriceText(item.referencePrice),
            vwap: item.route,
            percentChange: quote?.changeText ?? nextWatchlistAlertText(item, quote: quote)
        )
    }

