    private var analysisInboxWorkspace: some View {
        let criticalUnreadCount = analysisInboxCriticalUnreadCount()
        return VStack(alignment: .leading, spacing: 14) {
            VStack(alignment: .leading, spacing: 8) {
                HStack(alignment: .top, spacing: 10) {
                    VStack(alignment: .leading, spacing: 4) {
                        Label("News Inbox", systemImage: "tray.full")
                            .font(.title2.weight(.bold))
                        Text("Central feed for research, company news, and macro alerts. Critical unread news stays pinned at the top.")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                    }
                    Spacer()
                    Button {
                        Task { await refreshAnalysisInbox(reason: "manual") }
                    } label: {
                        Label("Refresh", systemImage: "arrow.triangle.2.circlepath")
                            .font(.caption.weight(.bold))
                    }
                    .buttonStyle(.bordered)
                }

                HStack(spacing: 10) {
                    Toggle("Unread only", isOn: $analysisInboxUnreadOnly)
                        .toggleStyle(.switch)
                    Spacer()
                    Text(analysisInboxStatus)
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(criticalUnreadCount > 0 ? .red : .secondary)
                        .lineLimit(1)
                }

                if criticalUnreadCount > 0 {
                    HStack(spacing: 8) {
                        Image(systemName: "exclamationmark.triangle.fill")
                        Text("\(criticalUnreadCount) critical unread news item\(criticalUnreadCount == 1 ? "" : "s")")
                            .font(.caption.weight(.bold))
                        Spacer(minLength: 0)
                    }
                    .foregroundStyle(.red)
                }

                HStack(spacing: 10) {
                    Button {
                        markAllAnalysisInboxRead()
                    } label: {
                        Label("Mark all read", systemImage: "checkmark.circle")
                            .font(.caption.weight(.bold))
                    }
                    .buttonStyle(.bordered)
                    .disabled(analysisInboxItems.isEmpty)

                    #if os(macOS)
                    Button {
                        openAnalysisInboxFolderInFinder()
                    } label: {
                        Label("Open folder", systemImage: "folder")
                            .font(.caption.weight(.bold))
                    }
                    .buttonStyle(.bordered)
                    #endif
                }
            }
            .padding(14)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color(UIColor.systemBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))

            VStack(alignment: .leading, spacing: 10) {
                sectionHeader("All News", icon: "newspaper")
                if isAnalysisInboxLoading {
                    Text("Loading…")
                        .font(.subheadline)
                        .foregroundStyle(.secondary)
                } else {
                    let rows = filteredAnalysisInboxItems()
                    if rows.isEmpty {
                        Text("No news inbox items found yet. Append standardized news or digest blocks into `AnalysisInbox.md` under the Investment iCloud folder.")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                            .fixedSize(horizontal: false, vertical: true)
                    } else {
                        ForEach(rows) { item in
                            analysisInboxRow(item)
                        }
                    }
                }
            }
            .padding(14)
            .background(Color(UIColor.systemBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))
        }
        .onAppear {
            if analysisInboxItems.isEmpty {
                Task { await refreshAnalysisInbox(reason: "open") }
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: UIApplication.didBecomeActiveNotification)) { _ in
            Task { await refreshAnalysisInbox(reason: "active") }
        }
    }

