    private func analysisInboxRow(_ item: NJInvestmentAnalysisInboxItem) -> some View {
        let isUnread = isAnalysisInboxUnread(itemID: item.id)
        let isCriticalUnread = item.isCritical && isUnread
        return Button {
            selectedAnalysisInboxItem = item
        } label: {
            HStack(alignment: .top, spacing: 10) {
                Image(systemName: item.isCritical ? "exclamationmark.triangle.fill" : "circle.fill")
                    .font(.system(size: item.isCritical ? 12 : 8, weight: .bold))
                    .foregroundStyle(isCriticalUnread ? .red : (isUnread ? Color.accentColor : Color.clear))
                    .frame(width: 14, height: 14)
                    .padding(.top, 6)
                VStack(alignment: .leading, spacing: 4) {
                    HStack(spacing: 8) {
                        Text(item.titleLine)
                            .font(.headline)
                            .fontWeight(isCriticalUnread ? .heavy : (isUnread ? .bold : .semibold))
                            .foregroundStyle(isCriticalUnread ? .red : .primary)
                        Spacer()
                        Text(analysisInboxTimestamp(item.asOf))
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(.secondary)
                    }
                    HStack(spacing: 8) {
                        if item.isCritical {
                            analysisInboxBadge(text: "Critical", tone: .red)
                        }
                        if !item.displaySeverity.isEmpty, !item.isCritical {
                            analysisInboxBadge(text: item.displaySeverity, tone: .orange)
                        }
                        if !item.displayCategory.isEmpty {
                            analysisInboxBadge(text: item.displayCategory, tone: .blue)
                        }
                        analysisInboxBadge(text: item.verdict, tone: verdictTone(item.verdict))
                        if item.displayNotify {
                            analysisInboxBadge(text: "Notify", tone: .orange)
                        }
                        Text(item.whatHappened)
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                            .lineLimit(2)
                    }
                }
            }
            .padding(12)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(isCriticalUnread ? Color.red.opacity(0.10) : Color(UIColor.secondarySystemGroupedBackground))
            .overlay(
                RoundedRectangle(cornerRadius: 10)
                    .stroke(isCriticalUnread ? Color.red.opacity(0.55) : Color.clear, lineWidth: 1)
            )
            .clipShape(RoundedRectangle(cornerRadius: 10))
        }
        .buttonStyle(.plain)
    }

    private func analysisInboxDetail(_ item: NJInvestmentAnalysisInboxItem) -> some View {
        VStack(alignment: .leading, spacing: 12) {
            VStack(alignment: .leading, spacing: 6) {
                Text(item.titleLine)
                    .font(.title3.weight(.bold))
                Text("\(analysisInboxTimestamp(item.asOf)) • Source: \(item.source)")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
                HStack(spacing: 8) {
                    if item.isCritical { analysisInboxBadge(text: "Critical", tone: .red) }
                    if !item.displaySeverity.isEmpty, !item.isCritical { analysisInboxBadge(text: item.displaySeverity, tone: .orange) }
                    if !item.displayCategory.isEmpty { analysisInboxBadge(text: item.displayCategory, tone: .blue) }
                    analysisInboxBadge(text: item.verdict, tone: verdictTone(item.verdict))
                    if item.displayNotify { analysisInboxBadge(text: "Notify", tone: .orange) }
                }
            }
            Divider()
            analysisInboxField(title: "What happened", body: item.whatHappened)
            analysisInboxField(title: "Trade read", body: item.tradeRead)
            analysisInboxField(title: "Next watch", body: item.nextWatch)
            if !item.symbols.isEmpty {
                analysisInboxField(title: "Symbols", body: item.symbols.joined(separator: ", "))
            }
            if !item.articlePath.isEmpty {
                analysisInboxField(title: "Article archive", body: item.articlePath)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }

