    private func analysisInboxBadge(text: String, tone: Color) -> some View {
        Text(text)
            .font(.caption.weight(.bold))
            .foregroundStyle(tone)
            .padding(.horizontal, 10)
            .padding(.vertical, 6)
            .background(tone.opacity(0.12))
            .clipShape(RoundedRectangle(cornerRadius: 8))
