    private func verdictTone(_ verdict: String) -> Color {
        let v = verdict.lowercased()
        if v.contains("support") { return .green }
        if v.contains("counter") { return .red }
        if v.contains("mixed") { return .orange }
        return .secondary
    }

    private func analysisInboxTimestamp(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm"
        return formatter.string(from: date)
    }

    private func filteredAnalysisInboxItems() -> [NJInvestmentAnalysisInboxItem] {
        let sorted = analysisInboxItems.sorted { lhs, rhs in
            let lhsCritical = lhs.isCritical && isAnalysisInboxUnread(itemID: lhs.id)
            let rhsCritical = rhs.isCritical && isAnalysisInboxUnread(itemID: rhs.id)
            if lhsCritical != rhsCritical { return lhsCritical }
            return lhs.asOf > rhs.asOf
        }
        guard analysisInboxUnreadOnly else { return sorted }
        return sorted.filter { isAnalysisInboxUnread(itemID: $0.id) }
    }

    private func analysisInboxCriticalUnreadCount() -> Int {
        analysisInboxItems.filter { $0.isCritical && isAnalysisInboxUnread(itemID: $0.id) }.count
    }

    private func isAnalysisInboxUnread(itemID: String) -> Bool {
        let map = decodeAnalysisInboxReadMap()
        return map[itemID] == nil
    }

    private func markAnalysisInboxRead(itemID: String) {
        var map = decodeAnalysisInboxReadMap()
        map[itemID] = Date().timeIntervalSince1970
        encodeAnalysisInboxReadMap(map)
        store.refreshInvestmentCriticalNewsBadge()
    }

    private func markAllAnalysisInboxRead() {
        var map = decodeAnalysisInboxReadMap()
        let now = Date().timeIntervalSince1970
        for item in analysisInboxItems {
            map[item.id] = now
        }
        encodeAnalysisInboxReadMap(map)
        store.refreshInvestmentCriticalNewsBadge()
    }

    private func decodeAnalysisInboxReadMap() -> [String: Double] {
        guard let data = analysisInboxReadStorage.data(using: .utf8) else { return [:] }
        return (try? JSONDecoder().decode([String: Double].self, from: data)) ?? [:]
    }

    private func encodeAnalysisInboxReadMap(_ map: [String: Double]) {
        if let data = try? JSONEncoder().encode(map), let str = String(data: data, encoding: .utf8) {
            analysisInboxReadStorage = str
        }
    }

    private func refreshAnalysisInbox(reason: String) async {
        guard !isAnalysisInboxLoading else { return }
        isAnalysisInboxLoading = true
        analysisInboxStatus = "Loading…"
        defer { isAnalysisInboxLoading = false }

        let start = Date()
        let items = loadAnalysisInboxItems()
        analysisInboxItems = items
        notifyNewCriticalAnalysisInboxItems(items)
        store.refreshInvestmentCriticalNewsBadge()
        let seconds = Date().timeIntervalSince(start)
        let criticalCount = items.filter { $0.isCritical && isAnalysisInboxUnread(itemID: $0.id) }.count
        analysisInboxStatus = "\(items.count) news • \(criticalCount) critical unread • refreshed \(String(format: "%.1fs", seconds)) • \(reason)"
    }

    private func notifyNewCriticalAnalysisInboxItems(_ items: [NJInvestmentAnalysisInboxItem]) {
        var notified = decodeAnalysisInboxNotifiedMap()
        let now = Date().timeIntervalSince1970
        var changed = false
        for item in items where item.isCritical && isAnalysisInboxUnread(itemID: item.id) && notified[item.id] == nil {
            NJInvestmentWatchlistNotifier.notifyCriticalNews(
                title: item.titleLine,
                source: item.source,
                summary: item.whatHappened
            )
            notified[item.id] = now
            changed = true
        }
        if changed {
            encodeAnalysisInboxNotifiedMap(notified)
        }
    }

    private func decodeAnalysisInboxNotifiedMap() -> [String: Double] {
        guard let data = analysisInboxNotifiedStorage.data(using: .utf8) else { return [:] }
        return (try? JSONDecoder().decode([String: Double].self, from: data)) ?? [:]
    }

    private func encodeAnalysisInboxNotifiedMap(_ map: [String: Double]) {
        if let data = try? JSONEncoder().encode(map), let str = String(data: data, encoding: .utf8) {
            analysisInboxNotifiedStorage = str
        }
    }

    private func loadAnalysisInboxItems() -> [NJInvestmentAnalysisInboxItem] {
        var rows: [NJInvestmentAnalysisInboxItem] = []
        if let u = analysisInboxMarkdownURL(), let data = try? Data(contentsOf: u) {
            rows.append(contentsOf: parseAnalysisInboxMarkdown(data: data, sourceLabel: u.lastPathComponent))
        }
        rows.removeAll { $0.isSuppressedNewsNoise }
        var deduped: [String: NJInvestmentAnalysisInboxItem] = [:]
        for row in rows {
            let key = analysisInboxDedupeKey(row)
            if let existing = deduped[key] {
                if row.asOf > existing.asOf {
                    deduped[key] = row
                }
            } else {
                deduped[key] = row
            }
        }
        return Array(deduped.values)
    }

    private func analysisInboxMarkdownURL() -> URL? {
        let fm = FileManager.default
        let dir: URL?
        if let root = fm.url(forUbiquityContainerIdentifier: "iCloud.com.CYC.NotionJournal") {
            // Prefer iCloud Drive so desktop automations can append and the inbox syncs across devices.
            let docs = root.appendingPathComponent("Documents", isDirectory: true)
            dir = docs.appendingPathComponent("Investment", isDirectory: true)
        } else if let support = fm.urls(for: .applicationSupportDirectory, in: .userDomainMask).first {
            // Fallback: local-only inbox.
            dir = support.appendingPathComponent("NotionJournal/Investment", isDirectory: true)
        } else {
            dir = nil
        }
        guard let dir else { return nil }
        try? fm.createDirectory(at: dir, withIntermediateDirectories: true)
        let file = dir.appendingPathComponent("AnalysisInbox.md", isDirectory: false)
        if !fm.fileExists(atPath: file.path) {
            let seed = """
# Investment Analysis Inbox

Append trade-thesis digests here. Each item starts with a `###` header line, then fields.

Header format (recommended):
### 2026-05-01 16:45 JST — 2026 Japan Trade (Market end)

Fields (required for best rendering):
Category: Macro News
Severity: Critical
Verdict: Mixed
Notify: Yes
What happened: ...
Trade read: ...
Next watch: ...

"""
            try? seed.write(to: file, atomically: true, encoding: .utf8)
        }
        return file
    }

    private func openAnalysisInboxFolderInFinder() {
        #if os(macOS)
        let fm = FileManager.default
        let dir: URL?
        if let root = fm.url(forUbiquityContainerIdentifier: "iCloud.com.CYC.NotionJournal") {
            dir = root.appendingPathComponent("Documents/Investment", isDirectory: true)
        } else {
            dir = fm.urls(for: .applicationSupportDirectory, in: .userDomainMask).first?.appendingPathComponent("NotionJournal/Investment", isDirectory: true)
        }
        guard let dir else { return }
        NSWorkspace.shared.open(dir)
        #endif
    }

    private func analysisInboxDedupeKey(_ item: NJInvestmentAnalysisInboxItem) -> String {
        let base = item.headline.isEmpty ? item.whatHappened : item.headline
        let cleaned = cleanInvestmentAnalysisInboxHeadline(base).lowercased()
        let words = cleaned
            .components(separatedBy: CharacterSet.alphanumerics.inverted)
            .filter { !$0.isEmpty && $0 != "and" && $0 != "to" && $0 != "the" && $0 != "a" && $0 != "an" }
        if cleaned.contains("collaborat") || cleaned.contains("partnership") || cleaned.contains("partner") {
            let entityWords = words.filter {
                !["collaborate", "collaborates", "collaboration", "partnership", "partner", "partners", "explore", "expands", "accelerate", "across", "with", "on", "ai", "innovation", "technological", "technology", "capabilities", "powered", "features", "saudi", "arabia"].contains($0)
            }
            if entityWords.count >= 2 {
                return "collab " + entityWords.prefix(2).joined(separator: " ")
            }
        }
        if !words.isEmpty {
            return words.prefix(14).joined(separator: " ")
        }
        return item.id
    }

    private func parseAnalysisInboxMarkdown(data: Data, sourceLabel: String) -> [NJInvestmentAnalysisInboxItem] {
        guard let text = String(data: data, encoding: .utf8) else { return [] }
        let lines = text.split(separator: "\n", omittingEmptySubsequences: false).map(String.init)
        var blocks: [(header: String, body: [String])] = []
        var currentHeader: String? = nil
        var currentBody: [String] = []

        func flush() {
            if let h = currentHeader {
                blocks.append((header: h, body: currentBody))
            }
            currentHeader = nil
            currentBody = []
        }

        for line in lines {
            if line.hasPrefix("### ") {
                flush()
                currentHeader = String(line.dropFirst(4)).trimmingCharacters(in: .whitespacesAndNewlines)
            } else if currentHeader != nil {
                currentBody.append(line)
            }
        }
        flush()

        return blocks.compactMap { block in
            parseAnalysisInboxBlock(header: block.header, body: block.body, sourceLabel: sourceLabel)
        }
    }

    private func parseAnalysisInboxBlock(header: String, body: [String], sourceLabel: String) -> NJInvestmentAnalysisInboxItem? {
        let cleanedBody = body.joined(separator: "\n").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !cleanedBody.isEmpty else { return nil }

        func parseField(_ key: String) -> String? {
            let prefix = key + ":"
            for line in body {
                let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
                if trimmed.lowercased().hasPrefix(prefix.lowercased()) {
                    return trimmed.dropFirst(prefix.count).trimmingCharacters(in: .whitespacesAndNewlines)
                }
            }
            return nil
        }

        let verdict = (parseField("Verdict") ?? "").isEmpty ? "No Signal" : (parseField("Verdict") ?? "No Signal")
        let severity = parseField("Severity") ?? ""
        let category = parseField("Category") ?? parseField("Type") ?? ""
        let notify = (parseField("Notify") ?? "").lowercased().hasPrefix("y")
        let source = parseField("Source") ?? sourceLabel
        let headline = cleanInvestmentAnalysisInboxHeadline(parseField("Headline") ?? "")
        let symbols = (parseField("Symbols") ?? "")
            .split(separator: ",")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        let cloudKitNewsID = parseField("CloudKit News ID") ?? ""
        let articlePath = parseField("Article Path") ?? ""
        var whatHappened = cleanInvestmentAnalysisInboxHeadline(parseField("What happened") ?? "")
        let tradeRead = parseField("Trade read") ?? ""
        let nextWatch = parseField("Next watch") ?? ""

        if whatHappened.isEmpty && tradeRead.isEmpty && nextWatch.isEmpty {
            whatHappened = cleanedBody
        }

        let asOf = parseInboxHeaderDate(header) ?? Date()
        let (tradeThesis, cadence) = parseInboxHeaderTradeAndCadence(header)
        let rawID = "\(header)\n\(verdict)\n\(notify ? 1 : 0)\n\(headline)\n\(whatHappened)\n\(tradeRead)\n\(nextWatch)\n\(sourceLabel)"
        let id = cloudKitNewsID.isEmpty ? sha256Hex(rawID) : cloudKitNewsID

        return NJInvestmentAnalysisInboxItem(
            id: id,
            tradeThesis: tradeThesis,
            cadence: cadence,
            severity: severity,
            category: category,
            verdict: verdict,
            notify: notify,
            headline: headline,
            whatHappened: whatHappened,
            tradeRead: tradeRead,
            nextWatch: nextWatch,
            asOf: asOf,
            source: source,
            symbols: symbols,
            cloudKitNewsID: cloudKitNewsID,
            articlePath: articlePath
        )
    }

    private func parseInboxHeaderTradeAndCadence(_ header: String) -> (trade: String, cadence: String) {
        let parts = header.components(separatedBy: "—").map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        if parts.count >= 2 {
            return parseInboxHeaderLabel(parts[1])
        }
        if let range = header.range(of: #"^\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}(?:\s+[A-Z]+[+-]?\d*)?\s+-\s+"#, options: .regularExpression) {
            return parseInboxHeaderLabel(String(header[range.upperBound...]))
        }
        return ("Trade", "Digest")
    }

    private func parseInboxHeaderLabel(_ label: String) -> (trade: String, cadence: String) {
        let cleaned = label.trimmingCharacters(in: .whitespacesAndNewlines)
        if let open = cleaned.firstIndex(of: "("), let close = cleaned.lastIndex(of: ")"), open < close {
            let trade = String(cleaned[..<open]).trimmingCharacters(in: .whitespacesAndNewlines)
            let cadence = String(cleaned[cleaned.index(after: open)..<close]).trimmingCharacters(in: .whitespacesAndNewlines)
            return (trade.isEmpty ? cleaned : trade, cadence.isEmpty ? "Digest" : cadence)
        }
        return (cleaned.isEmpty ? "Trade" : cleaned, "Digest")
    }

    private func parseInboxHeaderDate(_ header: String) -> Date? {
        let tokens = header.split(separator: " ").map(String.init)
        guard tokens.count >= 2 else { return nil }
        let raw = "\(tokens[0]) \(tokens[1])"
        let zoneToken = tokens.count >= 3 ? tokens[2] : ""

        let df = DateFormatter()
        df.locale = Locale(identifier: "en_US_POSIX")
        df.dateFormat = "yyyy-MM-dd HH:mm"
        if zoneToken.uppercased().hasPrefix("GMT+8") || zoneToken.uppercased().hasPrefix("HKT") {
            df.timeZone = TimeZone(identifier: "Asia/Hong_Kong")
        } else if zoneToken.uppercased().hasPrefix("GMT") {
            df.timeZone = TimeZone(secondsFromGMT: 0)
        } else {
            df.timeZone = TimeZone.current
        }
        return df.date(from: raw)
    }

    private func sha256Hex(_ s: String) -> String {
        let d = Data(s.utf8)
        let h = SHA256.hash(data: d)
        return h.compactMap { String(format: "%02x", $0) }.joined()
    }

