    private func heatlistContent(showHeader: Bool) -> some View {
        VStack(alignment: .leading, spacing: 14) {
            if showHeader {
                moduleCard {
                    HStack(alignment: .center, spacing: 12) {
                        Label("Heatlist", systemImage: "square.grid.3x3.fill")
                            .font(.headline.weight(.bold))
                        Spacer()
                        Button {
                            refreshLiveInvestmentDataIfVisible(reason: "manual")
                        } label: {
                            Label("Refresh", systemImage: "arrow.clockwise")
                                .font(.subheadline.weight(.semibold))
                        }
                        .buttonStyle(.borderedProminent)
                        .controlSize(.small)
                    }
                    Text(heatlistScopeText(for: selectedHeatMarket))
                        .font(.subheadline)
                        .foregroundStyle(.secondary)

                    Picker("Heat timeframe", selection: $selectedHeatTimeframe) {
                        ForEach(NJInvestmentHeatTimeframe.allCases) { timeframe in
                            Text(timeframe.rawValue).tag(timeframe)
                        }
                    }
                    .pickerStyle(.segmented)
                    .onChange(of: selectedHeatTimeframe) { _, _ in
                        refreshHeatMapIfVisible(reason: "timeframe")
                    }
                }
            }

            marketHeatPicker
            heatBenchmarkStrip(for: selectedHeatMarket)

            let groups = heatSectorGroups(for: selectedHeatMarket)
