                emptyInvestmentPanel("No heatlist symbols for this market yet.")
            } else {
                LazyVGrid(columns: [GridItem(.adaptive(minimum: isCompactLayout ? 150 : 210), spacing: 10)], spacing: 10) {
                    ForEach(groups, id: \.sector) { group in
