                    HStack {
                        Label("Major Symbols", systemImage: "rectangle.grid.3x2")
                            .font(.headline.weight(.bold))
                        Spacer()
                        Text(heatRefreshStatus)
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(.secondary)
                    }

                    LazyVGrid(columns: [GridItem(.adaptive(minimum: isCompactLayout ? 112 : 150), spacing: 8)], spacing: 8) {
                        ForEach(heatRows(for: selectedHeatMarket)) { row in
                            heatSymbolTile(row)
                        }
                    }
                }
            }
        }
    }

