    private func heatSectorCard(_ group: (sector: String, rows: [NJInvestmentWatchRow], average: Double?)) -> some View {
        let average = group.average
        let upCount = group.rows.filter { (heatMove(for: $0) ?? 0) > 0 }.count
        let marketCap = group.rows.compactMap(heatMarketCap(for:)).reduce(0, +)
        return VStack(alignment: .leading, spacing: 10) {
            HStack(alignment: .firstTextBaseline) {
                Text(group.sector)
                    .font(.headline.weight(.bold))
                    .lineLimit(2)
                Spacer()
                Text(average.map { String(format: "%+.2f%%", $0) } ?? "live")
                    .font(.subheadline.weight(.bold))
                    .foregroundStyle(heatTextColor(average))
            }
            Text("\(upCount)/\(group.rows.count) green")
                .font(.caption.weight(.semibold))
                .foregroundStyle(.secondary)
            Text(marketCap > 0 ? "cap weight \(compactVolumeText(marketCap))" : "cap weight loading")
                .font(.caption2.weight(.semibold))
                .foregroundStyle(.secondary)
            HStack(spacing: 4) {
                ForEach(group.rows.prefix(8)) { row in
                    RoundedRectangle(cornerRadius: 3)
                        .fill(heatTileColor(heatMove(for: row)))
                        .frame(height: 8)
                        .accessibilityLabel(row.symbol)
                }
                Spacer(minLength: 0)
            }
        }
        .padding(12)
        .frame(maxWidth: .infinity, minHeight: 106, alignment: .topLeading)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func heatSymbolTile(_ row: NJInvestmentWatchRow) -> some View {
        let move = heatMove(for: row)
        let cap = heatMarketCap(for: row)
        return Button {
            openWatchResearchPopup(for: row)
        } label: {
            VStack(alignment: .leading, spacing: 7) {
                HStack {
                    Text(row.symbol)
                        .font(.subheadline.weight(.bold))
                        .lineLimit(1)
                    Spacer()
                    Text(move.map { String(format: "%+.1f", $0) } ?? "--")
                        .font(.caption.weight(.bold))
                }
                Text(row.name)
                    .font(.caption)
                    .lineLimit(2)
                Text(heatSectorName(for: row))
                    .font(.caption2.weight(.semibold))
                    .foregroundStyle(.secondary)
                Text(cap.map(compactVolumeText) ?? "cap loading")
                    .font(.caption2.weight(.bold))
                    .foregroundStyle(.secondary)
            }
            .contentShape(Rectangle())
            .padding(10)
            .frame(maxWidth: .infinity, minHeight: heatTileHeight(for: row), alignment: .topLeading)
            .background(heatTileColor(move))
            .foregroundStyle(Color.primary)
            .clipShape(RoundedRectangle(cornerRadius: 8))
        }
        .buttonStyle(.plain)
    }

    private func heatBenchmarkTile(_ row: NJInvestmentWatchRow) -> some View {
        let move = heatMove(for: row)
        return Button {
            openWatchResearchPopup(for: row)
        } label: {
            VStack(alignment: .leading, spacing: 7) {
                HStack(alignment: .firstTextBaseline) {
                    Text(row.symbol)
                        .font(.subheadline.weight(.bold))
                        .lineLimit(1)
                    Spacer()
                    Text(move.map { String(format: "%+.2f%%", $0) } ?? "--")
                        .font(.subheadline.weight(.bold))
                        .foregroundStyle(heatTextColor(move))
                }
                Text(row.name)
                    .font(.caption.weight(.semibold))
                    .lineLimit(2)
                Text(row.usCloseReference)
                    .font(.caption2.weight(.semibold))
                    .foregroundStyle(.secondary)
            }
            .contentShape(Rectangle())
            .padding(10)
            .frame(maxWidth: .infinity, minHeight: 76, alignment: .topLeading)
            .background(heatTileColor(move))
            .clipShape(RoundedRectangle(cornerRadius: 8))
        }
        .buttonStyle(.plain)
    }

