    private func tradeNewsCheckpointSection(tradeName: String) -> some View {
        tradeCollapsibleBlock(title: "News Checkpoints", icon: "newspaper", isExpanded: $tradeNewsCheckpointsExpanded) {
            VStack(alignment: .leading, spacing: 12) {
                tradeTableHeader(["Cadence", "Scope", "Update Rule"], widths: [0.9, 1.7, 2.4])
                tradeTableRow(["Midday", tradeName, "Check HK/China company news, filings, price/volume exceptions, and thesis-impacting broker or regulatory updates."], widths: [0.9, 1.7, 2.4])
                tradeTableRow(["Day end", tradeName, "Summarize confirmed close, material news, risk changes, and what to watch next session."], widths: [0.9, 1.7, 2.4])

                tradeSubsectionTitle("Coverage")
                tradeTableHeader(["Trade", "Primary Lists", "Focus"], widths: [1.2, 1.9, 2.1])
                tradeTableRow(["HK/China Tech AI", "AI/cloud, commerce, EV/battery, semis/infra", "AI monetization, subsidy burn, buybacks, capex, supply-chain scarcity, policy risk."], widths: [1.2, 1.9, 2.1])
                tradeTableRow(["HK/China High Yield", "Banks, telecoms, utilities, energy, staples", "Dividend cut-off, payout safety, P/E, credit/rates risk, 52-week downside risk."], widths: [1.2, 1.9, 2.1])

                Text("Automation writes checkpoint notes twice each HK trading day to Docs/Investment_Trade_Thesis_News_Checkpoints.md.")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
                    .fixedSize(horizontal: false, vertical: true)
            }
        }
    }

