                    tradeTableHeader(["Trigger", "What To Watch", "Implication"], widths: [1.1, 2.2, 1.9])
                    tradeTableRow(["Real yields", "Gold up while USD strong; miners lag; TLT stress", "Supports gold-as-stress, not only dollar weakness"], widths: [1.1, 2.2, 1.9])
                    tradeTableRow(["Oil shock", "WTI spikes + term structure tightens; energy equities confirm", "Inflation impulse + risk-off tail risk"], widths: [1.1, 2.2, 1.9])
                    tradeTableRow(["Crypto liquidity", "BTC leads risk; ETH beta; stablecoin/reg headlines", "Liquidity-on vs regulation/off-ramp risk"], widths: [1.1, 2.2, 1.9])
                    tradeTableRow(["FX stress", "USD/JPY breaks higher or gaps; CNH weakens", "Watch for forced de-risking / Asia risk appetite hit"], widths: [1.1, 2.2, 1.9])
                }
            }

            tradeCollapsibleBlock(title: "News - Alternative Asset", icon: "newspaper", isExpanded: $alternativeAssetNewsExpanded) {
                VStack(alignment: .leading, spacing: 10) {
                    tradeConversationPlaceholder(role: "System", kind: "Scope", title: "What counts as material", body: "Material items: OPEC policy / supply disruptions, EIA inventory surprises that change trend, major sanctions/war escalation impacting oil, ETF flow shocks for BTC/Gold, exchange failures, major regulation/court rulings, and clear regime shifts in real yields or USD funding stress.")
                    tradeConversationPlaceholder(role: "System", kind: "Rule", title: "Avoid noise", body: "Skip routine influencer headlines and single-print macro noise unless price confirms (abnormal volume + follow-through).")
                }
            }
        }
    }

