                    tradeTableRow(["2026-04-30", "Post-Fed / unclear BOJ", "Now-May 22", "JPY weakness is the active phase. Hawkish Fed plus unclear BOJ can push USD/JPY from 160 toward 162 while the market tests intervention tolerance.", "Do not assume JPY reversal; watch JGBs first"], widths: [0.75, 1.35, 1.0, 2.0, 1.4])
