                    tradeTableRow(["2026-04-29", "Japan CPI", "Mixed", "National CPI re-accelerated in March, but core ex fresh food is still below 2%. Tokyo April CPI is the next early signal.", "Tokyo CPI May 1"], widths: [0.9, 0.75, 0.9, 1.9, 1.45])
                    tradeTableRow(["2026-04-30", "Key windows", "Set", "May 8 and May 13 are equity-fatigue windows for short Nikkei. May 22 is the CPI confirmation date for whether JPY can stop deteriorating.", "Expect possible JPY weakness until May 22"], widths: [0.9, 0.75, 0.9, 1.9, 1.45])
                    tradeTableRow(["2026-04-30", "USD/JPY", "160 test", "Post-Fed dollar strength plus weak BOJ attitude pushed JPY back into the intervention danger zone. Market is now testing when BOJ/MOF will act.", "Watch verbal escalation vs actual intervention"], widths: [0.9, 0.75, 0.9, 1.9, 1.45])
