    private var investmentLiquidityWorkspace: some View {
        let holdings = investmentLiquidHoldings
        let knownHoldings = holdings.filter { $0.amount != nil }
        let totalHKD = knownHoldings.compactMap(\.hkdEquivalent).reduce(0, +)
        let cashHKD = liquidityTotal(knownHoldings.filter { $0.instrumentType == .cash })
        let deployableHKD = liquidityTotal(knownHoldings.filter { $0.instrumentType == .cash || $0.instrumentType == .timeDeposit })
        let pendingCount = holdings.filter { $0.amount == nil }.count
        let deploymentRows = liquidityDeploymentRows(holdings: knownHoldings, mode: liquidityDeploymentRowMode)
        let deploymentInstitutions = liquidityDeploymentInstitutions(rows: deploymentRows)
        let dryPowderRows = liquidityDryPowderRows(holdings: knownHoldings)
        let budgetRows = investmentThesisBudgetRows(totalLiquidHKD: totalHKD)
        let childTradeRows = investmentChildTradeBudgetRows(totalLiquidHKD: totalHKD)

        return VStack(alignment: .leading, spacing: 14) {
            VStack(alignment: .leading, spacing: 10) {
                HStack(alignment: .top, spacing: 12) {
                    VStack(alignment: .leading, spacing: 4) {
                        sectionHeader("Liquidity & Risk Concentration", icon: "chart.pie")
                    }
                    Spacer()
                    VStack(alignment: .trailing, spacing: 8) {
                        Text(portfolioLiquidityStatus)
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(.secondary)
                            .multilineTextAlignment(.trailing)
                        Button {
                            refreshPortfolioLiquidityIfVisible(reason: "manual")
                        } label: {
                            Label("Refresh", systemImage: "arrow.clockwise")
                        }
                        .buttonStyle(.borderedProminent)
                        .controlSize(.small)
                    }
                }

                if let refreshedAt = portfolioLiquidityLastRefreshAt {
                    Text("Last holdings read: \(systemLiquidityRefreshDateText(refreshedAt))")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
            }

            VStack(alignment: .leading, spacing: 6) {
                Text("Liquid assets only. Fixed assets stay out of this map.")
                    .font(.subheadline.weight(.bold))
                Text("HKD-equivalent uses a 7.8 USD/HKD working rate until live FX is wired in. A file-backed holdings override at Docs/Investment_Liquidity_Holdings.json is loaded automatically when available; otherwise bundled balances stay in place.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            .padding(10)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color(UIColor.secondarySystemGroupedBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))

            LazyVGrid(columns: [GridItem(.adaptive(minimum: 170), spacing: 10)], spacing: 10) {
                liquidityMetricTile(title: "Liquid Assets", value: liquidityMoneyHKD(totalHKD), subtitle: "\(knownHoldings.count) known holdings")
                liquidityMetricTile(title: "Cash", value: liquidityMoneyHKD(cashHKD), subtitle: liquidityPercent(cashHKD, total: totalHKD))
                liquidityMetricTile(title: "Cash + TD", value: liquidityMoneyHKD(deployableHKD), subtitle: liquidityPercent(deployableHKD, total: totalHKD))
                liquidityMetricTile(title: "Pending", value: "\(pendingCount)", subtitle: "Needs amount")
            }

            LazyVGrid(columns: [GridItem(.adaptive(minimum: 260), spacing: 12)], spacing: 12) {
                liquidityConcentrationCard(title: "Currency", slices: liquiditySlices(knownHoldings, key: { $0.currency.uppercased() }))
                liquidityConcentrationCard(title: "Market", slices: liquiditySlices(knownHoldings, key: { $0.market }))
                liquidityConcentrationCard(title: "Instrument", slices: liquiditySlices(knownHoldings, key: { $0.instrumentType.rawValue }))
            }

            liquidityDeploymentMatrix(rows: deploymentRows, institutions: deploymentInstitutions)
            investmentThesisBudgetCard(rows: budgetRows, dryPowderHKD: cashHKD)
            investmentChildTradeBudgetCard(rows: childTradeRows, dryPowderHKD: cashHKD)
            liquidityDryPowderCard(rows: dryPowderRows)

            VStack(alignment: .leading, spacing: 8) {
                Text("Liquid Holdings")
                    .font(.headline.weight(.bold))
                ScrollView(.horizontal, showsIndicators: true) {
                    VStack(alignment: .leading, spacing: 8) {
                        tradeTableHeader(["Institution", "Account", "Type", "CCY", "Amount", "HKD Eq.", "Market", "Maturity", "Note"], widths: [1.1, 1.25, 0.9, 0.55, 0.95, 0.95, 0.9, 0.95, 1.8])
                        ForEach(holdings) { holding in
                            tradeTableRow(
                                [
                                    holding.institution,
                                    holding.accountLabel,
                                    holding.instrumentType.rawValue,
                                    holding.currency,
                                    holding.amount.map { liquidityMoney($0, currency: holding.currency) } ?? "Pending",
                                    holding.hkdEquivalent.map(liquidityMoneyHKD) ?? "Pending",
                                    holding.market,
                                    holding.maturity ?? "-",
                                    holding.note
                                ],
                                widths: [1.1, 1.25, 0.9, 0.55, 0.95, 0.95, 0.9, 0.95, 1.8]
                            )
                        }
                    }
                    .frame(minWidth: 980, alignment: .leading)
                }
            }
            .padding(14)
            .background(Color(UIColor.systemBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))
        }
    }

