    private var ledgerBackedLiquidPositions: [NJInvestmentLiquidHolding] {
        let positions = investmentPositionSummaries(from: investmentLedgerExecutions())
            .filter { abs($0.netQuantity) > 0.0001 }

        return positions.map { position in
            NJInvestmentLiquidHolding(
                id: "ledger-position-\(position.id)",
                institution: position.institutions.joined(separator: " / "),
                accountLabel: position.symbol,
                currency: position.currency,
                amount: position.marketValue ?? position.grossCost,
                instrumentType: .equity,
                market: liquidityMarketLabel(for: position),
                maturity: nil,
                note: position.tradeThesis
            )
        }
    }

    private func liquidityMarketLabel(for position: NJInvestmentPositionSummary) -> String {
        let symbol = position.symbol.uppercased()
        if symbol.hasSuffix(" HK") { return "HK Equity" }
        if symbol.hasSuffix(" CN") { return "China Equity" }
        if symbol.hasSuffix(" JP") || symbol.hasSuffix(".T") { return "Japan Equity" }
        if symbol.contains("USD") && symbol.contains("/") { return "FX / Macro" }
        return "US / Global Equity"
    }

    private func liquidityTotal(_ holdings: [NJInvestmentLiquidHolding]) -> Double {
        holdings.compactMap(\.hkdEquivalent).reduce(0, +)
    }

    private func liquiditySlices(_ holdings: [NJInvestmentLiquidHolding], key: (NJInvestmentLiquidHolding) -> String) -> [NJInvestmentLiquiditySlice] {
        Dictionary(grouping: holdings, by: key)
            .map { label, rows in
                NJInvestmentLiquiditySlice(
                    id: label,
                    label: label,
                    amountHKD: rows.compactMap(\.hkdEquivalent).reduce(0, +)
                )
            }
            .filter { $0.amountHKD > 0 }
            .sorted { $0.amountHKD > $1.amountHKD }
    }

    private func liquidityDeploymentRows(holdings: [NJInvestmentLiquidHolding], mode: NJInvestmentLiquidityDeploymentRowMode) -> [NJInvestmentLiquidityDeploymentRow] {
        var rows: [NJInvestmentLiquidityDeploymentRow] = []
        let holdingGroups = Dictionary(grouping: holdings) { holding -> String in
            switch holding.instrumentType {
            case .cash: return "Dry Powder / Cash"
            case .timeDeposit: return "Time Deposit"
            case .bond: return "Bond"
            case .equity: return "Open Position"
            case .pending: return "Pending"
            }
        }

        for label in ["Dry Powder / Cash", "Time Deposit", "Bond", "Open Position", "Pending"] {
            guard let groupHoldings = holdingGroups[label] else { continue }
            rows.append(
                NJInvestmentLiquidityDeploymentRow(
                    id: "holding-\(label)",
                    group: "Instrument",
                    label: label,
                    valuesByInstitution: liquidityValuesByInstitution(groupHoldings),
                    marketValueHKD: nil,
                    unrealizedPLHKD: nil,
                    marketValuePending: false,
                    profitLossPending: false
                )
            )
        }

        let ledgerRows = mode == .trade ? liquidityTradeDeploymentRows() : liquidityHoldingDeploymentRows()
        return rows + ledgerRows
    }

