    private func canonicalInvestmentThesis(_ thesis: String) -> String {
        let cleaned = thesis.trimmingCharacters(in: .whitespacesAndNewlines)
        let folded = cleaned
            .lowercased()
            .replacingOccurrences(of: " ", with: "")
            .replacingOccurrences(of: "-", with: "")
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: "/", with: "")

        if folded.contains("softwareovershoot") || folded.contains("saasovershoot") {
            return "Software overshoot"
        }
        if folded.contains("2026q1ustrade") || folded.contains("2026q1usshort") || folded.contains("usshort") {
            return "2026Q1 US Short"
        }
        if folded.contains("nikkeishort") || folded.contains("japantrade") {
            return "2026Q1 Nikkei Short"
        }
        if folded == "gold" || folded.contains("alternativeasset") {
            return "Gold"
        }
        return cleaned
    }

    private func canonicalInvestmentTradeName(_ execution: NJInvestmentLedgerExecution) -> String {
        let cleanedCode = execution.tradeCode.trimmingCharacters(in: .whitespacesAndNewlines)
        if !cleanedCode.isEmpty {
            return canonicalInvestmentTradeName(cleanedCode, thesis: execution.tradeThesis, symbol: execution.symbol)
        }
        return canonicalInvestmentTradeName(execution.symbol, thesis: execution.tradeThesis, symbol: execution.symbol)
    }

    private func canonicalInvestmentTradeName(_ rawName: String, thesis: String, symbol: String) -> String {
        let cleaned = rawName.trimmingCharacters(in: .whitespacesAndNewlines)
        let folded = cleaned
            .lowercased()
            .replacingOccurrences(of: " ", with: "")
            .replacingOccurrences(of: "-", with: "")
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: "/", with: "")
        let canonicalThesis = canonicalInvestmentThesis(thesis)

        if folded.contains("gldm") || folded.contains("gold") || symbol.uppercased().contains("GLD") {
            return "GLDM tranche plan"
        }
        if folded.contains("nvda") || symbol.uppercased().contains("NVDA") {
            return "NVDA overshoot"
        }
        if folded.contains("sqqq") || folded.contains("qqq") || folded.contains("usshort") || symbol.uppercased().contains("SQQQ") {
            return "US short core"
        }
        if folded.contains("nikkei") || symbol.uppercased().contains("NKY") || symbol.uppercased().contains("NIKKEI") {
            return "Nikkei short core"
        }
        if canonicalThesis == "Software overshoot" {
            return "Software overshoot core"
        }
        return cleaned.isEmpty ? "Unassigned trade" : cleaned
    }

    private func investmentChildTradeBudgetRows(totalLiquidHKD: Double) -> [NJInvestmentChildTradeBudgetRow] {
        let executions = investmentLedgerExecutions()
        let positions = investmentPositionSummaries(from: executions)
        let deployedByTrade = Dictionary(grouping: executions) { execution in
            "\(canonicalInvestmentThesis(execution.tradeThesis))|\(canonicalInvestmentTradeName(execution))"
        }
            .mapValues { rows in
                rows.reduce(0) { total, execution in
                    let fee = execution.fees ?? 0
                    let gross = execution.grossNotional
                    let signed = execution.side.uppercased() == "SELL" ? -(gross - fee) : gross + fee
                    return total + liquidityHKDEquivalent(signed, currency: execution.currency)
                }
            }
        let marketValueByTrade = Dictionary(grouping: positions) { position in
            "\(canonicalInvestmentThesis(position.tradeThesis))|\(canonicalInvestmentTradeName(position.symbol, thesis: position.tradeThesis, symbol: position.symbol))"
        }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let marketValue = position.marketValue else { return nil }
                    return liquidityHKDEquivalent(marketValue, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }
        let unrealizedByTrade = Dictionary(grouping: positions) { position in
            "\(canonicalInvestmentThesis(position.tradeThesis))|\(canonicalInvestmentTradeName(position.symbol, thesis: position.tradeThesis, symbol: position.symbol))"
        }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let unrealizedPL = position.unrealizedPL else { return nil }
                    return liquidityHKDEquivalent(unrealizedPL, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }

        var rows = investmentChildTradeBudgets(totalLiquidHKD: totalLiquidHKD).map { budget in
            let key = "\(budget.thesis)|\(budget.tradeName)"
            return NJInvestmentChildTradeBudgetRow(
                id: budget.id,
                thesis: budget.thesis,
                tradeName: budget.tradeName,
                plannedHKD: budget.plannedHKD,
                deployedHKD: deployedByTrade[key] ?? 0,
                marketValueHKD: marketValueByTrade[key] ?? nil,
                unrealizedPLHKD: unrealizedByTrade[key] ?? nil,
                lifecycle: budget.lifecycle,
                goal: budget.goal
            )
        }

        let budgetedKeys = Set(rows.map { "\($0.thesis)|\($0.tradeName)" })
        for key in deployedByTrade.keys.sorted() where !budgetedKeys.contains(key) {
            let parts = key.split(separator: "|", maxSplits: 1).map(String.init)
            let thesis = parts.first ?? "Unassigned thesis"
            let tradeName = parts.dropFirst().first ?? "Unassigned trade"
            rows.append(
                NJInvestmentChildTradeBudgetRow(
                    id: "ledger-child-\(key)",
                    thesis: thesis,
                    tradeName: tradeName,
                    plannedHKD: 0,
                    deployedHKD: deployedByTrade[key] ?? 0,
                    marketValueHKD: marketValueByTrade[key] ?? nil,
                    unrealizedPLHKD: unrealizedByTrade[key] ?? nil,
                    lifecycle: .active,
                    goal: "Ledger has executions for this trade name, but no child budget has been set yet."
                )
            )
        }

        return rows.sorted {
            if $0.thesis != $1.thesis { return $0.thesis < $1.thesis }
            if $0.plannedHKD == 0, $1.plannedHKD != 0 { return false }
            if $0.plannedHKD != 0, $1.plannedHKD == 0 { return true }
            return $0.tradeName < $1.tradeName
        }
    }

    private func investmentThesisBudgetRows(totalLiquidHKD: Double) -> [NJInvestmentThesisBudgetRow] {
        let executions = investmentLedgerExecutions()
        let positions = investmentPositionSummaries(from: executions)
        let deployedByThesis = Dictionary(grouping: executions) { canonicalInvestmentThesis($0.tradeThesis) }
            .mapValues { rows in
                rows.reduce(0) { total, execution in
                    let fee = execution.fees ?? 0
                    let gross = execution.grossNotional
                    let signed = execution.side.uppercased() == "SELL" ? -(gross - fee) : gross + fee
                    return total + liquidityHKDEquivalent(signed, currency: execution.currency)
                }
            }
        let marketValueByThesis = Dictionary(grouping: positions) { canonicalInvestmentThesis($0.tradeThesis) }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let marketValue = position.marketValue else { return nil }
                    return liquidityHKDEquivalent(marketValue, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }
        let unrealizedByThesis = Dictionary(grouping: positions) { canonicalInvestmentThesis($0.tradeThesis) }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let unrealizedPL = position.unrealizedPL else { return nil }
                    return liquidityHKDEquivalent(unrealizedPL, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }

        var rows = investmentThesisBudgets(totalLiquidHKD: totalLiquidHKD).map { budget in
            NJInvestmentThesisBudgetRow(
                id: budget.id,
                thesis: budget.thesis,
                plannedHKD: budget.plannedHKD,
                deployedHKD: deployedByThesis[budget.thesis] ?? 0,
                marketValueHKD: marketValueByThesis[budget.thesis] ?? nil,
                unrealizedPLHKD: unrealizedByThesis[budget.thesis] ?? nil,
                note: budget.note
            )
        }

        let budgetedTheses = Set(rows.map(\.thesis))
        for thesis in deployedByThesis.keys.sorted() where !budgetedTheses.contains(thesis) {
            rows.append(
                NJInvestmentThesisBudgetRow(
                    id: "ledger-only-\(thesis)",
                    thesis: thesis,
                    plannedHKD: 0,
                    deployedHKD: deployedByThesis[thesis] ?? 0,
                    marketValueHKD: marketValueByThesis[thesis] ?? nil,
                    unrealizedPLHKD: unrealizedByThesis[thesis] ?? nil,
                    note: "Ledger has executions, but no planned budget has been set yet."
                )
            )
        }

        return rows.sorted {
            if $0.plannedHKD == 0, $1.plannedHKD != 0 { return false }
            if $0.plannedHKD != 0, $1.plannedHKD == 0 { return true }
            return $0.thesis < $1.thesis
        }
    }

    private func liquidityValuesByInstitution(_ holdings: [NJInvestmentLiquidHolding]) -> [String: Double] {
        Dictionary(grouping: holdings) { $0.institution }
            .mapValues { rows in rows.compactMap(\.hkdEquivalent).reduce(0, +) }
    }

    private func liquidityTradeDeploymentRows() -> [NJInvestmentLiquidityDeploymentRow] {
        let executions = investmentLedgerExecutions()
        var values: [String: [String: Double]] = [:]
        let positions = investmentPositionSummaries(from: executions)
        let marketValueByThesis = Dictionary(grouping: positions) { canonicalInvestmentThesis($0.tradeThesis) }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let marketValue = position.marketValue else { return nil }
                    return liquidityHKDEquivalent(marketValue, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }
        let profitByThesis = Dictionary(grouping: positions) { canonicalInvestmentThesis($0.tradeThesis) }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let unrealizedPL = position.unrealizedPL else { return nil }
                    return liquidityHKDEquivalent(unrealizedPL, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }

        for execution in executions {
            let side = execution.side.uppercased()
            let signedAmount: Double
            if side == "SELL" {
                signedAmount = -(execution.grossNotional - (execution.fees ?? 0))
            } else {
                signedAmount = execution.grossNotional + (execution.fees ?? 0)
            }
            let hkdAmount = liquidityHKDEquivalent(signedAmount, currency: execution.currency)
            guard abs(hkdAmount) > 0.01 else { continue }
            values[canonicalInvestmentThesis(execution.tradeThesis), default: [:]][execution.institution, default: 0] += hkdAmount
        }

        return values
            .map { thesis, byInstitution in
                NJInvestmentLiquidityDeploymentRow(
                    id: "trade-\(thesis)",
                    group: "Trade",
                    label: thesis,
                    valuesByInstitution: byInstitution.filter { abs($0.value) > 0.01 },
                    marketValueHKD: marketValueByThesis[thesis] ?? nil,
                    unrealizedPLHKD: profitByThesis[thesis] ?? nil,
                    marketValuePending: true,
                    profitLossPending: true
                )
            }
            .filter { !$0.valuesByInstitution.isEmpty }
            .sorted { $0.label < $1.label }
    }

    private func liquidityHoldingDeploymentRows() -> [NJInvestmentLiquidityDeploymentRow] {
        let executions = investmentLedgerExecutions()
        let positions = investmentPositionSummaries(from: executions)
        var values: [String: [String: Double]] = [:]

        for execution in executions {
            let side = execution.side.uppercased()
            let signedAmount: Double
            if side == "SELL" {
                signedAmount = -(execution.grossNotional - (execution.fees ?? 0))
            } else {
                signedAmount = execution.grossNotional + (execution.fees ?? 0)
            }
            let hkdAmount = liquidityHKDEquivalent(signedAmount, currency: execution.currency)
            guard abs(hkdAmount) > 0.01 else { continue }
            let key = "\(execution.symbol) - \(canonicalInvestmentThesis(execution.tradeThesis))"
            values[key, default: [:]][execution.institution, default: 0] += hkdAmount
        }

        let profitByHolding = Dictionary(grouping: positions) { "\($0.symbol) - \(canonicalInvestmentThesis($0.tradeThesis))" }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let unrealizedPL = position.unrealizedPL else { return nil }
                    return liquidityHKDEquivalent(unrealizedPL, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }
        let marketValueByHolding = Dictionary(grouping: positions) { "\($0.symbol) - \(canonicalInvestmentThesis($0.tradeThesis))" }
            .mapValues { rows -> Double? in
                let values = rows.compactMap { position -> Double? in
                    guard let marketValue = position.marketValue else { return nil }
                    return liquidityHKDEquivalent(marketValue, currency: position.currency)
                }
                guard !values.isEmpty else { return nil }
                return values.reduce(0, +)
            }

        return values
            .map { label, byInstitution in
                NJInvestmentLiquidityDeploymentRow(
                    id: "holding-ledger-\(label)",
                    group: "Holding",
                    label: label,
                    valuesByInstitution: byInstitution.filter { abs($0.value) > 0.01 },
                    marketValueHKD: marketValueByHolding[label] ?? nil,
                    unrealizedPLHKD: profitByHolding[label] ?? nil,
                    marketValuePending: true,
                    profitLossPending: true
                )
            }
            .filter { !$0.valuesByInstitution.isEmpty }
            .sorted { $0.label < $1.label }
    }

    private func liquidityDeploymentInstitutions(rows: [NJInvestmentLiquidityDeploymentRow]) -> [String] {
        Array(Set(rows.flatMap { $0.valuesByInstitution.keys })).sorted()
    }

    private func liquidityDryPowderRows(holdings: [NJInvestmentLiquidHolding]) -> [NJInvestmentDryPowderRow] {
        Dictionary(grouping: holdings.filter { $0.instrumentType == .cash }) { $0.institution }
            .map { institution, rows in
                let total = rows.compactMap(\.hkdEquivalent).reduce(0, +)
                let breakdown = Dictionary(grouping: rows) { $0.currency.uppercased() }
                    .map { currency, currencyRows in
                        let amount = currencyRows.compactMap(\.amount).reduce(0, +)
                        return liquidityMoney(amount, currency: currency)
                    }
                    .sorted()
                    .joined(separator: "  |  ")
                return NJInvestmentDryPowderRow(
                    id: institution,
                    institution: institution,
                    hkdEquivalent: total,
                    currencyBreakdown: breakdown
                )
            }
            .sorted { $0.hkdEquivalent > $1.hkdEquivalent }
    }

