    private func liquidityPLCell(_ row: NJInvestmentLiquidityDeploymentRow, width: CGFloat) -> some View {
        let text: String
        let tone: Color
        if let unrealizedPLHKD = row.unrealizedPLHKD {
            text = liquidityMoneyHKD(unrealizedPLHKD)
            tone = unrealizedPLHKD < 0 ? .red : .green
        } else if row.profitLossPending {
            text = "Live pending"
            tone = .secondary
        } else {
            text = "-"
            tone = .secondary
        }

        return Text(text)
            .font(.caption.weight(.bold))
            .foregroundStyle(tone)
            .lineLimit(2)
            .minimumScaleFactor(0.75)
            .frame(width: width, height: 52, alignment: .trailing)
            .padding(.horizontal, 8)
            .background(Color(UIColor.systemBackground))
