    private func investmentChildTradeBudgetCard(rows: [NJInvestmentChildTradeBudgetRow], dryPowderHKD: Double) -> some View {
        let activeRows = rows.filter { $0.lifecycle == .active }
        let candidateRows = rows.filter { $0.lifecycle == .candidate }
        let closedRows = rows.filter { $0.lifecycle == .missed || $0.lifecycle == .dropped || $0.lifecycle == .invalidated }
        let opportunityHKD = rows.reduce(0) { $0 + $1.plannedHKD }
        let activeTargetHKD = activeRows.reduce(0) { $0 + $1.plannedHKD }
        let candidateTargetHKD = candidateRows.reduce(0) { $0 + $1.plannedHKD }
        let activeDeployedHKD = activeRows.reduce(0) { $0 + $1.deployedHKD }

        return VStack(alignment: .leading, spacing: 10) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 4) {
                    Text("Opportunity Book Inside Thesis")
                        .font(.headline.weight(.bold))
                    Text("A thesis can hold multiple named trades. Candidate capital can exceed actual capital so you can shop setups, then mark ideas active, missed, dropped, or invalidated.")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
                Spacer()
                VStack(alignment: .trailing, spacing: 2) {
                    Text("Dry Powder")
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(.secondary)
                    Text(liquidityMoneyHKD(dryPowderHKD))
                        .font(.subheadline.weight(.bold))
                        .monospacedDigit()
                }
            }

            LazyVGrid(columns: [GridItem(.adaptive(minimum: 165), spacing: 10)], spacing: 10) {
                liquidityMetricTile(title: "Opportunity Capital", value: liquidityMoneyHKD(opportunityHKD), subtitle: "\(rows.count) possible trades")
                liquidityMetricTile(title: "Active Target", value: liquidityMoneyHKD(activeTargetHKD), subtitle: "\(activeRows.count) active trades")
                liquidityMetricTile(title: "Candidate Target", value: liquidityMoneyHKD(candidateTargetHKD), subtitle: "\(candidateRows.count) shopping ideas")
                liquidityMetricTile(title: "Active Deployed", value: liquidityMoneyHKD(activeDeployedHKD), subtitle: liquidityPercent(activeDeployedHKD, total: max(activeTargetHKD, 1)))
                liquidityMetricTile(title: "Archived Ideas", value: "\(closedRows.count)", subtitle: "Missed / dropped / invalidated")
            }

            ScrollView(.horizontal, showsIndicators: true) {
                VStack(alignment: .leading, spacing: 0) {
                    HStack(spacing: 0) {
                        liquidityMatrixCell("Thesis", width: 210, isHeader: true, alignment: .leading)
                        liquidityMatrixCell("Trade Name", width: 230, isHeader: true, alignment: .leading)
                        liquidityMatrixCell("Status", width: 120, isHeader: true, alignment: .leading)
                        liquidityMatrixCell("Target", width: 140, isHeader: true, alignment: .trailing)
                        liquidityMatrixCell("Deployed", width: 140, isHeader: true, alignment: .trailing)
                        liquidityMatrixCell("Remaining", width: 140, isHeader: true, alignment: .trailing)
                        liquidityMatrixCell("MTM", width: 140, isHeader: true, alignment: .trailing)
                        liquidityMatrixCell("Unrealized P/L", width: 150, isHeader: true, alignment: .trailing)
                        liquidityMatrixCell("Exec %", width: 95, isHeader: true, alignment: .trailing)
                        liquidityMatrixCell("Goal / Rule", width: 360, isHeader: true, alignment: .leading)
                    }

                    ForEach(rows) { row in
                        HStack(spacing: 0) {
                            liquidityMatrixCell(row.thesis, width: 210, isHeader: false, alignment: .leading)
                            VStack(alignment: .leading, spacing: 2) {
                                Text(row.tradeName)
                                    .font(.caption.weight(.bold))
                                    .lineLimit(1)
                                Text(row.plannedHKD > 0 ? "Budgeted child trade" : "Target unset")
                                    .font(.caption2.weight(.semibold))
                                    .foregroundStyle(.secondary)
                            }
                            .frame(width: 230, height: 64, alignment: .leading)
                            .padding(.horizontal, 8)
                            .background(Color(UIColor.systemBackground))
                            .border(Color(UIColor.separator).opacity(0.35), width: 0.5)

                            liquidityTradeLifecycleCell(row.lifecycle, width: 120)
                            liquidityMatrixCell(row.plannedHKD > 0 ? liquidityMoneyHKD(row.plannedHKD) : "Unset", width: 140, isHeader: false, alignment: .trailing)
                            liquidityMatrixCell(liquidityMoneyHKD(row.deployedHKD), width: 140, isHeader: false, alignment: .trailing)
                            liquidityChildTradeRemainingCell(row, width: 140)
                            liquidityMatrixCell(row.marketValueHKD.map(liquidityMoneyHKD) ?? "Live pending", width: 140, isHeader: false, alignment: .trailing)
                            liquidityChildTradePLCell(row, width: 150)
                            liquidityMatrixCell(row.plannedHKD > 0 ? String(format: "%.1f%%", row.deployedPercent) : "-", width: 95, isHeader: false, alignment: .trailing)
                            liquidityMatrixCell(row.goal, width: 360, isHeader: false, alignment: .leading)
                        }
                    }
                }
                .frame(minWidth: 1_725, alignment: .leading)
            }
        }
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
