    private func liquidityPieColor(_ index: Int) -> Color {
        let palette: [Color] = [.blue, .green, .orange, .purple, .pink, .teal, .red, .indigo, .cyan, .brown]
        return palette[index % palette.count]
    }

    private func liquidityMoney(_ value: Double, currency: String) -> String {
        "\(currency.uppercased()) \(liquidityNumber(value))"
    }

    private func liquidityMoneyHKD(_ value: Double) -> String {
        "HKD \(liquidityNumber(value))"
    }

    private func liquidityHKDEquivalent(_ value: Double, currency: String) -> Double {
        switch currency.uppercased() {
        case "HKD":
            return value
        case "USD":
            return value * 7.8
        default:
            return value
        }
    }

    private func liquidityMatrixAmount(_ value: Double?) -> String {
        guard let value, abs(value) > 0.01 else { return "-" }
        return liquidityMoneyHKD(value)
    }

    private func liquidityNumber(_ value: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .decimal
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        return formatter.string(from: NSNumber(value: value)) ?? String(format: "%.2f", value)
    }

    private func liquidityPercent(_ value: Double, total: Double) -> String {
        guard total > 0 else { return "0%" }
        return "\(String(format: "%.1f", value / total * 100))%"
    }

