        let executions = investmentLedgerExecutions(filterTradeThesis: filterTradeThesis)
        let positions = investmentPositionSummaries(from: executions)
        let thesisSummaries = investmentThesisSummaries(from: positions)
        let portfolioSummaries = investmentPortfolioSummaries(from: positions)

