    private func investmentLedgerExecutions(filterTradeThesis: String? = nil) -> [NJInvestmentLedgerExecution] {
        store.notes.listInvestmentLedgerTransactions(limit: 500)
            .compactMap(investmentLedgerExecution(from:))
            .filter { execution in
                guard let filterTradeThesis else { return true }
                return execution.tradeThesis == filterTradeThesis
            }
            .sorted {
                if $0.dateKey != $1.dateKey { return $0.dateKey < $1.dateKey }
                if $0.transactionNumber != $1.transactionNumber { return $0.transactionNumber < $1.transactionNumber }
                return $0.transactionID < $1.transactionID
            }
    }

    private func investmentLedgerExecution(from row: NJInvestmentLedgerTransaction) -> NJInvestmentLedgerExecution? {
        guard row.deleted == 0 else { return nil }
        return NJInvestmentLedgerExecution(
            id: row.ledgerTransactionID,
            transactionID: row.ledgerTransactionID,
            transactionNumber: row.transactionNumber,
            dateKey: row.tradeDateKey,
            tradeThesis: row.tradeThesis,
            tradeCode: row.tradeCode,
            region: row.region,
            orderRef: row.brokerReference,
            institution: row.institution,
            accountLabel: row.accountLabel,
            symbol: row.symbol,
            side: row.side,
            quantity: row.quantity,
            executionPrice: row.price,
            currency: row.currencyCode,
            fees: row.fees == 0 ? nil : row.fees,
            status: row.status
        )
    }

    private func investmentPositionSummaries(from executions: [NJInvestmentLedgerExecution]) -> [NJInvestmentPositionSummary] {
        let grouped = Dictionary(grouping: executions) { "\($0.tradeThesis)|\($0.symbol)|\($0.currency)" }
        return grouped.values.map { rows in
            let sortedRows = rows.sorted {
                if $0.dateKey != $1.dateKey { return $0.dateKey < $1.dateKey }
                return $0.transactionID < $1.transactionID
            }
            var lots: [NJInvestmentOpenLot] = []
            var realizedPL = 0.0

            for execution in sortedRows {
                let fee = execution.fees ?? 0
                if execution.side.uppercased() == "SELL" {
                    var remainingSellQuantity = execution.quantity
                    let sellPriceAfterFee = execution.quantity == 0 ? execution.executionPrice : execution.executionPrice - fee / execution.quantity
                    var updatedLots: [NJInvestmentOpenLot] = []

                    for lot in lots {
                        guard remainingSellQuantity > 0 else {
                            updatedLots.append(lot)
                            continue
                        }
                        let consumed = min(lot.quantity, remainingSellQuantity)
                        realizedPL += consumed * (sellPriceAfterFee - lot.costPerShare)
                        remainingSellQuantity -= consumed
                        let remainingLotQuantity = lot.quantity - consumed
                        if remainingLotQuantity > 0.0001 {
                            updatedLots.append(
                                NJInvestmentOpenLot(
                                    id: lot.id,
                                    dateKey: lot.dateKey,
                                    orderRef: lot.orderRef,
                                    quantity: remainingLotQuantity,
                                    costPerShare: lot.costPerShare
                                )
                            )
                        }
                    }
                    lots = updatedLots
                } else {
                    let costPerShare = execution.quantity == 0 ? execution.executionPrice : execution.executionPrice + fee / execution.quantity
                    lots.append(
                        NJInvestmentOpenLot(
                            id: execution.transactionID,
                            dateKey: execution.dateKey,
                            orderRef: execution.orderRef,
                            quantity: execution.quantity,
                            costPerShare: costPerShare
                        )
                    )
                }
            }

            let first = sortedRows[0]
            let netQuantity = lots.reduce(0) { $0 + $1.quantity }
            let grossCost = lots.reduce(0) { $0 + $1.remainingCost }
            let averageCost = netQuantity == 0 ? 0 : grossCost / netQuantity
            return NJInvestmentPositionSummary(
                id: "\(first.tradeThesis)|\(first.symbol)|\(first.currency)",
                tradeThesis: first.tradeThesis,
                symbol: first.symbol,
                institutions: Array(Set(sortedRows.map(\.institution))).filter { !$0.isEmpty }.sorted(),
                currency: first.currency,
                netQuantity: netQuantity,
                averageCost: averageCost,
                grossCost: grossCost,
                realizedPL: realizedPL,
                currentPrice: investmentLedgerCurrentPrice(for: first.symbol, averageCost: averageCost),
                lots: lots
            )
        }
        .sorted { $0.id < $1.id }
    }

    private func investmentLedgerCurrentPrice(for symbol: String, averageCost: Double) -> Double? {
        guard let quote = investmentLiveQuote(for: symbol),
              quote.close.isFinite,
              quote.close > 0 else { return nil }

        if webullHKCode(for: symbol) != nil {
            if let band = investmentQuoteReferenceBand(for: symbol),
               !quote.close.isWithinInvestmentBand(low: band.low, high: band.high) {
                NJInvestmentQuoteDebugLog("QUOTE_REJECT_LEDGER symbol=\"\(quoteDebugToken(symbol))\" price=\"\(quote.close)\" reason=\"outside_reference_band\"")
                return nil
            }

            if averageCost > 0 {
                let ratio = quote.close / averageCost
                guard ratio >= 0.35 && ratio <= 2.25 else {
                    NJInvestmentQuoteDebugLog("QUOTE_REJECT_LEDGER symbol=\"\(quoteDebugToken(symbol))\" price=\"\(quote.close)\" avg=\"\(averageCost)\" reason=\"outside_cost_guardrail\"")
                    return nil
                }
            }
        }

        return quote.close
    }

    private func investmentLiveQuote(for symbol: String) -> NJInvestmentLiveQuote? {
        let keys = webullCacheKeys(for: symbol)
        for key in keys {
            if let quote = liveQuotes[key] {
                return quote
            }
        }
        let upperKeys = Set(keys.map { $0.uppercased() })
        return liveQuotes.first { key, quote in
            upperKeys.contains(key.uppercased()) || upperKeys.contains(quote.sourceSymbol.uppercased())
        }?.value
    }

    private func investmentThesisSummaries(from positions: [NJInvestmentPositionSummary]) -> [NJInvestmentThesisLedgerSummary] {
        let grouped = Dictionary(grouping: positions) { "\(canonicalInvestmentThesis($0.tradeThesis))|\($0.currency)" }
        return grouped.values.map { rows in
            let first = rows[0]
            let canonicalThesis = canonicalInvestmentThesis(first.tradeThesis)
            return NJInvestmentThesisLedgerSummary(
                id: "\(canonicalThesis)|\(first.currency)",
                tradeThesis: canonicalThesis,
                currency: first.currency,
                openCost: rows.reduce(0) { $0 + $1.grossCost },
                openMarketValue: optionalSum(rows.map(\.marketValue)),
                realizedPL: rows.reduce(0) { $0 + $1.realizedPL },
                unrealizedPL: optionalSum(rows.map(\.unrealizedPL)),
                openSymbols: rows.filter { abs($0.netQuantity) > 0.0001 }.count
            )
        }
        .sorted { $0.id < $1.id }
    }

    private func investmentPortfolioSummaries(from positions: [NJInvestmentPositionSummary]) -> [NJInvestmentPortfolioSummary] {
        Dictionary(grouping: positions) { $0.currency.uppercased() }
            .map { currency, rows in
                NJInvestmentPortfolioSummary(
                    currency: currency,
                    openCost: rows.reduce(0) { $0 + $1.grossCost },
                    marketValue: optionalSum(rows.map(\.marketValue)),
                    realizedPL: rows.reduce(0) { $0 + $1.realizedPL },
                    unrealizedPL: optionalSum(rows.map(\.unrealizedPL))
                )
            }
            .sorted { $0.currency < $1.currency }
    }

    private func investmentPortfolioSummaryStrip(_ summary: NJInvestmentPortfolioSummary) -> some View {
        let netPL = summary.netPL
        let netPLPercent = summary.netPLPercent
        let isLoss = (netPL ?? 0) < 0
        return HStack(spacing: 10) {
            portfolioMetricTile(
                title: "Net Gain / Loss",
                value: investmentOptionalMoney(netPL, currency: summary.currency),
                tone: isLoss ? .red : .green
            )
            portfolioMetricTile(
                title: "Net %",
                value: investmentOptionalPct(netPLPercent),
                tone: isLoss ? .red : .green
            )
            portfolioMetricTile(
                title: "Open Cost",
                value: investmentMoney(summary.openCost, currency: summary.currency),
                tone: .primary
            )
            portfolioMetricTile(
                title: "Market Value",
                value: investmentOptionalMoney(summary.marketValue, currency: summary.currency),
                tone: .primary
            )
        }
    }

    private func portfolioMetricTile(title: String, value: String, tone: Color) -> some View {
        VStack(alignment: .leading, spacing: 4) {
            Text(title)
                .font(.caption2.weight(.semibold))
                .foregroundStyle(.secondary)
            Text(value)
                .font(.headline.weight(.bold))
                .foregroundStyle(tone)
                .lineLimit(1)
                .minimumScaleFactor(0.75)
        }
        .frame(width: 160, height: 62, alignment: .leading)
        .padding(10)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func investmentPayloadDouble(_ value: Any?) -> Double? {
        if let value = value as? Double { return value }
        if let value = value as? Int { return Double(value) }
        if let value = value as? Int64 { return Double(value) }
        if let value = value as? String { return Double(value) }
        return nil
    }

    private func optionalSum(_ values: [Double?]) -> Double? {
        let present = values.compactMap { $0 }
        guard !present.isEmpty else { return nil }
        return present.reduce(0, +)
    }

    private func investmentMoney(_ value: Double, currency: String) -> String {
        let prefix = currency.uppercased() == "USD" ? "USD" : currency.uppercased()
        return "\(prefix) \(String(format: "%.2f", value))"
    }

    private func investmentOptionalMoney(_ value: Double?, currency: String) -> String {
        guard let value else { return "Live pending" }
        return investmentMoney(value, currency: currency)
    }

    private func investmentOptionalPct(_ value: Double?) -> String {
        guard let value else { return "Live pending" }
        return String(format: "%+.2f%%", value)
    }

    private func investmentQuantity(_ value: Double) -> String {
        if value.rounded() == value {
            return String(format: "%.0f", value)
        }
        return String(format: "%.2f", value)
    }

    private func emphasizedPLColumns(_ values: [Double?], baseColumn: Int) -> [Int] {
        values.enumerated().compactMap { index, value in
            guard let value, value < 0 else { return nil }
            return baseColumn + index
        }
    }

