    private var usQ1CrossMarketFatigueRows: [(String, String, String, String, String)] {
        [
            usQ1CrossMarketFatigueRow(id: "QQQ", label: "QQQ / Nasdaq 100", role: "US tech impulse"),
            usQ1CrossMarketFatigueRow(id: "SMH", label: "SMH / Semis", role: "AI hardware impulse"),
            usQ1CrossMarketFatigueRow(id: "tokyo", label: "Nikkei 225", role: "Japan follow-through"),
            usQ1CrossMarketFatigueRow(id: "hkse", label: "Hang Seng", role: "HK risk appetite"),
            usQ1CrossMarketFatigueRow(id: "shanghai-a", label: "Shanghai A", role: "China beta check"),
            usQ1CrossMarketFatigueRow(id: "usdjpy", label: "USD/JPY", role: "Yen stress check")
        ]
    }

    private func usQ1CrossMarketFatigueRow(id: String, label: String, role: String) -> (String, String, String, String, String) {
        let quote = liveQuotes[id]
        let value = quote.map { formattedLiveValue($0.close, lineID: id) } ?? "Awaiting live quote"
        let move = quote?.changeText ?? "Pending"
        let pct = quote.flatMap { numericValue(from: $0.changeText) }
        let qqqPct = liveQuotes["QQQ"].flatMap { numericValue(from: $0.changeText) }
        let smhPct = liveQuotes["SMH"].flatMap { numericValue(from: $0.changeText) }
        let read = usQ1CrossMarketFatigueRead(id: id, pct: pct, qqqPct: qqqPct, smhPct: smhPct)
        let implication = usQ1CrossMarketShortImplication(id: id, pct: pct, qqqPct: qqqPct, smhPct: smhPct)
        return ("\(label)\n\(role)", value, move, read, implication)
    }

    private func usQ1CrossMarketFatigueRead(id: String, pct: Double?, qqqPct: Double?, smhPct: Double?) -> String {
        guard let pct else { return "Waiting for live refresh; do not infer from stale marks." }
        switch id {
        case "QQQ":
            return pct > 0 ? "US tech is still trying to lift; the test is whether it fades into or after the close." : "US tech impulse is already failing despite upbeat earnings."
        case "SMH":
            return pct > 0 ? "AI hardware still confirms risk-on; wait for AMD T+1/T+2 before pressing." : "Semi beta is not confirming the AI earnings bid."
        case "tokyo", "hkse", "shanghai-a":
            if let qqqPct, qqqPct > 0, pct <= 0 {
                return "No Asia follow-through while US tech is green. This supports market fatigue."
            }
            if pct > 0 {
                return "Asia is confirming risk appetite; short needs stronger US fade evidence."
            }
            return "Asia is weak, but QQQ confirmation still matters."
        case "usdjpy":
            return pct > 0 ? "Yen weakness can support Japan mechanically, so Nikkei failure becomes more bearish." : "Yen relief is not enough alone; watch Nikkei/HK equity response."
        default:
            return "Context input."
        }
    }

    private func usQ1CrossMarketShortImplication(id: String, pct: Double?, qqqPct: Double?, smhPct: Double?) -> String {
        guard let pct else { return "Refresh first" }
        switch id {
        case "QQQ":
            return pct > 0 ? "Short only on pop/fade, not green strength alone" : "Supports starter / hold"
        case "SMH":
            return pct > 0 ? "Do not add semis yet" : "Supports AI exhaustion add"
        case "tokyo", "hkse", "shanghai-a":
            return (qqqPct ?? 0) > 0 && pct <= 0 ? "Raises QQQ short confidence" : "Wait for more confirmation"
        case "usdjpy":
            return "Use as Japan fatigue context"
        default:
            return "Context"
        }
    }

    private func usQ1FatigueRowIsConfirming(_ label: String) -> Bool {
        let lowered = label.lowercased()
        let id: String
        if lowered.contains("qqq") { id = "QQQ" }
        else if lowered.contains("smh") { id = "SMH" }
        else if lowered.contains("nikkei") { id = "tokyo" }
        else if lowered.contains("hang seng") { id = "hkse" }
        else if lowered.contains("shanghai") { id = "shanghai-a" }
        else { return false }

        guard let pct = liveQuotes[id].flatMap({ numericValue(from: $0.changeText) }) else { return false }
        if id == "QQQ" || id == "SMH" { return pct < 0 }
        let qqqPct = liveQuotes["QQQ"].flatMap { numericValue(from: $0.changeText) } ?? 0
        return qqqPct > 0 && pct <= 0
    }

