        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func usQ1NewsThesisRead(for item: NJObservationNewsItem) -> String {
        let text = item.title.lowercased()
        if text.contains("fade") || text.contains("selloff") || text.contains("sells off") || text.contains("slump") || text.contains("drops") || text.contains("falls") || text.contains("weak") {
            return "Thesis read: supports exhaustion if the weakness follows good earnings/news."
        }
        if text.contains("beat") || text.contains("earnings") || text.contains("guidance") || text.contains("results") || text.contains("capex") || text.contains("ai spending") {
            return "Thesis read: key article. Check whether good AI/earnings news is being sold into the close."
        }
        if text.contains("rally") || text.contains("surge") || text.contains("jumps") || text.contains("record") || text.contains("all-time high") || text.contains("high") {
            return "Thesis read: not bearish by itself. Watch if this strength fades by T+1/T+2."
        }
        return "Thesis read: context only. Use it if it explains QQQ, AI capex, buybacks, or positioning."
    }

    private func usQ1NewsReadColor(for item: NJObservationNewsItem) -> Color {
        let text = item.title.lowercased()
        if text.contains("fade") || text.contains("selloff") || text.contains("slump") || text.contains("drops") || text.contains("falls") || text.contains("weak") {
            return .red
        }
        if text.contains("beat") || text.contains("earnings") || text.contains("guidance") || text.contains("capex") || text.contains("ai spending") {
            return .orange
        }
        return .secondary
    }

    private func usQ1ThemeBlock(title: String, icon: String, isExpanded: Binding<Bool>, rows: [[String]]) -> some View {
        DisclosureGroup(isExpanded: isExpanded) {
            ScrollView(.horizontal, showsIndicators: true) {
                VStack(alignment: .leading, spacing: 8) {
                    tradeTableHeader(["Ticker", "Company", "Result Date", "Result", "T+1", "T+2", "T+3", "Current", "Fade Read"], widths: [0.7, 1.5, 1.0, 1.15, 0.75, 0.75, 0.75, 0.85, 1.45])
                    ForEach(Array(rows.enumerated()), id: \.offset) { _, row in
                        if let watchRow = watchRowFromThemeRow(row, themeTitle: title) {
                            let displayValues = usQ1ThemeDisplayValues(for: row)
                            tradeWatchButtonRow(
                                watchRow,
                                values: displayValues,
                                widths: [0.7, 1.5, 1.0, 1.15, 0.75, 0.75, 0.75, 0.85, 1.45],
                                emphasizedDownColumns: usQ1ThemeDownColumns(for: row)
                            )
                        } else {
                            tradeTableRow(row, widths: [0.7, 1.5, 1.0, 1.15, 0.75, 0.75, 0.75, 0.85, 1.45])
                        }
                    }
                }
                .frame(minWidth: 990, alignment: .leading)
            }
            .padding(.top, 8)
        } label: {
            HStack(spacing: 8) {
                Label(title, systemImage: icon)
                    .font(.headline.weight(.semibold))
                Text("\(rows.count)")
                    .font(.caption2.weight(.bold))
                    .foregroundStyle(.secondary)
                    .padding(.horizontal, 7)
                    .padding(.vertical, 3)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 6))
            }
        }
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func usQ1ThemeDisplayValues(for row: [String]) -> [String] {
        guard row.count >= 9 else { return row }
        let symbol = row[0]
        guard let quote = liveQuotes[symbol] else { return row }
        var values = row
        values[7] = "\(formattedWatchPrice(quote.close, symbol: symbol))\n\(quote.changeText)"
        return values
    }

    private func usQ1ThemeDownColumns(for row: [String]) -> [Int] {
        guard let symbol = row.first else { return [] }
        if let quote = liveQuotes[symbol] {
            return quote.isDown ? [7] : []
        }
        guard row.indices.contains(7),
              let pct = numericValue(from: row[7]) else { return [] }
        return pct < 0 ? [7] : []
    }

    private func watchRowFromThemeRow(_ row: [String], themeTitle: String) -> NJInvestmentWatchRow? {
        guard row.count >= 9 else { return nil }
        let symbol = row[0]
        guard !symbol.isEmpty else { return nil }
        return NJInvestmentWatchRow(
            id: "usq1-theme-\(normalizedResearchSymbol(symbol))-\(normalizedResearchSymbol(themeTitle))",
            symbol: symbol,
            name: row[1],
            monitorDate: "2026-04-29",
            resultDate: row[2],
            usCloseReference: row[3],
            tPlusOne: row[4],
            tPlusTwo: row[5],
            tPlusThree: row[6],
            initialPrice: row[3],
            week52High: "Theme ref",
            week52Low: "Theme ref",
            todayPrice: row[7],
            percentChange: row[8]
        )
    }

