    private var foodScareWorkspace: some View {
        VStack(alignment: .leading, spacing: 14) {
            VStack(alignment: .leading, spacing: 8) {
                HStack {
                    VStack(alignment: .leading, spacing: 4) {
                        Text("2026 Food Scare")
                            .font(.title2.weight(.bold))
                        Text("Food inflation and fertilizer stress, not a one-headline grain chase.")
                            .font(.subheadline)
                            .foregroundStyle(.secondary)
                    }
                    Spacer()
                    Label("Research / Wait For Confirmation", systemImage: "hourglass")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(.orange)
                        .padding(.horizontal, 10)
                        .padding(.vertical, 6)
                        .background(Color.orange.opacity(0.12))
                        .clipShape(RoundedRectangle(cornerRadius: 8))
                }
                Text("Core thesis: US withdrawal keeps Ukraine/Russia as a long-duration background war while Iran/Hormuz raises energy and fertilizer pressure. The investable edge is the lag from energy/fertilizer stress into crop economics, grain pricing, food inflation, and policy stress. Do not buy just because the story sounds scary; buy only when fertilizer plus grain or food-inflation evidence confirms.")
                    .font(.subheadline)
                    .fixedSize(horizontal: false, vertical: true)
            }
            .padding(14)
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color(UIColor.systemBackground))
