    private func tradeCollapsibleBlock<Content: View>(
        title: String,
        icon: String,
        focusCount: (count: Int, total: Int)? = nil,
        isExpanded: Binding<Bool>,
        @ViewBuilder content: @escaping () -> Content
    ) -> some View {
        DisclosureGroup(isExpanded: isExpanded) {
            ScrollView(.horizontal, showsIndicators: true) {
                content()
                    .frame(minWidth: 840, alignment: .leading)
            }
            .padding(.top, 8)
        } label: {
            HStack(spacing: 8) {
                Label(title, systemImage: icon)
                    .font(.headline.weight(.semibold))
                Label("Pinned", systemImage: "pin.fill")
                    .font(.caption2.weight(.bold))
                    .foregroundStyle(.secondary)
                    .padding(.horizontal, 7)
                    .padding(.vertical, 3)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 6))
                if let focusCount {
                    Label("Focus \(focusCount.count)/\(focusCount.total)", systemImage: focusCount.count > 0 ? "largecircle.fill.circle" : "circle")
                        .font(.caption2.weight(.bold))
                        .foregroundStyle(focusCount.count > 0 ? Color.orange : Color.secondary)
                        .padding(.horizontal, 7)
                        .padding(.vertical, 3)
                        .background((focusCount.count > 0 ? Color.orange : Color(UIColor.secondarySystemGroupedBackground)).opacity(focusCount.count > 0 ? 0.14 : 1))
                        .clipShape(RoundedRectangle(cornerRadius: 6))
                }
            }
        }
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func tradeConversationPlaceholder(role: String, kind: String, title: String, body: String) -> some View {
        VStack(alignment: .leading, spacing: 7) {
            HStack {
                Text(role)
                    .font(.caption.weight(.bold))
                    .padding(.horizontal, 8)
                    .padding(.vertical, 4)
                    .background(Color.accentColor.opacity(0.14))
                    .foregroundStyle(Color.accentColor)
                    .clipShape(RoundedRectangle(cornerRadius: 6))
                Text(kind)
                    .font(.caption.weight(.bold))
                    .padding(.horizontal, 8)
                    .padding(.vertical, 4)
                    .background(Color(UIColor.tertiarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 6))
                Spacer()
                Text("Newest first")
                    .font(.caption2.weight(.semibold))
                    .foregroundStyle(.secondary)
            }
            Text(title)
                .font(.subheadline.weight(.semibold))
            Text(body)
                .font(.caption)
                .foregroundStyle(.secondary)
        }
        .padding(12)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func tradeSubsectionTitle(_ title: String) -> some View {
        Text(title)
            .font(.subheadline.weight(.bold))
            .padding(.top, 4)
    }

    private func watchListTable(rows: [NJInvestmentWatchRow]) -> some View {
        let columns = visibleWatchColumns
        return VStack(alignment: .leading, spacing: 8) {
            HStack {
                Button {
                    withAnimation(.snappy) {
                        watchColumnEditorExpanded.toggle()
                    }
                } label: {
                    Label(watchColumnEditorExpanded ? "Hide Column Tools" : "Columns", systemImage: "slider.horizontal.3")
                        .font(.caption.weight(.semibold))
                }
                .buttonStyle(.bordered)

                Spacer()

                Button("Reset Local Layout") {
                    watchHiddenColumnsStorage = ""
                    watchColumnWidthsStorage = ""
                }
                .font(.caption.weight(.semibold))
                .buttonStyle(.bordered)
            }

            if watchColumnEditorExpanded {
                watchColumnEditor
            }

            ScrollView(.horizontal, showsIndicators: true) {
                VStack(alignment: .leading, spacing: 8) {
                    tradeTableHeader(columns.map(\.title), widths: columns.map { watchColumnWeight($0.id) })
                    ForEach(rows) { row in
                        Button {
                            openWatchResearchPopup(for: row)
                        } label: {
                            tradeTableRow(
                                columns.map { watchValue(for: row, columnID: $0.id) },
                                widths: columns.map { watchColumnWeight($0.id) },
                                emphasizedDownColumns: columns.enumerated().compactMap { index, column in
                                    watchValueIsDown(for: row, columnID: column.id) ? index : nil
                                }
                            )
                            .contentShape(Rectangle())
                        }
                        .buttonStyle(.plain)
                    }
                }
                .frame(minWidth: max(watchTableWidth(for: columns), 320), alignment: .leading)
            }
        }
    }

    private var watchColumnEditor: some View {
        VStack(alignment: .leading, spacing: 10) {
            ForEach(watchColumns) { column in
                VStack(alignment: .leading, spacing: 6) {
                    Toggle(isOn: watchColumnVisibleBinding(column.id)) {
                        Text(column.title)
                            .font(.caption.weight(.semibold))
                    }
                    .toggleStyle(.switch)

                    if !hiddenWatchColumnIDs.contains(column.id) {
                        HStack(spacing: 8) {
                            Text("Width")
                                .font(.caption2.weight(.semibold))
                                .foregroundStyle(.secondary)
                            Slider(value: watchColumnWidthBinding(column.id), in: 0.55...1.9, step: 0.05)
                            Text(String(format: "%.2fx", watchColumnWeight(column.id)))
                                .font(.caption2.monospacedDigit())
                                .foregroundStyle(.secondary)
                                .frame(width: 44, alignment: .trailing)
                        }
                    }
                }
                .padding(10)
                .background(Color(UIColor.tertiarySystemGroupedBackground))
                .clipShape(RoundedRectangle(cornerRadius: 8))
            }
        }
        .padding(10)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private var visibleWatchColumns: [NJInvestmentWatchColumn] {
        let hidden = hiddenWatchColumnIDs
        let visible = watchColumns.filter { !hidden.contains($0.id) }
        return visible.isEmpty ? watchColumns.prefix(1).map { $0 } : visible
    }

    private var hiddenWatchColumnIDs: Set<String> {
        Set(watchHiddenColumnsStorage.split(separator: ",").map(String.init))
    }

    private var watchColumnWidths: [String: CGFloat] {
        Dictionary(uniqueKeysWithValues: watchColumnWidthsStorage
            .split(separator: ";")
            .compactMap { item -> (String, CGFloat)? in
                let parts = item.split(separator: "=", maxSplits: 1).map(String.init)
                guard parts.count == 2, let value = Double(parts[1]) else { return nil }
                return (parts[0], CGFloat(value))
            })
    }

    private func watchColumnWeight(_ id: String) -> CGFloat {
        if let local = watchColumnWidths[id] {
            return min(max(local, 0.55), 1.9)
        }
        return watchColumns.first(where: { $0.id == id })?.defaultWeight ?? 1
    }

    private func watchColumnVisibleBinding(_ id: String) -> Binding<Bool> {
        Binding(
            get: { !hiddenWatchColumnIDs.contains(id) },
            set: { isVisible in
                var hidden = hiddenWatchColumnIDs
                if isVisible {
                    hidden.remove(id)
                } else if hidden.count < watchColumns.count - 1 {
                    hidden.insert(id)
                }
                watchHiddenColumnsStorage = hidden.sorted().joined(separator: ",")
            }
        )
    }

    private func watchColumnWidthBinding(_ id: String) -> Binding<Double> {
        Binding(
            get: { Double(watchColumnWeight(id)) },
            set: { value in
                var widths = watchColumnWidths
                widths[id] = CGFloat(value)
                watchColumnWidthsStorage = widths
                    .sorted { $0.key < $1.key }
                    .map { "\($0.key)=\(String(format: "%.2f", Double($0.value)))" }
                    .joined(separator: ";")
            }
        )
    }

    private func watchValue(for row: NJInvestmentWatchRow, columnID: String) -> String {
        let liveQuote = liveQuotes[row.symbol]
        let useStaticEventReaction = watchRowLocksEventReaction(row)
        let livePrice = useStaticEventReaction ? numericValue(from: row.todayPrice) : liveQuote?.close
        let liveTodayPrice = livePrice.map { formattedWatchPrice($0, symbol: row.symbol) } ?? "No Webull quote"
        let live52High = useStaticEventReaction ? nil : liveQuote?.fiftyTwoWeekHigh.map { formattedWatchPrice($0, symbol: row.symbol) }
        let live52Low = useStaticEventReaction ? nil : liveQuote?.fiftyTwoWeekLow.map { formattedWatchPrice($0, symbol: row.symbol) }
        switch columnID {
        case "symbol": return row.symbol
        case "name": return row.name
        case "usCloseReference": return row.usCloseReference
        case "monitorDate": return row.monitorDate
        case "resultDate": return row.resultDate
        case "tPlusOne": return row.tPlusOne
        case "tPlusTwo": return row.tPlusTwo
        case "tPlusThree": return row.tPlusThree
        case "initialPrice": return row.initialPrice
        case "week52High": return live52High ?? row.week52High
        case "week52Low": return live52Low ?? row.week52Low
        case "todayPrice": return useStaticEventReaction ? row.todayPrice : liveTodayPrice
        case "vwap": return row.vwap
        case "dayChange": return useStaticEventReaction ? row.percentChange : (liveQuotes[row.symbol]?.changeText ?? "No Webull quote")
        case "fromInitial": return percentDistance(from: livePrice, to: row.initialPrice) ?? row.percentFromInitialPrice
        case "fromHigh": return percentDistance(from: livePrice, to: live52High ?? row.week52High) ?? row.percentFrom52WeekHigh
        case "fromLow": return percentDistance(from: livePrice, to: live52Low ?? row.week52Low) ?? row.percentFrom52WeekLow
        default: return ""
        }
    }

    private func watchRowLocksEventReaction(_ row: NJInvestmentWatchRow) -> Bool {
        let text = "\(row.monitorDate) \(row.percentChange) \(row.tPlusOne) \(row.tPlusTwo) \(row.tPlusThree)".lowercased()
        return text.contains("event reaction") || text.contains("intraday") || text.contains("pre-result close") || text.contains("t+1")
    }

    private func watchValueContainsNegativeMove(_ value: String) -> Bool {
        let normalized = value.replacingOccurrences(of: "−", with: "-")
        return normalized.trimmingCharacters(in: .whitespacesAndNewlines).hasPrefix("-")
            || normalized.contains(" -")
            || normalized.contains("\n-")
    }

    private func watchValueIsDown(for row: NJInvestmentWatchRow, columnID: String) -> Bool {
        switch columnID {
        case "tPlusOne", "tPlusTwo", "tPlusThree", "dayChange", "fromInitial", "fromHigh", "fromLow":
            return watchValueContainsNegativeMove(watchValue(for: row, columnID: columnID))
        default:
            return false
        }
    }

    private func bankPEText(for row: NJInvestmentWatchRow) -> String {
        bankFundamentals[row.symbol]?.pe ?? manualBankFundamentals[row.symbol]?.pe ?? "Loading"
    }

    private func bankDividendYieldText(for row: NJInvestmentWatchRow) -> String {
        if let metric = bankFundamentals[row.symbol] {
            return metric.dividendYield
        }
        return manualBankFundamentals[row.symbol]?.dividendYield ?? "Loading"
    }

    private func highYieldPEText(for row: NJInvestmentWatchRow) -> String {
        bankFundamentals[row.symbol]?.pe ?? manualBankFundamentals[row.symbol]?.pe ?? "Loading"
    }

    private func highYieldDividendText(for row: NJInvestmentWatchRow) -> String {
        bankFundamentals[row.symbol]?.dividendYield ?? manualBankFundamentals[row.symbol]?.dividendYield ?? "Loading"
    }

    private func mfsDividendText(for row: NJInvestmentWatchRow) -> String {
        if let metric = bankFundamentals[row.symbol] {
            return "\(metric.annualDividend) / \(metric.dividendYield)"
        }
        if let metric = manualBankFundamentals[row.symbol] {
            return "\(metric.annualDividend) / \(metric.dividendYield)"
        }
        return row.tPlusOne
    }

    private enum MFSBlockKind {
        case cashParking
        case beatenDownQuality
        case usKeyName
        case aShare
    }

    private func mfsFocusCount(in rows: [NJInvestmentWatchRow], kind: MFSBlockKind) -> (count: Int, total: Int) {
        (rows.filter { mfsShouldFocus($0, kind: kind) }.count, rows.count)
    }

    private func updateMFSFocusBadge() {
        let count =
            mfsFocusCount(in: mfsCashParkingRows, kind: .cashParking).count +
            mfsFocusCount(in: mfsBeatenDownQualityRows, kind: .beatenDownQuality).count +
            mfsFocusCount(in: mfsUSKeyNameRows, kind: .usKeyName).count +
            mfsFocusCount(in: mfsAShareRows, kind: .aShare).count
        if store.investmentMFSFocusCount != count {
            store.investmentMFSFocusCount = count
        }
    }

    private func mfsStatusText(for row: NJInvestmentWatchRow, kind: MFSBlockKind) -> String {
        guard mfsHasPriceRange(row) else { return "Refresh" }
        if mfsShouldFocus(row, kind: kind) { return "FOCUS" }
        if mfsIsNearFocus(row, kind: kind) { return "Watch" }
        return "No alert"
    }

    private func mfsShouldFocus(_ row: NJInvestmentWatchRow, kind: MFSBlockKind) -> Bool {
        guard let distances = mfsPriceDistances(for: row) else { return false }
        switch kind {
        case .cashParking:
            guard let yield = mfsDividendYield(for: row), yield >= 5.5 else { return false }
            return distances.fromHigh <= -10 && distances.fromLow <= 20
        case .beatenDownQuality:
            return distances.fromHigh <= -30 && distances.fromLow <= 20
        case .usKeyName:
            return distances.fromHigh <= -25 && distances.fromLow <= 18
        case .aShare:
            return distances.fromHigh <= -25 && distances.fromLow <= 20
        }
    }

    private func mfsIsNearFocus(_ row: NJInvestmentWatchRow, kind: MFSBlockKind) -> Bool {
        guard let distances = mfsPriceDistances(for: row) else { return false }
        switch kind {
        case .cashParking:
            guard let yield = mfsDividendYield(for: row), yield >= 5.0 else { return false }
            return distances.fromHigh <= -8 && distances.fromLow <= 30
        case .beatenDownQuality, .aShare:
            return distances.fromHigh <= -20 && distances.fromLow <= 35
        case .usKeyName:
            return distances.fromHigh <= -18 && distances.fromLow <= 30
        }
    }

    private func mfsHasPriceRange(_ row: NJInvestmentWatchRow) -> Bool {
        mfsPriceDistances(for: row) != nil
    }

    private func mfsPriceDistances(for row: NJInvestmentWatchRow) -> (fromHigh: Double, fromLow: Double)? {
        let quote = liveQuotes[row.symbol]
        guard let price = quote?.close ?? numericValue(from: row.todayPrice),
              let high = quote?.fiftyTwoWeekHigh ?? numericValue(from: row.week52High),
              let low = quote?.fiftyTwoWeekLow ?? numericValue(from: row.week52Low),
              high > 0,
              low > 0 else { return nil }
        return ((price / high - 1) * 100, (price / low - 1) * 100)
    }

    private func mfsDividendYield(for row: NJInvestmentWatchRow) -> Double? {
        if let text = bankFundamentals[row.symbol]?.dividendYield ?? manualBankFundamentals[row.symbol]?.dividendYield {
            return numericValue(from: text)
        }
        return nil
    }

    private var manualBankFundamentals: [String: NJInvestmentFundamentalMetric] {
        [
            "0005 HK": NJInvestmentFundamentalMetric(id: "0005 HK", sourceSymbol: "0005", pe: "~9.8x", annualDividend: "50% EPS payout target", dividendYield: "~4.7%", source: "Manual fallback"),
            "2888 HK": NJInvestmentFundamentalMetric(id: "2888 HK", sourceSymbol: "2888", pe: "~8.8x", annualDividend: "Final + ordinary payout", dividendYield: "~4.1%", source: "Manual fallback")
        ]
    }

    private func formattedWatchPrice(_ value: Double, symbol: String) -> String {
        if symbol == "USD/JPY" || symbol == "USD/CNH" {
            return String(format: "%.4f", value)
        }
        if symbol.hasSuffix("HK") {
            return String(format: "HK$%.2f", value)
        }
        if symbol.hasSuffix("CN") {
            return String(format: "CNY %.2f", value)
        }
        if symbol.hasSuffix("JP") {
            return String(format: "JPY %.0f", value)
        }
        if symbol.hasSuffix("FP") || symbol.hasSuffix("GR") {
            return String(format: "EUR %.2f", value)
        }
        return String(format: "$%.2f", value)
    }

    private func japanBlueChipCurrentPriceText(for row: NJJapanBlueChipResultRow) -> String {
        guard let quote = liveQuotes[row.symbol] else { return row.currentPrice }
        let formatter = NumberFormatter()
        formatter.numberStyle = .decimal
        formatter.maximumFractionDigits = 0
        formatter.minimumFractionDigits = 0
        let numberText = formatter.string(from: NSNumber(value: quote.close.rounded())) ?? String(format: "%.0f", quote.close)
        return "JPY\(numberText)"
    }

    private func percentDistance(from livePrice: Double?, to anchorText: String) -> String? {
        guard let livePrice,
              let anchor = numericValue(from: anchorText),
              anchor != 0 else { return nil }
        let pct = (livePrice / anchor - 1) * 100
        return String(format: "%+.1f%%", pct)
    }

    private func floatingWatchResearchPopup(_ row: NJInvestmentWatchRow, containerSize: CGSize) -> some View {
        let popupSize = clampedWatchPopupSize(watchPopupSize, containerSize: containerSize)
        let resolvedCenter = clampedWatchPopupCenter(
            watchPopupCenter ?? defaultWatchPopupCenter(containerSize: containerSize, popupSize: popupSize),
            popupSize: popupSize,
            containerSize: containerSize
        )

        return VStack(spacing: 0) {
            floatingWatchPopupHeader(row, center: resolvedCenter, popupSize: popupSize, containerSize: containerSize)

            ScrollView {
                watchResearchPanel(row)
                    .padding(16)
            }
            .background(Color(UIColor.systemGroupedBackground))
        }
        .frame(width: popupSize.width, height: popupSize.height)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 12))
        .overlay(
            RoundedRectangle(cornerRadius: 12)
                .stroke(Color.secondary.opacity(0.18), lineWidth: 1)
        )
        .shadow(color: Color.black.opacity(0.22), radius: 24, x: 0, y: 12)
        .overlay(alignment: .bottomTrailing) {
            floatingWatchPopupResizeHandle(popupSize: popupSize, center: resolvedCenter, containerSize: containerSize)
        }
        .position(resolvedCenter)
        .zIndex(20)
    }

    private func floatingWatchPopupHeader(
        _ row: NJInvestmentWatchRow,
        center: CGPoint,
        popupSize: CGSize,
        containerSize: CGSize
    ) -> some View {
        HStack(spacing: 10) {
            Image(systemName: "arrow.up.left.and.arrow.down.right")
                .font(.caption.weight(.bold))
                .foregroundStyle(.secondary)
            VStack(alignment: .leading, spacing: 2) {
                Text("IRC")
                    .font(.headline.weight(.semibold))
                Text("\(row.symbol) - \(row.name). Drag header to move. Pull corner to resize.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            Spacer()
            Button {
                let resetSize = CGSize(width: 720, height: 740)
                watchPopupSize = resetSize
                watchPopupCenter = defaultWatchPopupCenter(containerSize: containerSize, popupSize: resetSize)
            } label: {
                Image(systemName: "arrow.counterclockwise")
            }
            .buttonStyle(.bordered)

            Button {
                selectedWatchRow = nil
                watchPopupCenter = nil
            } label: {
                Image(systemName: "xmark")
            }
            .buttonStyle(.borderedProminent)
        }
        .padding(.horizontal, 14)
        .padding(.vertical, 10)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .contentShape(Rectangle())
        .gesture(
            DragGesture()
                .onChanged { value in
                    if watchPopupDragStartCenter == nil {
                        watchPopupDragStartCenter = center
                    }
                    let start = watchPopupDragStartCenter ?? center
                    let proposed = CGPoint(
                        x: start.x + value.translation.width,
                        y: start.y + value.translation.height
                    )
                    watchPopupCenter = clampedWatchPopupCenter(
                        proposed,
                        popupSize: popupSize,
                        containerSize: containerSize
                    )
                }
                .onEnded { _ in
                    watchPopupDragStartCenter = nil
                }
        )
    }

    private func floatingWatchPopupResizeHandle(
        popupSize: CGSize,
        center: CGPoint,
        containerSize: CGSize
    ) -> some View {
        ZStack {
            RoundedRectangle(cornerRadius: 6)
                .fill(Color(UIColor.tertiarySystemGroupedBackground))
            Image(systemName: "arrow.down.right.and.arrow.up.left")
                .font(.caption.weight(.bold))
                .foregroundStyle(.secondary)
        }
        .frame(width: 34, height: 34)
        .padding(8)
        .contentShape(Rectangle())
        .gesture(
            DragGesture()
                .onChanged { value in
                    if watchPopupResizeStartSize == nil {
                        watchPopupResizeStartSize = popupSize
                    }
                    let start = watchPopupResizeStartSize ?? popupSize
                    let proposed = CGSize(
                        width: start.width + value.translation.width,
                        height: start.height + value.translation.height
                    )
                    let resized = clampedWatchPopupSize(proposed, containerSize: containerSize)
                    watchPopupSize = resized
                    watchPopupCenter = clampedWatchPopupCenter(
                        center,
                        popupSize: resized,
                        containerSize: containerSize
                    )
                }
                .onEnded { _ in
                    watchPopupResizeStartSize = nil
                }
        )
    }

    private func defaultWatchPopupCenter(containerSize: CGSize, popupSize: CGSize) -> CGPoint {
        CGPoint(
            x: max(popupSize.width / 2 + 12, containerSize.width / 2),
            y: max(popupSize.height / 2 + 12, containerSize.height / 2)
        )
    }

    private func clampedWatchPopupSize(_ size: CGSize, containerSize: CGSize) -> CGSize {
        let maxWidth = max(320, containerSize.width - 24)
        let maxHeight = max(360, containerSize.height - 24)
        let minWidth = min(420, maxWidth)
        let minHeight = min(440, maxHeight)
        return CGSize(
            width: min(max(size.width, minWidth), maxWidth),
            height: min(max(size.height, minHeight), maxHeight)
        )
    }

    private func clampedWatchPopupCenter(_ center: CGPoint, popupSize: CGSize, containerSize: CGSize) -> CGPoint {
        let margin: CGFloat = 12
        let halfWidth = popupSize.width / 2
        let halfHeight = popupSize.height / 2
        let minX = halfWidth + margin
        let maxX = max(minX, containerSize.width - halfWidth - margin)
        let minY = halfHeight + margin
        let maxY = max(minY, containerSize.height - halfHeight - margin)
        return CGPoint(
            x: min(max(center.x, minX), maxX),
            y: min(max(center.y, minY), maxY)
        )
    }

    private func watchResearchPanel(_ row: NJInvestmentWatchRow) -> some View {
