                if isCompactLayout {
                    VStack(alignment: .leading, spacing: 8) {
                        watchResearchHeaderMain(row: row, currentPrice: currentPrice, fromInitial: fromInitial)
                        watchResearchDayChange(dayChange)
                    }
                } else {
                    HStack(alignment: .top) {
                        watchResearchHeaderMain(row: row, currentPrice: currentPrice, fromInitial: fromInitial)
                        Spacer()
                        watchResearchDayChange(dayChange)
                    }
                }
            }
            .padding(14)
            .background(Color(UIColor.systemBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))

            watchPopupTabPicker
