    private func watchResearchCurrentPriceText(for row: NJInvestmentWatchRow) -> String {
        guard let livePrice = watchResearchCurrentPriceValue(for: row) else {
            return "Awaiting Webull quote"
        }
        return formattedWatchPrice(livePrice, symbol: row.symbol)
    }

    private func watchResearchFromInitialText(for row: NJInvestmentWatchRow) -> String {
        percentDistance(from: watchResearchCurrentPriceValue(for: row), to: row.initialPrice) ?? "Awaiting live quote"
    }

    private func watchResearchDayChangeText(for row: NJInvestmentWatchRow) -> String {
        if let quote = liveQuotes[row.symbol],
           let previousClose = quote.previousClose,
           previousClose != 0 {
            let pct = (quote.close / previousClose - 1) * 100
            return String(format: "%+.2f%%", pct)
        }
        if let latest = latestWatchChartPoint(for: row) {
            return latest.change
        }
        return "Awaiting live quote"
    }

    private func watchResearchCurrentPriceValue(for row: NJInvestmentWatchRow) -> Double? {
        if let quote = liveQuotes[row.symbol], quote.isWebullSource {
            return quote.close
        }
        if let latest = latestWatchChartPoint(for: row) {
            return latest.close ?? latest.value
        }
        return nil
    }

    private func latestWatchChartPoint(for row: NJInvestmentWatchRow) -> NJInvestmentChartPoint? {
        let selectedKey = watchChartKey(for: row, interval: selectedWatchChartInterval, range: selectedWatchChartRange)
        if let point = watchChartPoints[selectedKey]?.max(by: { $0.date < $1.date }) {
            return point
        }

        let fallbackKeys = [
            watchChartKey(for: row, interval: .daily, range: selectedWatchChartRange),
            watchChartKey(for: row, interval: .hourly, range: selectedWatchChartRange),
            watchChartKey(for: row, interval: .fifteenMinutes, range: selectedWatchChartRange),
            watchChartKey(for: row, interval: .fiveMinutes, range: selectedWatchChartRange)
        ]
        for key in fallbackKeys {
            if let point = watchChartPoints[key]?.max(by: { $0.date < $1.date }) {
                return point
            }
        }
        return nil
    }

