                    companyMetric("Open", liveQuotes[row.symbol]?.open.map { formattedWatchPrice($0, symbol: row.symbol) } ?? "n/a")
                    companyMetric("Volume", liveQuotes[row.symbol]?.volume.map(compactVolumeText) ?? "n/a")
                    companyMetric("52W High", profile?.fiftyTwoWeekHigh.map { formattedWatchPrice($0, symbol: row.symbol) } ?? row.week52High)
                    companyMetric("52W Low", profile?.fiftyTwoWeekLow.map { formattedWatchPrice($0, symbol: row.symbol) } ?? row.week52Low)
                    companyMetric("Market Cap", profile?.marketCap.map(compactVolumeText) ?? "n/a")
                    companyMetric("Trailing P/E", profile?.trailingPE.map { String(format: "%.1f", $0) } ?? "n/a")
                    companyMetric("Forward P/E", profile?.forwardPE.map { String(format: "%.1f", $0) } ?? "n/a")
                    companyMetric("Beta", profile?.beta.map { String(format: "%.2f", $0) } ?? "n/a")
                    companyMetric("Avg Volume", profile?.averageVolume.map(compactVolumeText) ?? "n/a")
                    companyMetric("Revenue Growth", profile?.revenueGrowth.map { String(format: "%+.1f%%", $0 * 100) } ?? "n/a")
                    companyMetric("Profit Margin", profile?.profitMargins.map { String(format: "%.1f%%", $0 * 100) } ?? "n/a")
                }

                markdownText("""
                **Snapshot read:** this is the instrument identity and valuation scratchpad. Webull OpenAPI fills HK quote fields from the local snapshot cache; Yahoo remains the metadata fallback when company fundamentals are missing.

                **Data plan:** refresh snapshots every 15 minutes during HK trading hours, then use the same Webull quote inside IRC, watch rows, trade thesis, and alert checks.
                """)

                Text(selectedWatchDataProvider.statusText)
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
                    .fixedSize(horizontal: false, vertical: true)

                if notesCount > 0 {
                    Text("\(notesCount) finance note block\(notesCount == 1 ? "" : "s") linked to \(watchJournalTags(for: row).joined(separator: ", ")).")
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(.secondary)
                }

                Button {
                    Task { await refreshWatchCompanyProfile(for: row, force: true) }
                    loadWatchSymbolNotes(for: row, force: true)
                } label: {
                    Label("Refresh Company Data", systemImage: "arrow.clockwise")
                        .font(.caption.weight(.semibold))
                }
                .buttonStyle(.bordered)
            }
            .task(id: "\(key).company.\(selectedWatchDataProvider.rawValue)") {
                await refreshWatchCompanyProfile(for: row)
                loadWatchSymbolNotes(for: row)
            }
        }
    }

