                                            .foregroundStyle(.secondary)
                                    }
                                    Text(item.whatHappened.isEmpty ? item.titleLine : item.whatHappened)
                                        .font(.subheadline.weight(item.isCritical ? .bold : .semibold))
                                        .foregroundStyle(item.isCritical ? .red : .primary)
                                        .fixedSize(horizontal: false, vertical: true)
                                    Text([item.source, item.symbols.joined(separator: ", ")].filter { !$0.isEmpty }.joined(separator: " - "))
                                        .font(.caption)
                                        .foregroundStyle(.secondary)
                                }
                                .padding(12)
                                .frame(maxWidth: .infinity, alignment: .leading)
                                .background(item.isCritical ? Color.red.opacity(0.10) : Color(UIColor.secondarySystemGroupedBackground))
