    private func localAnalysisInboxItems(for row: NJInvestmentWatchRow) -> [NJInvestmentAnalysisInboxItem] {
        let symbol = row.symbol.uppercased()
        let canonical = watchCanonicalTagToken(for: row.symbol).uppercased()
        let compactSymbol = symbol.replacingOccurrences(of: " ", with: "")
        let name = row.name.lowercased()

        return analysisInboxItems
            .filter { item in
                if item.isCritical { return true }
                let symbolText = item.symbols.joined(separator: " ").uppercased()
                if symbolText.contains(symbol) || symbolText.contains(canonical) || symbolText.contains(compactSymbol) {
                    return true
                }
                let haystack = [
                    item.tradeThesis,
                    item.category,
                    item.verdict,
                    item.whatHappened,
                    item.tradeRead,
                    item.nextWatch
                ].joined(separator: " ").lowercased()
                return haystack.contains(symbol.lowercased())
                    || haystack.contains(canonical.lowercased())
                    || haystack.contains(compactSymbol.lowercased())
                    || (!name.isEmpty && haystack.contains(name))
            }
            .sorted { lhs, rhs in
                if lhs.isCritical != rhs.isCritical { return lhs.isCritical }
                return lhs.asOf > rhs.asOf
            }
            .prefix(8)
            .map { $0 }
    }

