    private func watchReadableMarkdownSections(_ markdown: String) -> [String] {
        let chunks = markdown
            .components(separatedBy: "\n\n")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        return chunks.isEmpty ? [markdown] : chunks
    }

