    private func watchJournalTags(for row: NJInvestmentWatchRow) -> [String] {
        ["#\(watchCanonicalTagToken(for: row.symbol))"]
    }

    private func watchNotesKey(for row: NJInvestmentWatchRow) -> String {
        watchCanonicalTagToken(for: row.symbol).lowercased()
    }

    private func watchCanonicalTagToken(for symbol: String) -> String {
        let trimmed = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let parts = trimmed.split { $0 == " " || $0 == "\t" }.map(String.init)
        let token: String
        if parts.count == 2 {
            token = "\(parts[0]).\(parts[1])"
        } else {
            token = trimmed.replacingOccurrences(of: "/", with: "")
                .replacingOccurrences(of: " ", with: ".")
        }
        let allowed = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "._-"))
        return String(token.unicodeScalars.map { allowed.contains($0) ? Character($0) : "_" })
    }

    private func loadWatchSymbolNotes(for row: NJInvestmentWatchRow, force: Bool = false) {
        let key = watchNotesKey(for: row)
        if !force, watchSymbolNotes[key] != nil { return }

        let tags = watchJournalTags(for: row)
        watchSymbolNotesStatus[key] = "Searching journal blocks for \(tags.joined(separator: " "))..."

        do {
            let rows = try store.notes.exportTaggedBlockRows(tagFilter: tags.joined(separator: " "), limit: 12)
            let notes = rows.compactMap { row -> NJInvestmentSymbolNote? in
                let body = NJBlockExporter.plainTextFromPayloadJSON(row.payloadJSON)
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                guard !body.isEmpty else { return nil }
                return NJInvestmentSymbolNote(
                    id: row.blockID,
                    noteDomain: row.noteDomain,
                    dateText: watchNoteDateText(row.tsMs),
                    body: truncatedWatchNoteBody(body),
                    tags: row.blockTags
                )
            }
            watchSymbolNotes[key] = notes
            watchSymbolNotesStatus[key] = notes.isEmpty
                ? "No blocks found for \(tags.joined(separator: " ")). Add the tag to any trading-journal block, then refresh this tab."
                : "Showing latest \(notes.count) journal block\(notes.count == 1 ? "" : "s") for \(tags.joined(separator: " "))."
        } catch {
            watchSymbolNotes[key] = []
            watchSymbolNotesStatus[key] = "Could not load symbol notes: \(error.localizedDescription)"
        }
    }

    private func ensureWatchSymbolNote(for row: NJInvestmentWatchRow) {
        let key = watchNotesKey(for: row)
        if watchNotesEditorNoteIDs[key] != nil { return }

        var map = watchSymbolNoteIDMap()
        if let storedID = map[key], !storedID.isEmpty {
            watchNotesEditorNoteIDs[key] = NJNoteID(storedID)
            return
        }

        guard let notebookID = store.selectedNotebookID,
              let tabDomain = store.currentTabDomain else {
            watchSymbolNotesStatus[key] = "Select a notebook and tab before creating editable IRC notes."
            return
        }

        let note = store.notes.createNote(
            notebook: notebookID,
            tabDomain: tabDomain,
            title: "IRC Notes \(row.symbol)"
        )
        map[key] = note.id.raw
        saveWatchSymbolNoteIDMap(map)
        watchNotesEditorNoteIDs[key] = note.id
        seedWatchSymbolNote(noteID: note.id.raw, row: row)
        store.sync.schedulePush(debounceMs: 0)
        watchSymbolNotesStatus[key] = "Editable symbol note created. Add blocks here; the Proton floating bar appears while editing."
    }

    private func seedWatchSymbolNote(noteID: String, row: NJInvestmentWatchRow) {
        let token = watchCanonicalTagToken(for: row.symbol)
        let body = """
        \(row.symbol) \(row.name)
        #\(token)
        """
        let payloadJSON = NJQuickNotePayload.makePayloadJSON(from: body)
        guard let blockID = store.notes.createQuickNoteBlock(
            payloadJSON: payloadJSON,
            createdAtMs: DBNoteRepository.nowMs(),
            tags: ["investment", "irc-note", token]
        ) else { return }
        _ = store.notes.attachExistingBlockToNote(noteID: noteID, blockID: blockID, orderKey: store.notes.nextAppendOrderKey(noteID: noteID))
    }

    private func addWatchSymbolNoteBlock(for row: NJInvestmentWatchRow) {
        let key = watchNotesKey(for: row)
        ensureWatchSymbolNote(for: row)
        guard let noteID = watchNotesEditorNoteIDs[key]?.raw else {
            watchSymbolNotesStatus[key] = "Open a notebook/tab before adding an IRC note block."
            return
        }

        let token = watchCanonicalTagToken(for: row.symbol)
        let payloadJSON = NJQuickNotePayload.makePayloadJSON(from: "")
        guard let blockID = store.notes.createQuickNoteBlock(
            payloadJSON: payloadJSON,
            createdAtMs: DBNoteRepository.nowMs(),
            tags: ["investment", "irc-note", token]
        ) else {
            watchSymbolNotesStatus[key] = "Could not create a new IRC note block."
            return
        }

        let orderKey = max(1000.0, store.notes.nextAppendOrderKey(noteID: noteID))
        let instanceID = store.notes.attachExistingBlockToNote(noteID: noteID, blockID: blockID, orderKey: orderKey)
        guard !instanceID.isEmpty else {
            watchSymbolNotesStatus[key] = "Created a block, but could not attach it to this IRC note."
            return
        }

        watchNotesEditorReloadID = UUID()
        store.sync.schedulePush(debounceMs: 0)
        watchSymbolNotesStatus[key] = "Added a new editable IRC note block."
    }

    private func watchSymbolNoteIDMap() -> [String: String] {
        guard let data = watchSymbolNoteIDsStorage.data(using: .utf8),
              let decoded = try? JSONDecoder().decode([String: String].self, from: data) else {
            return [:]
        }
        return decoded
    }

    private func saveWatchSymbolNoteIDMap(_ map: [String: String]) {
        guard let data = try? JSONEncoder().encode(map),
              let encoded = String(data: data, encoding: .utf8) else { return }
        watchSymbolNoteIDsStorage = encoded
    }

    private func watchNoteDateText(_ ms: Int64) -> String {
        guard ms > 0 else { return "undated" }
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm"
        return formatter.string(from: Date(timeIntervalSince1970: Double(ms) / 1000.0))
    }

    private func truncatedWatchNoteBody(_ body: String) -> String {
        let cleaned = body.replacingOccurrences(of: "\n\n\n", with: "\n\n")
        guard cleaned.count > 900 else { return cleaned }
        return String(cleaned.prefix(900)).trimmingCharacters(in: .whitespacesAndNewlines) + "..."
    }

    private func markdownText(_ markdown: String) -> some View {
        Group {
            if let attributed = try? AttributedString(markdown: markdown) {
                Text(attributed)
            } else {
                Text(markdown)
            }
        }
        .font(.subheadline)
        .foregroundStyle(.secondary)
        .fixedSize(horizontal: false, vertical: true)
        .textSelection(.enabled)
    }

