    private func enableWatchDayTradeMode() {
        applyWatchChartPreset(.dayTrade)
    }

    private func applyWatchChartPreset(_ preset: NJInvestmentChartPreset) {
        selectedWatchChartInterval = preset.interval
        selectedWatchChartRange = preset.range
        watchShowCandles = true
        watchShowVolume = true
        watchShowVolumeSupportResistance = true
        persistWatchChartDefaults()
    }

    private var selectedWatchChartPresetBinding: Binding<NJInvestmentChartPreset> {
        Binding(
            get: {
                switch (selectedWatchChartRange, selectedWatchChartInterval) {
                case (.oneDay, .fiveMinutes):
                    return .dayTrade
                case (.fiveDays, .fifteenMinutes):
                    return .weekly
                case (.oneMonth, .hourly):
                    return .monthly
                case (.sixMonths, .daily):
                    return .quarterly
                case (.oneDay, _):
                    return .dayTrade
                case (.fiveDays, _):
                    return .weekly
                case (.oneMonth, _):
                    return .monthly
                case (.sixMonths, _):
                    return .quarterly
                default:
                    return .quarterly
                }
            },
            set: { preset in
                applyWatchChartPreset(preset)
            }
        )
    }

    private var watchChartRangePinchGesture: some Gesture {
        MagnificationGesture()
            .onChanged { _ in
                if watchChartPinchBaseRange == nil {
                    watchChartPinchBaseRange = selectedWatchChartRange
                }
            }
            .onEnded { value in
                applyWatchChartRangePinch(value)
            }
    }

    private func applyWatchChartRangePinch(_ magnification: CGFloat) {
        let baseRange = watchChartPinchBaseRange ?? selectedWatchChartRange
        watchChartPinchBaseRange = nil
        let targetRange = watchChartRange(from: baseRange, magnification: magnification)
        guard targetRange != selectedWatchChartRange else { return }
        selectedWatchChartRange = targetRange
        persistWatchChartDefaults()
    }

    private func watchChartRange(from baseRange: NJInvestmentChartRange, magnification: CGFloat) -> NJInvestmentChartRange {
        let ranges = NJInvestmentChartRange.allCases
        guard let baseIndex = ranges.firstIndex(of: baseRange) else { return baseRange }

        let step: Int
        switch magnification {
        case 2.35...:
            step = 3
        case 1.55..<2.35:
            step = 2
        case 1.14..<1.55:
            step = 1
        case ..<0.50:
            step = -3
        case 0.50..<0.70:
            step = -2
        case 0.70..<0.88:
            step = -1
        default:
            step = 0
        }

        let targetIndex = min(max(baseIndex + step, ranges.startIndex), ranges.index(before: ranges.endIndex))
        return ranges[targetIndex]
    }

    private var snapshotChartRangePinchGesture: some Gesture {
        MagnificationGesture()
            .onChanged { _ in
                if snapshotChartPinchBaseRange == nil {
                    snapshotChartPinchBaseRange = selectedSnapshotChartRange
                }
            }
            .onEnded { value in
                let baseRange = snapshotChartPinchBaseRange ?? selectedSnapshotChartRange
                snapshotChartPinchBaseRange = nil
                let targetRange = watchChartRange(from: baseRange, magnification: value)
                guard targetRange != selectedSnapshotChartRange else { return }
                selectedSnapshotChartRange = targetRange
            }
    }

    private func normalizedSnapshotChartInterval(_ interval: NJInvestmentChartInterval, for range: NJInvestmentChartRange) -> NJInvestmentChartInterval {
        switch interval {
        case .fiveMinutes:
            switch range {
            case .oneDay, .fiveDays:
                return .fiveMinutes
            case .oneMonth:
                return .fifteenMinutes
            case .threeMonths, .sixMonths:
                return .hourly
            case .oneYear, .threeYears, .fiveYears, .max:
                return .daily
            }
        case .fifteenMinutes:
            switch range {
            case .oneDay, .fiveDays, .oneMonth:
                return .fifteenMinutes
            case .threeMonths, .sixMonths:
                return .hourly
            case .oneYear, .threeYears, .fiveYears, .max:
                return .daily
            }
        case .hourly:
            switch range {
            case .oneDay, .fiveDays, .oneMonth, .threeMonths, .sixMonths:
                return .hourly
            case .oneYear, .threeYears, .fiveYears, .max:
                return .daily
            }
        case .daily:
            return .daily
        }
    }

