        }
    }

    private func watchChartEmptyState(key: String) -> some View {
        Text(watchChartStatus[key] ?? "Pulling chart data...")
            .font(.subheadline)
            .foregroundStyle(.secondary)
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(12)
            .background(Color(UIColor.secondarySystemGroupedBackground))
            .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func watchChartPlot(_ points: [NJInvestmentChartPoint], key: String, row: NJInvestmentWatchRow, height: CGFloat) -> some View {
        let vwapValue = numericValue(from: row.vwap)
        let volumeZones = watchVolumePriceZones(points)
        let fibonacciLevels = watchFibonacciLevels(points, key: key, xMode: selectedWatchChartInterval.isIntraday ? .compressedIndex : .date)
        let dayTradeLevels = dayTradeChartLevels(for: row)
        let maConfigs = activeMAConfigs
        let domainPoints = vwapValue.map {
            points + [NJInvestmentChartPoint(id: "\(row.id).vwap", date: points.last?.date ?? Date(), value: $0, change: "AVWAP", isDown: false)]
        } ?? points
        let zoneDomainPoints = volumeZones.map {
            NJInvestmentChartPoint(id: "\(row.id).zone.\($0.id)", date: points.last?.date ?? Date(), value: $0.center, change: $0.kind.title, isDown: $0.kind == .resistance)
        }
        let levelDomainPoints = dayTradeLevels.flatMap { level in
            [
                NJInvestmentChartPoint(id: "\(row.id).level.\(level.id).low", date: points.last?.date ?? Date(), value: level.low, change: level.title, isDown: level.kind == .invalidation),
                NJInvestmentChartPoint(id: "\(row.id).level.\(level.id).high", date: points.last?.date ?? Date(), value: level.high, change: level.title, isDown: level.kind == .invalidation)
            ]
        }
        let yDomain = smartChartYDomain(for: domainPoints + zoneDomainPoints + levelDomainPoints)
        if selectedWatchChartInterval.isIntraday {
            return AnyView(
                watchCompressedHourlyChartPlot(
                    points,
                    key: key,
                    row: row,
                    height: height,
                    vwapValue: vwapValue,
                    volumeZones: volumeZones,
                    fibonacciLevels: fibonacciLevels,
                    dayTradeLevels: dayTradeLevels,
                    yDomain: yDomain
                )
            )
        }
        return AnyView(VStack(spacing: 8) {
            Chart {
                if watchShowVolumeSupportResistance {
                    ForEach(volumeZones) { zone in
                        RectangleMark(
                            xStart: .value("Start", points.first?.date ?? Date()),
                            xEnd: .value("End", points.last?.date ?? Date()),
                            yStart: .value("Zone Low", zone.low),
                            yEnd: .value("Zone High", zone.high)
                        )
                        .foregroundStyle(zone.kind.color.opacity(0.10 + min(zone.share, 0.22)))

                        RuleMark(y: .value(zone.kind.title, zone.center))
                            .foregroundStyle(zone.kind.color.opacity(0.80))
                            .lineStyle(StrokeStyle(lineWidth: 1, dash: [4, 3]))
                            .annotation(position: isCompactLayout ? .leading : .trailing, alignment: .center) {
                                chartLineLabel(volumeZoneLineTitle(zone), color: zone.kind.color)
                            }
                    }
                }

                if watchShowCandles && points.contains(where: { $0.open != nil && $0.high != nil && $0.low != nil && $0.close != nil }) {
                    ForEach(points) { point in
                        if let open = point.open,
                           let high = point.high,
                           let low = point.low,
                           let close = point.close {
                            RuleMark(
                                x: .value("Date", point.date),
                                yStart: .value("Low", low),
                                yEnd: .value("High", high)
                            )
                            .foregroundStyle(close >= open ? Color.green.opacity(0.75) : Color.red.opacity(0.75))

                            RectangleMark(
                                x: .value("Date", point.date),
                                yStart: .value("Open", open),
                                yEnd: .value("Close", close),
                                width: .fixed(selectedWatchChartInterval.isIntraday ? 5 : 8)
                            )
                            .foregroundStyle(close >= open ? Color.green.opacity(0.62) : Color.red.opacity(0.62))
                        } else {
                            PointMark(
                                x: .value("Date", point.date),
                                y: .value("Price", point.value)
                            )
                            .foregroundStyle(point.isDown ? Color.red : Color.green)
                        }
                    }
                } else {
                    ForEach(points) { point in
                        LineMark(
                            x: .value("Date", point.date),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(Color.accentColor)

                        AreaMark(
                            x: .value("Date", point.date),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(
                            LinearGradient(
                                colors: [Color.accentColor.opacity(0.20), Color.accentColor.opacity(0.02)],
                                startPoint: .top,
                                endPoint: .bottom
                            )
                        )

                        if point.id == points.last?.id {
                            PointMark(
                                x: .value("Date", point.date),
                                y: .value("Price", point.value)
                            )
                            .foregroundStyle(point.isDown ? Color.red : Color.green)
                        }
                    }
                }

                if !maConfigs.isEmpty {
                    ForEach(maConfigs) { config in
                        ForEach(movingAverageSeries(points, config: config, key: key)) { point in
                            LineMark(
                                x: .value("Date", point.date),
                                y: .value(config.label, point.value),
                                series: .value("Overlay", config.label)
                            )
                                .foregroundStyle(config.color)
                                .lineStyle(maLineStyle(for: config))
                        }
                    }
                }

                if let vwapValue {
                    RuleMark(y: .value("AVWAP", vwapValue))
                        .foregroundStyle(Color.orange)
                        .lineStyle(StrokeStyle(lineWidth: 1.5, dash: [5, 4]))
                }

                if !fibonacciLevels.isEmpty {
                    ForEach(fibonacciLevels) { level in
                        RuleMark(y: .value(level.title, level.value))
                            .foregroundStyle(Color.indigo.opacity(level.ratio == 0.618 ? 0.85 : 0.55))
                            .lineStyle(StrokeStyle(lineWidth: level.ratio == 0.618 ? 1.4 : 1, dash: [2, 4]))
                            .annotation(position: isCompactLayout ? .leading : .trailing, alignment: .center) {
                                chartLineLabel(fibonacciLineTitle(level), color: .indigo)
                            }
                    }
                }

                if !dayTradeLevels.isEmpty {
                    ForEach(dayTradeLevels) { level in
                        if level.isZone {
                            RectangleMark(
                                xStart: .value("Start", points.first?.date ?? Date()),
                                xEnd: .value("End", points.last?.date ?? Date()),
                                yStart: .value("Level Low", level.low),
                                yEnd: .value("Level High", level.high)
                            )
                            .foregroundStyle(level.kind.color.opacity(0.10))
                        }

                        RuleMark(y: .value(level.title, level.center))
                            .foregroundStyle(level.kind.color.opacity(0.90))
                            .lineStyle(StrokeStyle(lineWidth: 1.4, dash: level.kind == .trigger ? [2, 4] : [6, 3]))
                            .annotation(position: isCompactLayout ? .leading : .trailing, alignment: .center) {
                                chartLineLabel(dayTradeLevelLineTitle(level), color: level.kind.color)
                            }
                    }
                }

                if let selected = selectedWatchChartPoints[key] {
                    RuleMark(x: .value("Selected", selected.date))
                        .foregroundStyle(Color.white.opacity(0.75))
                        .lineStyle(StrokeStyle(lineWidth: 1, dash: [3, 3]))
                }
            }
            .chartYScale(domain: yDomain)
            .chartPlotStyle { plotArea in
                plotArea
                    .background(Color.black)
            }
            .chartOverlay { chart in
                GeometryReader { proxy in
                    ZStack {
                        if let trendLine = activeWatchTrendLine(for: key, row: row) {
                            Path { path in
                                path.move(to: CGPoint(x: trendLine.start.x * proxy.size.width, y: trendLine.start.y * proxy.size.height))
                                path.addLine(to: CGPoint(x: trendLine.end.x * proxy.size.width, y: trendLine.end.y * proxy.size.height))
                            }
                            .stroke(Color.orange, style: StrokeStyle(lineWidth: 2.5, lineCap: .round, dash: [7, 5]))
                        }

                        if watchChartDrawingEnabled {
                            Rectangle()
                                .fill(Color.clear)
                                .contentShape(Rectangle())
                                .gesture(
                                    DragGesture(minimumDistance: 0)
                                        .onChanged { value in
                                            guard proxy.size.width > 0, proxy.size.height > 0 else { return }
                                            let line = NJInvestmentTrendLine(
                                                start: normalizedTrendPoint(value.startLocation, in: proxy.size),
                                                end: normalizedTrendPoint(value.location, in: proxy.size)
                                            )
                                            watchChartTrendLines[key] = line
                                            saveWatchTrendLine(line, for: key, row: row)
                                        }
                                )
                        }

                        if watchFibTraceEnabled {
                            Rectangle()
                                .fill(Color.clear)
                                .contentShape(Rectangle())
                                .gesture(
                                    DragGesture(minimumDistance: 0)
                                        .onChanged { value in
                                            watchFibTraces[key] = NJInvestmentFibTrace(
                                                start: normalizedTrendPoint(value.startLocation, in: proxy.size),
                                                end: normalizedTrendPoint(value.location, in: proxy.size)
                                            )
                                        }
                                )
                        }

                        if !watchChartDrawingEnabled && !watchFibTraceEnabled {
                            Rectangle()
                                .fill(Color.clear)
                                .contentShape(Rectangle())
                                .gesture(
                                    DragGesture(minimumDistance: 0)
                                        .onChanged { value in
                                            selectNearestWatchChartPoint(
                                                key: key,
                                                points: points,
                                                location: value.location,
                                                chart: chart,
                                                geometry: proxy
                                            )
                                        }
                                )
                        }
                    }
                }
            }
            .chartXAxis {
                AxisMarks(values: .automatic(desiredCount: 6)) { value in
                    AxisGridLine()
                        .foregroundStyle(Color.white.opacity(0.16))
                    AxisTick()
                        .foregroundStyle(Color.white.opacity(0.55))
                    AxisValueLabel {
                        if let date = value.as(Date.self) {
                            Text(watchXAxisLabel(for: date, interval: selectedWatchChartInterval))
                                .font(.system(size: 9, weight: .semibold))
                                .foregroundStyle(Color.white.opacity(0.78))
                        }
                    }
                }
            }
            .chartYAxis {
                AxisMarks(position: .trailing, values: .automatic(desiredCount: 6)) { value in
                    AxisGridLine()
                        .foregroundStyle(Color.white.opacity(0.14))
                    AxisTick()
                        .foregroundStyle(Color.white.opacity(0.55))
                    AxisValueLabel {
                        if let price = value.as(Double.self) {
                            Text(formattedChartValue(price))
                                .font(.system(size: 9, weight: .semibold))
                                .foregroundStyle(Color.white.opacity(0.78))
                        }
                    }
                }
            }
            .overlay(alignment: .topTrailing) {
                if vwapValue != nil {
                    Text("AVWAP \(row.vwap)")
                        .font(.caption2.weight(.bold))
                        .foregroundStyle(.orange)
                        .padding(.horizontal, 8)
                        .padding(.vertical, 4)
                        .background(Color(UIColor.systemBackground).opacity(0.92))
                        .clipShape(Capsule())
                        .padding(14)
                }
            }
            .overlay(alignment: .topLeading) {
                if !maConfigs.isEmpty {
                    movingAverageLegend
                        .padding(14)
                }
            }
            .overlay(alignment: .bottomTrailing) {
                if watchShowVolumeSupportResistance {
                    watchVolumeSupportResistanceOverlay(points)
                        .padding(14)
                }
            }
            .overlay(alignment: .topTrailing) {
                if !dayTradeLevels.isEmpty {
                    dayTradeLevelsOverlay(dayTradeLevels)
                        .padding(14)
                }
            }
            .overlay(alignment: .bottomLeading) {
                if let selected = selectedWatchChartPoints[key] {
                    watchSelectedOHLCOverlay(selected)
                        .padding(14)
                }
            }
            .frame(height: height)
            .padding(8)
            .background(Color.black)
            .clipShape(RoundedRectangle(cornerRadius: 8))

            if watchShowVolume, points.contains(where: { ($0.volume ?? 0) > 0 }) {
                Chart(points) { point in
                    BarMark(
                        x: .value("Date", point.date),
                        y: .value("Volume", point.volume ?? 0)
                    )
                    .foregroundStyle((point.close ?? point.value) < (point.open ?? point.value) ? Color.red.opacity(0.55) : Color.green.opacity(0.55))
                    if let avg = averageVolume(points) {
                        RuleMark(y: .value("Avg Vol", avg))
                            .foregroundStyle(Color.secondary)
                            .lineStyle(StrokeStyle(lineWidth: 1, dash: [3, 3]))
                    }
                }
                .chartXAxis {
                    AxisMarks(values: .automatic(desiredCount: 5)) { value in
                        AxisGridLine()
                            .foregroundStyle(Color.white.opacity(0.12))
                        AxisTick()
                            .foregroundStyle(Color.white.opacity(0.45))
                        AxisValueLabel {
                            if let date = value.as(Date.self) {
                                Text(watchXAxisLabel(for: date, interval: selectedWatchChartInterval))
                                    .font(.system(size: 8, weight: .semibold))
                                    .foregroundStyle(Color.white.opacity(0.70))
                            }
                        }
                    }
                }
                .chartYAxis {
                    AxisMarks(position: .trailing, values: .automatic(desiredCount: 3)) { value in
                        AxisGridLine()
                            .foregroundStyle(Color.white.opacity(0.12))
                        AxisTick()
                            .foregroundStyle(Color.white.opacity(0.45))
                        AxisValueLabel {
                            if let volume = value.as(Double.self) {
                                Text(compactVolumeText(volume))
                                    .font(.system(size: 8, weight: .semibold))
                                    .foregroundStyle(Color.white.opacity(0.70))
                            }
                        }
                    }
                }
                .frame(height: 92)
                .padding(8)
                .background(Color.black)
                .clipShape(RoundedRectangle(cornerRadius: 8))
            }

            watchIndicatorPanels(points, key: key, intraday: false)
        }
        .padding(10)
        .background(Color.black)
        .clipShape(RoundedRectangle(cornerRadius: 8))
        .simultaneousGesture(watchChartRangePinchGesture))
    }

    private func watchCompressedHourlyChartPlot(
        _ points: [NJInvestmentChartPoint],
        key: String,
        row: NJInvestmentWatchRow,
        height: CGFloat,
        vwapValue: Double?,
        volumeZones: [NJInvestmentVolumePriceZone],
        fibonacciLevels: [NJInvestmentFibonacciLevel],
        dayTradeLevels: [NJInvestmentTradeChartLevel],
        yDomain: ClosedRange<Double>
    ) -> some View {
        let indexedPoints = points.enumerated().map { NJInvestmentIndexedChartPoint(index: $0.offset, point: $0.element) }
        let indexByDate = Dictionary(uniqueKeysWithValues: indexedPoints.map { ($0.point.date, $0.index) })
        let maxIndex = max(points.count - 1, 0)
        let maConfigs = activeMAConfigs

        return VStack(spacing: 8) {
            Chart {
                if watchShowVolumeSupportResistance {
                    ForEach(volumeZones) { zone in
                        RectangleMark(
                            xStart: .value("Start", 0),
                            xEnd: .value("End", maxIndex),
                            yStart: .value("Zone Low", zone.low),
                            yEnd: .value("Zone High", zone.high)
                        )
                        .foregroundStyle(zone.kind.color.opacity(0.10 + min(zone.share, 0.22)))

                        RuleMark(y: .value(zone.kind.title, zone.center))
                            .foregroundStyle(zone.kind.color.opacity(0.80))
                            .lineStyle(StrokeStyle(lineWidth: 1, dash: [4, 3]))
                            .annotation(position: isCompactLayout ? .leading : .trailing, alignment: .center) {
                                chartLineLabel(volumeZoneLineTitle(zone), color: zone.kind.color)
                            }
                    }
                }

                if watchShowCandles && points.contains(where: { $0.open != nil && $0.high != nil && $0.low != nil && $0.close != nil }) {
                    ForEach(indexedPoints) { indexed in
                        let index = indexed.index
                        let point = indexed.point
                        if let open = point.open,
                           let high = point.high,
                           let low = point.low,
                           let close = point.close {
                            RuleMark(
                                x: .value("Bar", index),
                                yStart: .value("Low", low),
                                yEnd: .value("High", high)
                            )
                            .foregroundStyle(close >= open ? Color.green.opacity(0.75) : Color.red.opacity(0.75))

                            RectangleMark(
                                x: .value("Bar", index),
                                yStart: .value("Open", open),
                                yEnd: .value("Close", close),
                                width: .fixed(5)
                            )
                            .foregroundStyle(close >= open ? Color.green.opacity(0.62) : Color.red.opacity(0.62))
                        } else {
                            PointMark(
                                x: .value("Bar", index),
                                y: .value("Price", point.value)
                            )
                            .foregroundStyle(point.isDown ? Color.red : Color.green)
                        }
                    }
                } else {
                    ForEach(indexedPoints) { indexed in
                        let index = indexed.index
                        let point = indexed.point
                        LineMark(
                            x: .value("Bar", index),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(Color.accentColor)

                        AreaMark(
                            x: .value("Bar", index),
                            y: .value("Price", point.value)
                        )
                        .interpolationMethod(.catmullRom)
                        .foregroundStyle(
                            LinearGradient(
                                colors: [Color.accentColor.opacity(0.20), Color.accentColor.opacity(0.02)],
                                startPoint: .top,
                                endPoint: .bottom
                            )
                        )

                        if point.id == points.last?.id {
                            PointMark(
                                x: .value("Bar", index),
                                y: .value("Price", point.value)
                            )
                            .foregroundStyle(point.isDown ? Color.red : Color.green)
                        }
                    }
                }

                if !maConfigs.isEmpty {
                    ForEach(maConfigs) { config in
                        ForEach(movingAverageSeries(points, config: config, key: key)) { point in
                            if let index = indexByDate[point.date] {
                                LineMark(
                                    x: .value("Bar", index),
                                    y: .value(config.label, point.value),
                                    series: .value("Overlay", config.label)
                                )
                                    .foregroundStyle(config.color)
                                    .lineStyle(maLineStyle(for: config))
                            }
                        }
                    }
                }

                if let vwapValue {
                    RuleMark(y: .value("AVWAP", vwapValue))
                        .foregroundStyle(Color.orange)
                        .lineStyle(StrokeStyle(lineWidth: 1.5, dash: [5, 4]))
                }

                if !fibonacciLevels.isEmpty {
                    ForEach(fibonacciLevels) { level in
                        RuleMark(y: .value(level.title, level.value))
                            .foregroundStyle(Color.indigo.opacity(level.ratio == 0.618 ? 0.85 : 0.55))
                            .lineStyle(StrokeStyle(lineWidth: level.ratio == 0.618 ? 1.4 : 1, dash: [2, 4]))
                            .annotation(position: isCompactLayout ? .leading : .trailing, alignment: .center) {
                                chartLineLabel(fibonacciLineTitle(level), color: .indigo)
                            }
                    }
                }

                if !dayTradeLevels.isEmpty {
                    ForEach(dayTradeLevels) { level in
                        if level.isZone {
                            RectangleMark(
                                xStart: .value("Start", 0),
                                xEnd: .value("End", maxIndex),
                                yStart: .value("Level Low", level.low),
                                yEnd: .value("Level High", level.high)
                            )
                            .foregroundStyle(level.kind.color.opacity(0.10))
                        }

                        RuleMark(y: .value(level.title, level.center))
                            .foregroundStyle(level.kind.color.opacity(0.90))
                            .lineStyle(StrokeStyle(lineWidth: 1.4, dash: level.kind == .trigger ? [2, 4] : [6, 3]))
                            .annotation(position: isCompactLayout ? .leading : .trailing, alignment: .center) {
                                chartLineLabel(dayTradeLevelLineTitle(level), color: level.kind.color)
                            }
                    }
                }

                if let selected = selectedWatchChartPoints[key],
                   let selectedIndex = indexByDate[selected.date] {
                    RuleMark(x: .value("Selected", selectedIndex))
                        .foregroundStyle(Color.white.opacity(0.75))
                        .lineStyle(StrokeStyle(lineWidth: 1, dash: [3, 3]))
                }
            }
            .chartXScale(domain: 0...maxIndex)
            .chartYScale(domain: yDomain)
            .chartPlotStyle { plotArea in
                plotArea.background(Color.black)
            }
            .chartOverlay { chart in
                GeometryReader { proxy in
                    ZStack {
                        if let trendLine = activeWatchTrendLine(for: key, row: row) {
                            Path { path in
                                path.move(to: CGPoint(x: trendLine.start.x * proxy.size.width, y: trendLine.start.y * proxy.size.height))
                                path.addLine(to: CGPoint(x: trendLine.end.x * proxy.size.width, y: trendLine.end.y * proxy.size.height))
                            }
                            .stroke(Color.orange, style: StrokeStyle(lineWidth: 2.5, lineCap: .round, dash: [7, 5]))
                        }

                        if watchChartDrawingEnabled {
                            Rectangle()
                                .fill(Color.clear)
                                .contentShape(Rectangle())
                                .gesture(
                                    DragGesture(minimumDistance: 0)
                                        .onChanged { value in
                                            guard proxy.size.width > 0, proxy.size.height > 0 else { return }
                                            let line = NJInvestmentTrendLine(
                                                start: normalizedTrendPoint(value.startLocation, in: proxy.size),
                                                end: normalizedTrendPoint(value.location, in: proxy.size)
                                            )
                                            watchChartTrendLines[key] = line
                                            saveWatchTrendLine(line, for: key, row: row)
                                        }
                                )
                        }

                        if watchFibTraceEnabled {
                            Rectangle()
                                .fill(Color.clear)
                                .contentShape(Rectangle())
                                .gesture(
                                    DragGesture(minimumDistance: 0)
                                        .onChanged { value in
                                            watchFibTraces[key] = NJInvestmentFibTrace(
                                                start: normalizedTrendPoint(value.startLocation, in: proxy.size),
                                                end: normalizedTrendPoint(value.location, in: proxy.size)
                                            )
                                        }
                                )
                        }

                        if !watchChartDrawingEnabled && !watchFibTraceEnabled {
                            Rectangle()
                                .fill(Color.clear)
                                .contentShape(Rectangle())
                                .gesture(
                                    DragGesture(minimumDistance: 0)
                                        .onChanged { value in
                                            selectNearestIndexedWatchChartPoint(
                                                key: key,
                                                points: points,
                                                location: value.location,
                                                chart: chart,
                                                geometry: proxy
                                            )
                                        }
                                )
                        }
                    }
                }
            }
            .chartXAxis {
                AxisMarks(values: .automatic(desiredCount: 5)) { value in
                    AxisGridLine()
                        .foregroundStyle(Color.white.opacity(0.16))
                    AxisTick()
                        .foregroundStyle(Color.white.opacity(0.55))
                    AxisValueLabel {
                        if let index = value.as(Int.self),
                           points.indices.contains(index) {
                            Text(watchXAxisLabel(for: points[index].date, interval: selectedWatchChartInterval))
                                .font(.system(size: 9, weight: .semibold))
                                .foregroundStyle(Color.white.opacity(0.78))
                        }
                    }
                }
            }
            .chartYAxis {
                AxisMarks(position: .trailing, values: .automatic(desiredCount: 6)) { value in
                    AxisGridLine()
                        .foregroundStyle(Color.white.opacity(0.14))
                    AxisTick()
                        .foregroundStyle(Color.white.opacity(0.55))
                    AxisValueLabel {
                        if let price = value.as(Double.self) {
                            Text(formattedChartValue(price))
                                .font(.system(size: 9, weight: .semibold))
                                .foregroundStyle(Color.white.opacity(0.78))
                        }
                    }
                }
            }
            .overlay(alignment: .topTrailing) {
                if vwapValue != nil {
                    Text("AVWAP \(row.vwap)")
                        .font(.caption2.weight(.bold))
                        .foregroundStyle(.orange)
                        .padding(.horizontal, 8)
                        .padding(.vertical, 4)
                        .background(Color(UIColor.systemBackground).opacity(0.92))
                        .clipShape(Capsule())
                        .padding(14)
                }
            }
            .overlay(alignment: .topTrailing) {
                if !dayTradeLevels.isEmpty {
                    dayTradeLevelsOverlay(dayTradeLevels)
                        .padding(.top, vwapValue == nil ? 14 : 48)
                        .padding(.trailing, 14)
                }
            }
            .overlay(alignment: .topLeading) {
                if !maConfigs.isEmpty {
                    movingAverageLegend
                        .padding(14)
                }
            }
            .overlay(alignment: .bottomTrailing) {
                if watchShowVolumeSupportResistance {
                    watchVolumeSupportResistanceOverlay(points)
                        .padding(14)
                }
            }
            .overlay(alignment: .bottomLeading) {
                if let selected = selectedWatchChartPoints[key] {
                    watchSelectedOHLCOverlay(selected)
                        .padding(14)
                }
            }
            .frame(height: height)
            .padding(8)
            .background(Color.black)
            .clipShape(RoundedRectangle(cornerRadius: 8))

            if watchShowVolume, points.contains(where: { ($0.volume ?? 0) > 0 }) {
                Chart(indexedPoints) { indexed in
                    let point = indexed.point
                    BarMark(
                        x: .value("Bar", indexed.index),
                        y: .value("Volume", point.volume ?? 0)
                    )
                    .foregroundStyle((point.close ?? point.value) < (point.open ?? point.value) ? Color.red.opacity(0.55) : Color.green.opacity(0.55))
                    if let avg = averageVolume(points) {
                        RuleMark(y: .value("Avg Vol", avg))
                            .foregroundStyle(Color.secondary)
                            .lineStyle(StrokeStyle(lineWidth: 1, dash: [3, 3]))
                    }
                }
                .chartXScale(domain: 0...maxIndex)
                .chartXAxis {
                    AxisMarks(values: .automatic(desiredCount: 5)) { value in
                        AxisGridLine()
                            .foregroundStyle(Color.white.opacity(0.12))
                        AxisTick()
                            .foregroundStyle(Color.white.opacity(0.45))
                        AxisValueLabel {
                            if let index = value.as(Int.self),
                               points.indices.contains(index) {
                                Text(watchXAxisLabel(for: points[index].date, interval: selectedWatchChartInterval))
                                    .font(.system(size: 8, weight: .semibold))
                                    .foregroundStyle(Color.white.opacity(0.70))
                            }
                        }
                    }
                }
                .chartYAxis {
                    AxisMarks(position: .trailing, values: .automatic(desiredCount: 3)) { value in
                        AxisGridLine()
                            .foregroundStyle(Color.white.opacity(0.12))
                        AxisTick()
                            .foregroundStyle(Color.white.opacity(0.45))
                        AxisValueLabel {
                            if let volume = value.as(Double.self) {
                                Text(compactVolumeText(volume))
                                    .font(.system(size: 8, weight: .semibold))
                                    .foregroundStyle(Color.white.opacity(0.70))
                            }
                        }
                    }
                }
                .frame(height: 92)
                .padding(8)
                .background(Color.black)
                .clipShape(RoundedRectangle(cornerRadius: 8))
            }

            watchIndicatorPanels(points, key: key, intraday: true)
        }
        .padding(10)
        .background(Color.black)
        .clipShape(RoundedRectangle(cornerRadius: 8))
        .simultaneousGesture(watchChartRangePinchGesture)
    }

    private func intradayAxisLabel(for date: Date) -> String {
        watchXAxisLabel(for: date, interval: .hourly)
    }

    private func watchXAxisLabel(for date: Date, interval: NJInvestmentChartInterval) -> String {
        let formatter = DateFormatter()
        switch interval {
        case .daily:
            formatter.dateFormat = "M/d"
        case .hourly:
            formatter.dateFormat = "M/d HH"
        case .fifteenMinutes, .fiveMinutes:
            formatter.dateFormat = "M/d HH:mm"
        }
        return formatter.string(from: date)
    }

    private func selectNearestWatchChartPoint(
        key: String,
        points: [NJInvestmentChartPoint],
        location: CGPoint,
        chart: ChartProxy,
        geometry: GeometryProxy
    ) {
        let plotFrame = geometry[chart.plotAreaFrame]
        let x = location.x - plotFrame.origin.x
        guard x >= 0, x <= plotFrame.width,
              let date = chart.value(atX: x, as: Date.self),
              let nearest = nearestChartPoint(to: date, in: points) else { return }
        selectedWatchChartPoints[key] = nearest
    }

    private func selectNearestIndexedWatchChartPoint(
        key: String,
        points: [NJInvestmentChartPoint],
        location: CGPoint,
        chart: ChartProxy,
        geometry: GeometryProxy
    ) {
        let plotFrame = geometry[chart.plotAreaFrame]
        let x = location.x - plotFrame.origin.x
        guard x >= 0, x <= plotFrame.width,
              let rawIndex = chart.value(atX: x, as: Int.self),
              points.indices.contains(min(max(rawIndex, 0), points.count - 1)) else { return }
        selectedWatchChartPoints[key] = points[min(max(rawIndex, 0), points.count - 1)]
    }

    private func nearestChartPoint(to date: Date, in points: [NJInvestmentChartPoint]) -> NJInvestmentChartPoint? {
        points.min { lhs, rhs in
            abs(lhs.date.timeIntervalSince(date)) < abs(rhs.date.timeIntervalSince(date))
        }
    }

    private func watchSelectedOHLCOverlay(_ point: NJInvestmentChartPoint) -> some View {
        VStack(alignment: .leading, spacing: 5) {
