            HStack(spacing: 8) {
                ohlcValue("O", point.open ?? point.value)
                ohlcValue("H", point.high ?? max(point.open ?? point.value, point.close ?? point.value, point.value))
                ohlcValue("L", point.low ?? min(point.open ?? point.value, point.close ?? point.value, point.value))
                ohlcValue("C", point.close ?? point.value)
            }
        }
        .padding(.horizontal, 9)
        .padding(.vertical, 7)
        .background(Color(UIColor.systemBackground).opacity(0.94))
        .clipShape(RoundedRectangle(cornerRadius: 8))
        .shadow(color: Color.black.opacity(0.25), radius: 8, x: 0, y: 3)
    }

