    private func watchRSIPanel(_ points: [NJInvestmentChartPoint], key: String, intraday: Bool) -> some View {
        let rsiPoints = rsiSeries(points, period: 14)
        return VStack(alignment: .leading, spacing: 5) {
            indicatorPanelHeader("RSI 14", value: rsiPoints.last.map { String(format: "%.1f", $0.value) } ?? "n/a", tone: rsiTone(rsiPoints.last?.value))
            if rsiPoints.isEmpty {
                indicatorEmptyText("RSI needs at least 15 candles.")
            } else if intraday {
                let indexed = rsiPoints.enumerated().map { NJInvestmentIndexedChartPoint(index: $0.offset, point: $0.element) }
                Chart {
                    ForEach(indexed) { indexedPoint in
                        LineMark(
                            x: .value("Bar", indexedPoint.index),
                            y: .value("RSI", indexedPoint.point.value)
                        )
                        .foregroundStyle(Color.yellow)
                    }
                    RuleMark(y: .value("Overbought", 70))
                        .foregroundStyle(Color.red.opacity(0.75))
                        .lineStyle(StrokeStyle(lineWidth: 1, dash: [4, 3]))
                    RuleMark(y: .value("Oversold", 30))
                        .foregroundStyle(Color.green.opacity(0.75))
                        .lineStyle(StrokeStyle(lineWidth: 1, dash: [4, 3]))
                }
                .chartXScale(domain: 0...max(rsiPoints.count - 1, 0))
                .chartYScale(domain: 0...100)
                .chartXAxis(.hidden)
                .chartYAxis { AxisMarks(position: .trailing, values: [30, 50, 70]) }
                .frame(height: 96)
                .padding(8)
                .background(Color.black)
                .clipShape(RoundedRectangle(cornerRadius: 8))
            } else {
                Chart {
                    ForEach(rsiPoints) { point in
                        LineMark(
                            x: .value("Date", point.date),
                            y: .value("RSI", point.value)
                        )
                        .foregroundStyle(Color.yellow)
                    }
                    RuleMark(y: .value("Overbought", 70))
                        .foregroundStyle(Color.red.opacity(0.75))
                        .lineStyle(StrokeStyle(lineWidth: 1, dash: [4, 3]))
                    RuleMark(y: .value("Oversold", 30))
                        .foregroundStyle(Color.green.opacity(0.75))
                        .lineStyle(StrokeStyle(lineWidth: 1, dash: [4, 3]))
                }
                .chartYScale(domain: 0...100)
                .chartXAxis(.hidden)
                .chartYAxis { AxisMarks(position: .trailing, values: [30, 50, 70]) }
                .frame(height: 96)
                .padding(8)
                .background(Color.black)
                .clipShape(RoundedRectangle(cornerRadius: 8))
            }
        }
    }

