                let indexed = macdPoints.enumerated().map { NJInvestmentIndexedMACDPoint(index: $0.offset, point: $0.element) }
                Chart {
                    ForEach(indexed) { indexedPoint in
                        BarMark(
                            x: .value("Bar", indexedPoint.index),
                            y: .value("Histogram", indexedPoint.point.histogram)
                        )
                        .foregroundStyle(indexedPoint.point.histogram >= 0 ? Color.green.opacity(0.55) : Color.red.opacity(0.55))
                        LineMark(
                            x: .value("Bar", indexedPoint.index),
                            y: .value("MACD", indexedPoint.point.macd),
                            series: .value("Series", "MACD")
                        )
                        .foregroundStyle(Color.cyan)
