    private var activeMAConfigs: [NJInvestmentMAConfig] {
        allMAConfigs.filter { config in
            switch (config.kind, config.period) {
            case (.ma, 9): return watchShowMA9
            case (.ma, 20): return watchShowMA20
            case (.ma, 50): return watchShowMA50
            case (.ma, 200): return watchShowMA200
            case (.vwma, 9): return watchShowVWMA9
            case (.vwma, 20): return watchShowVWMA20
            case (.vwma, 50): return watchShowVWMA50
            case (.vwma, 200): return watchShowVWMA200
            default: return false
            }
        }
    }

    private var allMAConfigs: [NJInvestmentMAConfig] {
        [
            NJInvestmentMAConfig(kind: .ma, period: 9, color: maColor(for: .ma, period: 9), dashed: false),
            NJInvestmentMAConfig(kind: .ma, period: 20, color: maColor(for: .ma, period: 20), dashed: false),
            NJInvestmentMAConfig(kind: .ma, period: 50, color: maColor(for: .ma, period: 50), dashed: false),
            NJInvestmentMAConfig(kind: .ma, period: 200, color: maColor(for: .ma, period: 200), dashed: false),
            NJInvestmentMAConfig(kind: .vwma, period: 9, color: maColor(for: .vwma, period: 9), dashed: false),
            NJInvestmentMAConfig(kind: .vwma, period: 20, color: maColor(for: .vwma, period: 20), dashed: false),
            NJInvestmentMAConfig(kind: .vwma, period: 50, color: maColor(for: .vwma, period: 50), dashed: true),
            NJInvestmentMAConfig(kind: .vwma, period: 200, color: maColor(for: .vwma, period: 200), dashed: true)
        ]
    }

    private func maColor(for kind: NJInvestmentMAConfig.Kind, period: Int) -> Color {
        switch (kind, period) {
        case (.ma, 9): return Color(red: 1.00, green: 0.90, blue: 0.05)
        case (.ma, 20): return Color(red: 0.00, green: 0.82, blue: 1.00)
        case (.ma, 50): return Color(red: 1.00, green: 0.58, blue: 0.00)
        case (.ma, 200): return Color.white
        case (.vwma, 9): return Color(red: 0.25, green: 1.00, blue: 0.35)
        case (.vwma, 20): return Color(red: 0.10, green: 0.95, blue: 0.70)
        case (.vwma, 50): return Color(red: 1.00, green: 0.18, blue: 0.42)
        case (.vwma, 200): return Color(red: 0.72, green: 0.30, blue: 1.00)
        default: return .secondary
        }
    }

    private func maLineStyle(for config: NJInvestmentMAConfig) -> StrokeStyle {
        let width: CGFloat
        switch (config.kind, config.period) {
        case (.ma, 20): width = 1.8
        case (.ma, 50): width = 2.0
        case (.ma, 200): width = 2.2
        case (.vwma, 20), (.vwma, 50): width = 1.5
        default: width = 1.35
        }
        return config.dashed
            ? StrokeStyle(lineWidth: width, lineCap: .round, lineJoin: .round, dash: [5, 4])
            : StrokeStyle(lineWidth: width, lineCap: .round, lineJoin: .round)
    }

    private func movingAverageSeries(_ points: [NJInvestmentChartPoint], config: NJInvestmentMAConfig, key: String) -> [NJInvestmentChartPoint] {
        switch config.kind {
        case .ma:
            return movingAveragePoints(points, period: config.period, idPrefix: "\(key).ma\(config.period)")
        case .vwma:
            return volumeWeightedMovingAveragePoints(points, period: config.period, idPrefix: "\(key).vwma\(config.period)")
        }
    }

