    private func dayTradeChartLevels(for row: NJInvestmentWatchRow) -> [NJInvestmentTradeChartLevel] {
        guard selectedWatchChartRange == .oneDay else { return [] }
        switch selectedWatchChartInterval {
        case .fiveMinutes, .fifteenMinutes:
            break
        case .daily, .hourly:
            return []
        }

        switch row.symbol {
        case "DDOG":
            return [
                NJInvestmentTradeChartLevel(id: "ddog.support.14275-143", title: "Support $142.75-$143", low: 142.75, high: 143.0, kind: .support),
                NJInvestmentTradeChartLevel(id: "ddog.prior.14053", title: "Prior close $140.53", low: 140.53, high: 140.53, kind: .support),
                NJInvestmentTradeChartLevel(id: "ddog.warning.13901", title: "Warning $139.01", low: 139.01, high: 139.01, kind: .invalidation),
                NJInvestmentTradeChartLevel(id: "ddog.deep.13538", title: "Deep support $135.38", low: 135.38, high: 135.38, kind: .invalidation),
                NJInvestmentTradeChartLevel(id: "ddog.trigger.14733", title: "Trigger $147.33", low: 147.33, high: 147.33, kind: .trigger)
            ]
        case "NET":
            return [
                NJInvestmentTradeChartLevel(id: "net.support.218-220", title: "Support $218.28-$220", low: 218.28, high: 220.0, kind: .support),
                NJInvestmentTradeChartLevel(id: "net.prior.21750", title: "Prior close $217.50", low: 217.50, high: 217.50, kind: .support),
                NJInvestmentTradeChartLevel(id: "net.warning.214", title: "Warning $214", low: 214.0, high: 214.0, kind: .invalidation),
                NJInvestmentTradeChartLevel(id: "net.deep.209", title: "Deep support $209", low: 209.0, high: 209.0, kind: .invalidation),
                NJInvestmentTradeChartLevel(id: "net.trigger.22423", title: "Trigger $224.23", low: 224.23, high: 224.23, kind: .trigger)
            ]
        default:
            return []
        }
    }

