    private func watchChartCompactReadout(_ points: [NJInvestmentChartPoint], key: String) -> some View {
        let latest = points.last
        let latestRSI = rsiSeries(points, period: 14).last?.value
        let latestMACD = macdSeries(points).last
        let avgVolume = averageVolume(points)
        return ScrollView(.horizontal, showsIndicators: false) {
            HStack(spacing: 6) {
                if let latest {
                    readoutChip(
                        "Latest",
                        "\(formattedChartValue(latest.value)) \(latest.change)",
                        tone: latest.isDown ? .red : .green
                    )
                }
                readoutChip("RSI", latestRSI.map { String(format: "%.1f", $0) } ?? "n/a", tone: rsiTone(latestRSI))
                readoutChip("MACD", latestMACD.map { String(format: "%.2f", $0.macd) } ?? "n/a", tone: (latestMACD?.histogram ?? 0) >= 0 ? .green : .red)
                readoutChip("Signal", latestMACD.map { String(format: "%.2f", $0.signal) } ?? "n/a", tone: .secondary)
                readoutChip("Avg Vol", avgVolume.map { compactVolumeText($0) } ?? "n/a", tone: .secondary)
                ForEach(watchFibonacciLevels(points, key: key, xMode: selectedWatchChartInterval.isIntraday ? .compressedIndex : .date).filter { [0.382, 0.5, 0.618].contains($0.ratio) }) { level in
                    readoutChip(level.title, formattedChartValue(level.value), tone: .indigo)
                }
                readoutChip("Trend", watchChartTrendShortText(points), tone: .secondary)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
        }
    }

    private func readoutChip(_ title: String, _ value: String, tone: Color) -> some View {
        VStack(alignment: .leading, spacing: 1) {
            Text(title)
                .font(.caption2.weight(.semibold))
                .foregroundStyle(.secondary)
            Text(value)
                .font(.caption2.weight(.bold))
                .foregroundStyle(tone)
                .lineLimit(1)
                .minimumScaleFactor(0.75)
        }
        .padding(.horizontal, 7)
        .padding(.vertical, 5)
        .frame(minWidth: 58, alignment: .leading)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 6))
    }

    private func watchChartTrendShortText(_ points: [NJInvestmentChartPoint]) -> String {
        guard let first = points.first,
              let last = points.last,
              first.value != 0 else { return "waiting" }
        let pct = (last.value / first.value - 1) * 100
        return String(format: "%+.1f%%", pct)
    }

    private func watchChartIndicatorSummary(_ points: [NJInvestmentChartPoint]) -> some View {
        let latestRSI = rsiSeries(points, period: 14).last?.value
        let latestMACD = macdSeries(points).last
        let avgVolume = averageVolume(points)
        return LazyVGrid(columns: [GridItem(.adaptive(minimum: 132), spacing: 8)], alignment: .leading, spacing: 8) {
            indicatorChip("RSI 14", latestRSI.map { String(format: "%.1f", $0) } ?? "n/a", tone: rsiTone(latestRSI))
            indicatorChip("MACD", latestMACD.map { String(format: "%.2f", $0.macd) } ?? "n/a", tone: (latestMACD?.histogram ?? 0) >= 0 ? .green : .red)
            indicatorChip("Signal", latestMACD.map { String(format: "%.2f", $0.signal) } ?? "n/a", tone: .secondary)
            indicatorChip("Avg Vol", avgVolume.map { compactVolumeText($0) } ?? "n/a", tone: .secondary)
        }
    }

    private func watchVolumeSupportResistanceSummary(_ points: [NJInvestmentChartPoint]) -> some View {
        let zones = watchVolumePriceZones(points)
        let support = zones.first(where: { $0.kind == .support })
        let resistance = zones.first(where: { $0.kind == .resistance })
        return LazyVGrid(columns: [GridItem(.adaptive(minimum: 180), spacing: 8)], alignment: .leading, spacing: 8) {
            volumeZoneChip("Volume Support", zone: support, fallback: "n/a")
            volumeZoneChip("Volume Resistance", zone: resistance, fallback: "n/a")
        }
    }

    private func watchVolumeSupportResistanceOverlay(_ points: [NJInvestmentChartPoint]) -> some View {
        let zones = watchVolumePriceZones(points)
        let support = zones.first(where: { $0.kind == .support })
        let resistance = zones.first(where: { $0.kind == .resistance })
        return VStack(alignment: .leading, spacing: 5) {
            Button {
                withAnimation(.easeInOut(duration: 0.16)) {
                    watchVolumeOverlayExpanded.toggle()
                }
            } label: {
                HStack(spacing: 5) {
                    Image(systemName: watchVolumeOverlayExpanded ? "chevron.down" : "chevron.up")
                    Text("Vol S/R")
                }
                .font(.caption2.weight(.bold))
            }
            .buttonStyle(.plain)

            if watchVolumeOverlayExpanded {
                VStack(alignment: .leading, spacing: 4) {
