    private func watchFibonacciSummary(_ points: [NJInvestmentChartPoint], key: String) -> some View {
        let levels = watchFibonacciLevels(points, key: key, xMode: selectedWatchChartInterval.isIntraday ? .compressedIndex : .date)
        return Group {
            if !levels.isEmpty {
                LazyVGrid(columns: [GridItem(.adaptive(minimum: 118), spacing: 8)], alignment: .leading, spacing: 8) {
                    ForEach(levels.filter { [0.382, 0.5, 0.618].contains($0.ratio) }) { level in
                        indicatorChip(level.title, formattedChartValue(level.value), tone: .indigo)
                    }
                }
            } else if watchFibTraceEnabled {
                Text("Trace Fibonacci: drag across the move you want measured.")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
            }
        }
    }

    private enum NJInvestmentFibXMode {
        case date
        case compressedIndex
    }

    private func watchFibonacciLevels(_ points: [NJInvestmentChartPoint], key: String, xMode: NJInvestmentFibXMode) -> [NJInvestmentFibonacciLevel] {
        guard let trace = watchFibTraces[key],
              points.count > 1 else { return [] }
        let start = watchFibPrice(for: trace.start, points: points, xMode: xMode)
        let end = watchFibPrice(for: trace.end, points: points, xMode: xMode)
        let range = end - start
        guard abs(range) > 0.000001 else { return [] }
        let ratios = [0.236, 0.382, 0.5, 0.618, 0.786]
        return ratios.map { ratio in
            let value = end - range * ratio
            return NJInvestmentFibonacciLevel(
                id: String(format: "fib.%.3f", ratio),
                title: String(format: "Fib %.1f%%", ratio * 100),
                value: value,
                ratio: ratio
            )
        }
    }

    private func watchFibPrice(for point: CGPoint, points: [NJInvestmentChartPoint], xMode: NJInvestmentFibXMode) -> Double {
        guard !points.isEmpty else { return 0 }
        let clampedX = min(max(point.x, 0), 1)
        let index: Int
        switch xMode {
        case .compressedIndex:
            index = min(max(Int(round(clampedX * CGFloat(points.count - 1))), 0), points.count - 1)
        case .date:
            index = min(max(Int(round(clampedX * CGFloat(points.count - 1))), 0), points.count - 1)
        }
        return points[index].close ?? points[index].value
    }

