    private func watchVolumePriceZones(_ points: [NJInvestmentChartPoint]) -> [NJInvestmentVolumePriceZone] {
        guard let latest = points.last?.value else { return [] }
        let priced = points.compactMap { point -> (low: Double, high: Double, close: Double, volume: Double)? in
            let low = point.low ?? min(point.open ?? point.value, point.close ?? point.value, point.value)
            let high = point.high ?? max(point.open ?? point.value, point.close ?? point.value, point.value)
            let volume = point.volume ?? 0
            guard high >= low, volume > 0 else { return nil }
            return (low, high, point.close ?? point.value, volume)
        }
        guard let minPrice = priced.map(\.low).min(),
              let maxPrice = priced.map(\.high).max(),
              maxPrice > minPrice else { return [] }

        let binCount = min(max(Int(Double(priced.count).squareRoot() * 3), 12), 42)
        let binSize = (maxPrice - minPrice) / Double(binCount)
        guard binSize > 0 else { return [] }

        var buckets = Array(repeating: 0.0, count: binCount)
        for candle in priced {
            let typical = (candle.low + candle.high + candle.close) / 3.0
            let index = min(max(Int((typical - minPrice) / binSize), 0), binCount - 1)
            buckets[index] += candle.volume
        }

        let totalVolume = buckets.reduce(0, +)
        guard totalVolume > 0 else { return [] }

        return buckets.enumerated()
            .map { index, volume in
                let low = minPrice + Double(index) * binSize
                let high = low + binSize
                let center = (low + high) / 2.0
                return NJInvestmentVolumePriceZone(
                    id: "volzone.\(index)",
                    low: low,
                    high: high,
                    center: center,
                    volume: volume,
                    share: volume / totalVolume,
                    kind: center <= latest ? .support : .resistance
                )
            }
            .filter { $0.volume > 0 }
            .sorted { lhs, rhs in
                if lhs.kind.title == rhs.kind.title {
                    return lhs.volume > rhs.volume
                }
                return lhs.kind.title < rhs.kind.title
            }
            .reduce(into: [NJInvestmentVolumePriceZone]()) { out, zone in
                let alreadyHasKindCount = out.filter { $0.kind.title == zone.kind.title }.count
                guard alreadyHasKindCount < 2 else { return }
                out.append(zone)
            }
            .sorted { lhs, rhs in
                if lhs.kind.title == rhs.kind.title {
                    return abs(lhs.center - latest) < abs(rhs.center - latest)
                }
                return lhs.kind.title > rhs.kind.title
            }
    }

