    private func rsiTone(_ rsi: Double?) -> Color {
        guard let rsi else { return .secondary }
        if rsi >= 70 { return .red }
        if rsi <= 30 { return .green }
        return .primary
    }

    private func compactVolumeText(_ value: Double) -> String {
        if value >= 1_000_000_000 { return String(format: "%.1fB", value / 1_000_000_000) }
        if value >= 1_000_000 { return String(format: "%.1fM", value / 1_000_000) }
        if value >= 1_000 { return String(format: "%.1fK", value / 1_000) }
        return String(format: "%.0f", value)
    }

    private func averageVolume(_ points: [NJInvestmentChartPoint]) -> Double? {
        let values = points.suffix(20).compactMap(\.volume).filter { $0 > 0 }
        guard !values.isEmpty else { return nil }
        return values.reduce(0, +) / Double(values.count)
    }

    private func movingAveragePoints(_ points: [NJInvestmentChartPoint], period: Int, idPrefix: String) -> [NJInvestmentChartPoint] {
        guard period > 1, points.count >= period else { return [] }
        return points.enumerated().compactMap { index, point in
            guard index + 1 >= period else { return nil }
            let window = points[(index + 1 - period)...index].map(\.value)
            let avg = window.reduce(0, +) / Double(period)
            return NJInvestmentChartPoint(id: "\(idPrefix).\(point.id)", date: point.date, value: avg, change: "MA\(period)", isDown: false)
        }
    }

    private func volumeWeightedMovingAveragePoints(_ points: [NJInvestmentChartPoint], period: Int, idPrefix: String) -> [NJInvestmentChartPoint] {
        guard period > 1, points.count >= period else { return [] }
        return points.enumerated().compactMap { index, point in
            guard index + 1 >= period else { return nil }
            let window = points[(index + 1 - period)...index]
            let weighted = window.reduce(into: (priceVolume: 0.0, volume: 0.0)) { partial, candle in
                let volume = candle.volume ?? 0
                guard volume > 0 else { return }
                partial.priceVolume += candle.value * volume
                partial.volume += volume
            }
            guard weighted.volume > 0 else { return nil }
            let avg = weighted.priceVolume / weighted.volume
            return NJInvestmentChartPoint(id: "\(idPrefix).\(point.id)", date: point.date, value: avg, change: "VWMA\(period)", isDown: false)
        }
    }

    private func rsiSeries(_ points: [NJInvestmentChartPoint], period: Int) -> [NJInvestmentChartPoint] {
        guard points.count > period else { return [] }
        var out: [NJInvestmentChartPoint] = []
        for index in period..<points.count {
            let window = points[(index + 1 - period)...index]
            var gains = 0.0
            var losses = 0.0
            for pairIndex in window.indices.dropFirst() {
                let delta = points[pairIndex].value - points[pairIndex - 1].value
                if delta >= 0 { gains += delta } else { losses += abs(delta) }
            }
            let avgGain = gains / Double(period)
            let avgLoss = losses / Double(period)
            let rsi = avgLoss == 0 ? 100 : 100 - (100 / (1 + (avgGain / avgLoss)))
            let point = points[index]
            out.append(NJInvestmentChartPoint(id: "rsi.\(point.id)", date: point.date, value: rsi, change: "RSI", isDown: rsi < 50))
        }
        return out
    }

    private struct MACDPoint: Identifiable {
        let id = UUID()
        let date: Date
        let macd: Double
        let signal: Double
        let histogram: Double
    }

    private struct NJInvestmentIndexedMACDPoint: Identifiable {
        let index: Int
        let point: MACDPoint
        var id: String { "\(index)-\(point.date.timeIntervalSince1970)" }
    }

    private func macdSeries(_ points: [NJInvestmentChartPoint]) -> [MACDPoint] {
        let closes = points.map(\.value)
        guard closes.count >= 35 else { return [] }
        let ema12 = ema(closes, period: 12)
        let ema26 = ema(closes, period: 26)
        let macdLine = zip(ema12, ema26).map { $0 - $1 }
        let signal = ema(macdLine, period: 9)
        return macdLine.indices.compactMap { index in
            guard index < signal.count, index < points.count else { return nil }
            return MACDPoint(
                date: points[index].date,
                macd: macdLine[index],
                signal: signal[index],
                histogram: macdLine[index] - signal[index]
            )
        }
    }

    private func ema(_ values: [Double], period: Int) -> [Double] {
        guard let first = values.first, period > 1 else { return values }
        let multiplier = 2.0 / Double(period + 1)
        var previous = first
        return values.map { value in
            previous = (value - previous) * multiplier + previous
            return previous
        }
    }

    private func normalizedTrendPoint(_ point: CGPoint, in size: CGSize) -> CGPoint {
        CGPoint(
            x: min(max(point.x / max(size.width, 1), 0), 1),
            y: min(max(point.y / max(size.height, 1), 0), 1)
        )
    }

    private func watchChartTrendSummary(_ points: [NJInvestmentChartPoint]) -> String {
        guard let first = points.first,
              let last = points.last,
              first.value != 0 else { return "Trend: waiting for enough chart data." }
        let pct = (last.value / first.value - 1) * 100
        let direction = pct >= 0 ? "uptrend" : "downtrend"
        return "Trend: \(direction) over displayed range, \(String(format: "%+.1f%%", pct)). Draw Trend lets you mark support/resistance manually."
    }

