    private func watchChartKey(for row: NJInvestmentWatchRow, interval: NJInvestmentChartInterval, range: NJInvestmentChartRange) -> String {
        "\(row.id).\(interval.rawValue).\(range.rawValue)"
    }

    private func watchDrawingKey(for row: NJInvestmentWatchRow) -> String {
        watchNotesKey(for: row)
    }

    private func activeWatchTrendLine(for key: String, row: NJInvestmentWatchRow) -> NJInvestmentTrendLine? {
        let drawingKey = watchDrawingKey(for: row)
        return watchChartTrendLines[key] ?? watchSyncedTrendLines[drawingKey] ?? persistedWatchTrendLines()[drawingKey]
    }

    private func persistedWatchTrendLines() -> [String: NJInvestmentTrendLine] {
        guard let data = watchChartDrawingsStorage.data(using: .utf8),
              let decoded = try? JSONDecoder().decode([String: NJInvestmentTrendLine].self, from: data) else { return [:] }
        return decoded
    }

    private func watchDrawingID(for symbolKey: String) -> String {
        "trend.\(symbolKey)"
    }

    private func loadSyncedWatchTrendLines() {
        let rows = store.notes.listInvestmentChartDrawings()
        var lines: [String: NJInvestmentTrendLine] = [:]
        for row in rows where row.drawingType == "trend" {
            lines[row.symbolKey] = NJInvestmentTrendLine(
                start: CGPoint(x: row.startX, y: row.startY),
                end: CGPoint(x: row.endX, y: row.endY)
            )
        }
        watchSyncedTrendLines = lines
    }

    private func migrateLocalWatchTrendLinesIfNeeded() {
        let local = persistedWatchTrendLines()
        guard !local.isEmpty else { return }
        let nowMs = Int64(Date().timeIntervalSince1970 * 1000.0)
        for (symbolKey, line) in local where watchSyncedTrendLines[symbolKey] == nil {
            let row = NJInvestmentChartDrawing(
                drawingID: watchDrawingID(for: symbolKey),
                symbolKey: symbolKey,
                drawingType: "trend",
                startX: line.start.x,
                startY: line.start.y,
                endX: line.end.x,
                endY: line.end.y,
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                deleted: 0
            )
            store.notes.upsertInvestmentChartDrawing(row)
            watchSyncedTrendLines[symbolKey] = line
        }
    }

    private func saveWatchTrendLine(_ line: NJInvestmentTrendLine, for key: String, row: NJInvestmentWatchRow) {
        let symbolKey = watchDrawingKey(for: row)
        let nowMs = Int64(Date().timeIntervalSince1970 * 1000.0)
        let drawing = NJInvestmentChartDrawing(
            drawingID: watchDrawingID(for: symbolKey),
            symbolKey: symbolKey,
            drawingType: "trend",
            startX: line.start.x,
            startY: line.start.y,
            endX: line.end.x,
            endY: line.end.y,
            createdAtMs: nowMs,
            updatedAtMs: nowMs,
            deleted: 0
        )
        store.notes.upsertInvestmentChartDrawing(drawing)
        watchSyncedTrendLines[symbolKey] = line

        var lines = persistedWatchTrendLines()
        lines[symbolKey] = line
        if let data = try? JSONEncoder().encode(lines),
           let string = String(data: data, encoding: .utf8) {
            watchChartDrawingsStorage = string
        }
        watchChartTrendLines[key] = line
    }

    private func clearWatchTrendLine(for key: String, row: NJInvestmentWatchRow) {
        let symbolKey = watchDrawingKey(for: row)
        let nowMs = Int64(Date().timeIntervalSince1970 * 1000.0)
        store.notes.deleteInvestmentChartDrawing(drawingID: watchDrawingID(for: symbolKey), symbolKey: symbolKey, nowMs: nowMs)
        watchSyncedTrendLines[symbolKey] = nil

        var lines = persistedWatchTrendLines()
        lines[symbolKey] = nil
        if let data = try? JSONEncoder().encode(lines),
           let string = String(data: data, encoding: .utf8) {
            watchChartDrawingsStorage = string
        }
        watchChartTrendLines[key] = nil
    }

    private func refreshWatchChart(for row: NJInvestmentWatchRow, interval: NJInvestmentChartInterval? = nil) async {
        let chartInterval = interval ?? selectedWatchChartInterval
        let key = watchChartKey(for: row, interval: chartInterval, range: selectedWatchChartRange)
        guard let sourceSymbol = yahooWatchChartSymbol(for: row.symbol) else {
            watchChartPoints[key] = []
            watchChartStatus[key] = "No external chart source mapped for \(row.symbol)."
            return
        }

        let provider = resolvedWatchDataProvider()
        watchChartStatus[key] = "Pulling \(chartInterval.rawValue.lowercased()) / \(selectedWatchChartRange.rawValue) chart. Quote fields remain Webull-only."
        let range = yahooRangeText(for: chartInterval, range: selectedWatchChartRange)
        let intervalText = yahooIntervalText(for: chartInterval, range: selectedWatchChartRange)
        let points: [NJInvestmentChartPoint]
        switch provider {
        case .yahoo:
            points = await fetchYahooWatchChartPoints(rowID: row.id, sourceSymbol: sourceSymbol, range: range, interval: intervalText)
        case .stooq:
            points = chartInterval == .daily
                ? await fetchStooqWatchChartPoints(rowID: row.id, sourceSymbol: sourceSymbol)
                : await fetchYahooWatchChartPoints(rowID: row.id, sourceSymbol: sourceSymbol, range: range, interval: intervalText)
        case .ibkr:
            watchChartStatus[key] = "IBKR adapter is selected for future authenticated feeds. Chart uses the external chart adapter; quote fields stay Webull-only."
            points = await fetchYahooWatchChartPoints(rowID: row.id, sourceSymbol: sourceSymbol, range: range, interval: intervalText)
        case .webull:
            watchChartStatus[key] = "Webull adapter is selected for quotes. Chart uses the external chart adapter until Webull chart bridge is wired."
            points = await fetchYahooWatchChartPoints(rowID: row.id, sourceSymbol: sourceSymbol, range: range, interval: intervalText)
        case .auto:
            points = await fetchYahooWatchChartPoints(rowID: row.id, sourceSymbol: sourceSymbol, range: range, interval: intervalText)
        }
        watchChartPoints[key] = points
        watchChartStatus[key] = points.isEmpty
            ? "External chart source returned no usable points for \(sourceSymbol)."
            : "\(provider.rawValue) chart \(range) / \(intervalText) via \(sourceSymbol)"
    }

    private func resolvedWatchDataProvider() -> NJInvestmentMarketDataProvider {
        switch selectedWatchDataProvider {
        case .auto:
            return .webull
        case .yahoo, .stooq, .ibkr, .webull:
            return selectedWatchDataProvider
        }
    }

    private func shouldPreferWebullQuotes(for row: NJInvestmentWatchRow) -> Bool {
        cachedWebullPayload(for: row.symbol) != nil
    }

    private func investmentSymbolConvention(for symbol: String) -> NJInvestmentSymbolConvention? {
        let key = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        return investmentSymbolConventionsByKey[key] ?? NJInvestmentSymbolConventionRow(for: key)
    }

    private func loadInvestmentSymbolConventionRegistry() {
        let rows: [(symbolID: String, displaySymbol: String, platform: String, platformSymbol: String, aliasesJSON: String, status: String)] = store.notes.db.withDB { dbp in
            sqlite3_exec(dbp, """
            CREATE TABLE IF NOT EXISTS nj_investment_symbol_convention (
                convention_id TEXT PRIMARY KEY,
                symbol_id TEXT NOT NULL DEFAULT '',
                display_symbol TEXT NOT NULL DEFAULT '',
                platform TEXT NOT NULL DEFAULT '',
                platform_symbol TEXT NOT NULL DEFAULT '',
                platform_category TEXT NOT NULL DEFAULT '',
                platform_instrument_id TEXT NOT NULL DEFAULT '',
                platform_exchange TEXT NOT NULL DEFAULT '',
                platform_currency TEXT NOT NULL DEFAULT '',
                priority INTEGER NOT NULL DEFAULT 0,
                status TEXT NOT NULL DEFAULT '',
                verified_at_ms INTEGER NOT NULL DEFAULT 0,
                aliases_json TEXT NOT NULL DEFAULT '[]',
                notes TEXT NOT NULL DEFAULT '',
                created_at_ms INTEGER NOT NULL DEFAULT 0,
                updated_at_ms INTEGER NOT NULL DEFAULT 0,
                deleted INTEGER NOT NULL DEFAULT 0
            );
            """, nil, nil, nil)
            sqlite3_exec(dbp, "CREATE INDEX IF NOT EXISTS idx_nj_investment_symbol_convention_symbol ON nj_investment_symbol_convention(symbol_id ASC, platform ASC, priority ASC);", nil, nil, nil)
            sqlite3_exec(dbp, "CREATE INDEX IF NOT EXISTS idx_nj_investment_symbol_convention_platform ON nj_investment_symbol_convention(platform ASC, platform_category ASC, platform_symbol ASC);", nil, nil, nil)

            var stmt: OpaquePointer?
            let sql = """
            SELECT symbol_id, display_symbol, platform, platform_symbol, aliases_json, status
            FROM nj_investment_symbol_convention
            WHERE deleted = 0
            ORDER BY symbol_id ASC, platform ASC, priority ASC;
            """
            guard sqlite3_prepare_v2(dbp, sql, -1, &stmt, nil) == SQLITE_OK else { return [] }
            defer { sqlite3_finalize(stmt) }
            var out: [(symbolID: String, displaySymbol: String, platform: String, platformSymbol: String, aliasesJSON: String, status: String)] = []
            while sqlite3_step(stmt) == SQLITE_ROW {
                out.append((
                    symbolID: sqliteText(stmt, 0),
                    displaySymbol: sqliteText(stmt, 1),
                    platform: sqliteText(stmt, 2),
                    platformSymbol: sqliteText(stmt, 3),
                    aliasesJSON: sqliteText(stmt, 4),
                    status: sqliteText(stmt, 5)
                ))
            }
            return out
        }

        struct ConventionAccumulator {
            var instrumentID: String
            var name: String
            var webull: [String] = []
            var yahoo: [String] = []
            var stooq: [String] = []
            var ibkr: [String] = []
        }

        func appendUnique(_ values: [String], to array: inout [String]) {
            for value in values {
                let cleaned = value.trimmingCharacters(in: .whitespacesAndNewlines)
                guard !cleaned.isEmpty, !array.contains(where: { $0.caseInsensitiveCompare(cleaned) == .orderedSame }) else { continue }
                array.append(cleaned)
            }
        }

        var accumulators: [String: ConventionAccumulator] = [:]
        for row in rows {
            var acc = accumulators[row.symbolID] ?? ConventionAccumulator(instrumentID: row.displaySymbol, name: row.displaySymbol)
            let aliases = decodedStringArray(row.aliasesJSON)
            switch row.platform.lowercased() {
            case "webull":
                guard row.status != "not_quoteable" else { break }
                appendUnique([row.platformSymbol] + aliases, to: &acc.webull)
            case "yahoo":
                appendUnique([row.platformSymbol] + aliases, to: &acc.yahoo)
            case "stooq":
                appendUnique([row.platformSymbol] + aliases, to: &acc.stooq)
            case "ibkr":
                appendUnique([row.platformSymbol] + aliases, to: &acc.ibkr)
            default:
                break
            }
            accumulators[row.symbolID] = acc
        }

        var lookup: [String: NJInvestmentSymbolConvention] = [:]
        for acc in accumulators.values {
            let convention = NJInvestmentSymbolConvention(
                instrumentID: acc.instrumentID,
                name: acc.name,
                webull: acc.webull,
                yahoo: acc.yahoo,
                stooq: acc.stooq,
                ibkr: acc.ibkr
            )
            let keys = ([convention.instrumentID] + convention.webull + convention.yahoo + convention.stooq + convention.ibkr)
                .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() }
                .filter { !$0.isEmpty }
            for key in keys {
                lookup[key] = convention
            }
        }
        investmentSymbolConventionsByKey = lookup
        NJInvestmentDebugLog("SYMBOL_CONVENTION_REGISTRY_LOADED rows=\(rows.count) keys=\(lookup.count)")
    }

    private func sqliteText(_ stmt: OpaquePointer?, _ column: Int32) -> String {
        sqlite3_column_text(stmt, column).flatMap { String(cString: $0) } ?? ""
    }

    private func decodedStringArray(_ json: String) -> [String] {
        guard let data = json.data(using: .utf8),
              let values = try? JSONSerialization.jsonObject(with: data) as? [String] else { return [] }
        return values
    }

