            NSString(string: "~/Documents - Chi’s MacBook Air/New project/IRC/data/notion-journal-webull-quotes.json").expandingTildeInPath,
            NSString(string: "~/Library/Mobile Documents/iCloud~com~CYC~NotionJournal/Documents/Investment/WebullQuotes.json").expandingTildeInPath,
            NSString(string: "~/Library/Mobile Documents/iCloud~com~CYC~NotionJournal/Documents/Investment/notion-journal-webull-quotes.json").expandingTildeInPath
        ]

        if let existing = candidatePaths.first(where: { fm.fileExists(atPath: $0) }) {
            return URL(fileURLWithPath: existing)
        }
        return URL(fileURLWithPath: candidatePaths[0])
    }

    private func webullTicker(for symbol: String) -> String? {
        let upper = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if let convention = investmentSymbolConvention(for: upper),
           let primary = convention.webull.first {
            return primary
        }
        switch upper {
        case "SPX", "S&P", "S&P 500", "SP500", "^GSPC":
            return "SPX"
        case "DOW", "DJI", "^DJI":
            return "DJI"
        case "NASDAQ", "IXIC", "^IXIC":
            return "IXIC"
        case "US10Y", "US 10Y", "US10Y", "^TNX":
            return "TNX"
        case "VIX", "^VIX":
            return "VIX"
        case "HKSE", "HSI", "^HSI":
            return "HSI"
        case "SHANGHAI-A", "SHCOMP", "000001.SS":
            return "000001.SS"
        case "SHENZHEN-A", "399001.SZ":
            return "399001.SZ"
        case "TOKYO", "NIKKEI", "^N225":
            return "NIKKEI"
        case "STOXX600", "STOXX 600", "STOXX", "^STOXX":
            return "STOXX"
        case "STOXX50", "STOXX 50", "EURO STOXX 50", "^STOXX50E":
            return "STOXX50E"
        case "FTSE100", "FTSE 100", "^FTSE":
            return "FTSE"
        case "JGB", "JP10Y", "JAPAN 10Y":
            return "JP10Y"
        case "BUND10Y", "DE10Y", "GERMANY 10Y":
            return "DE10Y"
        case "UK10Y", "GILT10Y", "UK 10Y":
            return "UK10Y"
        case "USDCNH", "USD/CNH", "CNH=X":
            return "USDCNH"
        case "USDJPY", "USD/JPY", "JPY=X":
            return "USDJPY"
        case "EURUSD", "EUR/USD", "EURUSD=X":
            return "EURUSD"
        case "BITCOIN", "BTC", "BTC-USD":
            return "BTCUSD"
        case "ETHEREUM", "ETH", "ETH-USD":
            return "ETHUSD"
        case "BRENT", "BZ=F":
            return "BRENT"
        case "WTI", "CL=F":
            return "WTI"
        case "GOLD", "XAU/USD", "GC=F":
            return "GOLD"
        case "SILVER", "XAG/USD", "SI=F":
            return "SILVER"
        case "SU FP":
            return "SU.PA"
        case "ENR GR":
            return "ENR.DE"
        default:
            break
        }
        if upper.hasSuffix(" HK") {
            let code = String(upper.dropLast(3))
            return webullHKCode(from: code)
        }
        if upper.hasSuffix(".HK") {
            let code = String(upper.dropLast(3))
            return webullHKCode(from: code)
        }
        if upper.hasSuffix(" CN") {
            let code = String(upper.dropLast(3))
            return code.hasPrefix("6") ? "\(code).SS" : "\(code).SZ"
        }
        if upper.hasSuffix(" JP") {
            let code = String(upper.dropLast(3))
            return "\(code).T"
        }
        if !upper.isEmpty, !upper.contains(" "), !upper.hasPrefix("^") {
            return upper
        }
        return nil
    }

    private func webullAliasKeys(for symbol: String) -> [String] {
        if let convention = investmentSymbolConvention(for: symbol) {
            return [convention.instrumentID] + convention.webull + convention.yahoo + convention.stooq + convention.ibkr
        }
        switch symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() {
        case "SPX", "S&P", "S&P 500", "SP500", "^GSPC":
            return ["SPX", "INX", "IDXSP-SPX", "IDXSP-INX", "idxsp-spx", "idxsp-inx", "^GSPC", ".INX"]
        case "DOW", "DJI", "^DJI":
            return ["DJI", "DOW", "IDXDJX-DJI", "idxdjx-dji", "^DJI", ".DJI"]
        case "NASDAQ", "IXIC", "^IXIC":
            return ["IXIC", "NASDAQ", "IDXNASDAQ-IXIC", "idxnasdaq-ixic", "^IXIC", ".IXIC"]
        case "VIX", "^VIX":
            return ["VIX", "CBOE-VIX", "cboe-vix", "^VIX"]
        case "US10Y", "US 10Y", "^TNX", "TNX":
            return ["TNX", "US10Y", "US10YR", "^TNX", "CBOE-TNX", "cboe-tnx"]
        default:
            return []
        }
    }

    private func webullCacheKeys(for symbol: String) -> [String] {
        let upper = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        var keys: [String] = [upper] + webullAliasKeys(for: upper)
        if let mapped = liveSymbolMap[upper] ?? liveSymbolMap[symbol] {
            keys.append(mapped.uppercased())
            keys.append(mapped.replacingOccurrences(of: "yahoo:", with: "").uppercased())
            keys.append(mapped.replacingOccurrences(of: ".us", with: "").uppercased())
            keys.append(contentsOf: webullAliasKeys(for: mapped.replacingOccurrences(of: "yahoo:", with: "")))
        }
        if let yahoo = yahooFallbackSymbol(for: symbol) ?? usEquityYahooSymbol(for: upper) {
            keys.append(yahoo.uppercased())
            keys.append(yahoo.replacingOccurrences(of: ".US", with: "").uppercased())
            keys.append(yahoo.replacingOccurrences(of: "-", with: ".").uppercased())
        }
        if let ticker = webullTicker(for: upper) {
            keys.append(ticker)
            let code = ticker.replacingOccurrences(of: ".HK", with: "")
                .replacingOccurrences(of: ".SS", with: "")
                .replacingOccurrences(of: ".SZ", with: "")
                .replacingOccurrences(of: ".T", with: "")
                .replacingOccurrences(of: "HKEX-", with: "")
            keys.append("\(code) HK")
            keys.append("\(code).HK")
            keys.append("\(code) CN")
            keys.append("\(code) JP")
            keys.append(code)
            keys.append(code.hasPrefix("0") ? String(code.drop(while: { $0 == "0" })) : code)
            if code.count < 4 {
                keys.append(String(repeating: "0", count: 4 - code.count) + code)
            }
            keys.append(String(repeating: "0", count: max(0, 5 - code.count)) + code)
        }
        keys.append(upper.replacingOccurrences(of: ".", with: "-"))
        keys.append(upper.replacingOccurrences(of: "-", with: "."))
        var seen = Set<String>()
        return keys.filter { seen.insert($0).inserted }
    }

    private func readWebullQuoteCache() -> NJInvestmentWebullQuoteCachePayload? {
        guard let data = try? Data(contentsOf: webullQuoteCacheURL()) else { return nil }
        return try? JSONDecoder().decode(NJInvestmentWebullQuoteCachePayload.self, from: data)
    }

    private func cachedWebullPayload(for symbol: String) -> NJInvestmentWebullQuotePayload? {
        guard let cache = readWebullQuoteCache() else { return nil }
        let keys = Set(webullCacheKeys(for: symbol).map { $0.uppercased() })
        for key in webullCacheKeys(for: symbol) {
            if let quote = cache.quotes[key], quote.price != nil {
                return quote
            }
        }
        for (key, quote) in cache.quotes where quote.price != nil {
            let payloadSymbol = quote.symbol?.uppercased()
            if keys.contains(key.uppercased()) || payloadSymbol.map({ keys.contains($0) }) == true {
                return quote
            }
        }
        return nil
    }

    private func webullHKCode(from rawCode: String) -> String {
        let digits = rawCode.filter(\.isNumber)
        guard !digits.isEmpty else { return rawCode.uppercased() }
        if digits.count >= 5 {
            return digits
        }
        return String(repeating: "0", count: 5 - digits.count) + digits
    }

    private func webullQuoteDateParts(fetchedAt: String?) -> (dateKey: String, timeText: String) {
        let date = fetchedAt.flatMap { ISO8601DateFormatter().date(from: $0) } ?? Date()
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm"
        return (dateKey(date), formatter.string(from: date))
    }

    private func cachedWebullLiveQuote(for id: String) -> NJInvestmentLiveQuote? {
        guard let payload = cachedWebullPayload(for: id),
              let price = payload.price else { return nil }
        let parts = webullQuoteDateParts(fetchedAt: payload.fetchedAt)
        let quote = NJInvestmentLiveQuote(
            id: id,
            sourceSymbol: payload.symbol ?? webullTicker(for: id) ?? id,
            dateKey: parts.dateKey,
            timeText: parts.timeText,
            close: price,
            previousClose: payload.preClose,
            source: payload.source ?? "Webull OpenAPI",
            fiftyTwoWeekHigh: nil,
            fiftyTwoWeekLow: nil,
            open: payload.open,
            dayHigh: payload.high,
            dayLow: payload.low,
            volume: payload.volume
        )
        return webullQuoteLooksUsable(quote, for: id) ? quote : nil
    }

    private func webullQuoteLooksUsable(_ quote: NJInvestmentLiveQuote, for id: String) -> Bool {
        guard quote.isWebullSource else { return false }
        guard quote.close.isFinite, quote.close > 0 else { return false }
        guard webullQuoteDateLooksUsable(quote.dateKey) else { return false }
        guard webullQuotePriceLooksUsable(quote, for: id) else { return false }
        return webullQuoteSymbolLooksUsable(sourceSymbol: quote.sourceSymbol, source: quote.source, for: id)
    }

    private func webullQuotePriceLooksUsable(_ quote: NJInvestmentLiveQuote, for id: String) -> Bool {
        let upper = id.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let isSingleNameEquity = webullHKCode(for: upper) != nil ||
            upper.hasSuffix(" CN") ||
            upper.range(of: #"^[A-Z]{1,5}(\.[A-Z])?$"#, options: .regularExpression) != nil

        if webullHKCode(for: upper) != nil,
           let band = investmentQuoteReferenceBand(for: upper),
           !quote.close.isWithinInvestmentBand(low: band.low, high: band.high) {
            NJInvestmentQuoteDebugLog("QUOTE_REJECT provider=\"Webull\" id=\"\(quoteDebugToken(id))\" price=\"\(quote.close)\" reason=\"outside_reference_band\"")
            return false
        }

        if let previousClose = quote.previousClose,
           previousClose > 0,
           isSingleNameEquity {
            let ratio = quote.close / previousClose
            guard ratio >= 0.35 && ratio <= 2.0 else {
                NJInvestmentQuoteDebugLog("QUOTE_REJECT provider=\"Webull\" id=\"\(quoteDebugToken(id))\" price=\"\(quote.close)\" previous=\"\(previousClose)\" reason=\"outside_previous_close_guardrail\"")
                return false
            }
        }

        if let dayLow = quote.dayLow,
           let dayHigh = quote.dayHigh,
           dayLow > 0,
           dayHigh >= dayLow,
           isSingleNameEquity {
            guard quote.close >= dayLow * 0.95 && quote.close <= dayHigh * 1.05 else {
                NJInvestmentQuoteDebugLog("QUOTE_REJECT provider=\"Webull\" id=\"\(quoteDebugToken(id))\" price=\"\(quote.close)\" dayLow=\"\(dayLow)\" dayHigh=\"\(dayHigh)\" reason=\"outside_day_range\"")
                return false
            }
        }

        if let fiftyTwoWeekHigh = quote.fiftyTwoWeekHigh,
           fiftyTwoWeekHigh > 0,
           isSingleNameEquity,
           quote.close > fiftyTwoWeekHigh * 1.35 {
            NJInvestmentQuoteDebugLog("QUOTE_REJECT provider=\"Webull\" id=\"\(quoteDebugToken(id))\" price=\"\(quote.close)\" high52=\"\(fiftyTwoWeekHigh)\" reason=\"outside_52w_high\"")
            return false
        }

        return true
    }

    private func investmentQuoteReferenceBand(for symbol: String) -> (low: Double?, high: Double?)? {
        let upper = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let matchingRows = allInvestmentQuoteReferenceRows.filter { row in
            webullCacheKeys(for: row.symbol).map { $0.uppercased() }.contains(upper) ||
            webullCacheKeys(for: upper).map { $0.uppercased() }.contains(row.symbol.uppercased())
        }
        let lows = matchingRows.compactMap { numericValue(from: $0.week52Low) }
        let highs = matchingRows.compactMap { numericValue(from: $0.week52High) }
        let low = lows.min()
        let high = highs.max()
        return low == nil && high == nil ? nil : (low, high)
    }

