    private func webullQuoteDateLooksUsable(_ quoteDateKey: String) -> Bool {
        let today = dateKey(Date())
        let earliest = dateKey(calendar.date(byAdding: .day, value: -3, to: Date()) ?? Date())
        return quoteDateKey >= earliest && quoteDateKey <= today
    }

    private func webullQuoteSymbolLooksUsable(sourceSymbol: String, source: String, for id: String) -> Bool {
        let requested = id.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let symbol = sourceSymbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let label = source.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let combined = "\(symbol) \(label)"

        switch requested {
        case "SPX", "S&P", "S&P 500", "SP500", "^GSPC":
            return combined.contains("SPX") || combined.contains("INX") || combined.contains("S&P")
        case "DOW", "DJI", "^DJI":
            return combined.contains("DJI") || combined.contains("DJX") || combined.contains("DOW JONES")
        case "NASDAQ", "IXIC", "^IXIC":
            return combined.contains("IXIC") || combined.contains("NASDAQ COMPOSITE")
        case "US10Y", "US 10Y", "^TNX", "TNX":
            return combined.contains("TNX") || combined.contains("10Y")
        case "VIX", "^VIX":
            return combined.contains("VIX")
        default:
            break
        }

        if requested.hasSuffix(" HK") || requested.hasSuffix(".HK") {
            let expected = webullHKCode(from: requested.replacingOccurrences(of: " HK", with: "").replacingOccurrences(of: ".HK", with: ""))
            return symbol.contains(expected) || label.contains(expected)
        }

        if requested.range(of: #"^[A-Z]{1,5}$"#, options: .regularExpression) != nil {
            return symbol == requested || label.contains(" \(requested)") || label.hasSuffix(requested)
        }

        return true
    }

    private func cachedWebullProfilePair(for row: NJInvestmentWatchRow) -> (profile: NJInvestmentCompanyProfile, quote: NJInvestmentLiveQuote)? {
        guard let payload = cachedWebullPayload(for: row.symbol),
              let quote = cachedWebullLiveQuote(for: row.symbol) else { return nil }
        let exchange = webullExchange(for: row, payload: payload)
        let currency = webullCurrency(for: row, payload: payload)
        let profile = NJInvestmentCompanyProfile(
            symbol: row.symbol,
            sourceSymbol: payload.symbol ?? webullTicker(for: row.symbol) ?? row.symbol,
            displayName: row.name,
            exchange: exchange,
            currency: currency,
            regularMarketPrice: quote.close,
            previousClose: quote.previousClose,
            fiftyTwoWeekHigh: numericValue(from: row.week52High),
            fiftyTwoWeekLow: numericValue(from: row.week52Low),
            marketCap: nil,
            trailingPE: nil,
            forwardPE: nil,
            beta: nil,
            averageVolume: quote.volume,
            revenueGrowth: nil,
            profitMargins: nil,
            dividendYield: nil,
            dividendRate: nil,
            payoutRatio: nil,
            exDividendDate: nil,
            dividendDate: nil,
            earningsDate: nil,
            dataSource: .webull
        )
        return (profile, quote)
    }

    private func webullExchange(for row: NJInvestmentWatchRow, payload: NJInvestmentWebullQuotePayload) -> String {
        let upperSymbol = row.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let source = (payload.symbol ?? "").uppercased()
        if upperSymbol.hasSuffix(" HK") || upperSymbol.hasSuffix(".HK") || source.hasSuffix(".HK") {
            return "HKG"
        }
        if upperSymbol.hasSuffix(" JP") || source.hasSuffix(".T") {
            return "TSE"
        }
        if upperSymbol.hasSuffix(" CN") || source.hasSuffix(".SS") || source.hasSuffix(".SZ") {
            return "CN"
        }
        return "NMS"
    }

    private func webullCurrency(for row: NJInvestmentWatchRow, payload: NJInvestmentWebullQuotePayload) -> String {
        switch webullExchange(for: row, payload: payload) {
        case "HKG":
            return "HKD"
        case "TSE":
            return "JPY"
        case "CN":
            return "CNY"
        default:
            return "USD"
        }
    }

    private func mergedCompanyProfile(
        quoteProfile: NJInvestmentCompanyProfile?,
        metadataProfile: NJInvestmentCompanyProfile?,
        row: NJInvestmentWatchRow
    ) -> NJInvestmentCompanyProfile? {
        if let metadataProfile, let quoteProfile {
            return NJInvestmentCompanyProfile(
                symbol: row.symbol,
                sourceSymbol: metadataProfile.sourceSymbol,
                displayName: metadataProfile.displayName.isEmpty ? row.name : metadataProfile.displayName,
                exchange: quoteProfile.exchange.isEmpty ? metadataProfile.exchange : quoteProfile.exchange,
                currency: quoteProfile.currency.isEmpty ? metadataProfile.currency : quoteProfile.currency,
                regularMarketPrice: quoteProfile.regularMarketPrice ?? metadataProfile.regularMarketPrice,
                previousClose: quoteProfile.previousClose ?? metadataProfile.previousClose,
                fiftyTwoWeekHigh: quoteProfile.fiftyTwoWeekHigh ?? metadataProfile.fiftyTwoWeekHigh,
                fiftyTwoWeekLow: quoteProfile.fiftyTwoWeekLow ?? metadataProfile.fiftyTwoWeekLow,
                marketCap: metadataProfile.marketCap,
                trailingPE: metadataProfile.trailingPE,
                forwardPE: metadataProfile.forwardPE,
                beta: metadataProfile.beta,
                averageVolume: quoteProfile.averageVolume ?? metadataProfile.averageVolume,
                revenueGrowth: metadataProfile.revenueGrowth,
                profitMargins: metadataProfile.profitMargins,
                dividendYield: metadataProfile.dividendYield,
                dividendRate: metadataProfile.dividendRate,
                payoutRatio: metadataProfile.payoutRatio,
                exDividendDate: metadataProfile.exDividendDate,
                dividendDate: metadataProfile.dividendDate,
                earningsDate: metadataProfile.earningsDate,
                dataSource: metadataProfile.dataSource
            )
        }
        return metadataProfile ?? quoteProfile
    }

    private func refreshWatchCompanyProfile(for row: NJInvestmentWatchRow, force: Bool = false) async {
        let key = watchNotesKey(for: row)
        if !force, watchCompanyProfiles[key] != nil { return }
        let webullPair: (profile: NJInvestmentCompanyProfile, quote: NJInvestmentLiveQuote)? = {
            guard shouldPreferWebullQuotes(for: row) else { return nil }
            return cachedWebullProfilePair(for: row)
        }()
        if let webullPair {
            liveQuotes[row.symbol] = webullPair.quote
            persistCachedLiveQuotes([webullPair.quote])
        }
        guard let sourceSymbol = yahooWatchChartSymbol(for: row.symbol) else {
            watchCompanyProfiles[key] = webullPair?.profile
            watchCompanyProfileStatus[key] = "No external profile source mapped for \(row.symbol)."
            return
        }

        watchCompanyProfileStatus[key] = "Pulling company metadata for \(sourceSymbol)..."
        if let profile = await fetchYahooCompanyProfile(row: row, sourceSymbol: sourceSymbol) {
            watchCompanyProfiles[key] = mergedCompanyProfile(quoteProfile: webullPair?.profile, metadataProfile: profile, row: row)
            watchCompanyProfileStatus[key] = webullPair == nil
                ? "Loaded company metadata from \(profile.dataSource.rawValue)."
                : "Loaded Webull quote snapshot plus Yahoo dividend/calendar metadata."
        } else {
            watchCompanyProfiles[key] = webullPair?.profile
            watchCompanyProfileStatus[key] = webullPair == nil
                ? "Company metadata unavailable for \(sourceSymbol)."
                : "Using Webull quote snapshot. Yahoo dividend/calendar metadata unavailable for \(sourceSymbol)."
        }
    }

    private func fetchYahooCompanyProfile(row: NJInvestmentWatchRow, sourceSymbol: String) async -> NJInvestmentCompanyProfile? {
        let encoded = sourceSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? sourceSymbol
        if let summary = await fetchYahooQuoteSummaryProfile(row: row, sourceSymbol: sourceSymbol, encoded: encoded) {
            return summary
        }
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=2y&interval=1d&events=div%7Csplits") else { return nil }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = root["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let meta = result["meta"] as? [String: Any] else { return nil }

            let marketState = ((meta["marketState"] as? String) ?? "").uppercased()
            let profilePrice: Double? = {
                if marketState.contains("POST"), let value = doubleValue(meta["postMarketPrice"]) { return value }
                if marketState.contains("PRE"), let value = doubleValue(meta["preMarketPrice"]) { return value }
                return doubleValue(meta["regularMarketPrice"])
            }()

            let dividendEvents = yahooDividendEvents(from: result)
            let latestDividend = dividendEvents.last
            let trailingAnnualDividend = trailingAnnualDividendAmount(dividendEvents)
            let derivedDividendYield: Double? = {
                guard let price = profilePrice ?? doubleValue(meta["previousClose"]) ?? doubleValue(meta["chartPreviousClose"]),
                      price > 0,
                      let annual = trailingAnnualDividend else { return nil }
                return annual / price
            }()

            return NJInvestmentCompanyProfile(
                symbol: row.symbol,
                sourceSymbol: sourceSymbol,
                displayName: (meta["longName"] as? String) ?? (meta["shortName"] as? String) ?? row.name,
                exchange: (meta["exchangeName"] as? String) ?? (meta["fullExchangeName"] as? String) ?? "",
                currency: (meta["currency"] as? String) ?? "",
                regularMarketPrice: profilePrice,
                previousClose: doubleValue(meta["previousClose"]) ?? doubleValue(meta["chartPreviousClose"]),
                fiftyTwoWeekHigh: doubleValue(meta["fiftyTwoWeekHigh"]) ?? numericValue(from: row.week52High),
                fiftyTwoWeekLow: doubleValue(meta["fiftyTwoWeekLow"]) ?? numericValue(from: row.week52Low),
                marketCap: nil,
                trailingPE: nil,
                forwardPE: nil,
                beta: nil,
                averageVolume: nil,
                revenueGrowth: nil,
                profitMargins: nil,
                dividendYield: doubleValue(meta["trailingAnnualDividendYield"]) ?? derivedDividendYield,
                dividendRate: trailingAnnualDividend,
                payoutRatio: nil,
                exDividendDate: latestDividend?.date,
                dividendDate: doubleValue(meta["dividendDate"]).map { Date(timeIntervalSince1970: $0) },
                earningsDate: doubleValue(meta["earningsTimestamp"]).map { Date(timeIntervalSince1970: $0) },
                dataSource: .yahoo
            )
        } catch {
            return nil
        }
    }

    private func fetchYahooQuoteSummaryProfile(row: NJInvestmentWatchRow, sourceSymbol: String, encoded: String) async -> NJInvestmentCompanyProfile? {
        let modules = "price,summaryDetail,defaultKeyStatistics,financialData,calendarEvents"
        guard let url = URL(string: "https://query1.finance.yahoo.com/v10/finance/quoteSummary/\(encoded)?modules=\(modules)") else { return nil }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let quoteSummary = root["quoteSummary"] as? [String: Any],
                  let results = quoteSummary["result"] as? [[String: Any]],
                  let result = results.first else { return nil }

            let price = result["price"] as? [String: Any] ?? [:]
            let summary = result["summaryDetail"] as? [String: Any] ?? [:]
            let stats = result["defaultKeyStatistics"] as? [String: Any] ?? [:]
            let financial = result["financialData"] as? [String: Any] ?? [:]
            let calendar = result["calendarEvents"] as? [String: Any] ?? [:]
            let earnings = calendar["earnings"] as? [String: Any] ?? [:]
            let earningsDates = (earnings["earningsDate"] as? [[String: Any]]) ?? []

            let marketState = (yahooRawString(price["marketState"]) ?? "").uppercased()
            let profilePrice: Double? = {
                if marketState.contains("POST"), let value = yahooRawDouble(price["postMarketPrice"]) { return value }
                if marketState.contains("PRE"), let value = yahooRawDouble(price["preMarketPrice"]) { return value }
                return yahooRawDouble(price["regularMarketPrice"])
            }()

            return NJInvestmentCompanyProfile(
                symbol: row.symbol,
                sourceSymbol: sourceSymbol,
                displayName: yahooRawString(price["longName"]) ?? yahooRawString(price["shortName"]) ?? row.name,
                exchange: yahooRawString(price["exchangeName"]) ?? yahooRawString(price["fullExchangeName"]) ?? "",
                currency: yahooRawString(price["currency"]) ?? "",
                regularMarketPrice: profilePrice,
                previousClose: yahooRawDouble(summary["previousClose"]),
                fiftyTwoWeekHigh: yahooRawDouble(summary["fiftyTwoWeekHigh"]) ?? numericValue(from: row.week52High),
                fiftyTwoWeekLow: yahooRawDouble(summary["fiftyTwoWeekLow"]) ?? numericValue(from: row.week52Low),
                marketCap: yahooRawDouble(price["marketCap"]),
                trailingPE: yahooRawDouble(summary["trailingPE"]) ?? yahooRawDouble(stats["trailingPE"]),
                forwardPE: yahooRawDouble(stats["forwardPE"]),
                beta: yahooRawDouble(summary["beta"]),
                averageVolume: yahooRawDouble(summary["averageVolume"]),
                revenueGrowth: yahooRawDouble(financial["revenueGrowth"]),
                profitMargins: yahooRawDouble(financial["profitMargins"]),
                dividendYield: yahooRawDouble(summary["dividendYield"]),
                dividendRate: yahooRawDouble(summary["dividendRate"]),
                payoutRatio: yahooRawDouble(summary["payoutRatio"]),
                exDividendDate: yahooRawDate(summary["exDividendDate"]),
                dividendDate: yahooRawDate(summary["dividendDate"]),
                earningsDate: earningsDates.compactMap { yahooRawDate($0) }.first,
                dataSource: .yahoo
            )
        } catch {
            return nil
        }
    }

    private func yahooRawDouble(_ value: Any?) -> Double? {
        if let dict = value as? [String: Any] {
            return doubleValue(dict["raw"]) ?? doubleValue(dict["fmt"])
        }
        return doubleValue(value)
    }

    private func yahooRawString(_ value: Any?) -> String? {
        if let value = value as? String { return value }
        if let dict = value as? [String: Any] {
            return (dict["fmt"] as? String) ?? (dict["longFmt"] as? String) ?? dict["raw"].map { "\($0)" }
        }
        return nil
    }

    private func yahooRawDate(_ value: Any?) -> Date? {
        guard let seconds = yahooRawDouble(value) else { return nil }
        return Date(timeIntervalSince1970: seconds)
    }

    private func yahooDividendEvents(from result: [String: Any]) -> [NJInvestmentYahooDividendEvent] {
        guard let events = result["events"] as? [String: Any],
              let dividends = events["dividends"] as? [String: Any] else { return [] }

        return dividends.values.compactMap { raw -> NJInvestmentYahooDividendEvent? in
            guard let payload = raw as? [String: Any],
                  let timestamp = doubleValue(payload["date"]),
                  let amount = doubleValue(payload["amount"]) else { return nil }
            return NJInvestmentYahooDividendEvent(
                date: Date(timeIntervalSince1970: timestamp),
                amount: amount
            )
        }
        .sorted { $0.date < $1.date }
    }

    private func trailingAnnualDividendAmount(_ events: [NJInvestmentYahooDividendEvent]) -> Double? {
        guard let latestDate = events.last?.date else { return nil }
        let cutoff = Calendar.current.date(byAdding: .day, value: -365, to: latestDate) ?? latestDate.addingTimeInterval(-365 * 24 * 60 * 60)
        let trailing = events
            .filter { $0.date >= cutoff }
            .reduce(0.0) { $0 + $1.amount }
        return trailing > 0 ? trailing : nil
    }

    private func refreshWatchSymbolNews(for row: NJInvestmentWatchRow, force: Bool = false) async {
        let key = watchNotesKey(for: row)
        if !force, watchSymbolNews[key] != nil { return }
        if isWatchSymbolNewsLoading.contains(key) { return }

        isWatchSymbolNewsLoading.insert(key)
        watchSymbolNewsStatus[key] = "Pulling latest \(row.symbol) news..."
        defer { isWatchSymbolNewsLoading.remove(key) }

        let queries = watchNewsQueries(for: row)
        var rows: [NJObservationNewsItem] = []
        for query in queries {
            let items = await fetchWatchGoogleNewsRSS(query: query)
            rows.append(contentsOf: items)
        }

        let unique = Array(Dictionary(grouping: rows, by: { $0.title.lowercased() }).compactMap { $0.value.first })
            .sorted(by: observationNewsSort)
            .prefix(12)
        let items = Array(unique)
        watchSymbolNews[key] = items
        watchSymbolNewsStatus[key] = items.isEmpty
            ? "No recent RSS items returned for \(row.symbol)."
            : "Showing latest \(items.count) related news item\(items.count == 1 ? "" : "s"). Tap a row to read the article."
    }

    private func refreshWatchResearchReports(for row: NJInvestmentWatchRow, force: Bool = false) async {
        let key = watchNotesKey(for: row)
        if !force, watchResearchItems[key] != nil { return }
        if isWatchResearchLoading.contains(key) { return }

        isWatchResearchLoading.insert(key)
        watchResearchStatus[key] = "Searching outside research for \(row.symbol)..."
        defer { isWatchResearchLoading.remove(key) }

        var rows: [NJObservationNewsItem] = []
        for query in watchResearchQueries(for: row) {
            rows.append(contentsOf: await fetchWatchGoogleNewsRSS(query: query))
        }

        let unique = Array(Dictionary(grouping: rows, by: { $0.title.lowercased() }).compactMap { $0.value.first })
            .sorted(by: observationNewsSort)
            .prefix(10)
        let items = Array(unique)
        watchResearchItems[key] = items
        watchResearchStatus[key] = items.isEmpty
            ? "No outside research-report style items returned for \(row.symbol)."
            : "Showing \(items.count) outside research / analyst item\(items.count == 1 ? "" : "s"). Tap a row to read more."
    }

    private func watchNewsQueries(for row: NJInvestmentWatchRow) -> [String] {
        let cleanName = row.name.replacingOccurrences(of: "/", with: " ")
        let symbol = row.symbol
        return [
            "\(symbol) \(cleanName) stock news",
            "\(cleanName) earnings dividend stock",
            "\(symbol) analyst result guidance"
        ]
    }

    private func watchResearchQueries(for row: NJInvestmentWatchRow) -> [String] {
        let cleanName = row.name.replacingOccurrences(of: "/", with: " ")
        let symbol = row.symbol
        return [
            "\(symbol) \(cleanName) research report stock",
            "\(cleanName) analyst report target price",
            "\(symbol) \(cleanName) earnings analysis investment thesis"
        ]
    }

    private func fetchWatchGoogleNewsRSS(query: String) async -> [NJObservationNewsItem] {
        let encoded = query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? query
        guard let url = URL(string: "https://news.google.com/rss/search?q=\(encoded)&hl=en-US&gl=US&ceid=US:en") else { return [] }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")
        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            return NJObservationRSSParser.parse(data: data)
        } catch {
            return []
        }
    }

    private func shortDateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd"
        return formatter.string(from: date)
    }

    private func yahooIntervalText(for interval: NJInvestmentChartInterval, range: NJInvestmentChartRange) -> String {
        switch interval {
        case .daily:
            return "1d"
        case .hourly:
            return "1h"
        case .fifteenMinutes:
            return "15m"
        case .fiveMinutes:
            return "5m"
        }
    }

    private func yahooRangeText(for interval: NJInvestmentChartInterval, range: NJInvestmentChartRange) -> String {
        guard interval.isIntraday else { return range.yahooRange }
        switch interval {
        case .daily:
            return range.yahooRange
        case .hourly:
            switch range {
            case .oneDay, .fiveDays, .oneMonth, .threeMonths, .sixMonths:
                return range.yahooRange
            case .oneYear, .threeYears, .fiveYears, .max:
                return NJInvestmentChartRange.sixMonths.yahooRange
            }
        case .fifteenMinutes:
            switch range {
            case .oneDay, .fiveDays, .oneMonth:
                return range.yahooRange
            case .threeMonths, .sixMonths, .oneYear, .threeYears, .fiveYears, .max:
                return NJInvestmentChartRange.oneMonth.yahooRange
            }
        case .fiveMinutes:
            switch range {
            case .oneDay, .fiveDays:
                return range.yahooRange
            case .oneMonth, .threeMonths, .sixMonths, .oneYear, .threeYears, .fiveYears, .max:
                return NJInvestmentChartRange.fiveDays.yahooRange
            }
        }
    }

    private func yahooWatchChartSymbol(for symbol: String) -> String? {
        let upper = symbol.uppercased()
        switch upper {
        case "XAU/USD": return "GC=F"
        case "XAG/USD": return "SI=F"
        case "SPX": return "^GSPC"
        case "NASDAQ": return "^IXIC"
        case "DOW": return "^DJI"
        case "RUSSELL2000": return "^RUT"
        case "HSI": return "^HSI"
        case "HSTECH": return "3033.HK"
        case "HSCEI": return "2828.HK"
        case "SHANGHAI-A": return "000001.SS"
        case "SHENZHEN-A": return "399001.SZ"
        case "CSI300": return "000300.SS"
        case "CHINEXT": return "399006.SZ"
        case "NIKKEI": return "^N225"
        case "TOPIX": return "1306.T"
        case "USDJPY": return "JPY=X"
        case "STOXX600": return "^STOXX"
        case "STOXX50": return "^STOXX50E"
        case "FTSE100": return "^FTSE"
        case "DAX": return "^GDAXI"
        case "GOLD": return "GC=F"
        case "WTI": return "CL=F"
        default: break
        }
        if symbol == "USD/JPY" { return "JPY=X" }
        if symbol == "USD/CNH" { return "CNH=X" }
        if symbol == "SU FP" { return "SU.PA" }
        if symbol == "ENR GR" { return "ENR.DE" }
        if let mapped = liveSymbolMap[symbol] {
            if mapped.hasPrefix("yahoo:") {
                return String(mapped.dropFirst("yahoo:".count))
            }
            if mapped == "usdjpy" {
                return "JPY=X"
            }
            if mapped.hasSuffix(".us") {
                return mapped.replacingOccurrences(of: ".us", with: "").uppercased()
            }
        }
        if let fallback = yahooFallbackSymbol(for: symbol) {
            return fallback
        }
        if symbol.range(of: #"^[A-Z0-9.\-]+$"#, options: .regularExpression) != nil {
            return symbol
        }
        return nil
    }

    private func fetchYahooWatchChartPoints(rowID: String, sourceSymbol: String, range: String, interval: String) async -> [NJInvestmentChartPoint] {
        let encoded = sourceSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? sourceSymbol
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=\(range)&interval=\(interval)") else { return [] }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = root["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let timestamps = result["timestamp"] as? [TimeInterval],
                  let indicators = result["indicators"] as? [String: Any],
                  let quotes = indicators["quote"] as? [[String: Any]],
                  let quote = quotes.first,
                  let closes = quote["close"] as? [Any] else { return [] }

            let opens = quote["open"] as? [Any] ?? []
            let highs = quote["high"] as? [Any] ?? []
            let lows = quote["low"] as? [Any] ?? []
            let volumes = quote["volume"] as? [Any] ?? []

            var previousClose: Double?
            return timestamps.enumerated().compactMap { index, timestamp in
                guard index < closes.count,
                      let close = doubleValue(closes[index]) else { return nil }
                let open = index < opens.count ? doubleValue(opens[index]) : nil
                let high = index < highs.count ? doubleValue(highs[index]) : nil
                let low = index < lows.count ? doubleValue(lows[index]) : nil
                let volume = index < volumes.count ? doubleValue(volumes[index]) : nil
                let pct: Double? = {
                    guard let previousClose, previousClose != 0 else { return nil }
                    return (close / previousClose - 1) * 100
                }()
                previousClose = close
                return NJInvestmentChartPoint(
                    id: "watch.\(rowID).\(interval).\(Int(timestamp))",
                    date: Date(timeIntervalSince1970: timestamp),
                    value: close,
                    open: open,
                    high: high,
                    low: low,
                    close: close,
                    volume: volume,
                    change: pct.map { String(format: "%+.2f%%", $0) } ?? interval,
                    isDown: pct.map { $0 < 0 } ?? false
                )
            }
        } catch {
            return []
        }
    }

    private func fetchStooqWatchChartPoints(rowID: String, sourceSymbol: String) async -> [NJInvestmentChartPoint] {
        guard let stooqSymbol = stooqHistoricalSymbol(fromYahooSymbol: sourceSymbol) else { return [] }
        var components = URLComponents(string: "https://stooq.com/q/d/l/")!
        components.queryItems = [
            URLQueryItem(name: "s", value: stooqSymbol),
            URLQueryItem(name: "i", value: "d")
        ]
        guard let url = components.url else { return [] }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            guard let text = String(data: data, encoding: .utf8) else { return [] }
            let rows = text.split(whereSeparator: \.isNewline).dropFirst().map(String.init)
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.dateFormat = "yyyy-MM-dd"
            var previousClose: Double?
            return rows.compactMap { row in
                let values = parseSimpleCSVRow(row)
                guard values.count >= 6,
                      let date = formatter.date(from: values[0]),
                      let open = Double(values[1]),
                      let high = Double(values[2]),
                      let low = Double(values[3]),
                      let close = Double(values[4]) else { return nil }
                let volume = Double(values[5])
                let pct: Double? = {
                    guard let previousClose, previousClose != 0 else { return nil }
                    return (close / previousClose - 1) * 100
                }()
                previousClose = close
                return NJInvestmentChartPoint(
                    id: "stooq.\(rowID).\(values[0])",
                    date: date,
                    value: close,
                    open: open,
                    high: high,
                    low: low,
                    close: close,
                    volume: volume,
                    change: pct.map { String(format: "%+.2f%%", $0) } ?? "1d",
                    isDown: pct.map { $0 < 0 } ?? (close < open)
                )
            }
        } catch {
            return []
        }
    }

    private func stooqHistoricalSymbol(fromYahooSymbol symbol: String) -> String? {
        if symbol == "JPY=X" || symbol == "CNH=X" { return nil }
        if symbol.hasSuffix(".HK") {
            return symbol.lowercased()
        }
        if symbol.hasSuffix(".T") {
            return symbol.replacingOccurrences(of: ".T", with: ".jp").lowercased()
        }
        if symbol.hasSuffix(".SS") || symbol.hasSuffix(".SZ") {
            return symbol.lowercased()
        }
        if symbol.contains(".") {
            return symbol.lowercased()
        }
        return "\(symbol).us".lowercased()
    }

    private func doubleValue(_ value: Any?) -> Double? {
        if let value = value as? Double { return value }
        if let value = value as? Int { return Double(value) }
        if let value = value as? NSNumber { return value.doubleValue }
        if let value = value as? String { return Double(value) }
        return nil
    }

