    private func researchCard<Content: View>(title: String, status: String, @ViewBuilder content: () -> Content) -> some View {
        VStack(alignment: .leading, spacing: 10) {
            HStack(alignment: .firstTextBaseline) {
                Text(title)
                    .font(.headline)
                Spacer()
                Text(status)
                    .font(.caption.weight(.bold))
                    .padding(.horizontal, 10)
                    .padding(.vertical, 6)
                    .background(Color.accentColor.opacity(0.12))
                    .foregroundStyle(Color.accentColor)
                    .clipShape(RoundedRectangle(cornerRadius: 8))
            }
            content()
                .font(.subheadline)
                .foregroundStyle(.secondary)
                .fixedSize(horizontal: false, vertical: true)
        }
        .padding(14)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func watchTableWidth(for columns: [NJInvestmentWatchColumn]) -> CGFloat {
        let spacingWidth = CGFloat(max(columns.count - 1, 0)) * 8
        return columns.map { watchColumnWidth(for: $0.id, totalWeight: columns.map { watchColumnWeight($0.id) }.reduce(0, +)) }.reduce(0, +) + spacingWidth + 20
    }

    private func watchColumnWidth(for id: String, totalWeight: CGFloat) -> CGFloat {
        let tableWidth: CGFloat = isCompactLayout ? 760 : 960
        let weight = watchColumnWeight(id)
        return tableWidth * weight / max(totalWeight, 1)
    }

    private func tradeTableHeader(_ values: [String], widths: [CGFloat]) -> some View {
        HStack(spacing: 8) {
            ForEach(Array(values.enumerated()), id: \.offset) { index, value in
                Text(value)
                    .font(.caption.weight(.bold))
                    .foregroundStyle(.secondary)
                    .frame(width: tradeColumnWidth(at: index, widths: widths), alignment: .leading)
            }
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 8)
        .background(Color(UIColor.tertiarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 6))
    }

    private func tradeTableRow(_ values: [String], widths: [CGFloat], emphasizedDownColumns: [Int] = [], emphasized: Bool = false) -> some View {
        HStack(alignment: .top, spacing: 8) {
            ForEach(Array(values.enumerated()), id: \.offset) { index, value in
                Text(value)
                    .font(.caption.weight(emphasized ? .bold : .regular))
                    .foregroundStyle(emphasizedDownColumns.contains(index) ? Color.red : (emphasized ? Color.primary : Color.primary))
                    .fixedSize(horizontal: false, vertical: true)
                    .frame(width: tradeColumnWidth(at: index, widths: widths), alignment: .topLeading)
            }
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 9)
        .background(emphasized ? Color.orange.opacity(0.12) : Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 6))
    }

    private func tradeWatchButtonRow(_ row: NJInvestmentWatchRow, values: [String], widths: [CGFloat], emphasizedDownColumns: [Int] = [], emphasized: Bool = false) -> some View {
        Button {
            openWatchResearchPopup(for: row)
        } label: {
            tradeTableRow(values, widths: widths, emphasizedDownColumns: emphasizedDownColumns, emphasized: emphasized)
        }
        .buttonStyle(.plain)
    }

    private func openWatchResearchPopup(for row: NJInvestmentWatchRow) {
        guard let data = try? JSONEncoder().encode(row) else { return }
        if UIDevice.current.userInterfaceIdiom == .phone {
            selectedWatchRow = row
            return
        }
        selectedWatchRow = nil
        watchPopupCenter = nil
        openWindow(id: "investment-watch-research", value: data.base64EncodedString())
    }

    private func normalizedResearchSymbol(_ symbol: String) -> String {
        symbol
            .uppercased()
            .replacingOccurrences(of: "/", with: "")
            .components(separatedBy: CharacterSet.alphanumerics.inverted)
            .filter { !$0.isEmpty }
            .joined(separator: "_")
    }

    private func tradeColumnWidth(at index: Int, widths: [CGFloat]) -> CGFloat {
        let tableWidth: CGFloat = 800
        let spacingWidth = CGFloat(max(widths.count - 1, 0)) * 8
        let contentWidth = tableWidth - spacingWidth
        let totalWeight = max(widths.reduce(0, +), 1)
        let weight = widths.indices.contains(index) ? widths[index] : 1
        return contentWidth * weight / totalWeight
    }

