    private var marketSnapshotLineView: some View {
        let points = snapshotLinePoints(for: selectedSnapshotLineID)
        let dailyPoints = liveAdjustedChartPoints(chartPoints(from: points), lineID: selectedSnapshotLineID)
        let fetchedChartPoints = hourlyChartPoints[selectedSnapshotLineID] ?? []
        let usesExternalChartFeed = hourlyChartSource(for: selectedSnapshotLineID) != nil
        let chartPoints = usesExternalChartFeed
            ? fetchedChartPoints
            : chartPointsForSelectedInterval(filteredSnapshotDailyPoints(dailyPoints))
        let visibleChartPoints = zoomedSnapshotChartPoints(chartPoints)
        let showsSnapshotCandles = snapshotShowCandles && visibleChartPoints.contains(where: { $0.open != nil && $0.high != nil && $0.low != nil && $0.close != nil })
        let latestSnapshotPointID = visibleChartPoints.last?.id
        let selectedSnapshotDataPointID = selectedSnapshotDataPoint?.id
        let yDomain = smartChartYDomain(for: visibleChartPoints)
        return VStack(alignment: .leading, spacing: 10) {
            HStack(alignment: .top, spacing: 10) {
                sectionHeader(snapshotLineTitle(for: selectedSnapshotLineID), icon: "chart.line.uptrend.xyaxis")
                Spacer()
                if usesExternalChartFeed {
                    Toggle("Candles", isOn: $snapshotShowCandles)
                        .toggleStyle(.button)
                }
                Picker("Chart interval", selection: $selectedSnapshotChartInterval) {
                    ForEach(NJInvestmentChartInterval.allCases) { interval in
                        Text(interval.rawValue).tag(interval)
                    }
                }
                .pickerStyle(.segmented)
                .frame(maxWidth: isCompactLayout ? 260 : 380)
                if usesExternalChartFeed {
                    Menu {
                        ForEach(NJInvestmentChartRange.allCases) { range in
                            Button {
                                selectedSnapshotChartRange = range
                            } label: {
                                if selectedSnapshotChartRange == range {
                                    Label(range.rawValue, systemImage: "checkmark")
                                } else {
                                    Text(range.rawValue)
                                }
                            }
                        }
                    } label: {
                        Label(selectedSnapshotChartRange.rawValue, systemImage: "arrow.left.and.right")
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(.secondary)
                    }
                }
                Text(chartPoints.isEmpty ? "No chart yet" : "\(visibleChartPoints.count)/\(chartPoints.count) points")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
            }

            if chartPoints.isEmpty {
                Text(usesExternalChartFeed ? hourlyChartEmptyText : "Click a market snapshot metric above. A chart appears after numeric daily backfills exist.")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(12)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 8))
            } else {
                VStack(alignment: .leading, spacing: 10) {
                    if usesExternalChartFeed {
                        snapshotChartSurface(
                            visibleChartPoints: visibleChartPoints,
                            showsSnapshotCandles: showsSnapshotCandles,
                            latestSnapshotPointID: latestSnapshotPointID,
                            selectedSnapshotDataPointID: selectedSnapshotDataPointID,
                            yDomain: yDomain
                        )
                        .simultaneousGesture(snapshotChartRangePinchGesture)
                    } else {
                        snapshotChartSurface(
                            visibleChartPoints: visibleChartPoints,
                            showsSnapshotCandles: showsSnapshotCandles,
                            latestSnapshotPointID: latestSnapshotPointID,
                            selectedSnapshotDataPointID: selectedSnapshotDataPointID,
                            yDomain: yDomain
                        )
                        .simultaneousGesture(
                            MagnificationGesture()
                                .onChanged { value in
                                    snapshotChartZoomScale = clampedSnapshotZoom(snapshotChartBaseZoomScale * value)
                                }
                                .onEnded { value in
                                    snapshotChartBaseZoomScale = clampedSnapshotZoom(snapshotChartBaseZoomScale * value)
                                    snapshotChartZoomScale = snapshotChartBaseZoomScale
                                }
                        )
                    }

                    HStack(spacing: 10) {
                        if let latest = visibleChartPoints.last {
                            Text("Latest \(formattedChartValue(latest.value)) \(latest.change)")
                                .font(.caption.weight(.semibold))
                                .foregroundStyle(latest.isDown ? Color.red : Color.green)
                        }
                        if snapshotChartZoomScale > 1.05 {
                            Button("Reset zoom") {
                                snapshotChartZoomScale = 1
                                snapshotChartBaseZoomScale = 1
                            }
                            .font(.caption.weight(.semibold))
                            .buttonStyle(.bordered)
                        }
                    }
                }
            }
        }
        .padding(14)
        .background(Color(UIColor.systemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
    }

    private func snapshotChartSurface(
        visibleChartPoints: [NJInvestmentChartPoint],
        showsSnapshotCandles: Bool,
        latestSnapshotPointID: String?,
        selectedSnapshotDataPointID: String?,
        yDomain: ClosedRange<Double>
    ) -> some View {
        Group {
            if showsSnapshotCandles {
                Chart(visibleChartPoints) { point in
                    snapshotCandleMarks([point])
                    snapshotAuxiliaryMarks(for: point, latestID: latestSnapshotPointID, selectedID: selectedSnapshotDataPointID)
                }
            } else {
                Chart(visibleChartPoints) { point in
                    snapshotLineMarks(point)
                    snapshotAuxiliaryMarks(for: point, latestID: latestSnapshotPointID, selectedID: selectedSnapshotDataPointID)
                }
            }
        }
        .chartOverlay { chart in
            GeometryReader { proxy in
                Rectangle()
                    .fill(Color.clear)
                    .contentShape(Rectangle())
                    .gesture(
                        DragGesture(minimumDistance: 0)
                            .onEnded { value in
                                selectSnapshotDataPoint(
                                    points: visibleChartPoints,
                                    location: value.location,
                                    chart: chart,
                                    geometry: proxy
                                )
                            }
                    )
            }
        }
        .chartXAxis {
            AxisMarks(values: .automatic(desiredCount: 5))
        }
        .chartYAxis {
            AxisMarks(position: .trailing)
        }
        .chartYScale(domain: yDomain)
        .frame(height: 220)
        .padding(10)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
        .overlay(alignment: .topLeading) {
            if let point = selectedSnapshotDataPoint,
               point.title == snapshotLineTitle(for: selectedSnapshotLineID) {
                snapshotDataPointInlineCard(point)
                    .padding(16)
            }
        }
    }

    private func zoomedSnapshotChartPoints(_ points: [NJInvestmentChartPoint]) -> [NJInvestmentChartPoint] {
        guard snapshotChartZoomScale > 1.05, points.count > 2 else { return points }
        let visibleCount = max(8, Int(ceil(Double(points.count) / Double(snapshotChartZoomScale))))
        return Array(points.suffix(min(points.count, visibleCount)))
    }

    private func filteredSnapshotDailyPoints(_ points: [NJInvestmentChartPoint]) -> [NJInvestmentChartPoint] {
        guard let cutoff = calendar.date(byAdding: snapshotDateComponent(for: selectedSnapshotChartRange).component,
                                         value: snapshotDateComponent(for: selectedSnapshotChartRange).value,
                                         to: Date()) else { return points }
        return points.filter { $0.date >= cutoff }
    }

    private func snapshotDateComponent(for range: NJInvestmentChartRange) -> (component: Calendar.Component, value: Int) {
        switch range {
        case .oneDay:
            return (.day, -1)
        case .fiveDays:
            return (.day, -5)
        case .oneMonth:
            return (.month, -1)
        case .threeMonths:
            return (.month, -3)
        case .sixMonths:
            return (.month, -6)
        case .oneYear:
            return (.year, -1)
        case .threeYears:
            return (.year, -3)
        case .fiveYears:
            return (.year, -5)
        case .max:
            return (.year, -100)
        }
    }

    private func clampedSnapshotZoom(_ value: CGFloat) -> CGFloat {
        min(max(value, 1), 8)
    }

    private func selectSnapshotDataPoint(
        points: [NJInvestmentChartPoint],
        location: CGPoint,
        chart: ChartProxy,
        geometry: GeometryProxy
    ) {
        let plotFrame = geometry[chart.plotAreaFrame]
        let x = location.x - plotFrame.origin.x
        guard x >= 0, x <= plotFrame.width,
              let date = chart.value(atX: x, as: Date.self),
              let nearest = nearestChartPoint(to: date, in: points) else { return }
        selectedSnapshotDataPoint = snapshotDataPoint(for: nearest, lineID: selectedSnapshotLineID)
    }

    private func snapshotDataPointInlineCard(_ point: NJInvestmentSnapshotDataPoint) -> some View {
        VStack(alignment: .leading, spacing: 5) {
            HStack(spacing: 8) {
                Text(point.timestamp)
                    .font(.caption2.weight(.bold))
                    .foregroundStyle(.secondary)
                Text(point.change)
                    .font(.caption.weight(.bold))
                    .foregroundStyle(point.isDown ? Color.red : Color.green)
            }
            Text(point.value)
                .font(.headline.weight(.bold))
            Text(point.detail)
                .font(.caption2)
                .foregroundStyle(.secondary)
                .lineLimit(2)
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 8)
        .frame(maxWidth: 300, alignment: .leading)
        .background(.regularMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 8))
        .shadow(color: Color.black.opacity(0.14), radius: 8, x: 0, y: 3)
    }

    @ChartContentBuilder
    private func snapshotLineMarks(_ point: NJInvestmentChartPoint) -> some ChartContent {
        LineMark(
            x: .value("Date", point.date),
            y: .value("Value", point.value)
        )
        .interpolationMethod(.catmullRom)
        .foregroundStyle(Color.accentColor)

        AreaMark(
            x: .value("Date", point.date),
            y: .value("Value", point.value)
        )
        .interpolationMethod(.catmullRom)
        .foregroundStyle(
            LinearGradient(
                colors: [Color.accentColor.opacity(0.22), Color.accentColor.opacity(0.02)],
                startPoint: .top,
                endPoint: .bottom
            )
        )
    }

    @ChartContentBuilder
    private func snapshotCandleMarks(_ points: [NJInvestmentChartPoint]) -> some ChartContent {
        ForEach(points) { candle in
            if let open = candle.open,
               let high = candle.high,
               let low = candle.low,
               let close = candle.close {
                RuleMark(
                    x: .value("Date", candle.date),
                    yStart: .value("Low", low),
                    yEnd: .value("High", high)
                )
                .foregroundStyle(close >= open ? Color.green : Color.red)

                RectangleMark(
                    x: .value("Date", candle.date),
                    yStart: .value("Open", open),
                    yEnd: .value("Close", close),
                    width: 8
                )
                .foregroundStyle(close >= open ? Color.green : Color.red)
            }
        }
    }

    @ChartContentBuilder
    private func snapshotAuxiliaryMarks(for point: NJInvestmentChartPoint, latestID: String?, selectedID: String?) -> some ChartContent {
        if point.id == latestID {
            PointMark(
                x: .value("Date", point.date),
                y: .value("Value", point.value)
            )
            .foregroundStyle(point.isDown ? Color.red : Color.green)
        }

        if point.id == selectedID {
            RuleMark(x: .value("Selected", point.date))
                .foregroundStyle(Color.accentColor.opacity(0.75))
                .lineStyle(StrokeStyle(lineWidth: 1, dash: [3, 3]))
        }
    }

    private func snapshotDataPoint(for metric: NJInvestmentSnapshotMetric) -> NJInvestmentSnapshotDataPoint {
        NJInvestmentSnapshotDataPoint(
            id: "metric.\(metric.id).\(dateKey(Date()))",
            title: metric.title,
            timestamp: snapshotMetricTimestamp(from: metric.detail),
            value: metric.value,
            change: metric.change,
            source: metric.detail.lowercased().contains("live refresh") ? "Live snapshot card" : "Stored snapshot card",
            detail: metric.detail,
            isDown: snapshotChangeColor(metric.change) == .red
        )
    }

    private func snapshotDataPoint(for point: NJInvestmentChartPoint, lineID: String) -> NJInvestmentSnapshotDataPoint {
        NJInvestmentSnapshotDataPoint(
            id: point.id,
            title: snapshotLineTitle(for: lineID),
            timestamp: snapshotChartTimestamp(for: point.date),
            value: formattedChartValue(point.value),
            change: point.change,
            source: snapshotChartSourceLabel(for: point),
            detail: snapshotChartDetail(for: point),
            isDown: point.isDown
        )
    }

    private func snapshotMetricTimestamp(from detail: String) -> String {
        if detail.localizedCaseInsensitiveContains("Live refresh from Stooq") {
            return detail.components(separatedBy: ".").first ?? "Live snapshot"
        }
        if detail.localizedCaseInsensitiveContains("Latest verified close") {
            return detail.components(separatedBy: ".").first ?? "Latest verified close"
        }
        if detail.localizedCaseInsensitiveContains("Last verified close") {
            return detail.components(separatedBy: ".").first ?? "Last verified close"
        }
        return "Snapshot card"
    }

    private func snapshotChartTimestamp(for date: Date) -> String {
        let formatter = DateFormatter()
        formatter.calendar = calendar
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = selectedSnapshotChartInterval.isIntraday ? "yyyy-MM-dd HH:mm" : "yyyy-MM-dd"
        return formatter.string(from: date)
    }

    private func snapshotChartSourceLabel(for point: NJInvestmentChartPoint) -> String {
        if point.id.hasPrefix("watch.") || point.id.hasPrefix("hourly.") {
            return "Live intraday chart"
        }
        if point.id.hasPrefix("market_snapshot.") {
            return "Stored macro snapshot"
        }
        if point.id.hasPrefix("static.") {
            return "Static fallback snapshot"
        }
        return selectedSnapshotChartInterval.isIntraday ? "Intraday chart" : "Stored chart"
    }

    private func snapshotChartDetail(for point: NJInvestmentChartPoint) -> String {
        var parts: [String] = []
        parts.append("\(selectedSnapshotChartInterval.rawValue) point for \(snapshotLineTitle(for: selectedSnapshotLineID)).")
        if let open = point.open {
            parts.append("Open \(formattedChartValue(open))")
        }
        if let high = point.high {
            parts.append("High \(formattedChartValue(high))")
        }
        if let low = point.low {
            parts.append("Low \(formattedChartValue(low))")
        }
        if let close = point.close {
            parts.append("Close \(formattedChartValue(close))")
        }
        if let volume = point.volume {
            parts.append("Volume \(formattedCompactNumber(volume))")
        }
        parts.append("Record id: \(point.id)")
        return parts.joined(separator: "\n")
    }

    private func formattedCompactNumber(_ value: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .decimal
        formatter.maximumFractionDigits = value >= 1_000_000 ? 1 : 0
        if value >= 1_000_000_000 {
            return "\(formatter.string(from: NSNumber(value: value / 1_000_000_000)) ?? "\(value / 1_000_000_000)")B"
        }
        if value >= 1_000_000 {
            return "\(formatter.string(from: NSNumber(value: value / 1_000_000)) ?? "\(value / 1_000_000)")M"
        }
        if value >= 1_000 {
            return "\(formatter.string(from: NSNumber(value: value / 1_000)) ?? "\(value / 1_000)")K"
        }
        return formatter.string(from: NSNumber(value: value)) ?? "\(value)"
    }

