    private func smartChartYDomain(for points: [NJInvestmentChartPoint]) -> ClosedRange<Double> {
        let values = points.map(\.value)
        guard let minValue = values.min(), let maxValue = values.max() else {
            return 0...1
        }

        let range = maxValue - minValue
        if range == 0 {
            let baseline = max(abs(maxValue), 1)
            let padding = baseline * 0.01
            return (minValue - padding)...(maxValue + padding)
        }

        let padding = max(range * 0.12, max(abs(maxValue), abs(minValue), 1) * 0.002)
        return (minValue - padding)...(maxValue + padding)
    }

    private func chartPointsForSelectedInterval(_ points: [NJInvestmentChartPoint]) -> [NJInvestmentChartPoint] {
        guard selectedSnapshotChartInterval != .daily && !selectedSnapshotChartInterval.isIntraday else { return points }
        let grouped = Dictionary(grouping: points) { point in
            chartBucketKey(for: point.date, interval: selectedSnapshotChartInterval)
        }
        return grouped.values.compactMap { bucketPoints in
            bucketPoints.sorted { $0.date < $1.date }.last
        }
        .sorted { $0.date < $1.date }
    }

    private func chartBucketKey(for date: Date, interval: NJInvestmentChartInterval) -> String {
        switch interval {
        case .daily:
            return dateKey(date)
        case .hourly:
            let hour = calendar.component(.hour, from: date)
            return "\(dateKey(date))-\(hour)"
        case .fifteenMinutes:
            let hour = calendar.component(.hour, from: date)
            let minute = calendar.component(.minute, from: date)
            return "\(dateKey(date))-\(hour)-\((minute / 15) * 15)"
        case .fiveMinutes:
            let hour = calendar.component(.hour, from: date)
            let minute = calendar.component(.minute, from: date)
            return "\(dateKey(date))-\(hour)-\((minute / 5) * 5)"
        }
    }

    private var hourlyChartEmptyText: String {
        if hourlyChartSource(for: selectedSnapshotLineID) == nil {
            return "Hourly is not wired for this line yet. Daily/weekly/monthly/quarterly still use stored snapshots."
        }
        return hourlyChartStatus.isEmpty ? "Pulling hourly chart data..." : hourlyChartStatus
    }

    private func liveAdjustedMetric(_ metric: NJInvestmentSnapshotMetric) -> NJInvestmentSnapshotMetric {
        guard let quote = liveQuotes[metric.id],
              quote.isWebullSource ||
                yahooIndexFallbackSymbol(for: metric.id) != nil ||
                bondYieldFallbackSourceSymbol(for: metric.id) != nil else {
            return missingWebullMetric(metric)
        }
        return NJInvestmentSnapshotMetric(
            id: metric.id,
            title: metric.title,
            value: formattedLiveValue(quote.close, lineID: metric.id),
            change: quote.changeText,
            detail: liveMetricDetail(metric, quote: quote)
        )
    }

    private func missingWebullMetric(_ metric: NJInvestmentSnapshotMetric) -> NJInvestmentSnapshotMetric {
        if let sourceSymbol = bondYieldFallbackSourceSymbol(for: metric.id) {
            return NJInvestmentSnapshotMetric(
                id: metric.id,
                title: metric.title,
                value: "No yield data",
                change: "Missing",
                detail: "No bond-yield snapshot found for \(sourceSymbol). This macro line uses WorldGovernmentBonds / Investing.com fallback, not Webull stock quotes."
            )
        }
        if let sourceSymbol = yahooIndexFallbackSymbol(for: metric.id) {
            return NJInvestmentSnapshotMetric(
                id: metric.id,
                title: metric.title,
                value: "No index data",
                change: "Missing",
                detail: "No Yahoo chart snapshot found for \(sourceSymbol). Webull OpenAPI does not provide this cash index/FX line through the stock quote endpoint."
            )
        }
        let ticker = webullTicker(for: metric.id) ?? metric.id.uppercased()
        let gate = webullMissingGateText.map { " \($0)." } ?? ""
        return NJInvestmentSnapshotMetric(
            id: metric.id,
            title: metric.title,
            value: "No Webull data",
            change: "Missing",
            detail: "No Webull snapshot found for \(ticker).\(gate) Static Stooq/Yahoo values are hidden so this card cannot show stale quote data."
        )
    }

    private var webullMissingStatusText: String {
        if webullNetworkBackoffIsActive() {
            return "Webull network backoff"
        }
        if webullHKTokenStatus.localizedCaseInsensitiveContains("pending") {
            return "Webull token pending"
        }
        if webullHKTokenStatus.localizedCaseInsensitiveContains("invalid") {
            return "Webull token invalid"
        }
        if webullHKTokenStatus.localizedCaseInsensitiveContains("failed") {
            return "Webull token failed"
        }
        return "No Webull data"
    }

    private var webullMissingGateText: String? {
        if webullNetworkBackoffIsActive() {
            return webullHKLastNetworkError.isEmpty
                ? "Webull network failed recently; retry is paused briefly"
                : webullHKLastNetworkError
        }
        if webullHKTokenStatus.localizedCaseInsensitiveContains("pending") {
            return "Verify the Webull OpenAPI notification in Webull HK before OpenAPI quotes unlock"
        }
        if webullHKTokenStatus.localizedCaseInsensitiveContains("invalid") {
            return "Webull OpenAPI token must be recreated"
        }
        if webullHKTokenStatus.localizedCaseInsensitiveContains("failed") {
            return webullHKTokenStatus
        }
        return nil
    }

    private func liveMetricDetail(_ metric: NJInvestmentSnapshotMetric, quote: NJInvestmentLiveQuote) -> String {
        let sourceLine = "Live refresh from \(quote.source) \(quote.dateKey) \(quote.timeText)."
        let closeLine: String
        switch metric.id {
        case "us10y", "jgb", "bund10y", "uk10y":
            closeLine = "Yield level \(formattedLiveValue(quote.close, lineID: metric.id)); change is shown versus feed prior close when available."
        default:
            closeLine = "Level \(formattedLiveValue(quote.close, lineID: metric.id)); change is shown versus feed prior close when available."
        }
        return "\(sourceLine) \(closeLine)"
    }

    private func liveAdjustedChartPoints(_ points: [NJInvestmentChartPoint], lineID: String) -> [NJInvestmentChartPoint] {
        guard let quote = liveQuotes[lineID],
              let date = parseDateKey(quote.dateKey) else { return points }
        let liveValue = liveDisplayValue(quote.close, lineID: lineID)
        var out = points.filter { calendar.isDate($0.date, inSameDayAs: date) == false }
        out.append(
            NJInvestmentChartPoint(
                id: "live.\(lineID).\(quote.dateKey)",
                date: date,
                value: liveValue,
                change: quote.changeText,
                isDown: quote.isDown
            )
        )
        return out.sorted { $0.date < $1.date }
    }

    private func formattedLiveValue(_ value: Double, lineID: String) -> String {
        switch lineID {
        case "us10y", "jgb", "bund10y", "uk10y":
            return String(format: "%.2f%%", liveDisplayValue(value, lineID: lineID))
        case "eurusd", "usdcnh":
            return String(format: "%.4f", value)
        case "usdjpy":
            return String(format: "%.2f", value)
        case "bitcoin", "ethereum", "brent", "wti", "gold", "silver":
            return "$" + formattedChartValue(value)
        default:
            return formattedChartValue(value)
        }
    }

    private func liveDisplayValue(_ value: Double, lineID: String) -> Double {
        switch lineID {
        case "us10y", "jgb", "bund10y", "uk10y":
            return value > 20 ? value / 10.0 : value
        default:
            return value
        }
    }

    private func allSnapshotMetricIDs() -> [String] {
        [.us, .chinaHK, .japan, .europe, .crypto]
            .flatMap { snapshotMetrics(for: $0).map(\.id) }
    }

    private func chartPoints(from points: [NJInvestmentLinePoint]) -> [NJInvestmentChartPoint] {
        points.compactMap { point in
            guard let date = parseDateKey(point.dateKey),
                  let value = chartNumericValue(from: point.value) else { return nil }
            return NJInvestmentChartPoint(
                id: point.id,
                date: date,
                value: value,
                change: point.change,
                isDown: point.isDown
            )
        }
        .sorted { $0.date < $1.date }
    }

    private func chartNumericValue(from text: String) -> Double? {
        let cleaned = text
            .replacingOccurrences(of: ",", with: "")
            .replacingOccurrences(of: "$", with: "")
            .replacingOccurrences(of: "%", with: "")
        let pattern = #"-?\d*\.?\d+"#
        let nsRange = NSRange(cleaned.startIndex..<cleaned.endIndex, in: cleaned)
        guard let regex = try? NSRegularExpression(pattern: pattern),
              let match = regex.matches(in: cleaned, range: nsRange).last,
              let range = Range(match.range, in: cleaned) else { return nil }
        return Double(cleaned[range])
    }

    private func numericValue(from text: String) -> Double? {
        let cleaned = text
            .replacingOccurrences(of: ",", with: "")
            .replacingOccurrences(of: "$", with: "")
            .replacingOccurrences(of: "%", with: "")
        let pattern = #"[-+]?\d*\.?\d+"#
        guard let range = cleaned.range(of: pattern, options: .regularExpression) else { return nil }
        return Double(cleaned[range])
    }

