    private var hkMarketConstituentHeatRows: [NJInvestmentWatchRow] {
        chinaHKMarketConstituentHeatRows.filter { row in
            row.symbol.uppercased().contains(" HK")
        }
    }

    private var chinaMarketConstituentHeatRows: [NJInvestmentWatchRow] {
        chinaHKMarketConstituentHeatRows.filter { row in
            let symbol = row.symbol.uppercased()
            return symbol.contains(" CN") || symbol.contains("CNY") || symbol.contains("CNH")
        }
    }

