    private func heatConstituent(_ symbol: String, _ name: String, _ sector: String, _ marketCap: Double, _ index: String) -> NJInvestmentHeatConstituent {
        NJInvestmentHeatConstituent(symbol: symbol, name: name, sector: sector, marketCap: marketCap, index: index)
    }

    private func marketHeatRow(_ symbol: String, _ name: String, _ sector: String, index: String = "Market-wide", marketCap: Double? = nil) -> NJInvestmentWatchRow {
        NJInvestmentWatchRow(
            id: "market-wide-\(symbol.lowercased().replacingOccurrences(of: " ", with: "-").replacingOccurrences(of: "/", with: "-"))",
            symbol: symbol,
            name: name,
            monitorDate: "Market-wide",
            resultDate: index,
            usCloseReference: index,
            tPlusOne: sector,
            tPlusThree: "Broad market breadth symbol",
            initialPrice: "Refresh",
            week52High: marketCap.map { String($0) } ?? "Refresh",
            week52Low: "Refresh",
            todayPrice: "Refresh",
            percentChange: "Refresh"
        )
    }

    private func heatBenchmarkRows(for market: NJInvestmentMarket) -> [NJInvestmentWatchRow] {
        switch market {
        case .all:
            return [
                heatBenchmarkRow("SPX", "S&P 500", "US broad benchmark"),
                heatBenchmarkRow("NASDAQ", "Nasdaq Composite", "US tech/risk benchmark"),
                heatBenchmarkRow("HSI", "Hang Seng Index", "HK benchmark"),
                heatBenchmarkRow("SHANGHAI-A", "Shanghai A", "China Shanghai benchmark"),
                heatBenchmarkRow("SHENZHEN-A", "Shenzhen Component", "China Shenzhen benchmark"),
                heatBenchmarkRow("NIKKEI", "Nikkei 225", "Japan benchmark"),
                heatBenchmarkRow("STOXX600", "STOXX Europe 600", "Europe benchmark"),
                heatBenchmarkRow("BTC-USD", "Bitcoin", "Crypto risk benchmark")
            ]
        case .us:
            return [
                heatBenchmarkRow("SPX", "S&P 500", "US broad benchmark"),
                heatBenchmarkRow("NASDAQ", "Nasdaq Composite", "US tech/risk benchmark"),
                heatBenchmarkRow("DOW", "Dow Jones Industrial Average", "US blue-chip benchmark"),
                heatBenchmarkRow("RUSSELL2000", "Russell 2000", "US small-cap breadth")
            ]
        case .hk:
            return [
                heatBenchmarkRow("HSI", "Hang Seng Index", "HK benchmark"),
                heatBenchmarkRow("HSTECH", "Hang Seng TECH", "HK tech beta"),
                heatBenchmarkRow("HSCEI", "Hang Seng China Enterprises", "H-share flow proxy")
            ]
        case .china:
            return [
                heatBenchmarkRow("SHANGHAI-A", "Shanghai A", "Shanghai A-share benchmark"),
                heatBenchmarkRow("SHENZHEN-A", "Shenzhen Component", "Shenzhen A-share benchmark"),
                heatBenchmarkRow("CSI300", "CSI 300", "Mainland large-cap benchmark"),
                heatBenchmarkRow("CHINEXT", "ChiNext", "China growth/tech beta")
            ]
        case .chinaHK:
            return [
                heatBenchmarkRow("HSI", "Hang Seng Index", "HK benchmark"),
                heatBenchmarkRow("HSTECH", "Hang Seng TECH", "HK tech beta"),
                heatBenchmarkRow("SHANGHAI-A", "Shanghai A", "Shanghai A-share benchmark"),
                heatBenchmarkRow("SHENZHEN-A", "Shenzhen Component", "Shenzhen A-share benchmark")
            ]
