    private func heatBenchmarkRow(_ symbol: String, _ name: String, _ index: String) -> NJInvestmentWatchRow {
        marketHeatRow(symbol, name, "Major Index", index: index, marketCap: nil)
    }

    private func heatRows(for market: NJInvestmentMarket) -> [NJInvestmentWatchRow] {
        let rows: [NJInvestmentWatchRow]
        switch market {
        case .all:
            rows = marketWideHeatRows + usMarketConstituentHeatRows + hkMarketConstituentHeatRows + chinaMarketConstituentHeatRows + japanMarketConstituentHeatRows
        case .us:
            rows = usMarketConstituentHeatRows
        case .hk:
            rows = hkMarketConstituentHeatRows
        case .china:
            rows = chinaMarketConstituentHeatRows
        case .chinaHK:
            rows = chinaHKMarketConstituentHeatRows
        case .japan:
            rows = japanMarketConstituentHeatRows
        case .europe:
            rows = europeMarketConstituentHeatRows
        case .crypto:
            rows = cryptoMarketConstituentHeatRows
        }
        var seen = Set<String>()
        return rows
            .filter { row in
                seen.insert(row.symbol.uppercased()).inserted
            }
            .filter { row in
                if market == .all { return true }
                let rowMarket = heatMarket(for: row)
                if market == .chinaHK { return rowMarket == .hk || rowMarket == .china }
                return rowMarket == market
            }
            .sorted { lhs, rhs in
                let lhsCap = heatMarketCap(for: lhs) ?? 0
                let rhsCap = heatMarketCap(for: rhs) ?? 0
                if lhsCap != rhsCap { return lhsCap > rhsCap }
                let lhsMove = abs(heatMove(for: lhs) ?? 0)
                let rhsMove = abs(heatMove(for: rhs) ?? 0)
                if lhsMove != rhsMove { return lhsMove > rhsMove }
                return lhs.symbol < rhs.symbol
            }
    }

    private func heatlistScopeText(for market: NJInvestmentMarket) -> String {
        switch market {
        case .all:
            return "Global market flow across US, HK/China, Japan, Europe, and commodities. Tile size follows market cap so the largest companies visually carry more weight."
        case .us:
