        }
    }

    private func heatSectorGroups(for market: NJInvestmentMarket) -> [(sector: String, rows: [NJInvestmentWatchRow], average: Double?)] {
        let grouped = Dictionary(grouping: heatRows(for: market), by: heatSectorName(for:))
        return grouped.map { sector, rows in
            let weighted = rows.compactMap { row -> (move: Double, cap: Double)? in
                guard let move = heatMove(for: row) else { return nil }
                return (move, max(heatMarketCap(for: row) ?? 1, 1))
            }
            let capSum = weighted.map(\.cap).reduce(0, +)
            let average = capSum > 0 ? weighted.map { $0.move * $0.cap }.reduce(0, +) / capSum : nil
            return (sector: sector, rows: rows, average: average)
        }
        .sorted { lhs, rhs in
            let l = abs(lhs.average ?? -999)
            let r = abs(rhs.average ?? -999)
            if l != r { return l > r }
            return lhs.sector < rhs.sector
        }
    }

    private func heatCacheKey(for symbol: String, timeframe: NJInvestmentHeatTimeframe) -> String {
        "\(timeframe.rawValue).\(symbol.uppercased())"
    }

    private func refreshHeatMapIfVisible(reason: String) {
        guard store.selectedInvestmentSection == .macroLine || store.selectedInvestmentSection == .heatlist else { return }
        guard !isHeatRefreshRunning else { return }
        let rows = heatBenchmarkRows(for: selectedHeatMarket) + heatRows(for: selectedHeatMarket)
        let targets = rows.compactMap { row -> (NJInvestmentWatchRow, String)? in
            guard let sourceSymbol = yahooWatchChartSymbol(for: row.symbol) else { return nil }
            return (row, sourceSymbol)
        }
        guard !targets.isEmpty else {
            heatRefreshStatus = "No external symbols mapped"
            return
        }

        isHeatRefreshRunning = true
        heatRefreshStatus = "Calculating \(selectedHeatTimeframe.rawValue.lowercased()) heat..."
        let timeframe = selectedHeatTimeframe
        Task {
            let snapshots = await fetchHeatSnapshots(targets: targets, timeframe: timeframe)
            await MainActor.run {
                for (symbol, move, marketCap) in snapshots {
                    heatReturnCache[heatCacheKey(for: symbol, timeframe: timeframe)] = move
                    if let marketCap {
                        heatMarketCapCache[symbol.uppercased()] = marketCap
                    }
                }
                let formatter = DateFormatter()
                formatter.dateFormat = "HH:mm"
                heatRefreshStatus = snapshots.isEmpty
                    ? "No market-wide heat data"
                    : "\(timeframe.rawValue) constituent heat \(formatter.string(from: Date())) \(snapshots.count)/\(targets.count)"
                isHeatRefreshRunning = false
            }
        }
    }

    private func fetchHeatSnapshots(targets: [(NJInvestmentWatchRow, String)], timeframe: NJInvestmentHeatTimeframe) async -> [(String, Double, Double?)] {
        await withTaskGroup(of: (String, Double, Double?)?.self) { group in
            for (row, sourceSymbol) in targets {
                group.addTask {
                    guard let snapshot = await fetchYahooHeatSnapshot(sourceSymbol: sourceSymbol, timeframe: timeframe) else { return nil }
                    return (row.symbol, snapshot.move, snapshot.marketCap)
                }
            }

            var out: [(String, Double, Double?)] = []
            for await item in group {
                if let item { out.append(item) }
            }
            return out
        }
    }

    private nonisolated func fetchYahooHeatSnapshot(sourceSymbol: String, timeframe: NJInvestmentHeatTimeframe) async -> (move: Double, marketCap: Double?)? {
        let encoded = sourceSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? sourceSymbol
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=\(timeframe.yahooRange)&interval=1d") else { return nil }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = root["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let meta = result["meta"] as? [String: Any],
                  let indicators = result["indicators"] as? [String: Any],
                  let quotes = indicators["quote"] as? [[String: Any]],
                  let quote = quotes.first,
                  let closes = quote["close"] as? [Any] else { return nil }
            let validCloses = closes.compactMap { value -> Double? in
                if let value = value as? Double { return value }
                if let value = value as? Int { return Double(value) }
                if let value = value as? NSNumber { return value.doubleValue }
                if let value = value as? String { return Double(value) }
                return nil
            }
            guard validCloses.count > timeframe.lookbackSessions else { return nil }
            let latest = validCloses[validCloses.count - 1]
            let prior = validCloses[validCloses.count - 1 - timeframe.lookbackSessions]
            guard prior != 0 else { return nil }
            let marketCap: Double? = {
                if let value = meta["marketCap"] as? Double { return value }
                if let value = meta["marketCap"] as? Int { return Double(value) }
                if let value = meta["marketCap"] as? NSNumber { return value.doubleValue }
                if let value = meta["marketCap"] as? String { return Double(value) }
                return nil
            }()
            return ((latest / prior - 1) * 100.0, marketCap)
        } catch {
            return nil
        }
    }

    private func heatMarket(for row: NJInvestmentWatchRow) -> NJInvestmentMarket {
        let symbol = row.symbol.uppercased()
        let text = "\(row.name) \(row.usCloseReference) \(row.tPlusOne)".lowercased()
        if ["EWU", "EWG", "EWQ", "SAP", "NVO", "SHEL", "TTE"].contains(symbol) || text.contains("united kingdom") || text.contains("germany") || text.contains("france") {
            return .europe
        }
        if ["SPX", "NASDAQ", "DOW", "RUSSELL2000"].contains(symbol) {
            return .us
        }
        if ["HSI", "HSTECH", "HSCEI"].contains(symbol) {
            return .hk
        }
        if ["SHANGHAI-A", "SHENZHEN-A", "CSI300", "CHINEXT"].contains(symbol) {
            return .china
        }
        if ["NIKKEI", "TOPIX", "USDJPY"].contains(symbol) {
            return .japan
        }
        if ["STOXX600", "STOXX50", "FTSE100", "DAX"].contains(symbol) {
            return .europe
        }
        if ["BTC-USD", "ETH-USD", "GOLD", "WTI"].contains(symbol) {
            return .crypto
        }
        if symbol.contains(" HK") {
            return .hk
        }
        if symbol.contains(" CN") || symbol.contains("CNY") || symbol.contains("CNH") {
            return .china
        }
        if symbol.contains(" JP") || text.contains("japan") || text.contains("jpy") || symbol.contains("JPY") {
            return .japan
        }
        if symbol.contains(" FP") || symbol.contains(" GR") || symbol.contains(" LN") || symbol == "ASML" {
            return .europe
        }
        if symbol.contains("/") || text.contains("gold") || text.contains("oil") || text.contains("copper") || text.contains("commodity") {
            return .crypto
        }
        return .us
    }

    private func heatSectorName(for row: NJInvestmentWatchRow) -> String {
        let symbol = row.symbol.uppercased()
        let text = "\(row.name) \(row.usCloseReference) \(row.tPlusOne) \(row.tPlusThree)".lowercased()
        let explicitSectors = [
            "Index / ETF",
            "AI / Semis",
            "Software / Cloud",
            "Internet Platforms",
            "Financials",
            "Power / Infrastructure",
            "EV / Battery",
            "Health Care",
            "Consumer / Retail",
            "Commodity / Food",
            "Commodity / Crypto",
            "Industrials",
            "Sector ETF",
            "Information Technology",
            "Communication Services",
            "Consumer Discretionary",
            "Consumer Staples",
            "Energy",
            "Materials",
            "Utilities",
            "Real Estate",
            "China Flow / Index",
            "Major Index"
        ]
        if explicitSectors.contains(row.tPlusOne) {
            return row.tPlusOne == "Commodity / Crypto" ? "Commodity / Food" : row.tPlusOne
        }
        if ["QQQ", "SQQQ", "SPY", "RSP", "IWM", "SMH", "SOXX"].contains(symbol) { return "Index / ETF" }
        if text.contains("hbm") || text.contains("semi") || text.contains("gpu") || text.contains("ai accelerator") || text.contains("foundry") || text.contains("memory") || text.contains("networking") || ["NVDA", "AMD", "AVGO", "MU", "TSM", "ASML"].contains(symbol) { return "AI / Semis" }
        if text.contains("software") || text.contains("saas") || text.contains("cloud") || ["MSFT", "CRM", "NOW", "SNOW", "PLTR", "ORCL"].contains(symbol) { return "Software / Cloud" }
        if text.contains("china internet") || text.contains("commerce") || text.contains("gaming") || text.contains("ads") || text.contains("platform") || ["0700 HK", "9988 HK", "3690 HK", "9618 HK", "9888 HK"].contains(symbol) { return "Internet Platforms" }
        if text.contains("bank") || text.contains("insurance") || text.contains("financial") || ["JPM", "BRK.B", "V"].contains(symbol) { return "Financials" }
        if text.contains("utility") || text.contains("power") || text.contains("infrastructure") || text.contains("equipment rental") { return "Power / Infrastructure" }
        if text.contains("ev") || text.contains("battery") || text.contains("auto") || symbol == "TSLA" { return "EV / Battery" }
        if text.contains("health") || text.contains("pharma") || text.contains("medicine") || ["LLY", "UNH", "JNJ", "PFE"].contains(symbol) { return "Health Care" }
        if text.contains("retail") || text.contains("consumer") || ["COST", "WMT", "AMZN", "NKE"].contains(symbol) { return "Consumer / Retail" }
        if text.contains("gold") || text.contains("oil") || text.contains("copper") || text.contains("food") || text.contains("fertilizer") || text.contains("commodity") { return "Commodity / Food" }
        return "Other Watch"
    }

    private func heatMove(for row: NJInvestmentWatchRow) -> Double? {
        if let cached = heatReturnCache[heatCacheKey(for: row.symbol, timeframe: selectedHeatTimeframe)] {
            return cached
        }
        if let liveMove = liveQuotes[row.symbol].flatMap({ numericValue(from: $0.changeText) }) {
            return liveMove
        }
        return numericValue(from: row.percentChange)
    }

    private func heatMarketCap(for row: NJInvestmentWatchRow) -> Double? {
        let key = row.symbol.uppercased()
        if let cached = heatMarketCapCache[key] {
            return cached
        }
        if let fallback = Double(row.week52High), fallback > 1_000_000 {
            return fallback
        }
        return nil
    }

    private func heatTileHeight(for row: NJInvestmentWatchRow) -> CGFloat {
        guard let cap = heatMarketCap(for: row), cap > 0 else { return 92 }
        let trillion = cap / 1_000_000_000_000
        let scaled = 82 + sqrt(max(trillion, 0.04)) * 74
        return min(max(scaled, 92), isCompactLayout ? 190 : 240)
    }

    private func heatTileColor(_ move: Double?) -> Color {
        guard let move else { return Color(UIColor.secondarySystemGroupedBackground) }
        if move >= 3 { return Color.green.opacity(0.42) }
        if move >= 1 { return Color.green.opacity(0.27) }
        if move > 0 { return Color.green.opacity(0.16) }
        if move <= -3 { return Color.red.opacity(0.42) }
        if move <= -1 { return Color.red.opacity(0.27) }
        if move < 0 { return Color.red.opacity(0.16) }
        return Color(UIColor.secondarySystemGroupedBackground)
    }

    private func heatTextColor(_ move: Double?) -> Color {
        guard let move else { return .secondary }
        if move > 0 { return .green }
        if move < 0 { return .red }
        return .secondary
    }

