    private var selectedIndustryTheme: NJInvestmentIndustryTheme? {
        industryThemes.first { $0.id == selectedIndustryThemeID } ?? industryThemes.first
    }

    private func industryRows(for theme: NJInvestmentIndustryTheme) -> [NJInvestmentWatchRow] {
        let wanted = Set(theme.symbols.map { $0.uppercased() })
        let matched = allInvestmentHeatRows.filter { wanted.contains($0.symbol.uppercased()) }
        let existing = Set(matched.map { $0.symbol.uppercased() })
        let placeholders = theme.symbols
            .filter { !existing.contains($0.uppercased()) }
            .map {
                NJInvestmentWatchRow(
                    id: "industry-placeholder-\($0)",
                    symbol: $0,
                    name: $0,
                    monitorDate: "Watch",
                    resultDate: "TBD",
                    usCloseReference: theme.title,
                    tPlusOne: "Industry heat symbol",
                    tPlusThree: "Open console after quote source is wired",
                    initialPrice: "Refresh",
                    week52High: "Refresh",
                    week52Low: "Refresh",
                    todayPrice: "Refresh",
                    percentChange: "Refresh"
                )
            }
        return matched + placeholders
    }

    @MainActor
    private func refreshIndustryNews(force: Bool) async {
        guard let theme = selectedIndustryTheme else { return }
        if isIndustryNewsLoading { return }
        if !force, !industryNewsItems.isEmpty, industryNewsStatus.contains(theme.title) { return }

        isIndustryNewsLoading = true
        industryNewsStatus = "Loading"
        var seen = Set<String>()
        var rows: [NJObservationNewsItem] = []
        for query in theme.newsQueries {
            let items = await fetchIndustryGoogleNewsRSS(query: query)
            for item in items where seen.insert(item.title.normalizedObservationNewsKey).inserted {
                rows.append(item)
                if rows.count >= 8 { break }
            }
            if rows.count >= 8 { break }
        }
        industryNewsItems = rows.sorted(by: observationNewsSort)
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm"
        industryNewsStatus = rows.isEmpty ? "No news" : "\(theme.title) \(formatter.string(from: Date()))"
        isIndustryNewsLoading = false
    }

    private func fetchIndustryGoogleNewsRSS(query: String) async -> [NJObservationNewsItem] {
        var components = URLComponents(string: "https://news.google.com/rss/search")
        components?.queryItems = [
            URLQueryItem(name: "q", value: "\(query) when:1d"),
            URLQueryItem(name: "hl", value: "en-US"),
            URLQueryItem(name: "gl", value: "US"),
            URLQueryItem(name: "ceid", value: "US:en")
        ]
        guard let url = components?.url else { return [] }

        do {
            var request = URLRequest(url: url, timeoutInterval: 8)
            request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")
            let (data, _) = try await URLSession.shared.data(for: request)
            return NJObservationRSSParser.parse(data: data)
        } catch {
            NJInvestmentDebugLog("INDUSTRY_NEWS_ERR query=\(query) err=\(error.localizedDescription)")
            return []
        }
    }

    private func formattedChartValue(_ value: Double) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .decimal
        formatter.maximumFractionDigits = value >= 100 ? 1 : 2
        return formatter.string(from: NSNumber(value: value)) ?? "\(value)"
    }

