    private var compactCalendarAgenda: some View {
        let rows = calendarCells
            .filter { $0.day != nil }
            .map { cell -> NJInvestmentCompactCalendarRow in
                NJInvestmentCompactCalendarRow(
                    id: cell.key,
                    cell: cell,
                    events: filteredEvents(on: cell.key)
                )
            }
            .filter { !$0.events.isEmpty || $0.cell.isToday }

        return VStack(alignment: .leading, spacing: 8) {
            if rows.isEmpty {
                Text("No tracked macro events in this view.")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(12)
                    .background(Color(UIColor.secondarySystemGroupedBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 8))
            } else {
                ForEach(rows) { row in
                    compactCalendarRow(row.cell, events: row.events)
                }
            }
        }
    }

    private func compactCalendarRow(
        _ cell: (key: String, day: Int?, isToday: Bool),
        events: [NJFinanceMacroEvent]
    ) -> some View {
        let hasReportCardEvent = events.contains(where: isSystemRedDate)
        return VStack(alignment: .leading, spacing: 8) {
            HStack {
                Text(compactCalendarDateTitle(cell.key))
                    .font(.subheadline.weight(.semibold))
                    .foregroundStyle(hasReportCardEvent ? Color.red : (cell.isToday ? Color.accentColor : Color.primary))
                Spacer()
                if !events.isEmpty {
                    Text("\(events.count)")
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(.white)
                        .frame(width: 18, height: 18)
                        .background(hasReportCardEvent ? Color.red : Color.accentColor)
                        .clipShape(Circle())
                }
            }

            ForEach(events, id: \.eventID) { event in
                Button {
                    selectedEvent = event
                } label: {
                    Text(event.title)
                        .font(.caption.weight(.semibold))
                        .lineLimit(2)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(.horizontal, 8)
                        .padding(.vertical, 6)
                        .background(eventColor(event).opacity(0.16))
                        .clipShape(RoundedRectangle(cornerRadius: 6))
                }
                .buttonStyle(.plain)
            }
        }
        .padding(10)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color(UIColor.secondarySystemGroupedBackground))
        .clipShape(RoundedRectangle(cornerRadius: 8))
        .overlay {
            RoundedRectangle(cornerRadius: 8)
                .stroke(hasReportCardEvent ? Color.red.opacity(0.55) : Color.clear, lineWidth: 1.5)
        }
    }

    private func compactCalendarDateTitle(_ key: String) -> String {
        guard let date = parseDateKey(key) else { return key }
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "MMM d, EEE"
        return formatter.string(from: date)
    }

