    private func filteredEvents(on dateKey: String) -> [NJFinanceMacroEvent] {
        let storedEvents = (eventsByDate[dateKey] ?? [])
            .filter { shouldIncludeInMacroCalendar($0) }
            .filter { selectedMarket.matches(region: $0.region) }
        let watchlistEvents = watchlistCalendarEvents(on: dateKey)
            .filter { selectedMarket.matches(region: $0.region) }
        let systemEvents = systemCalendarEvents(on: dateKey)
            .filter { selectedMarket.matches(region: $0.region) }

        return (storedEvents + watchlistEvents + systemEvents)
            .sorted { ($0.impact, $0.timeText, $0.title) < ($1.impact, $1.timeText, $1.title) }
    }

    private func systemCalendarEvents(on dateKey: String) -> [NJFinanceMacroEvent] {
        let definitions = [
            ("system.us.cpi", "US CPI", "inflation_report_card", "US", "08:30 ET", "BLS CPI release; inflation report-card date.", Set(usCPIReleaseDateKeys2026)),
            ("system.us.payrolls", "US Payrolls / Unemployment", "labor_report_card", "US", "08:30 ET", "BLS Employment Situation release; labor report-card date.", Set(usPayrollReleaseDateKeys2026)),
            ("system.us.fomc", "FOMC Decision", "central_report_card", "US", "14:00 ET", "Federal Reserve policy decision / press conference window.", Set(fomcDecisionDateKeys2026)),
            ("system.us.triplewitch", "Triple Witching / OPEX", "triple_witching", "US", "All day", "Quarterly options expiration / forced positioning day.", Set(tripleWitchingDateKeys2026))
        ]

        let nowMs = DBNoteRepository.nowMs()
        return definitions.compactMap { prefix, title, category, region, timeText, notes, dates in
            guard dates.contains(dateKey) else { return nil }
            return NJFinanceMacroEvent(
                eventID: "\(prefix).\(dateKey)",
                dateKey: dateKey,
                title: title,
                category: category,
                region: region,
                timeText: timeText,
                impact: "high",
                source: "System calendar",
                notes: notes,
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                deleted: 0
            )
        }
    }

