    private func seedInvestmentSymbolRegistryIfNeeded() {
        let seedKey = "nj_investment_symbol_registry_seed_2026_05_06_v1"
        guard UserDefaults.standard.string(forKey: seedKey) != "1" else { return }

        let nowMs = DBNoteRepository.nowMs()
        var symbolsByID: [String: NJInvestmentSymbolRecord] = [:]
        var relationshipsByID: [String: NJInvestmentSymbolRelationshipRecord] = [:]

        func addSymbol(displaySymbol: String, name: String, sourceTitle: String, macroTags: [String]) -> String {
            let symbolID = investmentRegistrySymbolID(displaySymbol)
            guard !symbolID.isEmpty else { return "" }
            let metadata = investmentRegistryMetadata(displaySymbol: displaySymbol)
            let keywords = investmentRegistryJSONString([displaySymbol, name].filter { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty })
            symbolsByID[symbolID] = NJInvestmentSymbolRecord(
                symbolID: symbolID,
                displaySymbol: displaySymbol,
                name: name,
                assetClass: metadata.assetClass,
                market: metadata.market,
                exchange: metadata.exchange,
                currency: metadata.currency,
                ibSymbol: metadata.ibSymbol,
                ibSecType: metadata.ibSecType,
                ibExchange: metadata.ibExchange,
                ibCurrency: metadata.ibCurrency,
                newsKeywordsJSON: keywords,
                macroTagsJSON: investmentRegistryJSONString(macroTags + [sourceTitle]),
                status: "active",
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                deleted: 0
            )
            return symbolID
        }

        func addRelationship(symbolID: String, sourceType: String, sourceID: String, sourceTitle: String, role: String, priority: Int64, alertMode: String, notes: String) {
            guard !symbolID.isEmpty else { return }
            let relationshipID = investmentRegistryRelationshipID(sourceType: sourceType, sourceID: sourceID, symbolID: symbolID)
            relationshipsByID[relationshipID] = NJInvestmentSymbolRelationshipRecord(
                relationshipID: relationshipID,
                symbolID: symbolID,
                sourceType: sourceType,
                sourceID: sourceID,
                sourceTitle: sourceTitle,
                role: role,
                priority: priority,
                status: "watch",
                alertMode: alertMode,
                openedAtMs: nowMs,
                closedAtMs: 0,
                notes: notes,
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                deleted: 0
            )
        }

        func addRows(_ rows: [NJInvestmentWatchRow], sourceID: String, sourceTitle: String, role: String, priority: Int64, alertMode: String = "digest") {
            for row in rows {
                let symbolID = addSymbol(displaySymbol: row.symbol, name: row.name, sourceTitle: sourceTitle, macroTags: [role])
                addRelationship(
                    symbolID: symbolID,
                    sourceType: "trade_thesis",
                    sourceID: sourceID,
                    sourceTitle: sourceTitle,
                    role: role,
                    priority: priority,
                    alertMode: alertMode,
                    notes: row.resultDate.isEmpty ? row.usCloseReference : row.resultDate
                )
            }
        }

        func addMacroProxy(sourceID: String, sourceTitle: String, market: String, role: String, priority: Int64, notes: String) {
            let symbolID = investmentRegistrySymbolID("macro-\(sourceID)")
            symbolsByID[symbolID] = NJInvestmentSymbolRecord(
                symbolID: symbolID,
                displaySymbol: "MACRO:\(sourceID)",
                name: sourceTitle,
                assetClass: "macro",
                market: market,
                exchange: "Macro",
                currency: "",
                ibSymbol: "",
                ibSecType: "IND",
                ibExchange: "",
                ibCurrency: "",
                newsKeywordsJSON: investmentRegistryJSONString([sourceTitle, market, role]),
                macroTagsJSON: investmentRegistryJSONString([role, market, sourceTitle]),
                status: "active",
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                deleted: 0
            )
            addRelationship(
                symbolID: symbolID,
                sourceType: "macro_watch",
                sourceID: sourceID,
                sourceTitle: sourceTitle,
                role: role,
                priority: priority,
                alertMode: "breaking",
                notes: notes
            )
        }

        addRows(watchListRows, sourceID: "saas-overshoot", sourceTitle: "2026 Q1 Software overshoot", role: "software_watchlist", priority: 2)
        addRows(usQ1WatchListRows, sourceID: "us-q1-trade", sourceTitle: "2026 Q1 US Trade", role: "us_q1_watchlist", priority: 2)
        addRows(alternativeAssetWatchListRows, sourceID: "alternative-asset", sourceTitle: "Alternative Asset", role: "macro_cross_asset", priority: 1, alertMode: "breaking")
        addRows(mfsCashParkingRows, sourceID: "mfs-cash-parking", sourceTitle: "Cash Parking MFS", role: "mfs_cash_parking", priority: 3)
        addRows(mfsBeatenDownQualityRows, sourceID: "mfs-beaten-down-quality", sourceTitle: "Beaten-Down Quality MFS", role: "mfs_quality", priority: 3)
        addRows(mfsUSKeyNameRows, sourceID: "mfs-us-key-names", sourceTitle: "Mag 7 / US Key Names MFS", role: "mfs_us_key_name", priority: 3)
        addRows(mfsAShareRows, sourceID: "mfs-ashare", sourceTitle: "Shanghai A-Share MFS", role: "mfs_ashare", priority: 3)
        addRows(japanJPYWatchListRows, sourceID: "japan-jpy-trade", sourceTitle: "2026 Japan Trade", role: "japan_jpy", priority: 2)
        addRows(chinaAIWatchListRows, sourceID: "china-ai", sourceTitle: "China AI Trade", role: "china_ai", priority: 2)
        addRows(chinaBankWatchListRows, sourceID: "china-high-yield-bank", sourceTitle: "China High Yield Banks", role: "china_high_yield", priority: 3)
        addRows(chinaHighDividendWatchListRows, sourceID: "china-high-dividend", sourceTitle: "China High Dividend", role: "china_high_dividend", priority: 3)
        addRows(globalAIEquipmentRentalWatchListRows, sourceID: "global-ai-equipment-rental", sourceTitle: "2026 Global AI Infrastructure / US Equipment Rental", role: "ai_equipment_rental", priority: 1)
        addRows(globalAIMaterialsWatchListRows, sourceID: "global-ai-materials", sourceTitle: "2026 Global AI Infrastructure / Global Material Stock", role: "ai_materials", priority: 1)
        addRows(globalAIPowerEquipmentWatchListRows, sourceID: "global-ai-power-equipment", sourceTitle: "2026 Global AI Infrastructure / Global Power Equipment", role: "ai_power_equipment", priority: 1)
        addRows(globalAINetworkEquipmentWatchListRows, sourceID: "global-ai-network-equipment", sourceTitle: "2026 Global AI Infrastructure / Global Network Equipment", role: "ai_network_equipment", priority: 1)
        addRows(foodScareWatchListRows, sourceID: "food-scare-2026", sourceTitle: "2026 Food Scare", role: "food_scare", priority: 2, alertMode: "breaking")

        for item in investmentAlertWatchItems {
            let symbolID = addSymbol(displaySymbol: item.displaySymbol, name: item.name, sourceTitle: "Investment Alert Watchlist", macroTags: item.tags)
            addRelationship(
                symbolID: symbolID,
                sourceType: "watchlist_alert",
                sourceID: item.id,
                sourceTitle: "Investment Alert Watchlist / \(item.name)",
                role: "price_alert",
                priority: 1,
                alertMode: "breaking",
                notes: item.decisionQuestion
            )
        }

        for signal in macroSignals {
            addMacroProxy(
                sourceID: signal.id,
                sourceTitle: signal.title,
                market: signal.market.rawValue,
                role: "macro_signal",
                priority: signal.status.lowercased() == "stress" ? 1 : 2,
                notes: "\(signal.note) Next catalyst: \(signal.nextCatalyst)"
            )
        }

        for checklist in marketChecklists {
            addMacroProxy(
                sourceID: "checklist-\(checklist.id)",
                sourceTitle: checklist.title,
                market: checklist.market.rawValue,
                role: "macro_checklist",
                priority: 2,
                notes: checklist.items.joined(separator: " | ")
            )
        }

        for theme in industryThemes {
            for symbol in theme.symbols {
                let symbolID = addSymbol(displaySymbol: symbol, name: symbol, sourceTitle: theme.title, macroTags: theme.watchItems)
                addRelationship(
                    symbolID: symbolID,
                    sourceType: "industry_theme",
                    sourceID: theme.id,
                    sourceTitle: theme.title,
                    role: theme.mapRole,
                    priority: 3,
                    alertMode: "digest",
                    notes: theme.summary
                )
            }
        }

        let manualThesisSymbols: [(sourceID: String, title: String, role: String, symbols: [(String, String)])] = [
            ("dream-girl-mag7", "Dream Girl Trade / Mag 7", "mag7_relative_strength", [("NVDA", "Nvidia"), ("MSFT", "Microsoft"), ("AAPL", "Apple"), ("AMZN", "Amazon"), ("META", "Meta Platforms"), ("GOOGL", "Alphabet"), ("TSLA", "Tesla")]),
            ("trump-xi", "Trump-Xi Trade", "china_policy_macro", [("USD/CNH", "Offshore yuan"), ("KWEB", "China internet ETF"), ("FXI", "China large-cap ETF"), ("MCHI", "China ETF")]),
            ("commodity-crypto-major-news", "Commodity / Crypto News Tape", "commodity_crypto_news", [("BTC-USD", "Bitcoin"), ("ETH-USD", "Ethereum"), ("WTI", "WTI crude"), ("Brent", "Brent crude"), ("XAU/USD", "Gold spot"), ("XAG/USD", "Silver spot")])
        ]

        for thesis in manualThesisSymbols {
            for symbol in thesis.symbols {
                let symbolID = addSymbol(displaySymbol: symbol.0, name: symbol.1, sourceTitle: thesis.title, macroTags: [thesis.role])
                addRelationship(
                    symbolID: symbolID,
                    sourceType: "trade_thesis",
                    sourceID: thesis.sourceID,
                    sourceTitle: thesis.title,
                    role: thesis.role,
                    priority: 2,
                    alertMode: thesis.role.contains("macro") || thesis.role.contains("news") ? "breaking" : "digest",
                    notes: "Seeded from Investment Module trade thesis watch text."
                )
            }
        }

        for symbol in symbolsByID.values {
            store.notes.upsertInvestmentSymbol(symbol)
        }
        for relationship in relationshipsByID.values {
            store.notes.upsertInvestmentSymbolRelationship(relationship)
        }

        UserDefaults.standard.set("1", forKey: seedKey)
        store.sync.schedulePush(debounceMs: 0)
        NJInvestmentDebugLog("SYMBOL_REGISTRY_SEEDED symbols=\(symbolsByID.count) relationships=\(relationshipsByID.count)")
    }

    private func investmentRegistrySymbolID(_ displaySymbol: String) -> String {
        let upper = displaySymbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let mapped = upper.unicodeScalars.map { scalar -> Character in
            CharacterSet.alphanumerics.contains(scalar) ? Character(scalar) : "-"
        }
        return String(mapped).split(separator: "-").joined(separator: "-").lowercased()
    }

    private func investmentRegistryRelationshipID(sourceType: String, sourceID: String, symbolID: String) -> String {
        investmentRegistrySymbolID("\(sourceType)-\(sourceID)-\(symbolID)")
    }

    private func investmentRegistryJSONString(_ values: [String]) -> String {
        let cleaned = Array(Set(values.map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }.filter { !$0.isEmpty })).sorted()
        guard let data = try? JSONSerialization.data(withJSONObject: cleaned),
              let text = String(data: data, encoding: .utf8) else {
            return "[]"
        }
        return text
    }

    private func investmentRegistryMetadata(displaySymbol: String) -> (assetClass: String, market: String, exchange: String, currency: String, ibSymbol: String, ibSecType: String, ibExchange: String, ibCurrency: String) {
        let symbol = displaySymbol.trimmingCharacters(in: .whitespacesAndNewlines)
        let upper = symbol.uppercased()
        if upper.hasSuffix(" HK") {
            return ("equity", "HK", "HKSE", "HKD", String(symbol.dropLast(3)), "STK", "SEHK", "HKD")
        }
        if upper.hasSuffix(" JP") {
            return ("equity", "Japan", "TSE", "JPY", String(symbol.dropLast(3)), "STK", "TSEJ", "JPY")
        }
        if upper.hasSuffix(" FP") {
            return ("equity", "France", "Euronext Paris", "EUR", String(symbol.dropLast(3)), "STK", "SBF", "EUR")
        }
        if upper.hasSuffix(" GR") {
            return ("equity", "Germany", "Xetra", "EUR", String(symbol.dropLast(3)), "STK", "IBIS", "EUR")
        }
        if upper.contains("/") {
            return ("fx", "Global", "FX", upper, upper.replacingOccurrences(of: "/", with: ""), "CASH", "IDEALPRO", String(upper.suffix(3)))
        }
        if upper.hasSuffix("-USD") || upper == "BTC" || upper == "ETH" {
            return ("crypto", "Global", "Crypto", "USD", upper.replacingOccurrences(of: "-USD", with: ""), "CRYPTO", "PAXOS", "USD")
        }
        if ["WTI", "BRENT", "GOLD", "SILVER"].contains(upper) {
            return ("commodity", "Global", "Commodity", "USD", upper, "CMDTY", "SMART", "USD")
        }
        return ("equity", "US", "US", "USD", upper, "STK", "SMART", "USD")
    }

    private func fallbackWatchlistMonitorEvents(on dateKey: String) -> [NJFinanceMacroEvent] {
        let nowMs = DBNoteRepository.nowMs()
        var seen = Set<String>()

        return allWatchlistRowsForCalendar.compactMap { row in
            guard parsedWatchResultDateKey(row.resultDate) == nil else { return nil }
            guard majorMFSCalendarDefinition(for: row) == nil else { return nil }
            guard let monitorDateKey = parsedWatchMonitorDateKey(row.monitorDate), monitorDateKey == dateKey else { return nil }
            guard !hasExistingCalendarEvent(for: row, on: dateKey) else { return nil }

            let dedupeKey = "\(row.symbol.uppercased())|\(monitorDateKey)"
            guard seen.insert(dedupeKey).inserted else { return nil }

            let thesisCue = row.resultDate.trimmingCharacters(in: .whitespacesAndNewlines)
            let notes: String
            if thesisCue.isEmpty {
                notes = "Monitor this thesis row on \(monitorDateKey). Refresh the trade thesis, price action, and any follow-up work tied to \(row.symbol)."
            } else {
                notes = "Monitor this thesis row on \(monitorDateKey). Thesis cue: \(thesisCue). Refresh the trade thesis, price action, and any follow-up work tied to \(row.symbol)."
            }

            return NJFinanceMacroEvent(
                eventID: "watchlist.monitor.\(row.id).\(monitorDateKey)",
                dateKey: monitorDateKey,
                title: "\(row.name) thesis monitor",
                category: "watchlist_monitor",
                region: regionForWatchSymbol(row.symbol),
                timeText: "Monitor",
                impact: "medium",
                source: "Watchlist monitor date",
                notes: notes,
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                deleted: 0
            )
        }
    }

    private func parsedWatchResultDateKey(_ text: String) -> String? {
        let lowered = text.lowercased()
        if lowered.contains("needs refresh") || lowered.contains("reported") || lowered == "daily" {
            return nil
        }
        let hasEarningsCue =
            lowered.contains("earnings") ||
            lowered.contains("results") ||
            lowered.contains("trading update") ||
            lowered.contains("investor day") ||
            lowered.contains("capital markets day")

        if !hasEarningsCue && (lowered.contains("dividend") || lowered.contains(" ex ") || lowered.contains(" pay ")) {
            return nil
        }

        return firstDateKey(in: text)
    }

    private func parsedWatchMonitorDateKey(_ text: String) -> String? {
        firstDateKey(in: text)
    }

    private func firstDateKey(in text: String) -> String? {
        let pattern = #"\b(20\d{2}-\d{2}-\d{2})\b"#
        guard let regex = try? NSRegularExpression(pattern: pattern) else { return nil }
        let fullRange = NSRange(location: 0, length: text.utf16.count)
        guard let match = regex.firstMatch(in: text, options: [], range: fullRange),
              let range = Range(match.range(at: 1), in: text) else { return nil }
        return String(text[range])
    }

    private func timeTextForWatchResultDate(_ text: String) -> String {
        let lowered = text.lowercased()
        if lowered.contains("amc") || lowered.contains("after close") {
            return "After close"
        }
        if lowered.contains("bmo") || lowered.contains("before open") {
            return "Before open"
        }
        if lowered.contains("ind.") || lowered.contains("est.") || lowered.contains("est") {
            return "Estimated"
        }
        return "TBD"
    }

    private func majorMFSCalendarEvents(on dateKey: String) -> [NJFinanceMacroEvent] {
        var seen = Set<String>()
        let nowMs = DBNoteRepository.nowMs()
        var events: [NJFinanceMacroEvent] = []

        for row in allMFSRowsForCalendar {
            guard parsedWatchResultDateKey(row.resultDate) == nil else { continue }
            guard let eventDef = majorMFSCalendarDefinition(for: row), eventDef.dateKey == dateKey else { continue }
            let dedupeKey = "\(row.symbol.uppercased())|\(eventDef.dateKey)"
            guard seen.insert(dedupeKey).inserted else { continue }
            guard !hasExistingCalendarEvent(for: row, on: dateKey) else { continue }

            events.append(
                NJFinanceMacroEvent(
                    eventID: "watchlist.mfs.\(row.id).\(eventDef.dateKey)",
                    dateKey: eventDef.dateKey,
                    title: eventDef.title,
                    category: "watchlist_earnings",
                    region: regionForWatchSymbol(row.symbol),
                    timeText: eventDef.timeText,
                    impact: "high",
                    source: eventDef.source,
                    notes: eventDef.notes,
                    createdAtMs: nowMs,
                    updatedAtMs: nowMs,
                    deleted: 0
                )
            )
        }

        return events
    }

    private var allMFSRowsForCalendar: [NJInvestmentWatchRow] {
        mfsCashParkingRows +
        mfsBeatenDownQualityRows +
        mfsUSKeyNameRows +
        mfsAShareRows
    }

    private func majorMFSCalendarDefinition(for row: NJInvestmentWatchRow) -> (title: String, dateKey: String, timeText: String, source: String, notes: String)? {
        if let override = mfsCalendarOverridesBySymbol[row.symbol.uppercased()] {
            return override
        }

        if let mirroredRow = usQ1WatchListRows.first(where: { $0.symbol.caseInsensitiveCompare(row.symbol) == .orderedSame }),
           let dateKey = parsedWatchResultDateKey(mirroredRow.resultDate) {
            return (
                title: "\(row.name) earnings",
                dateKey: dateKey,
                timeText: timeTextForWatchResultDate(mirroredRow.resultDate),
                source: "Mirrored from US Q1 watchlist",
                notes: "Calendar event mirrored into the MFS workspace from the dated US Q1 watchlist row for \(row.symbol)."
            )
        }

        if let japanRow = japanBlueChipResultRows.first(where: { $0.symbol.caseInsensitiveCompare(row.symbol) == .orderedSame }) {
            return (
                title: "\(japanRow.company) results",
                dateKey: japanRow.resultDate,
                timeText: "TBD",
                source: "Japan blue-chip results tracker",
                notes: japanRow.expectedResult
            )
        }

        return nil
    }

