    private func hasExistingCalendarEvent(for row: NJInvestmentWatchRow, on dateKey: String) -> Bool {
        let symbol = row.symbol.lowercased()
        let name = row.name.lowercased()
        return (eventsByDate[dateKey] ?? []).contains { event in
            let title = event.title.lowercased()
            return title.contains(symbol) || title.contains(name)
        }
    }

    private func regionForWatchSymbol(_ symbol: String) -> String {
        let upper = symbol.uppercased()
        if upper.contains(" HK") || upper.hasSuffix("HK") { return "Hong Kong" }
        if upper.contains(" CN") || upper.hasSuffix("CN") { return "China" }
        if upper.contains(" JP") || upper.contains("JPY") { return "Japan" }
        if upper.contains(" FP") || upper.contains(" GR") { return "Europe" }
        if upper.contains("CNH") { return "China" }
        return "US"
    }

    private func refreshButtonTitle(for event: NJFinanceMacroEvent) -> String {
        if event.refreshRequestedAtMs > 0 {
            return "Refresh Requested For Next Run"
        }
        if event.category.lowercased().contains("earnings") {
            return "Request Earnings Refresh"
        }
        return "Request Reanalysis Next Run"
    }

    private func refreshStatusLine(for event: NJFinanceMacroEvent) -> String {
        guard event.refreshRequestedAtMs > 0 else { return "" }
        let date = Date(timeIntervalSince1970: TimeInterval(event.refreshRequestedAtMs) / 1000.0)
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.dateFormat = "yyyy-MM-dd HH:mm"
        return "Queued for the next Codex run since \(formatter.string(from: date))."
    }

    private func requestRefresh(for event: NJFinanceMacroEvent) {
        let nowMs = DBNoteRepository.nowMs()
        let reason: String
        if event.category.lowercased().contains("earnings") {
            reason = "manual earnings refresh from Investment Module"
        } else {
            reason = "manual macro reanalysis from Investment Module"
        }

        if event.eventID.hasPrefix("watchlist.earnings.") {
            var updated = event
            updated.refreshRequestedAtMs = nowMs
            updated.updatedAtMs = nowMs
            if updated.analysisSummary.isEmpty {
                updated.analysisSummary = "Pending Codex refresh request from the Investment Module."
            }
            store.notes.upsertFinanceMacroEvent(updated)
            selectedEvent = updated
        } else {
            store.notes.requestFinanceMacroEventRefresh(eventID: event.eventID, reason: reason, nowMs: nowMs)
            if var updated = store.notes.financeMacroEvent(eventID: event.eventID) {
                if updated.analysisSummary.isEmpty {
                    updated.analysisSummary = "Pending Codex refresh request from the Investment Module."
                    store.notes.upsertFinanceMacroEvent(updated)
                }
                selectedEvent = updated
            }
        }
        reloadEvents()
    }

    private func eventColor(_ event: NJFinanceMacroEvent) -> Color {
        if isSystemRedDate(event) {
            return .red
        }
        switch event.category.lowercased() {
        case let value where value.contains("market_close"): return .gray
        case let value where value.contains("inflation"): return .red
        case let value where value.contains("labor"): return .blue
        case let value where value.contains("central"): return .purple
        case let value where value.contains("earnings"): return .green
        case let value where value.contains("auction") || value.contains("debt"): return .orange
        default: return .green
        }
    }

    private func isSystemRedDate(_ event: NJFinanceMacroEvent) -> Bool {
        let category = event.category.lowercased()
        let title = event.title.lowercased()
        if category.contains("report_card") || category.contains("triple_witching") {
            return true
        }
        if category.contains("watchlist_earnings") || category.contains("earnings") {
            return true
        }
        if title.contains("triple witching") || title.contains("opex") || title.contains("options expiration") {
            return true
        }
        if title.contains("cpi") || title.contains("pce") || title.contains("ppi") {
            return true
        }
        if title.contains("payroll") || title.contains("employment") || title.contains("unemployment") {
            return true
        }
        if title.contains("fomc") || title.contains("fed decision") || title.contains("federal reserve") {
            return true
        }
        return false
    }

