    private func evaluateInvestmentWatchlistAlerts(quotes: [NJInvestmentLiveQuote]) {
        let quoteMap = Dictionary(uniqueKeysWithValues: quotes.map { ($0.id, $0) })
        var triggeredIDs = Set(watchlistTriggeredIDsStorage.split(separator: "|").map(String.init))
        var changed = false
        var firedCount = 0

        for item in investmentAlertWatchItems {
            guard let quote = quoteMap[item.symbol] ?? liveQuotes[item.symbol] else { continue }

            if quote.close > item.resetAbove {
                for rule in item.rules where triggeredIDs.remove(rule.id) != nil {
                    changed = true
                }
            }

            for rule in item.rules where quote.close <= rule.level && !triggeredIDs.contains(rule.id) {
                triggeredIDs.insert(rule.id)
                changed = true
                firedCount += 1
                NJInvestmentWatchlistNotifier.notify(
                    symbol: item.displaySymbol,
                    name: item.name,
                    priceText: watchlistPriceText(quote.close),
                    levelText: watchlistPriceText(rule.level),
                    severity: rule.severity,
                    decisionQuestion: item.decisionQuestion
                )
            }
        }

        if changed {
            watchlistTriggeredIDsStorage = triggeredIDs.sorted().joined(separator: "|")
        }

        if firedCount > 0 {
            watchlistAlertStatus = "Sent \(firedCount) watchlist alert\(firedCount == 1 ? "" : "s")"
        } else {
            watchlistAlertStatus = "Checked \(investmentAlertWatchItems.count) watchlist name\(investmentAlertWatchItems.count == 1 ? "" : "s"); no new trigger"
        }
    }

    private func watchlistPriceText(_ value: Double) -> String {
        if value >= 1000 {
            return String(format: "$%.0f", value)
        }
        return String(format: "$%.2f", value)
    }

    private func watchlistOptionalPriceText(_ value: Double?) -> String {
        guard let value else { return "n/a" }
        return watchlistPriceText(value)
    }

    private func watchlistVolumeText(_ value: Double?) -> String {
        guard let value else { return "n/a" }
        if value >= 1_000_000_000 {
            return String(format: "%.2fB", value / 1_000_000_000)
        }
        if value >= 1_000_000 {
            return String(format: "%.2fM", value / 1_000_000)
        }
        if value >= 1_000 {
            return String(format: "%.1fK", value / 1_000)
        }
        return String(format: "%.0f", value)
    }

    private func nextWatchlistAlertText(_ item: NJInvestmentAlertWatchItem, quote: NJInvestmentLiveQuote?) -> String {
        guard let price = quote?.close else {
            return item.rules.first.map { "\($0.severity) <= \(watchlistPriceText($0.level))" } ?? "n/a"
        }
        let nextRule = item.rules
            .filter { price > $0.level }
            .sorted { abs(price - $0.level) < abs(price - $1.level) }
            .first
        return nextRule.map { "\($0.severity) <= \(watchlistPriceText($0.level))" } ?? "Triggered"
    }

    private func refreshUSQ1MarketCloseNewsIfVisible(reason: String, force: Bool = false) {
        guard store.selectedInvestmentSection == .trades,
              store.selectedInvestmentTradeTab == .usQ1 else { return }
        guard !isUSQ1MarketNewsLoading else { return }

        let closeKey = usMarketCloseKey(for: Date())
        let isCloseWindow = isAfterUSMarketClose(Date())
        let isVisibleRefresh = ["open", "active", "section", "trade", "tab", "manual"].contains(reason)
        let shouldRefresh = force ||
            (usQ1MarketNewsItems.isEmpty && isVisibleRefresh) ||
            (isCloseWindow && lastUSQ1MarketNewsCloseKey != closeKey)

        guard shouldRefresh else { return }

        isUSQ1MarketNewsLoading = true
        usQ1MarketNewsStatus = isCloseWindow
            ? "Refreshing post-close US AI / QQQ exhaustion news..."
            : "Refreshing latest US AI / QQQ exhaustion news..."

        Task {
            let items = await fetchUSQ1MarketCloseNews()
            await MainActor.run {
                usQ1MarketNewsItems = items
                isUSQ1MarketNewsLoading = false
                if isCloseWindow {
                    lastUSQ1MarketNewsCloseKey = closeKey
                }

                let formatter = DateFormatter()
                formatter.dateFormat = "MMM d HH:mm"
                usQ1MarketNewsStatus = items.isEmpty
                    ? "No same-day US AI / QQQ exhaustion articles found. Old articles are hidden by design."
                    : "Read \(items.count) same-day articles at \(formatter.string(from: Date())). Auto-refreshes once after each US market close while this tab is open."
            }
        }
    }

    private func fetchUSQ1MarketCloseNews() async -> [NJObservationNewsItem] {
        let queries = [
            "QQQ AI stocks earnings pop fade Apple AMD Nvidia",
            "Nasdaq 100 mega cap tech earnings fatigue after close",
            "Apple AMD Nvidia AI earnings good news sold market",
            "SMH semiconductor stocks AI earnings fade AMD Nvidia",
            "US stock market corporate buyback window tech earnings fatigue"
        ]

        var seen = Set<String>()
        var rows: [NJObservationNewsItem] = []
        for query in queries {
            let items = await fetchUSQ1GoogleNewsRSS(query: query)
                .filter { usQ1NewsItemIsSameMarketDay($0) }
            for item in items where seen.insert(item.title).inserted {
                rows.append(item)
                if rows.count >= 8 { return rows }
            }
        }
        return rows
    }

    private func usQ1NewsItemIsSameMarketDay(_ item: NJObservationNewsItem) -> Bool {
        guard let publishedAt = item.publishedAt else { return false }
        var calendar = Calendar(identifier: .gregorian)
        calendar.timeZone = TimeZone(identifier: "America/New_York") ?? .current
        return calendar.isDate(publishedAt, inSameDayAs: Date())
    }

    private func fetchUSQ1GoogleNewsRSS(query: String) async -> [NJObservationNewsItem] {
        var components = URLComponents(string: "https://news.google.com/rss/search")
        components?.queryItems = [
            URLQueryItem(name: "q", value: query),
            URLQueryItem(name: "hl", value: "en-US"),
            URLQueryItem(name: "gl", value: "US"),
            URLQueryItem(name: "ceid", value: "US:en")
        ]
        guard let url = components?.url else { return [] }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            return NJObservationRSSParser.parse(data: data)
        } catch {
            NJInvestmentDebugLog("US_Q1_NEWS_ERR query=\(query) err=\(error.localizedDescription)")
            return []
        }
    }

    private func isAfterUSMarketClose(_ date: Date) -> Bool {
        var calendar = Calendar(identifier: .gregorian)
        calendar.timeZone = TimeZone(identifier: "America/New_York") ?? .current
        let components = calendar.dateComponents([.weekday, .hour, .minute], from: date)
        guard let weekday = components.weekday,
              let hour = components.hour,
              let minute = components.minute,
              (2...6).contains(weekday) else { return false }
        return hour > 16 || (hour == 16 && minute >= 5)
    }

    private func usMarketCloseKey(for date: Date) -> String {
        var calendar = Calendar(identifier: .gregorian)
        calendar.timeZone = TimeZone(identifier: "America/New_York") ?? .current
        let components = calendar.dateComponents([.year, .month, .day], from: date)
        return String(format: "%04d-%02d-%02d", components.year ?? 0, components.month ?? 0, components.day ?? 0)
    }

    private func refreshLiveInvestmentDataIfVisible(reason: String) {
        NJInvestmentDebugLog("LIVE_REFRESH_ENTER reason=\(reason) section=\(store.selectedInvestmentSection.rawValue) phase=\(scenePhase) running=\(isLiveRefreshRunning ? 1 : 0)")
        guard scenePhase == .active || reason == "manual" || reason == "open" else {
            NJInvestmentDebugLog("LIVE_REFRESH_SKIP reason=\(reason) cause=scene_phase phase=\(scenePhase)")
            return
        }
        guard store.selectedInvestmentSection == .macro ||
                store.selectedInvestmentSection == .macroLine ||
                store.selectedInvestmentSection == .liquidity ||
                store.selectedInvestmentSection == .heatlist ||
                store.selectedInvestmentSection == .industryAnalysis ||
                store.selectedInvestmentSection == .watchlist ||
                store.selectedInvestmentSection == .trades ||
                store.selectedInvestmentSection == .ledger else {
            NJInvestmentDebugLog("LIVE_REFRESH_SKIP reason=\(reason) cause=section section=\(store.selectedInvestmentSection.rawValue)")
            return
        }
        refreshUSQ1MarketCloseNewsIfVisible(reason: reason)
        refreshHeatMapIfVisible(reason: reason)
        refreshSystemLiquidityDashboardIfVisible(reason: reason)
        refreshPortfolioLiquidityIfVisible(reason: reason)
        guard !isLiveRefreshRunning else {
            NJInvestmentDebugLog("LIVE_REFRESH_SKIP reason=\(reason) cause=already_running")
            return
        }

        let ids = liveIDsForVisiblePage()
        guard !ids.isEmpty else {
            liveRefreshStatus = "No live symbols"
            liveRefreshError = nil
            NJInvestmentDebugLog("LIVE_REFRESH_SKIP reason=\(reason) cause=no_ids")
            return
        }

        isLiveRefreshRunning = true
        liveRefreshStatus = reason == "timer" ? "Refreshing" : "Refresh now"
        liveRefreshError = nil

        let requestedCount = ids.count
        NJInvestmentDebugLog("LIVE_REFRESH_TASK_START reason=\(reason) ids=\(requestedCount)")
        Task {
            let webullQuotes = await fetchWebullQuotes(ids: ids)
            let webullIDs = Set(webullQuotes.map(\.id))
            let fallbackQuotes = await fetchIndexFallbackQuotes(ids: ids.filter { !webullIDs.contains($0) })
            let quotes = webullQuotes + fallbackQuotes
            NJInvestmentDebugLog("LIVE_REFRESH_TASK_FETCH_DONE reason=\(reason) webull=\(webullQuotes.count) fallback=\(fallbackQuotes.count) requested=\(requestedCount)")
            await MainActor.run {
                logQuoteRefreshDiagnostics(reason: reason, requestedIDs: ids, webullQuotes: webullQuotes, fallbackQuotes: fallbackQuotes, quotes: quotes)
                let fetchedIDs = Set(quotes.map(\.id))
                for id in ids where !fetchedIDs.contains(id) {
                    liveQuotes[id] = nil
                }
                for quote in quotes {
                    liveQuotes[quote.id] = quote
                }
                persistLiveMacroQuotes(quotes)
                persistCachedLiveQuotes(quotes)
                let formatter = DateFormatter()
                formatter.dateFormat = "HH:mm"
                let missingCount = max(requestedCount - quotes.count, 0)
                liveRefreshStatus = quotes.isEmpty
                    ? webullMissingStatusText
                    : "Live \(formatter.string(from: Date())) \(quotes.count)/\(requestedCount)"
                let webullText = webullQuotes.isEmpty ? nil : "\(webullQuotes.count) Webull"
                let fallbackText = fallbackQuotes.isEmpty ? nil : "\(fallbackQuotes.count) market fallback"
                let missingText = missingCount > 0 ? "\(missingCount) missing quote" : nil
                liveRefreshError = [missingText, webullText, fallbackText, webullMissingGateText].compactMap { $0 }.joined(separator: " • ")
                isLiveRefreshRunning = false
                reloadEvents()
                refreshHourlyChartIfNeeded(reason: "live")
                updateMFSFocusBadge()
                evaluateInvestmentWatchlistAlerts(quotes: quotes)
                refreshChinaBankFundamentalsIfVisible(reason: reason)
                NJInvestmentDebugLog("LIVE_REFRESH_TASK_APPLY_DONE reason=\(reason) quotes=\(quotes.count) requested=\(requestedCount)")
            }
        }
    }

    private func refreshChinaBankFundamentalsIfVisible(reason: String) {
        guard store.selectedInvestmentSection == .trades,
              !isBankFundamentalRefreshRunning else { return }
        let rows: [NJInvestmentWatchRow]
        switch store.selectedInvestmentTradeTab {
        case .mfs:
            rows = (mfsCashParkingRows + mfsBeatenDownQualityRows)
                .filter { stockAnalysisHKGCode(for: $0.symbol) != nil }
        case .chinaHighYield:
            rows = chinaBankWatchListRows + chinaHighDividendWatchListRows
        default:
            return
        }
        guard !rows.isEmpty else { return }

        isBankFundamentalRefreshRunning = true
        bankFundamentalStatus = reason == "timer" ? "Refreshing P/E and dividend yield" : "Pulling P/E and dividend yield"

        Task {
            let metrics = await fetchStockAnalysisFundamentals(rows: rows)
            await MainActor.run {
                for metric in metrics {
                    bankFundamentals[metric.id] = metric
                }
                persistCachedFundamentals(metrics)
                let formatter = DateFormatter()
                formatter.dateFormat = "HH:mm"
                bankFundamentalStatus = metrics.isEmpty
                    ? "Fundamentals unavailable"
                    : "Fundamentals \(formatter.string(from: Date())) \(metrics.count)/\(rows.count)"
                isBankFundamentalRefreshRunning = false
                updateMFSFocusBadge()
            }
        }
    }

    private func refreshDetachedWatchQuote(for row: NJInvestmentWatchRow) async {
        let quotes = await fetchWebullQuotes(ids: [row.symbol])
        guard !quotes.isEmpty else { return }
        await MainActor.run {
            for quote in quotes {
                liveQuotes[quote.id] = quote
            }
            persistLiveMacroQuotes(quotes)
            persistCachedLiveQuotes(quotes)
        }
    }

    private func refreshHourlyChartIfNeeded(reason: String) {
        guard store.selectedInvestmentSection == .macro || store.selectedInvestmentSection == .macroLine else { return }
        guard let source = hourlyChartSource(for: selectedSnapshotLineID) else {
            if selectedSnapshotChartInterval.isIntraday || snapshotShowCandles {
                hourlyChartStatus = "\(selectedSnapshotChartInterval.shortTitle) is not available for \(snapshotLineTitle(for: selectedSnapshotLineID))."
                hourlyChartPoints[selectedSnapshotLineID] = []
            }
            return
        }

        let lineID = selectedSnapshotLineID
        let range = selectedSnapshotChartRange
        let interval = normalizedSnapshotChartInterval(selectedSnapshotChartInterval, for: range)
        if interval != selectedSnapshotChartInterval {
            selectedSnapshotChartInterval = interval
        }
        hourlyChartStatus = "Refreshing \(interval.rawValue)"
        Task {
            let points: [NJInvestmentChartPoint]
            let status: String
            switch source {
            case .yahoo(let symbol):
                if interval == .daily {
                    points = await fetchYahooDailyChartPoints(lineID: lineID, sourceSymbol: symbol, range: range)
                } else {
                    points = await fetchYahooHourlyChartPoints(lineID: lineID, sourceSymbol: symbol, interval: interval, range: range)
                }
                status = points.isEmpty ? "\(interval.rawValue) source returned no usable points." : "\(interval.rawValue) live from Yahoo chart"
            case .dailyYieldSnapshots:
                points = await MainActor.run { dailyYieldSnapshotPointsForHourlyView(lineID: lineID) }
                status = points.isEmpty
                    ? "No stored yield snapshots yet."
                    : "No free intraday yield feed wired; showing latest daily yield snapshots."
            }
            await MainActor.run {
                hourlyChartPoints[lineID] = points
                hourlyChartStatus = status
            }
        }
    }

    private func liveIDsForVisiblePage() -> [String] {
        switch store.selectedInvestmentSection {
        case .macro:
            let market = selectedMarket == .all ? marketForSnapshotLineID(selectedSnapshotLineID) : selectedMarket
            var ids = Set(snapshotMetrics(for: market).map(\.id))
            ids.insert(selectedSnapshotLineID)
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .macroLine:
            let market = selectedMarket == .all ? marketForSnapshotLineID(selectedSnapshotLineID) : selectedMarket
            var ids = Set(snapshotMetrics(for: market).map(\.id))
            ids.insert(selectedSnapshotLineID)
            ids.formUnion(heatBenchmarkRows(for: selectedHeatMarket).map(\.symbol))
            ids.formUnion(heatRows(for: selectedHeatMarket).map(\.symbol))
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .trades:
            var ids = Set(activeTradeWatchRows.map(\.symbol))
            if store.selectedInvestmentTradeTab == .usQ1 {
                ids.formUnion(["QQQ", "SQQQ", "SMH", "SOXX", "SPY", "RSP", "IWM", "hkse", "shanghai-a", "tokyo", "usdjpy"])
                ids.formUnion(usQ1ThemeSymbols)
            }
            if store.selectedInvestmentTradeTab == .japanJPY {
                ids.formUnion(japanBlueChipResultRows.map(\.symbol))
            }
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .heatlist:
            var ids = Set(heatRows(for: selectedHeatMarket).map(\.symbol))
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .industryAnalysis:
            guard let theme = selectedIndustryTheme else { return [] }
            var ids = Set(industryRows(for: theme).map(\.symbol))
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .watchlist:
            var ids = Set(investmentAlertWatchItems.map(\.symbol))
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .liquidity:
            return ["us10y", "jgb"]
        case .ledger:
            var ids = Set(store.notes.listInvestmentLedgerTransactions(limit: 500).map(\.symbol))
            if let detachedWatchRow {
                ids.insert(detachedWatchRow.symbol)
            }
            return Array(ids)
        case .observations, .tradeJournal:
            return detachedWatchRow.map { [$0.symbol] } ?? []
        case .analysisInbox:
            return detachedWatchRow.map { [$0.symbol] } ?? []
        }
    }

    private func logQuoteRefreshDiagnostics(
        reason: String,
        requestedIDs: [String],
        webullQuotes: [NJInvestmentLiveQuote],
        fallbackQuotes: [NJInvestmentLiveQuote],
        quotes: [NJInvestmentLiveQuote]
    ) {
        let requested = Array(Set(requestedIDs)).sorted { $0.localizedCaseInsensitiveCompare($1) == .orderedAscending }
        let fetchedIDs = Set(quotes.map(\.id))
        let webullIDs = Set(webullQuotes.map(\.id))
        let fallbackIDs = Set(fallbackQuotes.map(\.id))
        let missing = requested.filter { !fetchedIDs.contains($0) }
        let context = quoteDebugContext(reason: reason)

        NJInvestmentQuoteDebugLog("QUOTE_REFRESH_SUMMARY \(context) requested=\(requested.count) fetched=\(quotes.count) webull=\(webullQuotes.count) yahoo_index=\(fallbackQuotes.count) missing=\(missing.count)")

        for quote in quotes.sorted(by: { $0.id.localizedCaseInsensitiveCompare($1.id) == .orderedAscending }) {
            let provider = webullIDs.contains(quote.id) ? "webull" : (fallbackIDs.contains(quote.id) ? "yahoo_index" : "other")
            NJInvestmentQuoteDebugLog("QUOTE_FETCHED \(context) id=\(quoteDebugToken(quote.id)) provider=\(provider) source=\(quoteDebugValue(quote.source)) source_symbol=\(quoteDebugToken(quote.sourceSymbol)) value=\(quote.close) date=\(quoteDebugToken(quote.dateKey)) time=\(quoteDebugToken(quote.timeText))")
        }

        for id in missing {
            NJInvestmentQuoteDebugLog("QUOTE_MISSING \(context) id=\(quoteDebugToken(id)) plan=\(quoteDebugProviderPlan(for: id))")
        }
    }

    private func quoteDebugContext(reason: String) -> String {
        var parts = [
            "reason=\(quoteDebugToken(reason))",
            "section=\(quoteDebugToken(store.selectedInvestmentSection.rawValue))",
            "market=\(quoteDebugToken(selectedMarket.rawValue))",
            "heat_market=\(quoteDebugToken(selectedHeatMarket.rawValue))",
            "line=\(quoteDebugToken(selectedSnapshotLineID))"
        ]
        if store.selectedInvestmentSection == .trades {
            parts.append("trade=\(quoteDebugToken(store.selectedInvestmentTradeTab.rawValue))")
        }
        if let detachedWatchRow {
            parts.append("detached=\(quoteDebugToken(detachedWatchRow.symbol))")
        }
        return parts.joined(separator: " ")
    }

    private func quoteDebugProviderPlan(for id: String) -> String {
        let key = id.trimmingCharacters(in: .whitespacesAndNewlines)
        var parts: [String] = []
        if let yahoo = yahooIndexFallbackSymbol(for: key) {
            parts.append("yahoo_index=\(quoteDebugToken(yahoo))")
        }
        if let fallback = quoteFallbackSourceSymbol(for: key) {
            parts.append("fallback_source=\(quoteDebugToken(fallback))")
        }
        if let webull = webullOpenAPIRequestSymbol(for: key) {
            parts.append("webull_openapi=\(quoteDebugToken("\(webull.category):\(webull.symbol)"))")
        } else {
            parts.append("webull_openapi=none")
        }
        if let hk = webullHKCode(for: key) {
            parts.append("hk_code=\(quoteDebugToken(hk))")
        }
        if let convention = investmentSymbolConvention(for: key) {
            parts.append("instrument=\(quoteDebugToken(convention.instrumentID))")
            if !convention.webull.isEmpty {
                parts.append("webull_aliases=\(quoteDebugToken(convention.webull.joined(separator: ",")))")
            }
            if !convention.yahoo.isEmpty {
                parts.append("yahoo_aliases=\(quoteDebugToken(convention.yahoo.joined(separator: ",")))")
            }
            if !convention.stooq.isEmpty {
                parts.append("stooq_aliases=\(quoteDebugToken(convention.stooq.joined(separator: ",")))")
            }
            if !convention.ibkr.isEmpty {
                parts.append("ibkr_aliases=\(quoteDebugToken(convention.ibkr.joined(separator: ",")))")
            }
        } else {
            parts.append("convention=none")
        }
        parts.append("webull_openapi_backoff=\(webullOpenAPINetworkBackoffIsActive() ? 1 : 0)")
        parts.append("webull_web_backoff=\(webullWebNetworkBackoffIsActive() ? 1 : 0)")
        return parts.joined(separator: " ")
    }

    private func quoteDebugToken(_ value: String) -> String {
        let escaped = value
            .replacingOccurrences(of: "\\", with: "\\\\")
            .replacingOccurrences(of: "\"", with: "\\\"")
            .replacingOccurrences(of: "\n", with: "\\n")
        return "\"\(escaped)\""
    }

    private func quoteDebugValue(_ value: String) -> String {
        quoteDebugToken(value)
    }

