    private func fetchStooqQuotes(ids: [String]) async -> [NJInvestmentLiveQuote] {
        await withTaskGroup(of: NJInvestmentLiveQuote?.self) { group in
            for id in ids {
                guard let sourceSymbol = liveSourceSymbol(for: id) else { continue }
                group.addTask {
                    if let quote = await fetchLiveQuote(id: id, sourceSymbol: sourceSymbol) {
                        return quote
                    }
                    guard !sourceSymbol.hasPrefix("yahoo:"),
                          let yahooFallback = yahooFallbackSymbol(for: id) else { return nil }
                    return await fetchYahooChartQuote(id: id, sourceSymbol: yahooFallback)
                }
            }

            var quotes: [NJInvestmentLiveQuote] = []
            for await quote in group {
                if let quote {
                    quotes.append(quote)
                }
            }
            return quotes
        }
    }

    private func fetchIndexFallbackQuotes(ids: [String]) async -> [NJInvestmentLiveQuote] {
        await withTaskGroup(of: NJInvestmentLiveQuote?.self) { group in
            for id in ids {
                guard let sourceSymbol = quoteFallbackSourceSymbol(for: id) else { continue }
                group.addTask {
                    await fetchLiveQuote(id: id, sourceSymbol: sourceSymbol)
                }
            }

            var quotes: [NJInvestmentLiveQuote] = []
            for await quote in group {
                if let quote {
                    quotes.append(quote)
                }
            }
            return quotes
        }
    }

    private func quoteFallbackSourceSymbol(for id: String) -> String? {
        let key = id.trimmingCharacters(in: .whitespacesAndNewlines)
        let upper = key.uppercased()
        if let bondYield = bondYieldFallbackSourceSymbol(for: key) {
            return bondYield
        }
        if let yahoo = yahooIndexFallbackSymbol(for: key) {
            return "yahoo:\(yahoo)"
        }
        if let yahoo = yahooFallbackSymbol(for: key) {
            return "yahoo:\(yahoo)"
        }
        if let mapped = liveSymbolMap[upper.lowercased()] ?? liveSymbolMap[upper] ?? liveSymbolMap[key] {
            return mapped
        }
        switch upper {
        case "BRK.B":
            return "yahoo:BRK-B"
        case "BTC", "BITCOIN", "BTC-USD":
            return "yahoo:BTC-USD"
        case "ETH", "ETHEREUM", "ETH-USD":
            return "yahoo:ETH-USD"
        case "XAU/USD", "XAUUSD", "GOLD":
            return "yahoo:GC=F"
        case "XAG/USD", "XAGUSD", "SILVER":
            return "yahoo:SI=F"
        default:
            break
        }
        if upper.hasSuffix(" LN") {
            return "yahoo:\(String(upper.dropLast(3))).L"
        }
        if upper.hasSuffix(" FP") {
            return "yahoo:\(String(upper.dropLast(3))).PA"
        }
        if upper.hasSuffix(" GR") {
            return "yahoo:\(String(upper.dropLast(3))).DE"
        }
        if upper.range(of: #"^[A-Z]{1,5}(\.[A-Z])?$"#, options: .regularExpression) != nil {
            return "yahoo:\(upper.replacingOccurrences(of: ".", with: "-"))"
        }
        return nil
    }

    private func bondYieldFallbackSourceSymbol(for id: String) -> String? {
        let key = id
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
            .replacingOccurrences(of: "-", with: " ")
            .replacingOccurrences(of: "_", with: " ")
        let compact = key.replacingOccurrences(of: " ", with: "")
        switch key {
        case "JGB", "10Y JGB", "JGB 10Y", "JP 10Y", "JAPAN 10Y":
            return "wgb:japan:11"
        case "BUND10Y", "10Y BUND", "BUND 10Y", "DE 10Y", "GERMANY 10Y":
            return "wgb:germany:2"
        case "UK10Y", "GILT10Y", "10Y GILT", "GILT 10Y", "UK 10Y", "UNITED KINGDOM 10Y":
            return "wgb:united-kingdom:5"
        default:
            switch compact {
            case "JP10Y", "JAPAN10Y", "JGB10Y":
                return "wgb:japan:11"
            case "BUND10Y", "DE10Y", "GERMANY10Y":
                return "wgb:germany:2"
            case "UK10Y", "GILT10Y", "UNITEDKINGDOM10Y":
                return "wgb:united-kingdom:5"
            default:
                return nil
            }
        }
    }

    private func yahooIndexFallbackSymbol(for id: String) -> String? {
        let key = id.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        switch key {
        case "SPX", "S&P", "S&P 500", "SP500", "^GSPC":
            return "^GSPC"
        case "DOW", "DJI", "^DJI":
            return "^DJI"
        case "NASDAQ", "IXIC", "^IXIC":
            return "^IXIC"
        case "RUSSELL2000", "RUT", "^RUT":
            return "^RUT"
        case "VIX", "^VIX":
            return "^VIX"
        case "US10Y", "US 10Y", "^TNX", "TNX":
            return "^TNX"
        case "HKSE", "HSI", "^HSI":
            return "^HSI"
        case "HSTECH", "^HSTECH":
            return "^HSTECH"
        case "HSCEI", "^HSCE":
            return "^HSCE"
        case "TOKYO", "NIKKEI", "^N225":
            return "^N225"
        case "TOPIX", "^TOPX":
            return "^TOPX"
        case "SHANGHAI-A", "SHCOMP", "000001.SS":
            return "000001.SS"
        case "SHENZHEN-A", "399001.SZ":
            return "399001.SZ"
        case "CSI300", "CSI 300", "000300.SS":
            return "000300.SS"
        case "CHINEXT", "399006.SZ":
            return "399006.SZ"
        case "USDCNH", "USD/CNH", "CNH=X":
            return "CNH=X"
        case "USDJPY", "USD/JPY", "JPY=X":
            return "JPY=X"
        case "STOXX600", "^STOXX":
            return "^STOXX"
        case "STOXX50", "STOXX 50", "EURO STOXX 50", "^STOXX50E":
            return "^STOXX50E"
        case "FTSE100", "FTSE 100", "^FTSE":
            return "^FTSE"
        case "DAX", "^GDAXI":
            return "^GDAXI"
        case "EURUSD", "EUR/USD", "EURUSD=X":
            return "EURUSD=X"
        case "JGB", "JP10Y", "JAPAN 10Y":
            return nil
        case "BUND10Y", "DE10Y", "GERMANY 10Y":
            return nil
        case "UK10Y", "GILT10Y", "UK 10Y":
            return nil
        default:
            return yahooHourlySymbol(for: key.lowercased())
        }
    }

    private func fetchWebullCachedQuotes(ids: [String]) -> [NJInvestmentLiveQuote] {
        ids.compactMap { id in
            return cachedWebullLiveQuote(for: id)
        }
    }

    private func fetchWebullQuotes(ids: [String]) async -> [NJInvestmentLiveQuote] {
        let webullIDs = ids.filter { yahooIndexFallbackSymbol(for: $0) == nil && bondYieldFallbackSourceSymbol(for: $0) == nil }
        guard !webullIDs.isEmpty else { return [] }

        let openAPI = await fetchWebullOpenAPIQuotes(ids: webullIDs)
        let openAPIIDs = Set(openAPI.map(\.id))
        var directMissing = webullIDs.filter { !openAPIIDs.contains($0) }
        if webullOpenAPINetworkBackoffIsActive() {
            directMissing = directMissing.filter { webullOpenAPIRequestSymbol(for: $0) == nil }
        }
        if webullWebNetworkBackoffIsActive() {
            return openAPI + fetchWebullCachedQuotes(ids: directMissing)
        }

        let direct = await withTaskGroup(of: NJInvestmentLiveQuote?.self) { group in
            for id in directMissing {
                group.addTask {
                    await fetchWebullWebQuote(id: id)
                }
            }

            var quotes: [NJInvestmentLiveQuote] = []
            for await quote in group {
                if let quote {
                    quotes.append(quote)
                }
            }
            return quotes
        }
        let directIDs = Set(direct.map(\.id))
        let cached = fetchWebullCachedQuotes(ids: webullIDs.filter { !openAPIIDs.contains($0) && !directIDs.contains($0) })
        return openAPI + direct + cached
    }

    private func fetchWebullOpenAPIQuotes(ids: [String]) async -> [NJInvestmentLiveQuote] {
        guard webullHKAppKey.isEmpty == false, webullHKAppSecret.isEmpty == false else { return [] }
        guard !webullOpenAPINetworkBackoffIsActive() else { return [] }
        guard let token = await validWebullHKAccessToken(), token.isEmpty == false else { return [] }

        var requestedByCategory: [String: [(id: String, symbol: String)]] = [:]
        for id in ids {
            guard let request = webullOpenAPIRequestSymbol(for: id) else { continue }
            requestedByCategory[request.category, default: []].append((id, request.symbol))
        }
        guard requestedByCategory.isEmpty == false else { return [] }

        var quotes: [NJInvestmentLiveQuote] = []
        for (category, requests) in requestedByCategory {
            for chunk in requests.chunked(into: category == "HK_STOCK" ? 20 : 100) {
                let symbols = chunk.map(\.symbol).joined(separator: ",")
                var query = [
                    "symbols": symbols,
                    "category": category
                ]
                if category == "US_STOCK" || category == "US_ETF" {
                    query["extend_hour_required"] = "true"
                }
                let response = await webullOpenAPIRequest(
                    method: "GET",
                    path: "/openapi/market-data/stock/snapshot",
                    query: query,
                    body: nil,
                    accessToken: token
                )
                guard response.status == 200,
                      let data = response.data,
                      let snapshots = try? JSONDecoder().decode([NJInvestmentWebullOpenAPISnapshot].self, from: data) else {
                    if response.status == 401 || response.status == 403 {
                        let error = response.data.flatMap { data -> NJInvestmentWebullOpenAPIError? in
                            try? JSONDecoder().decode(NJInvestmentWebullOpenAPIError.self, from: data)
                        }
                        let message = error?.message ?? ""
                        if message.localizedCaseInsensitiveContains("permission") {
                            webullHKTokenStatus = "Permission denied"
                        } else {
                            webullHKTokenStatus = "Invalid token"
                            webullHKAccessToken = ""
                        }
                    }
                    continue
                }

                var idsBySymbol: [String: String] = [:]
                for request in chunk {
                    for key in webullOpenAPIMatchKeys(for: request.symbol) {
                        idsBySymbol[key] = request.id
                    }
                }
                for snapshot in snapshots {
                    guard let symbol = snapshot.symbol,
                          let id = webullOpenAPIMatchKeys(for: symbol).compactMap({ idsBySymbol[$0] }).first,
                          let quote = webullOpenAPIQuote(id: id, category: category, snapshot: snapshot) else { continue }
                    quotes.append(quote)
                }
            }
        }
        if quotes.isEmpty == false {
            webullHKTokenStatus = "Normal"
        }
        return quotes
    }

    private func webullOpenAPIRequestSymbol(for id: String) -> (symbol: String, category: String)? {
        let upper = id.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        if yahooIndexFallbackSymbol(for: upper) != nil {
            return nil
        }
        if bondYieldFallbackSourceSymbol(for: upper) != nil {
            return nil
        }
        if let hk = webullHKCode(for: upper) {
            return (hk, "HK_STOCK")
        }
        if upper.hasSuffix(" CN") {
            let code = String(upper.dropLast(3)).filter(\.isNumber)
            guard code.isEmpty == false else { return nil }
            return (code, "CN_STOCK")
        }
        if let convention = investmentSymbolConvention(for: upper),
           let primary = convention.webull.first?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() {
            if primary.range(of: #"^[A-Z]{1,5}(\.[A-Z])?$"#, options: .regularExpression) != nil {
                return (primary, webullUSEquityCategory(for: primary))
            }
            if primary.range(of: #"^\d{6}$"#, options: .regularExpression) != nil {
                return (primary, "CN_STOCK")
            }
        }
        if let convention = investmentSymbolConvention(for: upper),
           convention.instrumentID != upper || ["SPX", "DJI", "IXIC", "HSI", "VIX", "TNX"].contains(upper) {
            return nil
        }
        if upper.range(of: #"^[A-Z]{1,5}(\.[A-Z])?$"#, options: .regularExpression) != nil {
            return (upper, webullUSEquityCategory(for: upper))
        }
        return nil
    }

    private func webullUSEquityCategory(for symbol: String) -> String {
        let etfs: Set<String> = [
            "SPY", "VOO", "IVV", "QQQ", "QQQM", "DIA", "IWM", "RSP",
            "SQQQ", "TQQQ", "SOXX", "SMH", "XLK", "XLF", "XLE", "XLU",
            "XLB", "XLI", "XLP", "XLRE", "XLV", "XLY",
            "TLT", "IEF", "SHY", "HYG", "LQD", "GLD", "SLV", "USO",
            "DBA", "CORN", "WEAT",
            "KWEB", "FXI", "ASHR", "MCHI", "EWH", "EWJ", "EWU", "EWG", "EWQ"
        ]
        return etfs.contains(symbol.uppercased()) ? "US_ETF" : "US_STOCK"
    }

    private func webullOpenAPIMatchKeys(for symbol: String) -> [String] {
        let upper = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        var keys = [upper]
        let digits = upper.filter(\.isNumber)
        if !digits.isEmpty, digits.count == upper.count {
            keys.append(digits)
            keys.append(String(digits.drop(while: { $0 == "0" })))
            keys.append(webullHKCode(from: digits))
        }
        var seen = Set<String>()
        return keys.filter { !$0.isEmpty && seen.insert($0).inserted }
    }

    private func validWebullHKAccessToken() async -> String? {
        if let token = webullReusableStoredToken() {
            return token
        }

        guard !webullOpenAPINetworkBackoffIsActive() else { return nil }

        if let pendingToken = webullCurrentStoredToken(),
           webullHKTokenStatus.localizedCaseInsensitiveContains("pending") {
            let checked = await webullCheckStoredToken(pendingToken)
            if checked.status?.uppercased() == "NORMAL" {
                return checked.token ?? pendingToken
            }
            return nil
        }

        let created = await webullOpenAPITokenRequest(path: "/openapi/auth/token/create", token: webullCurrentStoredToken())
        guard let token = created.token, token.isEmpty == false else {
            webullHKTokenStatus = created.status ?? "Token create failed"
            return nil
        }

        webullPersistToken(token, expires: created.expires, status: created.status)
        let createdStatus = created.status?.uppercased() ?? "PENDING"
        if createdStatus == "NORMAL" {
            webullHKTokenStatus = "Normal"
            return token
        }

        let check = await webullCheckStoredToken(token)
        let checkedStatus = check.status?.uppercased() ?? createdStatus
        if checkedStatus == "NORMAL" {
            webullHKTokenStatus = "Normal"
            return check.token ?? token
        }
        if checkedStatus == "PENDING" {
            webullHKTokenStatus = "Pending verification"
            return nil
        }

        webullHKTokenStatus = checkedStatus
        return nil
    }

    private func webullReusableStoredToken() -> String? {
        guard let token = webullCurrentStoredToken(),
              !token.isEmpty,
              webullTokenExpiryIsUsable(webullHKAccessTokenExpires) else { return nil }
        return token
    }

    private func webullCheckStoredToken(_ token: String) async -> NJInvestmentWebullOpenAPIToken {
        let check = await webullOpenAPITokenRequest(path: "/openapi/auth/token/check", token: token)
        if let checkedToken = check.token, checkedToken.isEmpty == false {
            webullPersistToken(checkedToken, expires: check.expires, status: check.status)
        } else if let status = check.status, !status.isEmpty {
            webullHKTokenStatus = status == "NORMAL" ? "Normal" : status.capitalized
        }
        return check
    }

    private func webullTokenStatusIsNormal(_ status: String?) -> Bool {
        status?.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() == "NORMAL"
    }

    private func webullTokenExpiryIsUsable(_ expires: Double) -> Bool {
        guard expires > 0 else { return true }
        let now = Date().timeIntervalSince1970
        let expirySeconds = expires > 10_000_000_000 ? expires / 1000.0 : expires
        return expirySeconds - now > 3600
    }

    private func webullOpenAPITokenRequest(path: String, token: String?) async -> NJInvestmentWebullOpenAPIToken {
        let body = token.map { ["token": $0] } ?? [:]
        let response = await webullOpenAPIRequest(method: "POST", path: path, query: [:], body: body, accessToken: nil)
        guard let data = response.data,
              let result = try? JSONDecoder().decode(NJInvestmentWebullOpenAPIToken.self, from: data) else {
            if let data = response.data,
               let error = try? JSONDecoder().decode(NJInvestmentWebullOpenAPIError.self, from: data) {
                return NJInvestmentWebullOpenAPIToken(token: token, expires: nil, status: error.errorCode ?? "HTTP \(response.status)")
            }
            return NJInvestmentWebullOpenAPIToken(token: token, expires: nil, status: "HTTP \(response.status)")
        }
        return result
    }

    private func webullCurrentStoredToken() -> String? {
        let stored = webullLoadStoredToken()
        if let stored,
           !stored.token.isEmpty,
           webullTokenStatusIsNormal(stored.status),
           webullTokenExpiryIsUsable(Double(stored.expires ?? 0)),
           (!webullTokenStatusIsNormal(webullHKTokenStatus) || webullHKAccessToken.isEmpty) {
            webullHKAccessToken = stored.token
            webullHKAccessTokenExpires = Double(stored.expires ?? 0)
            webullHKTokenStatus = "Normal"
            return stored.token
        }
        if !webullHKAccessToken.isEmpty {
            return webullHKAccessToken
        }
        guard let stored,
              !stored.token.isEmpty else { return nil }
        webullHKAccessToken = stored.token
        webullHKAccessTokenExpires = Double(stored.expires ?? 0)
        if let status = stored.status, !status.isEmpty {
            webullHKTokenStatus = status == "NORMAL" ? "Normal" : status.capitalized
        }
        return stored.token
    }

    private func webullPersistToken(_ token: String, expires: Int64?, status: String?) {
        webullHKAccessToken = token
        webullHKAccessTokenExpires = Double(expires ?? 0)
        if let status, !status.isEmpty {
            webullHKTokenStatus = status == "NORMAL" ? "Normal" : status.capitalized
        }
        let payload = NJInvestmentWebullOpenAPITokenStore(
            token: token,
            expires: expires,
            status: status,
            savedAt: ISO8601DateFormatter().string(from: Date())
        )
        guard let data = try? JSONEncoder().encode(payload) else { return }
        for url in webullTokenStoreURLs() {
            do {
                try FileManager.default.createDirectory(at: url.deletingLastPathComponent(), withIntermediateDirectories: true)
                try data.write(to: url, options: [.atomic])
            } catch {
                continue
            }
        }
    }

    private func webullLoadStoredToken() -> NJInvestmentWebullOpenAPITokenStore? {
        for url in webullTokenStoreURLs() {
            guard let data = try? Data(contentsOf: url),
                  let token = try? JSONDecoder().decode(NJInvestmentWebullOpenAPITokenStore.self, from: data) else { continue }
            return token
        }
        return nil
    }

    private func webullTokenStoreURLs() -> [URL] {
        var urls: [URL] = []
        if let support = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first {
            urls.append(support.appendingPathComponent("NotionJournal/WebullHK/openapi-token.json"))
        }
        urls.append(URL(fileURLWithPath: NSString(string: "~/Library/Mobile Documents/iCloud~com~CYC~NotionJournal/Documents/Investment/webull-openapi-token.json").expandingTildeInPath))
        urls.append(URL(fileURLWithPath: NSString(string: "~/Documents/New project/IRC/data/webull-openapi-token.json").expandingTildeInPath))
        return urls
    }

    private func webullOpenAPIQuote(id: String, category: String, snapshot: NJInvestmentWebullOpenAPISnapshot) -> NJInvestmentLiveQuote? {
        guard let close = snapshot.price.flatMap(Double.init) else { return nil }
        let previousClose = snapshot.preClose.flatMap(Double.init)
        let dateParts = webullOpenAPIDateParts(ms: snapshot.lastTradeTime)
        let sourceSymbol = snapshot.symbol ?? webullOpenAPIRequestSymbol(for: id)?.symbol ?? id
        let quote = NJInvestmentLiveQuote(
            id: id,
            sourceSymbol: sourceSymbol,
            dateKey: dateParts.dateKey,
            timeText: dateParts.timeText,
            close: close,
            previousClose: previousClose,
            source: "Webull HK OpenAPI \(category) \(sourceSymbol)",
            fiftyTwoWeekHigh: nil,
            fiftyTwoWeekLow: nil,
            open: snapshot.open.flatMap(Double.init),
            dayHigh: snapshot.high.flatMap(Double.init),
            dayLow: snapshot.low.flatMap(Double.init),
            volume: snapshot.volume.flatMap(Double.init)
        )
        return webullQuoteLooksUsable(quote, for: id) ? quote : nil
    }

    private func webullOpenAPIDateParts(ms: Int64?) -> (dateKey: String, timeText: String) {
        let date = ms.map { Date(timeIntervalSince1970: TimeInterval($0) / 1000.0) } ?? Date()
        let dateFormatter = DateFormatter()
        dateFormatter.locale = Locale(identifier: "en_US_POSIX")
        dateFormatter.dateFormat = "yyyy-MM-dd"
        let timeFormatter = DateFormatter()
        timeFormatter.locale = Locale(identifier: "en_US_POSIX")
        timeFormatter.dateFormat = "HH:mm"
        return (dateFormatter.string(from: date), timeFormatter.string(from: date))
    }

    private func webullOpenAPIRequest(
        method: String,
        path: String,
        query: [String: String],
        body: [String: String]?,
        accessToken: String?
    ) async -> (status: Int, data: Data?) {
        let host = "api.webull.hk"
        var components = URLComponents()
        components.scheme = "https"
        components.host = host
        components.path = path
        components.queryItems = query
            .sorted { $0.key < $1.key }
            .map { URLQueryItem(name: $0.key, value: $0.value) }
        guard let url = components.url else { return (0, nil) }

        let bodyData: Data?
        let bodyString: String?
        if let body {
            bodyData = try? JSONSerialization.data(withJSONObject: body, options: [.sortedKeys])
            bodyString = bodyData.flatMap { String(data: $0, encoding: .utf8) }
        } else {
            bodyData = nil
            bodyString = nil
        }

        let timestamp = webullOpenAPITimestamp()
        let nonce = UUID().uuidString.replacingOccurrences(of: "-", with: "").lowercased()
        guard let signature = webullOpenAPISignature(
            path: path,
            query: query,
            bodyString: bodyString,
            host: host,
            timestamp: timestamp,
            nonce: nonce
        ) else { return (0, nil) }

        var request = URLRequest(url: url, timeoutInterval: 15)
        request.httpMethod = method
        request.setValue(webullHKAppKey, forHTTPHeaderField: "x-app-key")
        request.setValue(timestamp, forHTTPHeaderField: "x-timestamp")
        request.setValue(signature, forHTTPHeaderField: "x-signature")
        request.setValue("HMAC-SHA1", forHTTPHeaderField: "x-signature-algorithm")
        request.setValue("1.0", forHTTPHeaderField: "x-signature-version")
        request.setValue(nonce, forHTTPHeaderField: "x-signature-nonce")
        request.setValue("v2", forHTTPHeaderField: "x-version")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue("NotionJournal/1.0", forHTTPHeaderField: "User-Agent")
        if let accessToken, accessToken.isEmpty == false {
            request.setValue(accessToken, forHTTPHeaderField: "x-access-token")
        }
        if let bodyData {
            request.httpBody = bodyData
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        }

        do {
            let (data, response) = try await URLSession.shared.data(for: request)
            let status = (response as? HTTPURLResponse)?.statusCode ?? 0
            if status > 0 {
                webullClearNetworkBackoff()
            }
            return (status, data)
        } catch {
            webullMarkNetworkFailure(error, context: host)
            return ((error as NSError).code, nil)
        }
    }

    private func webullNetworkBackoffIsActive(now: Date = Date()) -> Bool {
        webullHKNetworkBackoffUntil > now.timeIntervalSince1970
    }

    private func webullOpenAPINetworkBackoffIsActive(now: Date = Date()) -> Bool {
        webullNetworkBackoffIsActive(now: now) && webullHKLastNetworkError.localizedCaseInsensitiveContains("api.webull.hk")
    }

    private func webullWebNetworkBackoffIsActive(now: Date = Date()) -> Bool {
        webullNetworkBackoffIsActive(now: now) && webullHKLastNetworkError.localizedCaseInsensitiveContains("www.webull")
    }

    private func webullClearNetworkBackoff() {
        webullHKNetworkBackoffUntil = 0
        webullHKLastNetworkError = ""
    }

    private func webullMarkNetworkFailure(_ error: Error, context: String) {
        let nse = error as NSError
        let retryAt = Date().addingTimeInterval(10 * 60)
        webullHKNetworkBackoffUntil = retryAt.timeIntervalSince1970
        webullHKLastNetworkError = "\(context) network error \(nse.code); retry paused until \(webullBackoffTimeText(retryAt))"
        if nse.domain == NSURLErrorDomain {
            webullHKTokenStatus = "Network failed"
        }
    }

    private func webullBackoffTimeText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm"
        return formatter.string(from: date)
    }

    private func webullOpenAPISignature(
        path: String,
        query: [String: String],
        bodyString: String?,
        host: String,
        timestamp: String,
        nonce: String
    ) -> String? {
        var params = query
        params["host"] = host
        params["x-app-key"] = webullHKAppKey
        params["x-signature-algorithm"] = "HMAC-SHA1"
        params["x-signature-nonce"] = nonce
        params["x-signature-version"] = "1.0"
        params["x-timestamp"] = timestamp

        let paramString = params
            .sorted { $0.key < $1.key }
            .map { "\($0.key)=\($0.value)" }
            .joined(separator: "&")
        var signatureString = "\(path)&\(paramString)"
        if let bodyString, bodyString.isEmpty == false {
            let digest = Insecure.MD5.hash(data: Data(bodyString.utf8))
                .map { String(format: "%02x", $0) }
                .joined()
                .uppercased()
            signatureString += "&\(digest)"
        }
        guard let encoded = signatureString.addingPercentEncoding(withAllowedCharacters: .webullOpenAPISignatureAllowed) else { return nil }
        let key = SymmetricKey(data: Data("\(webullHKAppSecret)&".utf8))
        let signature = HMAC<Insecure.SHA1>.authenticationCode(for: Data(encoded.utf8), using: key)
        return Data(signature).base64EncodedString()
    }

    private func webullOpenAPITimestamp() -> String {
        let formatter = DateFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.timeZone = TimeZone(secondsFromGMT: 0)
        formatter.dateFormat = "yyyy-MM-dd'T'HH:mm:ss'Z'"
        return formatter.string(from: Date())
    }

    private func webullQuoteSlugs(for id: String) -> [String] {
        if let convention = investmentSymbolConvention(for: id),
           !convention.webull.isEmpty {
            let slugs = convention.webull
                .filter { $0.contains("-") }
                .map { $0.lowercased() }
            return slugs.reduce(into: [String]()) { result, slug in
                if !result.contains(slug) {
                    result.append(slug)
                }
            }
        }
        let compact = id
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: " ", with: "")
            .lowercased()
        guard compact.range(of: #"^[a-z]{1,5}$"#, options: .regularExpression) != nil else {
            return []
        }
        return ["nasdaq-\(compact)", "nyse-\(compact)", "amex-\(compact)"]
    }

    private func fetchWebullWebQuote(id: String) async -> NJInvestmentLiveQuote? {
        guard !webullWebNetworkBackoffIsActive() else { return nil }
        if let hkQuote = await fetchWebullHKQuote(id: id) {
            return hkQuote
        }
        for slug in webullQuoteSlugs(for: id) {
            guard let url = URL(string: "https://www.webull.com/quote/\(slug)") else { continue }
            var request = URLRequest(url: url, timeoutInterval: 10)
            request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")
            request.setValue("text/html,application/xhtml+xml", forHTTPHeaderField: "Accept")

            do {
                let (data, _) = try await URLSession.shared.data(for: request)
                guard let html = String(data: data, encoding: .utf8),
                      let quote = parseWebullWebQuote(id: id, slug: slug, html: html) else { continue }
                webullClearNetworkBackoff()
                return quote
            } catch {
                webullMarkNetworkFailure(error, context: "www.webull.com")
                continue
            }
        }
        return nil
    }

    private func webullHKCode(for id: String) -> String? {
        let upper = id.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let rawCode: String
        if upper.hasSuffix(" HK") {
            rawCode = String(upper.dropLast(3))
        } else if upper.hasSuffix(".HK") {
            rawCode = String(upper.dropLast(3))
        } else {
            return nil
        }
        let digits = rawCode.filter(\.isNumber)
        guard !digits.isEmpty else { return nil }
        if digits.count >= 5 {
            return digits
        }
        return String(repeating: "0", count: 5 - digits.count) + digits
    }

    private func fetchWebullHKQuote(id: String) async -> NJInvestmentLiveQuote? {
        guard let code = webullHKCode(for: id),
              let url = URL(string: "https://www.webull.hk/en/quote/hk") else { return nil }
        var request = URLRequest(url: url, timeoutInterval: 10)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")
        request.setValue("text/html,application/xhtml+xml", forHTTPHeaderField: "Accept")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let html = String(data: data, encoding: .utf8) else { return nil }
            if let quote = parseWebullHKQuote(id: id, code: code, html: html) {
                webullClearNetworkBackoff()
                return quote
            }
            return nil
        } catch {
            webullMarkNetworkFailure(error, context: "www.webull.hk")
            return nil
        }
    }

    private func parseWebullHKQuote(id: String, code: String, html: String) -> NJInvestmentLiveQuote? {
        let needle = #""symbol":"\#(code)""#
        guard let symbolRange = html.range(of: needle) else { return nil }
        let lower = html.index(symbolRange.lowerBound, offsetBy: -min(1200, html.distance(from: html.startIndex, to: symbolRange.lowerBound)))
        let upper = html.index(symbolRange.upperBound, offsetBy: min(3200, html.distance(from: symbolRange.upperBound, to: html.endIndex)))
        let quoteHTML = String(html[lower..<upper])
        guard let closeText = webullJSONField("close", in: quoteHTML),
              let close = Double(closeText) else { return nil }
        let preClose = webullJSONField("preClose", in: quoteHTML).flatMap(Double.init)
        let open = webullJSONField("open", in: quoteHTML).flatMap(Double.init)
        let high = webullJSONField("high", in: quoteHTML).flatMap(Double.init)
        let low = webullJSONField("low", in: quoteHTML).flatMap(Double.init)
        let volume = webullJSONField("volume", in: quoteHTML).flatMap(Double.init)
        let name = webullJSONField("name", in: quoteHTML) ?? code
        let dateParts = webullDateParts(from: webullJSONField("tradeTime", in: quoteHTML))
        let quote = NJInvestmentLiveQuote(
            id: id,
            sourceSymbol: code,
            dateKey: dateParts.dateKey,
            timeText: dateParts.timeText,
            close: close,
            previousClose: preClose,
            source: "Webull HK quote \(name)",
            fiftyTwoWeekHigh: webullJSONField("fiftyTwoWkHigh", in: quoteHTML).flatMap(Double.init),
            fiftyTwoWeekLow: webullJSONField("fiftyTwoWkLow", in: quoteHTML).flatMap(Double.init),
            open: open,
            dayHigh: high,
            dayLow: low,
            volume: volume
        )
        return webullQuoteLooksUsable(quote, for: id) ? quote : nil
    }

    private func parseWebullWebQuote(id: String, slug: String, html: String) -> NJInvestmentLiveQuote? {
        let quoteHTML = webullTickerRTSection(in: html)
        guard let closeText = webullJSONField("close", in: quoteHTML),
              let close = Double(closeText) else { return nil }
        let preClose = webullJSONField("preClose", in: quoteHTML).flatMap(Double.init)
        let open = webullJSONField("open", in: quoteHTML).flatMap(Double.init)
        let high = webullJSONField("high", in: quoteHTML).flatMap(Double.init)
        let low = webullJSONField("low", in: quoteHTML).flatMap(Double.init)
        let volume = webullJSONField("volume", in: quoteHTML).flatMap(Double.init)
        let symbol = webullJSONField("disSymbol", in: quoteHTML) ?? webullJSONField("symbol", in: quoteHTML) ?? slug
        let dateParts = webullDateParts(from: webullJSONField("tradeTime", in: quoteHTML))
        let quote = NJInvestmentLiveQuote(
            id: id,
            sourceSymbol: slug,
            dateKey: dateParts.dateKey,
            timeText: dateParts.timeText,
            close: close,
            previousClose: preClose,
            source: "Webull web \(symbol)",
            fiftyTwoWeekHigh: webullJSONField("fiftyTwoWkHigh", in: quoteHTML).flatMap(Double.init),
            fiftyTwoWeekLow: webullJSONField("fiftyTwoWkLow", in: quoteHTML).flatMap(Double.init),
            open: open,
            dayHigh: high,
            dayLow: low,
            volume: volume
        )
        return webullQuoteLooksUsable(quote, for: id) ? quote : nil
    }

    private func webullTickerRTSection(in html: String) -> String {
        guard let start = html.range(of: #""tickerRT":{"#)?.lowerBound else { return html }
        let suffix = String(html[start...])
        if let end = suffix.range(of: #""newsData":"#)?.lowerBound {
            return String(suffix[..<end])
        }
        return String(suffix.prefix(5000))
    }

    private func webullJSONField(_ key: String, in html: String) -> String? {
        let pattern = "\"" + NSRegularExpression.escapedPattern(for: key) + "\":\"([^\"]*)\""
        guard let regex = try? NSRegularExpression(pattern: pattern),
              let match = regex.firstMatch(in: html, range: NSRange(html.startIndex..., in: html)),
              match.numberOfRanges > 1,
              let range = Range(match.range(at: 1), in: html) else { return nil }
        return String(html[range])
            .replacingOccurrences(of: #"\/"#, with: "/")
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func webullDateParts(from raw: String?) -> (dateKey: String, timeText: String) {
        let date = raw.flatMap { value -> Date? in
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.dateFormat = "yyyy-MM-dd'T'HH:mm:ss.SSSZ"
            return formatter.date(from: value)
        } ?? Date()
        let dateFormatter = DateFormatter()
        dateFormatter.locale = Locale(identifier: "en_US_POSIX")
        dateFormatter.dateFormat = "yyyy-MM-dd"
        let timeFormatter = DateFormatter()
        timeFormatter.locale = Locale(identifier: "en_US_POSIX")
        timeFormatter.dateFormat = "HH:mm"
        return (dateFormatter.string(from: date), timeFormatter.string(from: date))
    }

    private nonisolated func fetchStockAnalysisFundamentals(rows: [NJInvestmentWatchRow]) async -> [NJInvestmentFundamentalMetric] {
        await withTaskGroup(of: NJInvestmentFundamentalMetric?.self) { group in
            for row in rows {
                guard let sourceSymbol = stockAnalysisHKGCode(for: row.symbol) else { continue }
                group.addTask {
                    await fetchStockAnalysisFundamental(id: row.symbol, sourceSymbol: sourceSymbol)
                }
            }

            var metrics: [NJInvestmentFundamentalMetric] = []
            for await metric in group {
                if let metric {
                    metrics.append(metric)
                }
            }
            return metrics
        }
    }

    private nonisolated func fetchStockAnalysisFundamental(id: String, sourceSymbol: String) async -> NJInvestmentFundamentalMetric? {
        guard let url = URL(string: "https://stockanalysis.com/quote/hkg/\(sourceSymbol)/statistics/") else { return nil }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let html = String(data: data, encoding: .utf8) else { return nil }
            let pe = extractStockAnalysisMetric(id: "pe", from: html)
                ?? extractStockAnalysisMetric(id: "peForward", from: html)
                ?? "n/a"
            let annualDividend = extractStockAnalysisMetric(id: "dps", from: html) ?? "n/a"
            let dividendYield = extractStockAnalysisMetric(id: "dividendYield", from: html) ?? "n/a"
            guard pe != "n/a" || dividendYield != "n/a" else { return nil }
            return NJInvestmentFundamentalMetric(
                id: id,
                sourceSymbol: sourceSymbol,
                pe: pe,
                annualDividend: annualDividend,
                dividendYield: dividendYield,
                source: "StockAnalysis"
            )
        } catch {
            return nil
        }
    }

    private nonisolated func extractStockAnalysisMetric(id: String, from html: String) -> String? {
        let pattern = #"\{id:"\#(NSRegularExpression.escapedPattern(for: id))",title:"[^"]+",value:"([^"]+)""#
        guard let regex = try? NSRegularExpression(pattern: pattern),
              let match = regex.firstMatch(in: html, range: NSRange(html.startIndex..., in: html)),
              match.numberOfRanges > 1,
              let range = Range(match.range(at: 1), in: html) else { return nil }
        let value = String(html[range])
        return value == "n/a" ? nil : value
    }

    private nonisolated func stockAnalysisHKGCode(for symbol: String) -> String? {
        let parts = symbol.split(separator: " ").map(String.init)
        guard parts.count == 2, parts[1] == "HK" else { return nil }
        return parts[0]
    }

    private func liveSourceSymbol(for id: String) -> String? {
        if store.selectedInvestmentSection == .trades,
           store.selectedInvestmentTradeTab == .usQ1,
           let yahooSymbol = usQ1YahooLiveSymbol(for: id) {
            return "yahoo:\(yahooSymbol)"
        }
        if let mapped = liveSymbolMap[id] {
            return mapped
        }
        if let yahoo = yahooFallbackSymbol(for: id) ?? usEquityYahooSymbol(for: id) {
            return "yahoo:\(yahoo)"
        }
        return nil
    }

    private func usEquityYahooSymbol(for id: String) -> String? {
        let trimmed = id.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty,
              trimmed.range(of: #"^[A-Z][A-Z0-9.\-]{0,9}$"#, options: .regularExpression) != nil else {
            return nil
        }
        return trimmed.replacingOccurrences(of: ".", with: "-")
    }

    private func usQ1YahooLiveSymbol(for id: String) -> String? {
        switch id {
        case "QQQ", "SQQQ", "SPY", "SMH", "SOXX", "RSP", "IWM", "DIA",
             "AAPL", "AMD", "NVDA", "MSFT", "META", "AMZN", "GOOGL", "TSLA",
             "INTC", "MU", "TSM", "ASML", "AVGO", "QCOM", "AMAT", "LRCX", "KLAC", "MRVL", "SMCI",
             "WDC", "STX", "SNDK", "HPE", "JPM", "GS", "BAC", "C", "MS", "V", "MA", "AXP",
             "COST", "WMT", "HD", "LOW", "TGT", "TJX", "NKE", "JNJ", "UNH", "LLY", "ABBV", "MRK", "PFE", "ABT", "ISRG",
             "ORCL", "CRM", "NOW", "PLTR", "SNOW", "XOM", "CVX", "CAT", "GE":
            return id
        case "BRK.B":
            return "BRK-B"
