    private nonisolated func yahooFallbackSymbol(for id: String) -> String? {
        let parts = id.split(separator: " ").map(String.init)
        guard parts.count == 2 else { return nil }
        let code = parts[0]
        switch parts[1] {
        case "HK":
            return "\(code).HK"
        case "CN":
            if code.hasPrefix("6") {
                return "\(code).SS"
            }
            return "\(code).SZ"
        case "JP":
            return "\(code).T"
        case "LN":
            return "\(code).L"
        case "FP":
            return "\(code).PA"
        case "GR":
            return "\(code).DE"
        default:
            return nil
        }
    }

    private func fetchLiveQuote(id: String, sourceSymbol: String) async -> NJInvestmentLiveQuote? {
        if sourceSymbol.hasPrefix("yahoo:") {
            return await fetchYahooChartQuote(id: id, sourceSymbol: String(sourceSymbol.dropFirst("yahoo:".count)))
        }
        if sourceSymbol.hasPrefix("wgb:") {
            let parts = sourceSymbol.split(separator: ":").map(String.init)
            guard parts.count == 3 else { return nil }
            return await fetchWorldGovernmentBondQuote(id: id, countrySlug: parts[1], countrySymbol: parts[2])
        }
        return await fetchStooqQuote(id: id, sourceSymbol: sourceSymbol)
    }

    private func fetchStooqQuote(id: String, sourceSymbol: String) async -> NJInvestmentLiveQuote? {
        var components = URLComponents(string: "https://stooq.com/q/l/")!
        components.queryItems = [
            URLQueryItem(name: "s", value: sourceSymbol),
            URLQueryItem(name: "f", value: "sd2t2ohlcvp"),
            URLQueryItem(name: "h", value: ""),
            URLQueryItem(name: "e", value: "csv")
        ]
        guard let url = components.url else { return nil }

        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            guard let text = String(data: data, encoding: .utf8) else { return nil }
            let rows = text.split(whereSeparator: \.isNewline).map(String.init)
            guard rows.count > 1 else { return nil }
            let values = parseSimpleCSVRow(rows[1])
            guard values.count >= 7,
                  values[1] != "N/D",
                  let open = Double(values[3]),
                  let dayHigh = Double(values[4]),
                  let dayLow = Double(values[5]),
                  let close = Double(values[6]) else { return nil }
            let volume = values.count > 7 ? Double(values[7]) : nil
            let previousClose = values.count > 8 ? Double(values[8]) : nil
            return NJInvestmentLiveQuote(
                id: id,
                sourceSymbol: values[0],
                dateKey: values[1],
                timeText: values[2],
                close: close,
                previousClose: previousClose ?? open,
                source: "Stooq",
                open: open,
                dayHigh: dayHigh,
                dayLow: dayLow,
                volume: volume
            )
        } catch {
            return nil
        }
    }

    private func fetchYahooChartQuote(id: String, sourceSymbol: String) async -> NJInvestmentLiveQuote? {
        let encoded = sourceSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? sourceSymbol
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=5d&interval=1d") else { return nil }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = root["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let meta = result["meta"] as? [String: Any] else { return nil }

            let marketState = ((meta["marketState"] as? String) ?? "").uppercased()
            let regularClose = yahooDoubleValue(meta["regularMarketPrice"])
            let preMarketPrice = yahooDoubleValue(meta["preMarketPrice"])
            let postMarketPrice = yahooDoubleValue(meta["postMarketPrice"])
            let close: Double? = {
                if marketState.contains("POST"), let postMarketPrice { return postMarketPrice }
                if marketState.contains("PRE"), let preMarketPrice { return preMarketPrice }
                return regularClose
            }()
            let previous = yahooPreviousDailyClose(from: result) ?? yahooDoubleValue(meta["previousClose"]) ?? yahooDoubleValue(meta["chartPreviousClose"])
            let week52High = meta["fiftyTwoWeekHigh"] as? Double
            let week52Low = meta["fiftyTwoWeekLow"] as? Double
            let open = yahooDoubleValue(meta["regularMarketOpen"]) ?? yahooDoubleValue(meta["open"])
            let dayHigh = yahooDoubleValue(meta["regularMarketDayHigh"]) ?? yahooDoubleValue(meta["dayHigh"])
            let dayLow = yahooDoubleValue(meta["regularMarketDayLow"]) ?? yahooDoubleValue(meta["dayLow"])
            let volume = yahooDoubleValue(meta["regularMarketVolume"]) ?? yahooDoubleValue(meta["volume"])
            let marketTimeValue: TimeInterval? = {
                if marketState.contains("POST"), let value = meta["postMarketTime"] as? TimeInterval { return value }
                if marketState.contains("PRE"), let value = meta["preMarketTime"] as? TimeInterval { return value }
                return meta["regularMarketTime"] as? TimeInterval
            }()
            let marketTime = marketTimeValue.map { Date(timeIntervalSince1970: $0) } ?? Date()
            guard let close else { return nil }

            let normalizedClose = normalizedYahooQuoteValue(close, lineID: id)
            let normalizedPrevious = previous.map { normalizedYahooQuoteValue($0, lineID: id) }
            let normalizedOpen = open.map { normalizedYahooQuoteValue($0, lineID: id) }
            let normalizedDayHigh = dayHigh.map { normalizedYahooQuoteValue($0, lineID: id) }
            let normalizedDayLow = dayLow.map { normalizedYahooQuoteValue($0, lineID: id) }

            return NJInvestmentLiveQuote(
                id: id,
                sourceSymbol: sourceSymbol,
                dateKey: marketSessionDateKey(for: id, date: marketTime),
                timeText: liveTimeText(marketTime),
                close: normalizedClose,
                previousClose: normalizedPrevious,
                source: "Yahoo chart",
                fiftyTwoWeekHigh: week52High,
                fiftyTwoWeekLow: week52Low,
                open: normalizedOpen,
                dayHigh: normalizedDayHigh,
                dayLow: normalizedDayLow,
                volume: volume
            )
        } catch {
            return nil
        }
    }

    private func normalizedYahooQuoteValue(_ value: Double, lineID: String) -> Double {
        switch lineID {
        case "us10y":
            return value > 10 ? value / 10 : value
        default:
            return value
        }
    }

    private func yahooPreviousDailyClose(from result: [String: Any]) -> Double? {
        guard let indicators = result["indicators"] as? [String: Any],
              let quotes = indicators["quote"] as? [[String: Any]],
              let quote = quotes.first,
              let closes = quote["close"] as? [Any] else { return nil }
        let validCloses = closes.compactMap(yahooDoubleValue)
        guard validCloses.count >= 2 else { return nil }
        return validCloses[validCloses.count - 2]
    }

    private func yahooDoubleValue(_ value: Any?) -> Double? {
        if let value = value as? Double { return value }
        if let value = value as? Int { return Double(value) }
        if let value = value as? NSNumber { return value.doubleValue }
        if let value = value as? String { return Double(value) }
        return nil
    }

    private func fetchYahooHourlyChartPoints(lineID: String, sourceSymbol: String, interval: NJInvestmentChartInterval = .hourly, range: NJInvestmentChartRange = .fiveDays) async -> [NJInvestmentChartPoint] {
        let encoded = sourceSymbol.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed) ?? sourceSymbol
        let resolvedRange = yahooRangeText(for: interval, range: range)
        let intervalText = yahooIntervalText(for: interval, range: range)
        guard let url = URL(string: "https://query1.finance.yahoo.com/v8/finance/chart/\(encoded)?range=\(resolvedRange)&interval=\(intervalText)") else { return [] }
        var request = URLRequest(url: url)
        request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")

        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let chart = root["chart"] as? [String: Any],
                  let results = chart["result"] as? [[String: Any]],
                  let result = results.first,
                  let timestamps = result["timestamp"] as? [TimeInterval],
                  let indicators = result["indicators"] as? [String: Any],
                  let quotes = indicators["quote"] as? [[String: Any]],
                  let quote = quotes.first,
                  let closes = quote["close"] as? [Any] else { return [] }

            let opens = quote["open"] as? [Any]
            let highs = quote["high"] as? [Any]
            let lows = quote["low"] as? [Any]
            let volumes = quote["volume"] as? [Any]

            var previousClose: Double?
            return zip(Array(timestamps.enumerated()), closes).compactMap { indexedTimestamp, rawClose in
                let (index, timestamp) = indexedTimestamp
                guard let close = yahooDoubleValue(rawClose) else { return nil }
                let adjustedClose = hourlyAdjustedValue(close, lineID: lineID)
                let pct: Double? = {
                    guard let previousClose, previousClose != 0 else { return nil }
                    return (adjustedClose / previousClose - 1) * 100
                }()
                previousClose = adjustedClose
                let open = opens.flatMap { index < $0.count ? yahooDoubleValue($0[index]) : nil }.map { hourlyAdjustedValue($0, lineID: lineID) }
                let high = highs.flatMap { index < $0.count ? yahooDoubleValue($0[index]) : nil }.map { hourlyAdjustedValue($0, lineID: lineID) }
                let low = lows.flatMap { index < $0.count ? yahooDoubleValue($0[index]) : nil }.map { hourlyAdjustedValue($0, lineID: lineID) }
                let volume = volumes.flatMap { index < $0.count ? yahooDoubleValue($0[index]) : nil }
                return NJInvestmentChartPoint(
                    id: "hourly.\(lineID).\(Int(timestamp))",
                    date: Date(timeIntervalSince1970: timestamp),
                    value: adjustedClose,
                    open: open,
                    high: high,
                    low: low,
                    close: adjustedClose,
                    volume: volume,
                    change: pct.map { String(format: "%+.2f%%", $0) } ?? interval.shortTitle,
                    isDown: pct.map { $0 < 0 } ?? false
                )
            }
        } catch {
            return []
        }
    }

