    private func dailyYieldSnapshotPointsForHourlyView(lineID: String) -> [NJInvestmentChartPoint] {
        let dailyPoints = liveAdjustedChartPoints(chartPoints(from: snapshotLinePoints(for: lineID)), lineID: lineID)
        let recentPoints = Array(dailyPoints.suffix(10))
        return recentPoints.map { point in
            let sessionDate = calendar.date(bySettingHour: 15, minute: 0, second: 0, of: point.date) ?? point.date
            return NJInvestmentChartPoint(
                id: "yield-hourly-fallback.\(lineID).\(Int(sessionDate.timeIntervalSince1970))",
                date: sessionDate,
                value: point.value,
                change: point.change,
                isDown: point.isDown
            )
        }
    }

    private func hourlyAdjustedValue(_ value: Double, lineID: String) -> Double {
        lineID == "us10y" && value > 10 ? value / 10 : value
    }

    private func fetchWorldGovernmentBondQuote(id: String, countrySlug: String, countrySymbol: String) async -> NJInvestmentLiveQuote? {
        guard let url = URL(string: "https://www.worldgovernmentbonds.com/wp-json/common/v1/historical") else { return nil }
        let countryInfo: (name: String, flag: String)
        switch countrySlug {
        case "united-kingdom":
            countryInfo = ("United Kingdom", "gb")
        case "japan":
            countryInfo = ("Japan", "jp")
        default:
            countryInfo = ("Germany", "de")
        }
        let globalVar: [String: Any] = [
            "JS_VARIABLE": "jsGlobalVars",
            "FUNCTION": "Bond",
            "DOMESTIC": true,
            "ENDPOINT": "https://www.worldgovernmentbonds.com/wp-json/common/v1/historical",
            "DATE_RIF": "2099-12-31",
            "OBJ": ["UNIT": "%", "DECIMAL": 3, "UNIT_DELTA": "bp", "DECIMAL_DELTA": 1],
            "COUNTRY1": ["SYMBOL": countrySymbol, "PAESE": countryInfo.name, "PAESE_UPPERCASE": countryInfo.name.uppercased(), "BANDIERA": countryInfo.flag, "URL_PAGE": countrySlug],
            "OBJ1": ["DURATA_STRING": "10 Years", "DURATA": 120]
        ]
        let body = ["GLOBALVAR": globalVar]

        do {
            var request = URLRequest(url: url)
            request.httpMethod = "POST"
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
            request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")
            request.setValue("https://www.worldgovernmentbonds.com", forHTTPHeaderField: "Origin")
            request.setValue("https://www.worldgovernmentbonds.com/bond-historical-data/\(countrySlug)/10-years/", forHTTPHeaderField: "Referer")
            request.httpBody = try JSONSerialization.data(withJSONObject: body)

            let (data, _) = try await URLSession.shared.data(for: request)
            guard let root = try JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let result = root["result"] as? [String: Any],
                  let valueText = result["ultimoValore"] as? String,
                  let close = Double(valueText) else {
                NJInvestmentQuoteDebugLog("QUOTE_PROVIDER_FAIL provider=\"WorldGovernmentBonds\" id=\"\(quoteDebugToken(id))\" slug=\"\(quoteDebugToken(countrySlug))\" symbol=\"\(quoteDebugToken(countrySymbol))\" error=\"parse\"")
                return await fetchInvestingBondQuote(id: id, countrySlug: countrySlug)
            }
            let now = Date()
            return NJInvestmentLiveQuote(
                id: id,
                sourceSymbol: "\(countryInfo.name) 10Y",
                dateKey: marketSessionDateKey(for: id, date: now),
                timeText: result["ultimoTimestampDesc"] as? String ?? liveTimeText(now),
                close: close,
                previousClose: nil,
                source: "WorldGovernmentBonds"
            )
        } catch {
            NJInvestmentQuoteDebugLog("QUOTE_PROVIDER_FAIL provider=\"WorldGovernmentBonds\" id=\"\(quoteDebugToken(id))\" slug=\"\(quoteDebugToken(countrySlug))\" symbol=\"\(quoteDebugToken(countrySymbol))\" error=\"\(quoteDebugToken(error.localizedDescription))\"")
            return await fetchInvestingBondQuote(id: id, countrySlug: countrySlug)
        }
    }

    private func fetchInvestingBondQuote(id: String, countrySlug: String) async -> NJInvestmentLiveQuote? {
        let pageSlug: String
        let sourceName: String
        switch countrySlug {
        case "japan":
            pageSlug = "japan-10-year-bond-yield"
            sourceName = "Japan 10Y"
        case "united-kingdom":
            pageSlug = "uk-10-year-bond-yield"
            sourceName = "UK 10Y"
        default:
            pageSlug = "germany-10-year-bond-yield"
            sourceName = "Germany 10Y"
        }
        guard let url = URL(string: "https://www.investing.com/rates-bonds/\(pageSlug)") else { return nil }

        do {
            var request = URLRequest(url: url)
            request.setValue("Mozilla/5.0", forHTTPHeaderField: "User-Agent")
            let (data, _) = try await URLSession.shared.data(for: request)
            guard let html = String(data: data, encoding: .utf8) else { return nil }

            func investingField(_ field: String) -> String? {
                let pattern = #"data-test="\#(NSRegularExpression.escapedPattern(for: field))"[^>]*>([^<]+)"#
                guard let regex = try? NSRegularExpression(pattern: pattern),
                      let match = regex.firstMatch(in: html, range: NSRange(html.startIndex..., in: html)),
                      match.numberOfRanges > 1,
                      let range = Range(match.range(at: 1), in: html) else { return nil }
                return String(html[range])
                    .replacingOccurrences(of: ",", with: "")
                    .replacingOccurrences(of: "%", with: "")
                    .replacingOccurrences(of: "(", with: "")
                    .replacingOccurrences(of: ")", with: "")
                    .trimmingCharacters(in: .whitespacesAndNewlines)
            }

            guard let closeText = investingField("instrument-price-last"),
                  let close = Double(closeText) else {
                NJInvestmentQuoteDebugLog("QUOTE_PROVIDER_FAIL provider=\"Investing.com\" id=\"\(quoteDebugToken(id))\" slug=\"\(quoteDebugToken(pageSlug))\" error=\"parse\"")
                return nil
            }
            let change = investingField("instrument-price-change").flatMap(Double.init)
            let previousClose = change.map { close - $0 }
            let now = Date()
            return NJInvestmentLiveQuote(
                id: id,
                sourceSymbol: sourceName,
                dateKey: marketSessionDateKey(for: id, date: now),
                timeText: liveTimeText(now),
                close: close,
                previousClose: previousClose,
                source: "Investing.com bond"
            )
        } catch {
            NJInvestmentQuoteDebugLog("QUOTE_PROVIDER_FAIL provider=\"Investing.com\" id=\"\(quoteDebugToken(id))\" slug=\"\(quoteDebugToken(pageSlug))\" error=\"\(quoteDebugToken(error.localizedDescription))\"")
            return nil
        }
    }

    private func liveTimeText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm"
        return formatter.string(from: date)
    }

    private func marketSessionDateKey(for lineID: String, date: Date) -> String {
        var sessionCalendar = Calendar(identifier: .gregorian)
        sessionCalendar.timeZone = marketTimeZone(for: lineID)
        let components = sessionCalendar.dateComponents([.year, .month, .day], from: date)
        return String(format: "%04d-%02d-%02d", components.year ?? 0, components.month ?? 0, components.day ?? 0)
    }

    private func marketTimeZone(for lineID: String) -> TimeZone {
        switch lineID {
        case "spx", "dow", "nasdaq", "us10y", "vix":
            return TimeZone(identifier: "America/New_York") ?? .current
        case "hkse", "usdcnh":
            return TimeZone(identifier: "Asia/Hong_Kong") ?? .current
        case "shanghai-a":
            return TimeZone(identifier: "Asia/Shanghai") ?? .current
        case "tokyo", "jgb", "usdjpy":
            return TimeZone(identifier: "Asia/Tokyo") ?? .current
        case "stoxx600", "stoxx50", "ftse100", "bund10y", "uk10y", "eurusd":
            return TimeZone(identifier: "Europe/Berlin") ?? .current
        default:
            return .current
        }
    }

    private func parseSimpleCSVRow(_ row: String) -> [String] {
        row.split(separator: ",", omittingEmptySubsequences: false)
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
    }

    private func persistLiveMacroQuotes(_ quotes: [NJInvestmentLiveQuote]) {
        let now = DBNoteRepository.nowMs()
        for quote in quotes {
            guard let prefix = macroEventPrefix(for: quote.id) else { continue }
            store.notes.upsertFinanceMacroEvent(
                NJFinanceMacroEvent(
                    eventID: "\(prefix)\(quote.dateKey)",
                    dateKey: quote.dateKey,
                    title: "\(macroSnapshotTitlePrefix(for: quote.id)) \(formattedLiveValue(quote.close, lineID: quote.id)) \(quote.changeText)",
                    category: "market_snapshot",
                    region: macroSnapshotRegion(for: quote.id),
                    timeText: quote.timeText,
                    impact: quote.isDown ? "down" : "up",
                    source: "\(quote.source) live quote \(quote.sourceSymbol)",
                    notes: "Live refresh while Investment page is visible. Quote fields use Webull, Yahoo chart, or bond-yield fallback depending on the instrument. Change uses the quote's prior-close field when available.",
                    createdAtMs: now,
                    updatedAtMs: now,
                    deleted: 0
                )
            )
        }
    }

    private func hydrateCachedInvestmentData() {
        hydrateCachedLiveQuotes()
        hydrateCachedFundamentals()
        hydrateCachedSystemLiquiditySnapshots()
        refreshJapanJPYThesisFromNote()
    }

    private func hydrateCachedLiveQuotes() {
        let now = Date()
        let start = calendar.date(byAdding: .day, value: -60, to: now) ?? now
        let rows = store.notes
            .listFinanceMacroEvents(startKey: dateKey(start), endKey: dateKey(now))
            .filter { $0.category == "cache_live_quote" && $0.deleted == 0 }

        var newestByID: [String: (updatedAtMs: Int64, quote: NJInvestmentLiveQuote)] = [:]
        for row in rows {
            guard let payload = decodeCachePayload(NJInvestmentLiveQuoteCachePayload.self, from: row.notes) else { continue }
            let quote = NJInvestmentLiveQuote(
                id: payload.id,
                sourceSymbol: payload.sourceSymbol,
                dateKey: payload.dateKey,
                timeText: payload.timeText,
                close: payload.close,
                previousClose: payload.previousClose,
                source: payload.source,
                fiftyTwoWeekHigh: payload.fiftyTwoWeekHigh,
                fiftyTwoWeekLow: payload.fiftyTwoWeekLow
            )
            if let existing = newestByID[payload.id], existing.updatedAtMs >= row.updatedAtMs { continue }
            newestByID[payload.id] = (row.updatedAtMs, quote)
        }

        guard !newestByID.isEmpty else { return }
        for (_, entry) in newestByID {
            guard cachedQuoteLooksUsable(entry.quote) else { continue }
            liveQuotes[entry.quote.id] = entry.quote
        }
        NJInvestmentDebugLog("LIVE_CACHE_HYDRATE quotes=\(newestByID.count)")
    }

    private func cachedQuoteLooksUsable(_ quote: NJInvestmentLiveQuote) -> Bool {
        quote.close.isFinite && quote.close > 0
    }

    private func hydrateCachedFundamentals() {
        let now = Date()
        let start = calendar.date(byAdding: .day, value: -120, to: now) ?? now
        let rows = store.notes
            .listFinanceMacroEvents(startKey: dateKey(start), endKey: dateKey(now))
            .filter { $0.category == "cache_fundamental" && $0.deleted == 0 }

        var newestByID: [String: (updatedAtMs: Int64, metric: NJInvestmentFundamentalMetric)] = [:]
        for row in rows {
            guard let payload = decodeCachePayload(NJInvestmentFundamentalCachePayload.self, from: row.notes) else { continue }
            let metric = NJInvestmentFundamentalMetric(
                id: payload.id,
                sourceSymbol: payload.sourceSymbol,
                pe: payload.pe,
                annualDividend: payload.annualDividend,
                dividendYield: payload.dividendYield,
                source: payload.source
            )
            if let existing = newestByID[payload.id], existing.updatedAtMs >= row.updatedAtMs { continue }
            newestByID[payload.id] = (row.updatedAtMs, metric)
        }

        guard !newestByID.isEmpty else { return }
        for (_, entry) in newestByID {
            bankFundamentals[entry.metric.id] = entry.metric
        }
        NJInvestmentDebugLog("FUND_CACHE_HYDRATE metrics=\(newestByID.count)")
    }

    private func refreshJapanJPYThesisFromNote() {
        Task {
            let loaded = await loadJapanJPYTradeThesisFromNote()
            await MainActor.run {
                if let loaded {
                    japanTradeThesisLastUpdateText = loaded.updateText
                    japanTradeThesisNoteUpdatedAtText = loaded.updatedAtText
                } else {
                    japanTradeThesisLastUpdateText = "No local note found for 2026 JPY Trade."
                    japanTradeThesisNoteUpdatedAtText = ""
                }
            }
        }
    }

    private func loadJapanJPYTradeThesisFromNote() async -> (updateText: String, updatedAtText: String)? {
        await Task.detached(priority: .utility) {
            let notes = store.db.queryRows("""
            SELECT note_id, updated_at_ms
            FROM nj_note
            WHERE deleted = 0
              AND notebook = 'Me'
              AND tab_domain = 'me.finance'
              AND title = '2026 JPY Trade'
            ORDER BY updated_at_ms DESC
            LIMIT 1;
            """)
            guard let note = notes.first,
                  let noteID = note["note_id"],
                  !noteID.isEmpty
            else { return nil }

            let updatedAtMs = Int64(note["updated_at_ms"] ?? "") ?? 0
            let updatedAtText: String = {
                guard updatedAtMs > 0 else { return "" }
                let dt = Date(timeIntervalSince1970: TimeInterval(updatedAtMs) / 1000.0)
                let formatter = DateFormatter()
                formatter.dateFormat = "yyyy-MM-dd HH:mm"
                return "Note updated: \(formatter.string(from: dt))"
            }()

            let blocks = store.db.queryRows("""
            SELECT b.payload_json AS payload_json
            FROM nj_note_block nb
            JOIN nj_block b
              ON b.block_id = nb.block_id
            WHERE nb.deleted = 0
              AND b.deleted = 0
              AND nb.note_id = '\(noteID)'
            ORDER BY nb.order_key ASC
            LIMIT 1;
            """)
            guard let payload = blocks.first?["payload_json"], !payload.isEmpty else {
                return (updateText: "Note found but content block is missing.", updatedAtText: updatedAtText)
            }

            let body = extractClipBodyFromPayloadJSON(payload) ?? ""
            let updateText = extractLatestUpdateBlock(from: body)
                .trimmingCharacters(in: .whitespacesAndNewlines)
            let finalText = updateText.isEmpty ? "Note found but no update block was detected." : updateText
            return (updateText: finalText, updatedAtText: updatedAtText)
        }.value
    }

    private func extractClipBodyFromPayloadJSON(_ payloadJSON: String) -> String? {
        guard let data = payloadJSON.data(using: .utf8),
              let root = (try? JSONSerialization.jsonObject(with: data)) as? [String: Any],
              let sections = root["sections"] as? [String: Any],
              let clip = sections["clip"] as? [String: Any],
              let clipData = clip["data"] as? [String: Any],
              let body = clipData["body"] as? String
        else { return nil }
        return body
    }

    private func extractLatestUpdateBlock(from body: String) -> String {
        let lines = body.split(separator: "\n", omittingEmptySubsequences: false).map(String.init)
        var lastStart: Int? = nil
        for (i, line) in lines.enumerated() {
            if line.hasPrefix("Update ") {
                lastStart = i
            }
        }
        guard let start = lastStart else { return "" }

        var end = lines.count
        for i in (start + 1)..<lines.count {
            if lines[i].hasPrefix("Update ") {
                end = i
                break
            }
        }
        return lines[start..<end].joined(separator: "\n")
    }

    private func hydrateCachedSystemLiquiditySnapshots() {
        let now = Date()
        let start = calendar.date(byAdding: .day, value: -370, to: now) ?? now
        let rows = store.notes
            .listFinanceMacroEvents(startKey: dateKey(start), endKey: dateKey(now))
            .filter { $0.category == "cache_system_liquidity" && $0.deleted == 0 }

        var newestByID: [String: (updatedAtMs: Int64, snapshot: NJSystemLiquiditySnapshot)] = [:]
        var newestRefreshAtMs: Int64 = 0
        for row in rows {
            guard let payload = decodeCachePayload(NJSystemLiquiditySnapshotCachePayload.self, from: row.notes) else { continue }
            let tone = NJSystemLiquidityTone(rawValue: payload.tone) ?? .research
            let updatedAt = Date(timeIntervalSince1970: TimeInterval(payload.updatedAtMs) / 1000.0)
            let snapshot = NJSystemLiquiditySnapshot(
                valueText: payload.valueText,
                detailText: payload.detailText,
                tone: tone,
                source: payload.source,
                updatedAt: updatedAt,
                numericValue: payload.numericValue
            )
            if let existing = newestByID[payload.id], existing.updatedAtMs >= row.updatedAtMs { continue }
            newestByID[payload.id] = (row.updatedAtMs, snapshot)
            newestRefreshAtMs = max(newestRefreshAtMs, row.updatedAtMs)
        }

        guard !newestByID.isEmpty else { return }
        var hydrated: [String: NJSystemLiquiditySnapshot] = [:]
        for (id, entry) in newestByID {
            hydrated[id] = entry.snapshot
        }
        systemLiquiditySnapshots.merge(hydrated) { _, new in new }
        if newestRefreshAtMs > 0 {
            let refreshedAt = Date(timeIntervalSince1970: TimeInterval(newestRefreshAtMs) / 1000.0)
            if systemLiquidityLastRefreshAt == nil || refreshedAt > (systemLiquidityLastRefreshAt ?? .distantPast) {
                systemLiquidityLastRefreshAt = refreshedAt
                systemLiquidityStatus = "Synced daily read available"
            }
        }
        NJInvestmentDebugLog("LIQUIDITY_CACHE_HYDRATE snapshots=\(newestByID.count)")
    }

    private func persistCachedLiveQuotes(_ quotes: [NJInvestmentLiveQuote]) {
        guard !quotes.isEmpty else { return }
        let nowMs = DBNoteRepository.nowMs()
        for quote in quotes {
            let payload = NJInvestmentLiveQuoteCachePayload(
                id: quote.id,
                sourceSymbol: quote.sourceSymbol,
                dateKey: quote.dateKey,
                timeText: quote.timeText,
                close: quote.close,
                previousClose: quote.previousClose,
                source: quote.source,
                fiftyTwoWeekHigh: quote.fiftyTwoWeekHigh,
                fiftyTwoWeekLow: quote.fiftyTwoWeekLow,
                cachedAtMs: nowMs
            )
            guard let notesJSON = encodeCachePayload(payload) else { continue }

            store.notes.upsertFinanceMacroEvent(
                NJFinanceMacroEvent(
                    eventID: "cache.live_quote.\(cacheKeyFragment(quote.id))",
                    dateKey: quote.dateKey,
                    title: "Quote \(quote.id) \(quote.valueText) \(quote.changeText)",
                    category: "cache_live_quote",
                    region: cacheRegion(for: quote.id),
                    timeText: quote.timeText,
                    impact: quote.isDown ? "down" : "up",
                    source: quote.source,
                    notes: notesJSON,
                    createdAtMs: nowMs,
                    updatedAtMs: nowMs,
                    deleted: 0
                )
            )
        }
    }

