    private func persistCachedSystemLiquiditySnapshots(_ snapshots: [String: NJSystemLiquiditySnapshot]) {
        guard !snapshots.isEmpty else { return }
        let nowMs = DBNoteRepository.nowMs()
        let fallbackDate = Date()
        for (id, snapshot) in snapshots {
            let updatedAt = snapshot.updatedAt ?? fallbackDate
            let updatedAtMs = Int64(updatedAt.timeIntervalSince1970 * 1000)
            let payload = NJSystemLiquiditySnapshotCachePayload(
                id: id,
                numericValue: snapshot.numericValue,
                valueText: snapshot.valueText,
                detailText: snapshot.detailText,
                tone: snapshot.tone.rawValue,
                source: snapshot.source,
                updatedAtMs: updatedAtMs,
                cachedAtMs: nowMs
            )
            guard let notesJSON = encodeCachePayload(payload) else { continue }
            let key = dateKey(updatedAt)
            store.notes.upsertFinanceMacroEvent(
                NJFinanceMacroEvent(
                    eventID: "cache.system_liquidity.\(cacheKeyFragment(id)).\(key)",
                    dateKey: key,
                    title: "Liquidity \(id) \(snapshot.valueText)",
                    category: "cache_system_liquidity",
                    region: "Liquidity",
                    timeText: systemLiquidityTimeText(updatedAt),
                    impact: snapshot.tone.rawValue.lowercased(),
                    source: snapshot.source,
                    notes: notesJSON,
                    createdAtMs: nowMs,
                    updatedAtMs: nowMs,
                    deleted: 0
                )
            )
        }
    }

    private func cacheKeyFragment(_ raw: String) -> String {
        let allowed = Set("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_.")
        let cleaned = raw.map { allowed.contains($0) ? $0 : "_" }
        return String(cleaned).lowercased()
    }

    private func cacheRegion(for symbol: String) -> String {
        if symbol.contains("/") { return "FX" }
        let parts = symbol.split(separator: " ").map(String.init)
        if parts.count == 2 {
            switch parts[1] {
            case "HK", "CN": return "HK / China"
            case "JP": return "Japan"
            default: break
            }
        }
        if ["tokyo", "jgb", "usdjpy"].contains(symbol) { return "Japan" }
        if ["hkse", "shanghai-a", "usdcnh"].contains(symbol) { return "HK / China" }
        if ["bitcoin", "ethereum", "brent", "wti", "gold", "silver"].contains(symbol) { return "Commodity / Crypto" }
        if ["stoxx600", "stoxx50", "ftse100", "bund10y", "uk10y", "eurusd"].contains(symbol) { return "Europe" }
        return "US"
    }

    private func encodeCachePayload<T: Encodable>(_ payload: T) -> String? {
        let encoder = JSONEncoder()
        guard let data = try? encoder.encode(payload) else { return nil }
        return String(data: data, encoding: .utf8)
    }

    private func decodeCachePayload<T: Decodable>(_ type: T.Type, from text: String) -> T? {
        guard let data = text.data(using: .utf8) else { return nil }
        let decoder = JSONDecoder()
        return try? decoder.decode(type, from: data)
    }

